INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('e7316dd2-63a5-5a75-b004-aab4c1ab4f9c', 'arabic-8eme', 'الجملة المركّبة', 'الجملة المركّبة في السنة الثامنة: أنواعها الثلاثة (التركيب بالوصل، والتركيب بالإسناد، والتركيب بالربط)، والجملة الموصولة (الاسم الموصول وصلته والعائد)، والتمييز بين الجمل التي لها محلّ من الإعراب (الواقعة خبرًا أو حالًا أو نعتًا أو مفعولًا به أو مضافًا إليه) والجمل التي لا محلّ لها (الابتدائية، وصلة الموصول، والمعطوفة على ما لا محلّ له)', '# ⚔️ الجملة المركّبة — أنواعُها ومحلُّها من الإعراب

> 💡 «الجملةُ البسيطةُ نواةٌ واحدة، فإذا تشابكتِ النّوى وُلدتِ الجملةُ المركّبة؛ وسرُّ إعرابها سؤالٌ واحد: أهذه الجملةُ الصّغرى ركنٌ لها محلّ، أم رابطةٌ لا محلّ لها؟»

عرفتَ في السّنة الماضية أنّ **الجملة البسيطة** تقوم على نواةٍ إسناديّةٍ واحدة، وأنّ **الجملة المركّبة** تضمّ أكثر من نواة. هذا العام نرتقي خطوةً: نصنّف المركّبةَ إلى **ثلاثة أنواع**، ونتعلّم **الجملة الموصولة**، ثمّ نجيب عن أهمّ سؤال في إعراب الجمل: **متى يكون للجملة محلٌّ من الإعراب، ومتى لا محلَّ لها؟**

## 🏰 تذكيرٌ سريع: النّواة والتّركيب

كلّ نواةٍ إسناديّة هي [فعل + فاعل] أو [مبتدأ + خبر]. فإذا تعدّدت النّوى صارت الجملةُ **مركّبة**. والجديد أنّ الجملة الكبرى قد تحتوي على **جملةٍ صغرى** بداخلها، وهذه الصّغرى قد تكون ركنًا في الكبرى (فلها محلّ)، وقد تكون مجرّد صلةٍ أو معطوفةٍ (فلا محلّ لها).

## ⚡ أنواع الجملة المركّبة الثّلاثة

| النّوع                | كيف تترابط الجمل                                | مثال                                |
| --------------------- | ----------------------------------------------- | ----------------------------------- |
| **التّركيب بالوصل**   | جملتان مستقلّتان تُوصَلان بحرف عطف (و، ف، ثمّ…) | طلعتِ الشّمسُ **و**غرّدتِ العصافيرُ |
| **التّركيب بالإسناد** | جملةٌ صغرى تقع ركنًا (خبرًا…) في جملةٍ كبرى     | العصفورُ **يغرّدُ فوق الغصنِ**      |
| **التّركيب بالرّبط**  | جملةٌ تُربَط بأخرى بأداة ربطٍ (اسم موصول…)      | أحترمُ المعلّمَ **الّذي يُخلصُ**    |

> 🗡️ الميزان: في **الوصل** حرفُ عطفٍ يصل جملتين تامّتين؛ وفي **الإسناد** جملةٌ صغرى تسدّ مسدّ ركنٍ (كالخبر)؛ وفي **الرّبط** أداةٌ (كالموصول) تُلحِق جملةً بأخرى.

## 🔮 الجملة الموصولة

**الاسم الموصول** يدلّ على معيّنٍ بجملةٍ بعده تُسمّى **الصّلة**. أشهر الموصولات: الّذي، الّتي، اللّذانِ، اللّتانِ، الّذين، اللّاتي، ومَن (للعاقل)، وما (لغير العاقل).

- **صلة الموصول**: جملةٌ خبريّةٌ تأتي بعد الموصول فتوضّح معناه، ولا بدّ أن تشتمل على **عائدٍ**: ضميرٍ يعود على الموصول (بارزٍ أو مستترٍ).
- **إعراب الصّلة**: صلة الموصول **لا محلّ لها من الإعراب** أبدًا.
- **إعراب الموصول نفسه**: الاسم الموصول مبنيٌّ، فيُعرب **بحسب موقعه** في الجملة الكبرى (فاعلًا، مفعولًا، مبتدأً…).

مثال: _فازَ الّذي اجتهدَ_ — «الّذي» اسمٌ موصولٌ مبنيٌّ في محلّ رفع فاعل «فازَ»، وصلتُه جملة «اجتهدَ» (عائدُها ضميرٌ مستترٌ يعود على الّذي)، وهي **لا محلّ لها**.

> ⚠️ لا تخلط بين **الموصول** (له إعرابٌ بحسب موقعه) و**صلته** (لا محلّ لها دائمًا). الصّلة خادمةٌ للموصول، تكمّل معناه ولا تُعرب.

## 🛡️ الجمل الّتي لا محلّ لها من الإعراب

هي جملٌ لا تحلّ محلّ مفردٍ فلا تُعرب. أبرزها في هذا الدّرس:

1. **الجملة الابتدائيّة**: الّتي يُستهلّ بها الكلام، لا تسبقها عاملٌ يطلبها. مثال: _العلمُ يرفعُ صاحبَه_ — الجملة الكبرى ابتدائيّة لا محلّ لها.
2. **صلة الموصول**: كما مرّ، لا محلّ لها.
3. **الجملة المعطوفة على جملةٍ لا محلّ لها**: تأخذ حكمَ ما عُطفت عليه. مثال: _طلعتِ الشّمسُ وغرّدتِ العصافيرُ_ — جملة «غرّدتِ العصافيرُ» معطوفةٌ على ابتدائيّةٍ، فلا محلّ لها.

## 📐 الجمل الّتي لها محلّ من الإعراب

هي جملٌ تحلّ محلّ المفرد فتُعرب بإعرابه (رفعًا أو نصبًا أو جرًّا). أهمّها:

| موقع الجملة الصّغرى         | محلّها       | مثال                          |
| --------------------------- | ------------ | ----------------------------- |
| **خبرًا** للمبتدأ           | محلّ رفع     | التّلميذُ **يجتهدُ**          |
| **خبرًا** لناسخٍ            | محلّ نصب     | كانَ المطرُ **يهطلُ**         |
| **حالًا** (بعد معرفة)       | محلّ نصب     | جاءَ الطّفلُ **يبكي**         |
| **نعتًا** (بعد نكرة)        | بحسب المنعوت | رأيتُ طائرًا **يحلّقُ**       |
| **مفعولًا به** (مقول القول) | محلّ نصب     | قالَ الرّجلُ: **إنّي مسافرٌ** |
| **مضافًا إليه** (بعد ظرفٍ)  | محلّ جرّ     | جلستُ حيثُ **يجلسُ الضّيوفُ** |

## 🧮 لا تخلط: الجملة النّعت والجملة الحال

الجملتان كلتاهما **لهما محلّ نصبٍ أو رفعٍ**، والفارق في صاحبهما:

- إذا وقعتِ الجملةُ بعد **نكرةٍ** فهي **نعتٌ**: _رأيتُ طائرًا يحلّقُ_ (طائرًا نكرة).
- إذا وقعتِ الجملةُ بعد **معرفةٍ** فهي **حالٌ**: _رأيتُ الطّائرَ يحلّقُ_ (الطّائرَ معرفة).

> ⚠️ الخطأ الشّائع: الحكم على الجملة بالنّظر إلى شكلها وحده؛ الصّواب النّظرُ إلى **صاحبها**: نكرةٌ قبلها ⟶ نعت، معرفةٌ قبلها ⟶ حال.

## 🧪 منهجيّة تحديد محلّ الجملة

أمام أيّ جملةٍ صغرى داخل جملةٍ كبرى، اسأل بالتّرتيب:

1. **هل هي صلةُ موصولٍ أو ابتدائيّةٌ أو معطوفةٌ على ما لا محلّ له؟** ⟶ إذن **لا محلّ لها**.
2. وإلّا، **أيَّ ركنٍ تسدّ؟** خبرًا، حالًا، نعتًا، مفعولًا، مضافًا إليه؟ ⟶ محلّها إعرابُ ذلك الرّكن (رفع/نصب/جرّ).
3. **تحقّق**: استبدلها بمفردٍ يؤدّي وظيفتها؛ فإن استقام المعنى فلها محلّ ذلك المفرد.

> 🏆 بهذا تملك مفتاح الجملة المركّبة كلَّه: تصنّف تركيبها (وصلٌ، إسنادٌ، ربطٌ)، وتفكّ الجملة الموصولة، وتحكم على كلّ جملةٍ صغرى: أَلها محلٌّ من الإعراب أم لا. عتبةٌ جديدة عبرتَها نحو إعرابٍ أدقّ.', '# 📜 ملخّص: الجملة المركّبة — أنواعها ومحلّها من الإعراب

- **الجملة المركّبة**: تحتوي على أكثر من نواة إسناديّة، وقد تضمّ جملةً صغرى داخل جملةٍ كبرى.
- **أنواع التركيب الثلاثة**:
  - **بالوصل**: جملتان مستقلّتان تُوصَلان بحرف عطف (الواو، الفاء، ثمّ…).
  - **بالإسناد**: جملةٌ صغرى تقع ركنًا في الكبرى (خبرًا…).
  - **بالربط**: جملةٌ تُربَط بأخرى بأداة ربطٍ كالاسم الموصول.
- **الجملة الموصولة**: اسمٌ موصول (الّذي، الّتي، مَن، ما…) + **صلة** بعده فيها **عائدٌ** (ضمير يعود على الموصول).
  - **صلة الموصول لا محلّ لها من الإعراب** أبدًا.
  - **الاسم الموصول** مبنيٌّ، يُعرب بحسب موقعه (فاعلًا، مفعولًا، مبتدأً…).
- **الجمل التي لا محلّ لها**: الابتدائيّة، وصلة الموصول، والمعطوفة على جملةٍ لا محلّ لها.
- **الجمل التي لها محلّ**: الواقعة خبرًا (رفع/نصب)، حالًا بعد معرفة (نصب)، نعتًا بعد نكرة (بحسب المنعوت)، مفعولًا به/مقول القول (نصب)، مضافًا إليه بعد ظرفٍ (جرّ).
- **نعت أم حال؟** بعد **نكرةٍ** ⟶ نعت، بعد **معرفةٍ** ⟶ حال، وكلتاهما لها محلّ.
- **منهجيّة المحلّ**: أهي صلةٌ/ابتدائيّةٌ/معطوفةٌ على ما لا محلّ له؟ فلا محلّ لها؛ وإلّا فمحلّها إعرابُ الرّكن الذي تسدّه، ويُتحقّق باستبدالها بمفرد.', 8, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('9c0c6656-27fd-5a19-9686-7973e09dd6ed', 'arabic-8eme', 'اسم التفضيل: صياغته وأحكامه ومطابقته وإعرابه', 'صوغ اسم التفضيل على وزن أفعَل وشروطه، وأحكامه مجرّدًا ومعرّفًا بأل ومضافًا إلى نكرة أو معرفة، ومطابقته وإعرابه، والتفضيل بأشدّ وأكثر عند تعذّر الصوغ المباشر', '# ⚔️ اسم التفضيل — سلاح المقارنة على وزن أفعَل

> 💡 «حين يشترك بطلان في صفةٍ ويزيد أحدهما على الآخر فيها، يستدعي اللسانُ سلاحًا واحدًا: اسم التفضيل. كلمةٌ على وزن أفعَل تُعلن مَن الأقوى.»

في الفصول السّابقة اشتققتَ من الجذر أسماءً تصف الفاعل والمفعول والحدث. الآن ترتقي درجةً: لن تصف بطلًا واحدًا، بل ستُوازن بين بطلين وتُعلن الأزيد. هذا هو **اسم التفضيل**، وهذه مغامرة إتقانه.

## 🏰 ما اسم التفضيل؟

**اسم التفضيل** اسمٌ مشتقٌّ على وزن **أفعَل** يدلّ على أنّ شيئين اشتركا في صفةٍ وزاد أحدهما على الآخر فيها.

- في «العلمُ **أنفعُ** من المالِ»: العلم والمال اشتركا في «النّفع»، وزاد العلمُ فيه.
- نسمّي الأوّل (العلم) **المفضَّل**، والثّاني (المال) **المفضَّل عليه**، وتدخل **«مِن» الجارّة** على المفضَّل عليه.

> 🗡️ اسم التفضيل ليس مجرّد وصفٍ لشيء، بل حكمٌ بالزّيادة في صفةٍ مشتركة بين طرفين.

## ⚡ صياغته المباشرة على وزن أفعَل — وشروطها

يُصاغ اسم التفضيل مباشرةً على وزن **أفعَل** من فعلٍ تتوفّر فيه شروطٌ سبعة؛ إن اختلّ واحدٌ منها امتنع الصّوغ المباشر:

1. أن يكون **فعلًا ثلاثيًّا** (ثلاثة أحرف): كَرُمَ ← أكرَم، شَرُفَ ← أشرَف، عَظُمَ ← أعظَم.
2. أن يكون **مجرّدًا** (غير مزيد): فيخرج «استخرج، اجتهد، أكرَم» لأنّها مزيدة.
3. أن يكون **متصرّفًا** (له ماضٍ ومضارع): فتخرج الأفعال الجامدة مثل «نِعمَ، بِئسَ، عسى».
4. أن يكون **تامًّا** (لا ناقصًا): فتخرج «كان» وأخواتها.
5. أن يكون **مبنيًّا للمعلوم** (لا للمجهول): فيخرج «عُرِفَ، كُسِرَ».
6. أن يكون **مثبتًا** (غير منفيّ): فيخرج «ما اجتهدَ».
7. أن يكون **قابلًا للتّفاوت** (تقبل صفته الزّيادة والنّقص): فيخرج مثل «ماتَ، فَنِيَ» لأنّها لا تتفاوت، فلا مفاضلة فيها.

> ⚠️ شرطٌ ثامن دقيق: ألاّ يكون الوصف من الفعل على وزن **أفعَل الّذي مؤنّثه فَعلاء** (الدّالّ على لونٍ أو عيبٍ): حَمِرَ ← أحمر/حمراء، سَوِدَ ← أسود/سوداء، عَرِجَ ← أعرج/عرجاء. فهذه لا يُصاغ منها اسم تفضيلٍ مباشرٌ رغم أنّها ثلاثيّة.

## 🔮 عند تعذّر الصّوغ المباشر — أشدّ / أكثر + مصدر

إذا فُقد شرطٌ من الشّروط (كأن يكون الفعل مزيدًا، أو الوصف على وزن أفعَل فعلاء) توصّلنا إلى التّفضيل بطريقةٍ **غير مباشرة**:

> نأتي باسم تفضيلٍ مساعدٍ مناسب (**أكثر، أشدّ، أعظم، أحسن**) ثمّ نُتبعه بـ**مصدر** الفعل الأصليّ **منصوبًا على أنّه تمييز**.

- الفعل مزيد (اجتهد): محمّدٌ **أكثرُ اجتهادًا** من زميله. («اجتهادًا» تمييز منصوب.)
- الفعل مزيد (استخرج): هذا المنجمُ **أكثرُ استخراجًا** للفسفاط.
- الوصف لونٌ (حَمِرَ): هذا الثّوبُ **أشدُّ حُمرةً** من ذاك. (لا نقول «أحمرُ منه».)

> 🗡️ في هذا التّركيب: «أكثر/أشدّ» هو اسم التفضيل العامل، والمصدر بعده **تمييزٌ منصوب** يكشف جهة المفاضلة.

## 🛡️ أحكامه الأربعة — المطابقة بحسب حالته

يأتي اسم التفضيل «أفعَل» في **أربع حالات**، ولكلّ حالةٍ حكمٌ في المطابقة:

**1. مجرّدًا من «أل» والإضافة** (نكرة): يلزم **الإفراد والتّذكير دائمًا** مهما كان المفضَّل، ويُذكر بعده غالبًا **«مِن»**.

- الطّالبُ **أفضلُ** من غيره · الطّالبتانِ **أفضلُ** من غيرهما · الطّالباتُ **أفضلُ** من غيرهنّ (يبقى «أفضل» على حاله).

**2. مقترنًا بـ«أل»** (معرّفًا): يجب أن **يُطابق** موصوفه في الإفراد والتّثنية والجمع والتّذكير والتّأنيث، ولا تُذكر بعده «مِن».

- المذكّر: الأفضل · المؤنّث: **الفُضلى** · المثنّى: الأفضلان · جمع المذكّر: الأفضلون · جمع المؤنّث: **الفُضليات**.
- محمّدٌ **الأفضلُ** · فاطمةُ **الفُضلى** · هم **الأفضلون** · هنّ **الفُضليات**.

**3. مضافًا إلى نكرة**: يلزم **الإفراد والتّذكير** (كالمجرّد).

- محمّدٌ **أفضلُ** طالبٍ · هندٌ **أفضلُ** طالبةٍ (يبقى «أفضل» مفردًا مذكّرًا وإن كان المفضَّل مؤنّثًا).

**4. مضافًا إلى معرفة**: يجوز فيه **وجهان**؛ إمّا الإفراد والتّذكير، وإمّا المطابقة.

- هندٌ **أفضلُ** الطّالبات (إفراد) أو **فُضلى** الطّالبات (مطابقة) · هم **أفضلُ** القوم أو **أفضلو** القوم.

> ⚠️ الخطأ الأكبر أن يُطابق التّلميذُ اسمَ التفضيل في الحالة المجرّدة أو المضافة إلى نكرة، فيقول «الطّالباتُ فُضليات من غيرهنّ» أو «هندٌ فُضلى طالبةٍ». الصّواب لزوم الإفراد والتّذكير: «أفضلُ».

## 🧮 إعرابه

اسم التفضيل اسمٌ مُعرَب يأخذ موقعه من الجملة: يقع **خبرًا** (العلمُ أنفعُ)، **نعتًا** (رأيتُ الطّالبَ الأفضلَ)، **حالًا**، أو **مبتدأً**... ويُعرَب حسب موقعه رفعًا أو نصبًا أو جرًّا. أمّا ما بعد «مِن» فاسمٌ مجرور (مفضَّل عليه)، و**المصدر** بعد «أشدّ/أكثر» **تمييزٌ منصوب**.

> 🏆 أتقنتَ الآن صوغ اسم التفضيل وشروطه، وأحكامه الأربعة، ومطابقته وإعرابه، والتّفضيل غير المباشر بأشدّ وأكثر. سلاحُ المقارنة صار بيدك — إلى الميدان!', '# 📜 ملخّص: اسم التفضيل (صرف)

- **اسم التفضيل**: اسمٌ مشتقٌّ على وزنِ **أفعَل** يدلّ على أنّ شيئين اشتركا في صفةٍ وزاد أحدُهما فيها. الأوّلُ **المفضَّلُ**، والثاني **المفضَّلُ عليه**، وتدخلُ **«مِن» الجارّةُ** على المفضَّلِ عليه. مثل: _العلمُ أنفعُ من المالِ._
- **شروطُ صوغِه المباشرِ**: يُصاغ من فعلٍ **ثلاثيٍّ مجرّدٍ متصرّفٍ تامٍّ مبنيٍّ للمعلومِ مثبتٍ قابلٍ للتفاوتِ**، وليس الوصفُ منه على وزنِ **أفعَلَ الذي مؤنّثُه فَعلاءُ** (لونٍ أو عيبٍ). مثل: كَرُمَ ← أكرَم ؛ شَرُفَ ← أشرَف.
- **عند تعذّرِ الصوغِ** (فعلٌ مزيدٌ، أو وصفُ لونٍ/عيبٍ...): نأتي بـ**أشدّ / أكثر / أعظم** ثمّ **مصدرِ** الفعلِ الأصليِّ **منصوبًا على أنّه تمييزٌ**. مثل: _أكثرُ اجتهادًا ؛ أشدُّ حُمرةً._
- **أحكامُه الأربعةُ (المطابقةُ)**:
  - **مجرّدًا** (بلا أل وبلا إضافةٍ): يلزمُ **الإفرادَ والتذكيرَ دائمًا**، وبعدَه «مِن». مثل: _الطالبتانِ أفضلُ من غيرِهما._
  - **معرّفًا بأل**: **يطابقُ** موصوفَه إفرادًا وتثنيةً وجمعًا وتذكيرًا وتأنيثًا، ولا تدخلُ «مِن». مثل: الأفضل، **الفُضلى**، الأفضلون، **الفُضليات**.
  - **مضافًا إلى نكرةٍ**: يلزمُ **الإفرادَ والتذكيرَ**. مثل: _هندٌ أفضلُ طالبةٍ._
  - **مضافًا إلى معرفةٍ**: يجوزُ فيه **وجهان**: الإفرادُ والتذكيرُ، أو المطابقةُ. مثل: _أفضلُ الطلابِ_ أو _أفاضلُ الطلابِ._
- **إعرابُه**: اسمٌ مُعرَبٌ يأخذُ موقعَه من الجملةِ (خبرًا، نعتًا، حالًا، مبتدأً...) رفعًا أو نصبًا أو جرًّا. والمفضَّلُ عليه بعدَ «مِن» **مجرورٌ**، والمصدرُ بعدَ «أشدّ/أكثر» **تمييزٌ منصوبٌ**.', 9, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
