INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d82d724-6bb2-5407-9240-01559b0931aa', 'af904884-b140-541d-a637-7e3a3676fc40', 'ما النعتُ في اصطلاح النحاة؟', '[{"id":"a","text":"اسمٌ يدلّ على مكانِ وقوعِ الفعلِ"},{"id":"b","text":"حرفٌ يربطُ بين جملتين"},{"id":"c","text":"تابعٌ يذكرُ صفةً في الاسمِ قبلَه أو فيما يتّصلُ به"},{"id":"d","text":"فعلٌ يدلّ على حدثٍ في زمنٍ"}]'::jsonb, 'c', 'النعتُ (الصفةُ) تابعٌ يذكرُ صفةً في متبوعِه (المنعوتِ) أو فيما يتّصلُ به، ويتبعُه في إعرابِه. وليس ظرفًا ولا حرفًا ولا فعلًا.', 1)
