INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0fc02db1-67a3-53d9-93db-2f5ffb908b47', 'af904884-b140-541d-a637-7e3a3676fc40', 'النعتُ الحقيقيُّ يطابقُ منعوتَه في كم أمرٍ؟', '[{"id":"a","text":"أمرٍ واحدٍ فقط هو الإعرابُ"},{"id":"b","text":"أمرين: الإعرابِ والتعريفِ"},{"id":"c","text":"ثلاثةِ أمورٍ دونَ العددِ"},{"id":"d","text":"أربعةِ أمورٍ: الإعرابِ والتعريفِ والعددِ والتذكيرِ/التأنيثِ"}]'::jsonb, 'd', 'النعتُ الحقيقيُّ يصفُ المنعوتَ نفسَه فيطابقُه في أربعةٍ كاملةٍ: الإعرابِ، والتعريفِ والتنكيرِ، والعددِ، والتذكيرِ والتأنيثِ.', 3)
