INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ec685cd4-b73b-5c36-a483-5a7d518b3ce1', 'af904884-b140-541d-a637-7e3a3676fc40', 'الجملةُ الواقعةُ بعدَ نكرةٍ نحو «رأيتُ طائرًا يحلّقُ» تُعربُ...', '[{"id":"a","text":"حالًا؛ لأنّها جملةٌ فعليّةٌ"},{"id":"b","text":"نعتًا (صفةً) في محلِّ نصبٍ؛ لأنّها بعدَ نكرةٍ"},{"id":"c","text":"مفعولًا به ثانيًا"},{"id":"d","text":"مبتدأً وخبرًا"}]'::jsonb, 'b', 'القاعدةُ: الجملُ بعدَ النكراتِ نعوتٌ، وبعدَ المعارفِ أحوالٌ. و«طائرًا» نكرةٌ، فجملةُ «يحلّقُ» نعتٌ في محلِّ نصبٍ.', 4)
