INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e470e3e-2db9-524c-b1d1-92e9948b36f3', 'af904884-b140-541d-a637-7e3a3676fc40', 'في «فازَ اللاعبُ السريعةُ قدماه»، ما نوعُ النعتِ «السريعةُ»، ولماذا جاء مؤنّثًا مع أنّ «اللاعبُ» مذكّرٌ؟', '[{"id":"a","text":"نعتٌ حقيقيٌّ، وجاء مؤنّثًا خطأً"},{"id":"b","text":"نعتٌ سببيٌّ، أُنّثَ لأنّه يطابقُ «قدماه» المؤنّثَ الذي بعدَه"},{"id":"c","text":"حالٌ منصوبةٌ"},{"id":"d","text":"نعتٌ حقيقيٌّ يطابقُ «اللاعبَ» في التأنيثِ"}]'::jsonb, 'b', '«السريعةُ» نعتٌ سببيٌّ؛ لأنّه لا يصفُ اللاعبَ نفسَه بل يصفُ «قدميه». والنعتُ السببيُّ يطابقُ الاسمَ الذي بعدَه (قدماه مؤنّثٌ) في التأنيثِ، ويطابقُ المنعوتَ (اللاعبُ) في الإعرابِ والتعريفِ فقط، ويبقى مفردًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

