INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('26b34e24-bfa7-5065-83e5-c7ed91da2a50', '53d27f11-ff61-563f-bdbc-207bce2074e8', 'أكملْ بالنعتِ الصحيحِ: «سلّمتُ على الطبيبِ ...»', '[{"id":"a","text":"الماهرُ"},{"id":"b","text":"الماهرِ"},{"id":"c","text":"ماهرٍ"},{"id":"d","text":"الماهرَ"}]'::jsonb, 'b', '«الطبيبِ» مجرورٌ (بحرفِ الجرِّ «على») ومعرفةٌ (بأل)، فيطابقُه النعتُ في الجرِّ والتعريفِ: «الماهرِ». و«ماهرٍ» نكرةٌ لا تطابقُ المعرفةَ.', 5)
