INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c8b069f6-0457-5146-aefd-6161b721d2ea', '53d27f11-ff61-563f-bdbc-207bce2074e8', 'في «جاءَ ضيفٌ كريمٌ»، ما إعرابُ «كريمٌ»؟', '[{"id":"a","text":"نعتٌ مرفوعٌ وعلامةُ رفعِه الضمّةُ"},{"id":"b","text":"فاعلٌ مرفوعٌ وعلامةُ رفعِه الضمّةُ"},{"id":"c","text":"خبرٌ مرفوعٌ"},{"id":"d","text":"نعتٌ منصوبٌ وعلامةُ نصبِه الفتحةُ"}]'::jsonb, 'a', '«كريمٌ» تابعٌ لـ«ضيفٌ» (الفاعلِ المرفوعِ)، فهو نعتٌ مرفوعٌ وعلامةُ رفعِه الضمّةُ. والفاعلُ هو «ضيفٌ» لا «كريمٌ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3a10c680-23b8-5d2b-bd00-8f34ceb920fd', '8b933caf-da7d-5ceb-bcde-8a029d3416b6', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: النعتُ الحقيقيُّ والسببيُّ', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('51a4a5d1-094c-5316-8f6b-5720be884d6e', '3a10c680-23b8-5d2b-bd00-8f34ceb920fd', 'ما نوعُ النعتِ في «سرنا في وادٍ ماؤه عذبٌ»؟', '[{"id":"a","text":"نعتٌ مفردٌ"},{"id":"b","text":"نعتٌ جملةٌ اسميّةٌ"},{"id":"c","text":"نعتٌ شبهُ جملةٍ"},{"id":"d","text":"حالٌ"}]'::jsonb, 'b', '«ماؤه عذبٌ» جملةٌ اسميّةٌ (مبتدأٌ وخبرٌ) وقعتْ بعدَ النكرةِ «وادٍ» فوصفتْها، فهي نعتٌ جملةٌ اسميّةٌ في محلِّ جرٍّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4108ba71-3922-53c5-9f63-9c5b866330cd', '3a10c680-23b8-5d2b-bd00-8f34ceb920fd', 'في «أُعجبتُ بلوحةٍ ألوانُها زاهيةٌ»، ما محلُّ جملةِ «ألوانُها زاهيةٌ» من الإعرابِ؟', '[{"id":"a","text":"نعتٌ في محلِّ جرٍّ"},{"id":"b","text":"نعتٌ في محلِّ رفعٍ"},{"id":"c","text":"حالٌ في محلِّ نصبٍ"},{"id":"d","text":"لا محلَّ لها من الإعرابِ"}]'::jsonb, 'a', '«لوحةٍ» نكرةٌ مجرورةٌ بالباءِ، والجملةُ بعدَها نعتٌ يتبعُها في الجرِّ؛ فجملةُ «ألوانُها زاهيةٌ» نعتٌ في محلِّ جرٍّ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('32026e73-acff-57ab-a289-9ff28db71284', '3a10c680-23b8-5d2b-bd00-8f34ceb920fd', 'أكملْ بالنعتِ السببيِّ الصحيحِ: «قرأتُ قصّةً ... خيالُها»', '[{"id":"a","text":"جميلةً"},{"id":"b","text":"جميلٌ"},{"id":"c","text":"الجميلةَ"},{"id":"d","text":"جميلًا"}]'::jsonb, 'd', 'النعتُ السببيُّ يطابقُ المنعوتَ «قصّةً» في النصبِ والتنكيرِ، ويبقى مفردًا، ويطابقُ الاسمَ الذي بعدَه «خيالُها» (مذكّرٌ) في التذكيرِ؛ فالصوابُ «جميلًا» (منصوبٌ نكرةٌ مفردٌ مذكّرٌ).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7c13f2f-4181-582a-8c19-489bb6bcc602', '3a10c680-23b8-5d2b-bd00-8f34ceb920fd', 'أكملْ بالنعتِ السببيِّ الصحيحِ: «حضرتِ المعلّمةُ ... تلاميذُها»', '[{"id":"a","text":"المجتهدةُ"},{"id":"b","text":"المجتهدونَ"},{"id":"c","text":"المجتهدُ"},{"id":"d","text":"المجتهداتُ"}]'::jsonb, 'c', 'النعتُ السببيُّ يطابقُ المنعوتَ «المعلّمةُ» في الرفعِ والتعريفِ، ويبقى مفردًا، لكنّه يطابقُ الاسمَ الذي بعدَه «تلاميذُها» (مذكّرٌ) في التذكيرِ؛ فالصوابُ «المجتهدُ» مذكّرًا مفردًا وإن كان المنعوتُ مؤنّثًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('72d4ccae-0f7c-5678-97b2-8b2486f8fc1e', '3a10c680-23b8-5d2b-bd00-8f34ceb920fd', 'في «أقبلَ القائدُ يبتسمُ»، بمَ تُعربُ جملةُ «يبتسمُ»؟', '[{"id":"a","text":"نعتٌ في محلِّ رفعٍ"},{"id":"b","text":"خبرٌ في محلِّ رفعٍ"},{"id":"c","text":"حالٌ في محلِّ نصبٍ"},{"id":"d","text":"نعتٌ مفردٌ منصوبٌ"}]'::jsonb, 'c', '«القائدُ» معرفةٌ، والجملةُ بعدَ المعرفةِ حالٌ لا نعتٌ؛ فجملةُ «يبتسمُ» حالٌ في محلِّ نصبٍ. ولو كان «قائدٌ» نكرةً لكانتْ نعتًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1e172e84-6df1-5b92-a0ca-659b7dc6fb19', '3a10c680-23b8-5d2b-bd00-8f34ceb920fd', 'في «شربنا ماءً باردًا»، ما إعرابُ «باردًا»؟', '[{"id":"a","text":"نعتٌ منصوبٌ وعلامةُ نصبِه الفتحةُ"},{"id":"b","text":"مفعولٌ به منصوبٌ"},{"id":"c","text":"حالٌ منصوبةٌ"},{"id":"d","text":"نعتٌ مرفوعٌ"}]'::jsonb, 'a', '«باردًا» تابعٌ لـ«ماءً» (المفعولِ به المنصوبِ)، فهو نعتٌ منصوبٌ وعلامةُ نصبِه الفتحةُ. والمفعولُ به هو «ماءً» لا «باردًا».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

