  ('9d06a910-ba5e-55de-9eaf-d488cf6c8850', '8b933caf-da7d-5ceb-bcde-8a029d3416b6', 'arabic-8eme', '⭐⭐ تمرين: أنواعُ النعتِ ومطابقتُه', 2, 70, 15, 'practice', 'admin', 3)
