INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('66830eba-b315-50c5-8125-cd68d0b46e16', '9d06a910-ba5e-55de-9eaf-d488cf6c8850', 'ما نوعُ النعتِ «واسعٌ» في «طريقٌ واسعٌ»؟', '[{"id":"a","text":"نعتٌ مفردٌ"},{"id":"b","text":"نعتٌ جملةٌ"},{"id":"c","text":"نعتٌ شبهُ جملةٍ"},{"id":"d","text":"نعتٌ سببيٌّ"}]'::jsonb, 'a', '«واسعٌ» كلمةٌ واحدةٌ ليست جملةً ولا شبهَ جملةٍ، فهو نعتٌ مفردٌ يصفُ «طريقٌ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
