  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f7a321ba-4494-587b-a3e1-8be687e6e426', '9d06a910-ba5e-55de-9eaf-d488cf6c8850', 'ما نوعُ النعتِ في «رأيتُ عصفورًا يشربُ الماءَ»؟', '[{"id":"a","text":"نعتٌ مفردٌ"},{"id":"b","text":"نعتٌ شبهُ جملةٍ"},{"id":"c","text":"نعتٌ جملةٌ فعليّةٌ"},{"id":"d","text":"حالٌ"}]'::jsonb, 'c', '«يشربُ الماءَ» جملةٌ فعليّةٌ وقعتْ بعدَ النكرةِ «عصفورًا» فوصفتْها، والجملُ بعدَ النكراتِ نعوتٌ؛ فهي نعتٌ جملةٌ فعليّةٌ في محلِّ نصبٍ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3855e37f-5b14-531b-b5a7-23d3427bfb7d', '9d06a910-ba5e-55de-9eaf-d488cf6c8850', 'ما نوعُ النعتِ في «جلسنا في ظلٍّ تحتَ النخلةِ»؟', '[{"id":"a","text":"نعتٌ جملةٌ اسميّةٌ"},{"id":"b","text":"نعتٌ مفردٌ"},{"id":"c","text":"حالٌ"},{"id":"d","text":"نعتٌ شبهُ جملةٍ (ظرفٌ)"}]'::jsonb, 'd', '«تحتَ النخلةِ» ظرفٌ (شبهُ جملةٍ) وقعَ بعدَ النكرةِ «ظلٍّ» فوصفَها، وشبهُ الجملةِ بعدَ النكرةِ نعتٌ؛ فهو نعتٌ شبهُ جملةٍ في محلِّ جرٍّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0eb811f5-90ac-50d2-82fd-ca56e16a37f8', '9d06a910-ba5e-55de-9eaf-d488cf6c8850', 'أكملْ بالنعتِ الصحيحِ: «كافأتُ التلميذاتِ ...»', '[{"id":"a","text":"المجتهدُ"},{"id":"b","text":"المجتهداتِ"},{"id":"c","text":"المجتهدونَ"},{"id":"d","text":"المجتهدةَ"}]'::jsonb, 'b', '«التلميذاتِ» جمعُ مؤنّثٍ سالمٌ منصوبٌ (بالكسرةِ نيابةً عن الفتحةِ) معرفةٌ، فيطابقُه النعتُ الحقيقيُّ في ذلك: «المجتهداتِ». والمفردُ «المجتهدةَ» لا يطابقُ الجمعَ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4832db44-6c3f-5133-965a-e1e53eaf158d', '9d06a910-ba5e-55de-9eaf-d488cf6c8850', 'في «رأيتُ طفلًا يبكي»، بمَ تُعربُ جملةُ «يبكي»؟', '[{"id":"a","text":"نعتٌ في محلِّ نصبٍ"},{"id":"b","text":"حالٌ في محلِّ نصبٍ"},{"id":"c","text":"مفعولٌ به"},{"id":"d","text":"مبتدأٌ"}]'::jsonb, 'a', '«طفلًا» نكرةٌ، والجملةُ بعدَ النكرةِ نعتٌ لا حالٌ؛ فجملةُ «يبكي» نعتٌ في محلِّ نصبٍ. ولو قلتَ «رأيتُ الطفلَ يبكي» (معرفةٌ) لصارتْ حالًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f1bce14b-588c-5a4b-b7b6-fc18398d3232', '9d06a910-ba5e-55de-9eaf-d488cf6c8850', 'أكملْ بالنعتِ السببيِّ الصحيحِ: «هذا رجلٌ ... خُلُقُه»', '[{"id":"a","text":"كريمةٌ"},{"id":"b","text":"كريمونَ"},{"id":"c","text":"كريمٌ"},{"id":"d","text":"الكريمُ"}]'::jsonb, 'c', 'النعتُ السببيُّ يطابقُ المنعوتَ «رجلٌ» في التنكيرِ والرفعِ، ويبقى مفردًا، ويطابقُ الاسمَ الذي بعدَه «خُلُقُه» (مذكّرٌ) في التذكيرِ؛ فالصوابُ «كريمٌ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
