INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8946ce4f-d2c6-513e-ae5f-d595267ade70', '9087e0e3-1a48-59ca-af4c-fbe4a4a1c21b', 'الجملُ وأشباهُ الجملِ الواقعةُ بعدَ المعارفِ تُعربُ...', '[{"id":"a","text":"أحوالًا"},{"id":"b","text":"نعوتًا"},{"id":"c","text":"أخبارًا"},{"id":"d","text":"أبدالًا"}]'::jsonb, 'a', 'القاعدةُ الحاسمةُ: الجملُ وأشباهُ الجملِ بعدَ النكراتِ نعوتٌ، وبعدَ المعارفِ أحوالٌ. فبعدَ المعرفةِ تكونُ حالًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
