INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('38c1d92a-aec3-57f7-b631-7a4df35fb676', '9087e0e3-1a48-59ca-af4c-fbe4a4a1c21b', 'أكملْ بالنعتِ السببيِّ الصحيحِ: «رأيتُ رجالًا ... أبناؤهم»', '[{"id":"a","text":"مؤدّبينَ"},{"id":"b","text":"مؤدّبونَ"},{"id":"c","text":"مؤدّبًا"},{"id":"d","text":"مؤدّبةً"}]'::jsonb, 'c', 'الفخُّ هنا جمعُ المنعوتِ «رجالًا». لكنّ النعتَ السببيَّ يبقى مفردًا دائمًا؛ فيطابقُ المنعوتَ في النصبِ والتنكيرِ، ويطابقُ «أبناؤهم» (مذكّرٌ) في التذكيرِ، ويظلُّ مفردًا: «مؤدّبًا».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('793b08e6-255a-5025-9172-a5e1df5a6f89', '9087e0e3-1a48-59ca-af4c-fbe4a4a1c21b', 'أكملْ بالنعتِ السببيِّ الصحيحِ: «حضرَ الوزيرُ ... مكانتُه»', '[{"id":"a","text":"العظيمُ"},{"id":"b","text":"العظيمةُ"},{"id":"c","text":"عظيمةٌ"},{"id":"d","text":"العظيمِ"}]'::jsonb, 'b', 'النعتُ السببيُّ يطابقُ المنعوتَ «الوزيرُ» في الرفعِ والتعريفِ، لكنّه يطابقُ الاسمَ الذي بعدَه «مكانتُه» (مؤنّثٌ) في التأنيثِ؛ فالصوابُ «العظيمةُ» مؤنّثةً مرفوعةً معرفةً، وإن كان المنعوتُ مذكّرًا.', 3)
