  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1875f2fc-4173-5236-896e-170f8f5398fa', '9087e0e3-1a48-59ca-af4c-fbe4a4a1c21b', 'في «عندي كتابٌ صفحاتُه ملوّنةٌ»، بمَ تُعربُ جملةُ «صفحاتُه ملوّنةٌ»؟', '[{"id":"a","text":"نعتٌ في محلِّ رفعٍ"},{"id":"b","text":"نعتٌ في محلِّ نصبٍ"},{"id":"c","text":"حالٌ في محلِّ نصبٍ"},{"id":"d","text":"خبرٌ في محلِّ رفعٍ"}]'::jsonb, 'a', '«كتابٌ» نكرةٌ مرفوعةٌ (مبتدأٌ مؤخّرٌ)، والجملةُ الاسميّةُ بعدَها نعتٌ يتبعُها في الرفعِ؛ فجملةُ «صفحاتُه ملوّنةٌ» نعتٌ في محلِّ رفعٍ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a1b9f9b3-c171-583a-a7f8-d4c225d6d374', '9087e0e3-1a48-59ca-af4c-fbe4a4a1c21b', 'في «السماءُ صافيةٌ»، ما إعرابُ «صافيةٌ»؟', '[{"id":"a","text":"نعتٌ مرفوعٌ"},{"id":"b","text":"خبرٌ مرفوعٌ"},{"id":"c","text":"نعتٌ سببيٌّ مرفوعٌ"},{"id":"d","text":"حالٌ"}]'::jsonb, 'b', 'هنا إسنادٌ تامٌّ (مبتدأٌ وخبرٌ)، فـ«صافيةٌ» خبرٌ مرفوعٌ لا نعتٌ. والفرقُ: «السماءُ الصافيةُ...» (صافيةُ نعتٌ والكلامُ ناقصٌ ينتظرُ خبرًا)، أمّا «السماءُ صافيةٌ» فجملةٌ تامّةٌ خبرُها «صافيةٌ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6ea3b48b-0d49-58ed-89bc-25b47c1e9576', '9087e0e3-1a48-59ca-af4c-fbe4a4a1c21b', 'أكملْ بالنعتِ الصحيحِ: «شاهدتُ جبالًا ...» (جبالٌ جمعٌ لغيرِ العاقلِ)', '[{"id":"a","text":"شامخينَ"},{"id":"b","text":"شامخاتٍ"},{"id":"c","text":"شامخةً"},{"id":"d","text":"شامخونَ"}]'::jsonb, 'c', 'جمعُ غيرِ العاقلِ يُعامَلُ في الوصفِ معاملةَ المفردةِ المؤنّثةِ؛ فيُقالُ «جبالٌ شامخةٌ» لا «شامخونَ». والمنعوتُ منصوبٌ نكرةٌ، فالنعتُ «شامخةً» منصوبةٌ نكرةٌ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('c02315bc-cde2-5a4e-af6b-35b3f66a219c', '8b933caf-da7d-5ceb-bcde-8a029d3416b6', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: تمرّسٌ على النعتِ وإعرابِه', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e9a1f506-14b1-51b5-88c2-af2bcea12fb2', 'c02315bc-cde2-5a4e-af6b-35b3f66a219c', 'في «اشترى أبي سيّارةً حديثةً»، ما إعرابُ «حديثةً»؟', '[{"id":"a","text":"نعتٌ منصوبٌ"},{"id":"b","text":"نعتٌ مرفوعٌ"},{"id":"c","text":"نعتٌ مجرورٌ"},{"id":"d","text":"حالٌ منصوبةٌ"}]'::jsonb, 'a', '«سيّارةً» مفعولٌ به منصوبٌ، والنعتُ يتبعُه في النصبِ؛ فـ«حديثةً» نعتٌ منصوبٌ وعلامةُ نصبِه الفتحةُ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9bb48bc0-d5e2-581e-b035-0a3d21eadf61', 'c02315bc-cde2-5a4e-af6b-35b3f66a219c', 'في «هذا رجلٌ يساعدُ الفقراءَ»، بمَ تُعربُ جملةُ «يساعدُ الفقراءَ»؟', '[{"id":"a","text":"حالٌ في محلِّ نصبٍ"},{"id":"b","text":"نعتٌ جملةٌ فعليّةٌ في محلِّ رفعٍ"},{"id":"c","text":"مفعولٌ به"},{"id":"d","text":"نعتٌ مفردٌ"}]'::jsonb, 'b', '«رجلٌ» نكرةٌ مرفوعةٌ (خبرُ «هذا»)، والجملةُ بعدَها نعتٌ يتبعُها في الرفعِ؛ فجملةُ «يساعدُ الفقراءَ» نعتٌ في محلِّ رفعٍ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d8aa9b4c-9b7a-5001-a566-d87f71fe8dcf', 'c02315bc-cde2-5a4e-af6b-35b3f66a219c', 'في «شاهدتُ الهلالَ بينَ السحابِ»، بمَ يُعربُ شبهُ الجملةِ «بينَ السحابِ»؟', '[{"id":"a","text":"نعتٌ شبهُ جملةٍ"},{"id":"b","text":"نعتٌ مفردٌ"},{"id":"c","text":"حالٌ (شبهُ جملةٍ)"},{"id":"d","text":"مفعولٌ به"}]'::jsonb, 'c', '«الهلالَ» معرفةٌ، وشبهُ الجملةِ بعدَ المعرفةِ حالٌ لا نعتٌ؛ فـ«بينَ السحابِ» حالٌ. ولو كان «هلالًا» نكرةً لكان نعتًا شبهَ جملةٍ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d2af77c-12e2-5fd0-9232-6d5c309c1031', 'c02315bc-cde2-5a4e-af6b-35b3f66a219c', 'أكملْ بالنعتِ السببيِّ الصحيحِ: «مررتُ برجلٍ ... سيرتُه»', '[{"id":"a","text":"حسنٍ"},{"id":"b","text":"حسنةٍ"},{"id":"c","text":"حسنةً"},{"id":"d","text":"الحسنةِ"}]'::jsonb, 'b', 'النعتُ السببيُّ يطابقُ المنعوتَ «رجلٍ» في الجرِّ والتنكيرِ، ويبقى مفردًا، ويطابقُ الاسمَ الذي بعدَه «سيرتُه» (مؤنّثٌ) في التأنيثِ؛ فالصوابُ «حسنةٍ» (مجرورةٌ نكرةٌ مفردةٌ مؤنّثةٌ).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5b3f08c2-d9ef-5e8e-8e62-e7f906c5671b', 'c02315bc-cde2-5a4e-af6b-35b3f66a219c', 'في «جاءَ الرجلُ الكريمُ أبوه»، ما إعرابُ «الكريمُ»؟', '[{"id":"a","text":"نعتٌ (سببيٌّ) مرفوعٌ"},{"id":"b","text":"خبرٌ مرفوعٌ"},{"id":"c","text":"بدلٌ مرفوعٌ"},{"id":"d","text":"فاعلٌ مرفوعٌ"}]'::jsonb, 'a', '«الكريمُ» نعتٌ سببيٌّ تابعٌ للمنعوتِ «الرجلُ» في الرفعِ والتعريفِ؛ فهو نعتٌ مرفوعٌ. وقد وصفَ «أباه» في المعنى ورفعَه بعدَه، لكنّه في الإعرابِ تابعٌ للرجلِ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f8323e5-925e-56d6-a48b-106fd7831b85', 'c02315bc-cde2-5a4e-af6b-35b3f66a219c', 'أكملْ بالنعتِ الحقيقيِّ الصحيحِ: «التقيتُ بطالبَينِ ...»', '[{"id":"a","text":"مؤدّبٍ"},{"id":"b","text":"مؤدّبونَ"},{"id":"c","text":"مؤدّبانِ"},{"id":"d","text":"مؤدّبَينِ"}]'::jsonb, 'd', '«طالبَينِ» مثنّى مذكّرٌ مجرورٌ (بالياءِ) نكرةٌ، فيطابقُه النعتُ الحقيقيُّ في ذلك كلِّه: «مؤدّبَينِ» (مثنّى مجرورٌ بالياءِ). و«مؤدّبانِ» مرفوعٌ لا يطابقُ المجرورَ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3d324dc2-7ce2-539d-b5a1-3e5cbf0c179e', '8b933caf-da7d-5ceb-bcde-8a029d3416b6', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: النعتُ السببيُّ وأسرارُ المطابقةِ', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ecd6242-cf06-5e03-81b9-49003d3df30f', '3d324dc2-7ce2-539d-b5a1-3e5cbf0c179e', 'النعتُ السببيُّ من حيثُ العددُ يكونُ...', '[{"id":"a","text":"مفردًا مهما كان المنعوتُ"},{"id":"b","text":"مطابقًا للمنعوتِ في العددِ"},{"id":"c","text":"جمعًا دائمًا"},{"id":"d","text":"مثنّى دائمًا"}]'::jsonb, 'a', 'النعتُ السببيُّ يبقى مفردًا أبدًا؛ لأنّه يرفعُ اسمًا ظاهرًا بعدَه، فلا يتحمّلُ علامةَ التثنيةِ أو الجمعِ مهما كان عددُ المنعوتِ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('882969e6-20b0-5549-bbd3-b704889df35b', '3d324dc2-7ce2-539d-b5a1-3e5cbf0c179e', 'أكملْ بالنعتِ السببيِّ الصحيحِ: «سلّمتُ على تاجرٍ ... بضاعتُه»', '[{"id":"a","text":"كثيرِ"},{"id":"b","text":"كثيرةٍ"},{"id":"c","text":"كثيرةً"},{"id":"d","text":"الكثيرةِ"}]'::jsonb, 'b', 'النعتُ السببيُّ يطابقُ المنعوتَ «تاجرٍ» في الجرِّ والتنكيرِ، ويبقى مفردًا، ويطابقُ الاسمَ الذي بعدَه «بضاعتُه» (مؤنّثٌ) في التأنيثِ؛ فالصوابُ «كثيرةٍ» (مجرورةٌ نكرةٌ مفردةٌ مؤنّثةٌ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68f06443-9dd5-567c-9028-9849b1b733b5', '3d324dc2-7ce2-539d-b5a1-3e5cbf0c179e', 'في «قابلتُ فلّاحًا يحرثُ أرضَه»، بمَ تُعربُ جملةُ «يحرثُ أرضَه»؟', '[{"id":"a","text":"نعتٌ في محلِّ نصبٍ"},{"id":"b","text":"حالٌ في محلِّ نصبٍ"},{"id":"c","text":"نعتٌ مفردٌ منصوبٌ"},{"id":"d","text":"مفعولٌ به ثانٍ"}]'::jsonb, 'a', '«فلّاحًا» نكرةٌ منصوبةٌ، والجملةُ بعدَها نعتٌ يتبعُها في النصبِ؛ فجملةُ «يحرثُ أرضَه» نعتٌ في محلِّ نصبٍ لا حالٌ (لأنّ المنعوتَ نكرةٌ).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1686fad-d322-553e-b0c9-1066868dc5e7', '3d324dc2-7ce2-539d-b5a1-3e5cbf0c179e', 'أكملْ بالنعتِ الحقيقيِّ الصحيحِ: «كرّمتِ المدرسةُ المعلّماتِ ...»', '[{"id":"a","text":"المخلصاتُ"},{"id":"b","text":"المخلصينَ"},{"id":"c","text":"المخلصاتِ"},{"id":"d","text":"المخلصةَ"}]'::jsonb, 'c', '«المعلّماتِ» جمعُ مؤنّثٍ سالمٌ منصوبٌ (بالكسرةِ) معرفةٌ، فيطابقُه النعتُ الحقيقيُّ في العددِ والتأنيثِ والنصبِ والتعريفِ: «المخلصاتِ». و«المخلصينَ» جمعُ مذكّرٍ لا يطابقُ جمعَ المؤنّثِ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e3eb579-87fe-5590-8db6-b92c46bbdf1d', '3d324dc2-7ce2-539d-b5a1-3e5cbf0c179e', 'في «رأيتُ بستانًا مثمرةً أشجارُه»، ما نوعُ النعتِ «مثمرةً»؟', '[{"id":"a","text":"نعتٌ حقيقيٌّ"},{"id":"b","text":"نعتٌ سببيٌّ"},{"id":"c","text":"حالٌ"},{"id":"d","text":"بدلٌ"}]'::jsonb, 'b', '«مثمرةً» لا تصفُ «البستانَ» نفسَه بل تصفُ «أشجارَه»؛ فهي نعتٌ سببيٌّ. ولذلك بقيتْ مفردةً وأُنّثتْ تبعًا لـ«أشجارُه» (المؤنّثِ)، وطابقتِ المنعوتَ «بستانًا» في النصبِ والتنكيرِ فقط.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5f1a289a-1018-5bc5-acf3-37bb1a73781c', '3d324dc2-7ce2-539d-b5a1-3e5cbf0c179e', 'أكملْ بالنعتِ الحقيقيِّ الصحيحِ: «التقيتُ بمعلّمتَينِ ...»', '[{"id":"a","text":"فاضلتانِ"},{"id":"b","text":"فاضلاتٍ"},{"id":"c","text":"فاضلتَينِ"},{"id":"d","text":"فاضلةٍ"}]'::jsonb, 'c', '«معلّمتَينِ» مثنّى مؤنّثٌ مجرورٌ (بالياءِ) نكرةٌ، فيطابقُه النعتُ الحقيقيُّ في ذلك كلِّه: «فاضلتَينِ» (مثنّى مؤنّثٌ مجرورٌ بالياءِ). و«فاضلتانِ» مرفوعٌ لا يطابقُ المجرورَ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('6812300e-06b7-5fbf-8049-3099f7663560', '53ee79a4-de63-550a-b864-3140b91c2b3f', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
