INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8874aa45-8781-54ae-819d-d20bd665399f', '6812300e-06b7-5fbf-8049-3099f7663560', 'التوكيد واحدٌ من التّوابع الأربعة، وهي:', '[{"id":"a","text":"النّعت والتوكيد والبدل والعطف"},{"id":"b","text":"الفاعل والمفعول به والحال والتمييز"},{"id":"c","text":"المبتدأ والخبر والفعل والفاعل"},{"id":"d","text":"الجرّ والنّصب والرّفع والجزم"}]'::jsonb, 'a', 'التّوابع أربعة: النّعت، والتوكيد، والبدل، والعطف؛ وكلّها تتبع ما قبلها في الإعراب. والتوكيد أحدها، وهو موضوع هذا الفصل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
