INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c230263-dc5b-5dda-a86d-944cfbaea4ed', '6812300e-06b7-5fbf-8049-3099f7663560', '«انتبهْ انتبهْ للمنعرج عند مدخل جربة» — ما نوع التوكيد في «انتبهْ» الثّانية؟', '[{"id":"a","text":"توكيد معنويّ"},{"id":"b","text":"بدل"},{"id":"c","text":"توكيد لفظيّ، لأنّه إعادةٌ للّفظ نفسه"},{"id":"d","text":"نعت"}]'::jsonb, 'c', 'التوكيد اللفظيّ هو إعادة اللفظ نفسه؛ وهنا أُعيد الفعل «انتبهْ» مرّة ثانية، فهو توكيد لفظيّ للفعل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9f6b5a90-da55-5774-8b67-cca33c004a0d', '6812300e-06b7-5fbf-8049-3099f7663560', '«رجعَ التلاميذُ كلُّهم سالمين من رحلة عين دراهم» — ما إعراب «كلُّهم»؟', '[{"id":"a","text":"«كلُّ» فاعل مرفوع، و«هم» مضاف إليه"},{"id":"b","text":"«كلُّ» توكيد معنويّ مرفوع تابع للتلاميذ، و«هم» مضاف إليه"},{"id":"c","text":"«كلُّهم» بدل منصوب"},{"id":"d","text":"«كلُّ» نعت مرفوع"}]'::jsonb, 'b', '«كلّ» أُضيفت إلى الضّمير «هم» العائد على «التلاميذُ»، فهي توكيد معنويّ للشّمول، تابعٌ للمؤكَّد في الرّفع، والضّمير «هم» مضاف إليه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f0f024ee-f30c-5e31-84db-c507fe8d7ded', '6812300e-06b7-5fbf-8049-3099f7663560', '«فازَ الأخوان كلاهما في سباق الحمّامات» — بأيّ علامة رُفع التوكيد «كلا»؟', '[{"id":"a","text":"بالضّمّة الظّاهرة"},{"id":"b","text":"بالواو"},{"id":"c","text":"مبنيّة لا محلّ لها"},{"id":"d","text":"بالألف، لأنّها تُعرب إعراب المثنّى"}]'::jsonb, 'd', 'كلا وكلتا حين تُضافان إلى الضّمير تُعربان إعراب المثنّى: بالألف رفعًا وبالياء نصبًا وجرًّا؛ وهنا «كلاهما» توكيد مرفوع بالألف تبعًا للفاعل «الأخوان».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47b558e7-45e5-5ab5-b553-317202cf2ef7', '6812300e-06b7-5fbf-8049-3099f7663560', '«جاء البطلان أنفسُهما» — لماذا جاءت «أنفس» بصيغة الجمع مع أنّ المؤكَّد مثنّى؟', '[{"id":"a","text":"لأنّ نفسًا وعينًا تُجمعان (أنفُس، أعيُن) في توكيد المثنّى والجمع"},{"id":"b","text":"خطأ، والصّواب «نفساهما» بالمثنّى"},{"id":"c","text":"لأنّ التوكيد لا يطابق المؤكَّد"},{"id":"d","text":"لأنّها هنا توكيد لفظيّ"}]'::jsonb, 'a', 'من أحكام المطابقة أنّ «نفس» و«عين» في توكيد المثنّى تأتيان بصيغة الجمع (أنفُس، أعيُن)، فيقال: جاء البطلان أنفسُهما، لا «نفساهما».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('00d649bf-3708-5794-a3ad-f44c3c2666ad', '53ee79a4-de63-550a-b864-3140b91c2b3f', 'arabic-8eme', '⭐ تمرين: التوكيد', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('50837d71-e5df-5895-a38b-e0e501569998', '00d649bf-3708-5794-a3ad-f44c3c2666ad', 'أيّ مجموعةٍ تضمّ ألفاظ التوكيد المعنويّ؟', '[{"id":"a","text":"نفس، عين، كلّ، جميع، كلا وكلتا"},{"id":"b","text":"الّذي، الّتي، مَن، ما"},{"id":"c","text":"في، على، عن، إلى"},{"id":"d","text":"هذا، ذلك، تلك، أولئك"}]'::jsonb, 'a', 'ألفاظ التوكيد المعنويّ محفوظةٌ معدودة: «نفس» و«عين» لتوكيد الذّات، و«كلّ» و«جميع» لتوكيد الشّمول، و«كلا» و«كلتا» لتوكيد المثنّى؛ وكلّها تُضاف إلى ضمير.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d738fdc-fb05-5340-a189-9782c675bf8a', '00d649bf-3708-5794-a3ad-f44c3c2666ad', '«الصّبرَ الصّبرَ يا بطل» — ما نوع التوكيد في «الصّبرَ» الثّانية؟', '[{"id":"a","text":"توكيد معنويّ"},{"id":"b","text":"توكيد لفظيّ، لأنّه إعادةٌ للاسم نفسه"},{"id":"c","text":"نعت"},{"id":"d","text":"بدل"}]'::jsonb, 'b', 'التوكيد اللفظيّ هو إعادة اللفظ نفسه؛ وهنا أُعيد الاسم «الصّبرَ» مرّة ثانية لتقويته، فهو توكيد لفظيّ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('27ae7e80-23b2-56d1-a24b-e61fa6504fe6', '00d649bf-3708-5794-a3ad-f44c3c2666ad', '«حضرَ الفلّاحونَ جميعُهم لجني الزّيتون بصفاقس» — ما نوع «جميعُهم»؟', '[{"id":"a","text":"توكيد لفظيّ"},{"id":"b","text":"نعت"},{"id":"c","text":"توكيد معنويّ يفيد الشّمول"},{"id":"d","text":"حال"}]'::jsonb, 'c', '«جميع» من ألفاظ التوكيد المعنويّ الدّالّة على الشّمول، وقد أُضيفت إلى الضّمير «هم» العائد على «الفلّاحونَ»، فهي توكيد معنويّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7f086d43-9a28-5678-a23c-d59d2a8a0d08', '00d649bf-3708-5794-a3ad-f44c3c2666ad', 'نستعمل «كلتا» لتوكيد:', '[{"id":"a","text":"المفرد المذكّر"},{"id":"b","text":"الجمع"},{"id":"c","text":"المثنّى المذكّر"},{"id":"d","text":"المثنّى المؤنّث"}]'::jsonb, 'd', '«كلا» لتوكيد المثنّى المذكّر، و«كلتا» لتوكيد المثنّى المؤنّث؛ فنقول: الأخوان كلاهما، والأختان كلتاهما.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('afdafdaf-ffcd-5fc0-86a2-4c585e9a06f4', '00d649bf-3708-5794-a3ad-f44c3c2666ad', '«قابلتُ المُخرجَ نفسَه في مهرجان قرطاج» — ما إعراب «نفسَ»؟', '[{"id":"a","text":"فاعل مرفوع"},{"id":"b","text":"توكيد معنويّ منصوب تابع للمفعول به «المُخرجَ»، و«الهاء» مضاف إليه"},{"id":"c","text":"مضاف إليه مجرور"},{"id":"d","text":"بدل مرفوع"}]'::jsonb, 'b', '«نفس» توكيد معنويّ يتبع المؤكَّد في إعرابه؛ والمؤكَّد «المُخرجَ» مفعول به منصوب، فجاءت «نفسَ» منصوبة تبعًا له، و«الهاء» ضميرٌ في محلّ جرّ مضاف إليه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('046fb2cf-870e-5dcf-8519-c3d35b08602f', '00d649bf-3708-5794-a3ad-f44c3c2666ad', '«شاركَ كلُّ التلاميذِ في تنظيف شاطئ بنزرت» — ما إعراب «كلُّ» هنا؟', '[{"id":"a","text":"توكيد معنويّ مرفوع"},{"id":"b","text":"نعت مرفوع"},{"id":"c","text":"فاعل مرفوع، لأنّها أُضيفت إلى اسمٍ ظاهر لا إلى ضمير"},{"id":"d","text":"بدل مرفوع"}]'::jsonb, 'c', 'لا تكون هذه الألفاظ توكيدًا إلّا إذا أُضيفت إلى ضمير يعود على المؤكَّد؛ وهنا أُضيفت «كلّ» إلى الاسم الظّاهر «التلاميذِ»، فخرجت من التوكيد وأُعربت حسب موقعها فاعلًا مرفوعًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('6489bbec-a4f7-5444-8bf9-6c269cef1bf1', '53ee79a4-de63-550a-b864-3140b91c2b3f', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: تمييز نوعَي التوكيد وإعرابه', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2abc565a-6762-5a80-9320-d09da426be44', '6489bbec-a4f7-5444-8bf9-6c269cef1bf1', '«وصلَ القطارُ القطارُ إلى محطّة سوسة» — ما نوع «القطارُ» الثّانية وما إعرابها؟', '[{"id":"a","text":"توكيد لفظيّ مرفوع تابع للفاعل «القطارُ»"},{"id":"b","text":"توكيد معنويّ مرفوع"},{"id":"c","text":"بدل منصوب"},{"id":"d","text":"نعت مجرور"}]'::jsonb, 'a', 'التوكيد اللفظيّ هو إعادة اللفظ نفسه؛ فأُعيد الاسم «القطارُ» توكيدًا لفظيًّا يتبع المؤكَّد في إعرابه، والمؤكَّد فاعل مرفوع فالتوكيد مرفوع مثله.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07d2ee43-db0f-54c5-a5f6-b346aa5bc042', '6489bbec-a4f7-5444-8bf9-6c269cef1bf1', '«كرّمَ الوالي الفائزَين كليهما في ملعب المنستير» — ما إعراب «كليهما»؟', '[{"id":"a","text":"توكيد مرفوع بالألف تابع للفاعل"},{"id":"b","text":"مفعول به ثانٍ منصوب بالفتحة"},{"id":"c","text":"توكيد منصوب بالياء تابع للمفعول به «الفائزَين»، و«هما» مضاف إليه"},{"id":"d","text":"توكيد مجرور بالياء"}]'::jsonb, 'c', '«الفائزَين» مفعول به منصوب بالياء (مثنّى)، و«كلا» تتبعه فتُعرب إعراب المثنّى: بالياء في النّصب. فـ«كليهما» توكيد منصوب بالياء، و«هما» مضاف إليه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eda2f8ca-9d90-55af-ae2b-22c10fb40cc2', '6489bbec-a4f7-5444-8bf9-6c269cef1bf1', '«سافرَ المديرُ عينُه لحضور الملتقى بتوزر» — ما دلالة «عينُه» وما إعرابها؟', '[{"id":"a","text":"تفيد الشّمول؛ توكيد مرفوع"},{"id":"b","text":"تفيد توكيد الذّات (هو بنفسه لا نائبه)؛ «عينُ» توكيد معنويّ مرفوع تابع للفاعل، والهاء مضاف إليه"},{"id":"c","text":"«عينُ» مبتدأ مرفوع"},{"id":"d","text":"«عينُ» بدل اشتمال"}]'::jsonb, 'b', '«عين» كـ«نفس» من ألفاظ توكيد الذّات: تُثبّت أنّ المقصود هو المديرُ ذاتُه لا نائبُه. أُضيفت إلى الضّمير «الهاء» فهي توكيد معنويّ تابع للفاعل المرفوع، والهاء مضاف إليه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8077c4b4-f7d1-528d-a97d-c585f2729a8b', '6489bbec-a4f7-5444-8bf9-6c269cef1bf1', 'أيّ جملةٍ ضُبط فيها توكيد «كلا/كلتا» ضبطًا صحيحًا؟', '[{"id":"a","text":"رأيتُ الفريقَين كلاهما"},{"id":"b","text":"مررتُ بالبطلتَين كلتاهما"},{"id":"c","text":"نجحَ الطالبان كليهما"},{"id":"d","text":"صافحتُ الضّيفَين كليهما"}]'::jsonb, 'd', 'كلا وكلتا تُعربان إعراب المثنّى: بالألف رفعًا وبالياء نصبًا وجرًّا. «صافحتُ الضّيفَين» مفعول به منصوب، فالتوكيد «كليهما» بالياء صحيح. أمّا «رأيتُ الفريقَين» فنصبٌ يوجب «كليهما»، و«مررتُ بالبطلتَين» جرٌّ يوجب «كلتيهما»، و«نجحَ الطالبان» رفعٌ يوجب «كلاهما».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b8321d28-581e-5986-aed2-2871eb0c2f3c', '6489bbec-a4f7-5444-8bf9-6c269cef1bf1', '«انطلقتَ أنتَ أوّلًا في سباق الدرّاجات ببنزرت» — ما إعراب «أنتَ»؟', '[{"id":"a","text":"توكيد لفظيّ للضّمير المتّصل (تاء الفاعل)، مبنيّ في محلّ رفع"},{"id":"b","text":"فاعل ثانٍ مرفوع"},{"id":"c","text":"مبتدأ مرفوع"},{"id":"d","text":"توكيد معنويّ"}]'::jsonb, 'a', 'الضّمير المنفصل «أنتَ» أكّد الضّمير المتّصل (تاء الفاعل في انطلقتَ) بإعادة معناه، فهو توكيد لفظيّ مبنيّ في محلّ رفع؛ وليس فاعلًا ثانيًا لأنّ الفعل لا يرفع فاعلَين.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('860b0aa3-6aba-553d-81f4-5f1dc626474c', '6489bbec-a4f7-5444-8bf9-6c269cef1bf1', '«شاهدتُ الوزيرَ نفسَه» ثمّ «حضرَ الوزيرُ نفسُه» — لماذا اختلف ضبط «نفس» بين الجملتين؟', '[{"id":"a","text":"لأنّ الأولى توكيد معنويّ والثانية توكيد لفظيّ"},{"id":"b","text":"لأنّ التوكيد يتبع المؤكَّد في إعرابه؛ فتبعت «نفسَه» المفعولَ المنصوب، وتبعت «نفسُه» الفاعلَ المرفوع"},{"id":"c","text":"خطأ، والصواب «نفسَه» في الحالتين"},{"id":"d","text":"لأنّ التوكيد المعنويّ لا يتبع المؤكَّد"}]'::jsonb, 'b', 'التوكيد المعنويّ تابعٌ للمؤكَّد في الرّفع والنّصب والجرّ. في الأولى «الوزيرَ» مفعول به منصوب فجاءت «نفسَه» منصوبة، وفي الثانية «الوزيرُ» فاعل مرفوع فجاءت «نفسُه» مرفوعة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('18d60212-ccdf-5344-b544-6bc14bd0f5a4', '53ee79a4-de63-550a-b864-3140b91c2b3f', 'arabic-8eme', '⭐⭐ تمرين مراجعة (نمط امتحان): نوعا التوكيد وإعرابه', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e4db6a5d-ac74-51ee-9586-bd2d7b8d9a8f', '18d60212-ccdf-5344-b544-6bc14bd0f5a4', 'التوكيد اللفظيّ يكون بـ:', '[{"id":"a","text":"إعادة اللفظ نفسه (اسمًا أو فعلًا أو حرفًا أو جملة)"},{"id":"b","text":"لفظٍ من: نفس، عين، كلّ، جميع"},{"id":"c","text":"حرف عطف يربط بين اسمين"},{"id":"d","text":"اسمٍ موصول يعود على المؤكَّد"}]'::jsonb, 'a', 'التوكيد اللفظيّ إعادةُ اللفظ نفسه لتقويته (اسمًا أو فعلًا أو حرفًا أو ضميرًا أو جملة). أمّا نفس وعين وكلّ وجميع فهي ألفاظ التوكيد المعنويّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5911b607-9117-511e-ad1d-2a44f9a3becf', '18d60212-ccdf-5344-b544-6bc14bd0f5a4', '«أتمَّ العمّالُ كلُّهم ترميم مدرّج الجم» — «كلُّهم» توكيد معنويّ يفيد:', '[{"id":"a","text":"توكيد الذّات"},{"id":"b","text":"الشّمول (أنّ الحكم عمّ جميع الأفراد)"},{"id":"c","text":"توكيد المثنّى"},{"id":"d","text":"النّفي"}]'::jsonb, 'b', '«كلّ» و«جميع» من ألفاظ توكيد الشّمول؛ فـ«كلُّهم» تمنع توهّم أنّ الترميم تمّ على يد بعض العمّال دون بعض، بل عمّهم جميعًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('034066b6-2a32-5e41-87b9-297b89840ba3', '18d60212-ccdf-5344-b544-6bc14bd0f5a4', '«حاورتُ الكاتبةَ نفسَها في مكتبة تونس» — ما إعراب «نفسَها»؟', '[{"id":"a","text":"«نفسَ» فاعل مرفوع"},{"id":"b","text":"«نفسَ» بدل مرفوع"},{"id":"c","text":"«نفسَ» توكيد معنويّ منصوب تابع للمفعول به «الكاتبةَ»، و«ها» مضاف إليه"},{"id":"d","text":"«نفسَ» حال منصوب"}]'::jsonb, 'c', '«الكاتبةَ» مفعول به منصوب، والتوكيد يتبع المؤكَّد؛ فجاءت «نفسَ» توكيدًا معنويًّا منصوبًا، والضّمير «ها» في محلّ جرّ مضاف إليه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('613943aa-cd06-52e9-b628-4b1d2d617c8c', '18d60212-ccdf-5344-b544-6bc14bd0f5a4', '«رجعَ الحاجّان كلاهما من البقاع المقدّسة» — بأيّ علامةٍ رُفعت «كلا»؟', '[{"id":"a","text":"بالألف، لأنّها تُعرب إعراب المثنّى"},{"id":"b","text":"بالضّمّة الظّاهرة"},{"id":"c","text":"بالواو"},{"id":"d","text":"مبنيّة لا محلّ لها من الإعراب"}]'::jsonb, 'a', 'كلا وكلتا المضافتان إلى ضمير تُعربان إعراب المثنّى؛ فتُرفعان بالألف. وهنا «كلاهما» توكيد مرفوع بالألف تبعًا للفاعل «الحاجّان».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3436a266-8457-562d-80d1-c318f0058f1e', '18d60212-ccdf-5344-b544-6bc14bd0f5a4', 'متى تخرج «جميع» من باب التوكيد فتُعرب حسب موقعها؟', '[{"id":"a","text":"إذا اتّصل بها ضميرٌ يعود على المؤكَّد"},{"id":"b","text":"إذا سبقها فعل ماضٍ"},{"id":"c","text":"إذا وقعت في آخر الجملة"},{"id":"d","text":"إذا أُضيفت إلى اسمٍ ظاهر، نحو: حضرَ جميعُ الطلابِ («جميعُ» فاعل)"}]'::jsonb, 'd', 'لا تكون هذه الألفاظ توكيدًا إلّا مضافةً إلى ضمير؛ فإن أُضيفت إلى اسمٍ ظاهر خرجت من التوكيد وأُعربت حسب موقعها. في «حضرَ جميعُ الطلابِ» أُضيفت «جميعُ» إلى «الطلابِ» فصارت فاعلًا مرفوعًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d3ec6db8-ee35-57c2-9693-7983ea1275fe', '18d60212-ccdf-5344-b544-6bc14bd0f5a4', '«سلّمتُ الجائزةَ للفائزتَين كلتيهما في مهرجان الحمّامات» — ما إعراب «كلتيهما»؟', '[{"id":"a","text":"توكيد مرفوع بالألف"},{"id":"b","text":"توكيد مجرور بالياء تابع للاسم المجرور «الفائزتَين»، و«هما» مضاف إليه"},{"id":"c","text":"مفعول به منصوب"},{"id":"d","text":"اسم مجرور بالكسرة الظّاهرة"}]'::jsonb, 'b', '«الفائزتَين» اسم مجرور باللام (مثنّى مجرور بالياء)، والتوكيد يتبعه فيُعرب إعراب المثنّى بالياء في الجرّ؛ فـ«كلتيهما» توكيد مجرور بالياء، و«هما» مضاف إليه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9dbc493f-ec58-5c4f-a9ec-65b26d91945c', '53ee79a4-de63-550a-b864-3140b91c2b3f', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: دقائق التوكيد وإعرابه', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e006735f-d896-50f7-9c4c-c360eaea4aa5', '9dbc493f-ec58-5c4f-a9ec-65b26d91945c', '«حضرَ الفريقُ كلُّه للتّدريب» — «كلُّه» توكيد شمول، فلِمَ جاء الضّمير «ه» مفردًا لا «هم»؟', '[{"id":"a","text":"خطأ؛ والصواب «كلُّهم»"},{"id":"b","text":"لأنّ المؤكَّد «الفريق» مفردٌ في لفظه (اسم يدلّ على جماعة)، فطابقه الضّمير في الإفراد"},{"id":"c","text":"لأنّ «كلّ» لا تطابق المؤكَّد أبدًا"},{"id":"d","text":"لأنّه توكيد لفظيّ لا معنويّ"}]'::jsonb, 'b', 'ضمير التوكيد يطابق المؤكَّد في لفظه؛ و«الفريق» مفردٌ لفظًا وإن دلّ على جماعة، فعاد عليه ضميرٌ مفردٌ «كلُّه». ولو قيل «اللاعبون كلُّهم» لعاد الضّمير جمعًا لمطابقة لفظ الجمع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d533380a-e6de-5525-bcaf-6a95926c59af', '9dbc493f-ec58-5c4f-a9ec-65b26d91945c', '«كافأتِ الإدارةُ المتفوّقين ...» — أيّ ضبطٍ لتوكيد الشّمول هو الصحيح؟', '[{"id":"a","text":"كافأتِ الإدارةُ المتفوّقين كلَّهم (بالنّصب، تبعًا للمفعول به المنصوب)"},{"id":"b","text":"كافأتِ الإدارةُ المتفوّقين كلُّهم (بالرّفع)"},{"id":"c","text":"كافأتِ الإدارةُ المتفوّقين كلِّهم (بالجرّ)"},{"id":"d","text":"لا يصحّ توكيد المفعول به"}]'::jsonb, 'a', '«المتفوّقين» مفعول به منصوب، والتوكيد يتبع المؤكَّد؛ فيجب نصب التوكيد: «كلَّهم». والتوكيد يقع على الفاعل والمفعول والمجرور جميعًا، فلا وجه لمنع توكيد المفعول.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d69176a8-f684-5509-b4dc-ee694f987f64', '9dbc493f-ec58-5c4f-a9ec-65b26d91945c', '«جاءتِ المُعلّمتان ... لتكريم التلاميذ بقفصة» — ما صورة توكيد الذّات الصحيحة في الفراغ؟', '[{"id":"a","text":"نفساهما (لأنّ المؤكَّد مثنّى)"},{"id":"b","text":"نفسهما (بالإفراد)"},{"id":"c","text":"أنفسُهما (لأنّ «نفس» و«عين» تُجمعان في توكيد المثنّى، وهي مرفوعة تبعًا للفاعل)"},{"id":"d","text":"أنفسِهما (بالجرّ)"}]'::jsonb, 'c', 'من أحكام المطابقة أنّ «نفس» و«عين» في توكيد المثنّى تأتيان بصيغة الجمع (أنفُس، أعيُن) لا المثنّى؛ فيقال: جاءتِ المُعلّمتان أنفسُهما، توكيدٌ مرفوع تبعًا للفاعل، و«هما» مضاف إليه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8669eef5-54c1-5658-a166-bfc76e170968', '9dbc493f-ec58-5c4f-a9ec-65b26d91945c', '«حضرَ كلا المهندسَين الاجتماعَ» — ما إعراب «كلا» هنا، وهل هي توكيد؟', '[{"id":"a","text":"توكيد مرفوع بالألف تابع لما بعده"},{"id":"b","text":"مفعول به منصوب بالياء"},{"id":"c","text":"حال منصوب"},{"id":"d","text":"ليست توكيدًا؛ أُضيفت إلى الاسم الظّاهر «المهندسَين»، فأُعربت فاعلًا مرفوعًا بضمّةٍ مقدّرة على الألف"}]'::jsonb, 'd', '«كلا» لا تكون توكيدًا إلّا مضافةً إلى ضمير؛ وهنا أُضيفت إلى الاسم الظّاهر «المهندسَين»، فخرجت من التوكيد وأُعربت حسب موقعها فاعلًا مرفوعًا بضمّةٍ مقدّرة على الألف (اسم مقصور).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c104c79b-4049-5db8-af20-863284c595f0', '9dbc493f-ec58-5c4f-a9ec-65b26d91945c', '«الصّدقَ الصّدقَ فإنّه منجاة» — ما نوع التوكيد وما إعراب «الصّدقَ» الثّانية، ولِمَ النّصب؟', '[{"id":"a","text":"توكيد لفظيّ منصوب؛ لأنّ المؤكَّد «الصّدقَ» مفعول به لفعلٍ محذوف تقديره «الزَمِ»، فتبعه التوكيد في النّصب"},{"id":"b","text":"توكيد معنويّ مرفوع"},{"id":"c","text":"مبتدأ مرفوع بالضّمّة"},{"id":"d","text":"بدل مجرور"}]'::jsonb, 'a', 'هذا أسلوب إغراء: «الصّدقَ» الأولى مفعول به منصوب لفعلٍ محذوف تقديره «الزَمِ». و«الصّدقَ» الثّانية توكيد لفظيّ (إعادة اللفظ) يتبع المؤكَّد المنصوب، فجاء منصوبًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a2e96162-294a-5a54-bee4-e3449d4af460', '9dbc493f-ec58-5c4f-a9ec-65b26d91945c', '«سُررتُ بنجاحِ الطالبَين كليهما، ثمّ هنّأتُ الطالبَين كليهما» — علّل ورود «كليهما» بالياء في الموضعين.', '[{"id":"a","text":"لأنّها مبنيّة دائمًا على الياء"},{"id":"b","text":"لأنّها في الأولى مجرورة تابعة للمجرور، وفي الثانية منصوبة تابعة للمفعول، والياء علامة المثنّى في الجرّ والنّصب معًا"},{"id":"c","text":"لأنّها ممنوعة من الصرف"},{"id":"d","text":"خطأ؛ الثانية يجب أن تكون «كلاهما»"}]'::jsonb, 'b', '«كلا» تُعرب إعراب المثنّى، وعلامة المثنّى في النّصب والجرّ واحدة: الياء. فـ«الطالبَين» الأولى مجرور فتبعه التوكيد مجرورًا بالياء، والثانية مفعول به منصوب فتبعه التوكيد منصوبًا بالياء؛ فاتّفقت الصورة «كليهما».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b9e59c81-d2f5-5965-bb12-70b65cdd93c3', '53ee79a4-de63-550a-b864-3140b91c2b3f', 'arabic-8eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة على التوكيد', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
