  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d41e430d-f6e4-5b29-855f-a79a0ad8640f', 'b9e59c81-d2f5-5965-bb12-70b65cdd93c3', 'أيّ الجمل الآتية تتضمّن توكيدًا لفظيًّا؟', '[{"id":"a","text":"عادَ الطلابُ كلُّهم من الرحلة"},{"id":"b","text":"جاء المديرُ نفسُه"},{"id":"c","text":"نعم نعم سأزور متحف باردو"},{"id":"d","text":"فاز الفريقان كلاهما"}]'::jsonb, 'c', 'التوكيد اللفظيّ إعادةُ اللفظ نفسه؛ وقد أُعيد الحرف «نعم» توكيدًا لفظيًّا. أمّا البواقي فتوكيدٌ معنويّ (كلُّهم، نفسُه، كلاهما).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cfe98f0f-840c-5db1-bcc9-ccfb8d0f32e8', 'b9e59c81-d2f5-5965-bb12-70b65cdd93c3', '«طالعتُ الكتابَ نفسَه الّذي نصحتَني به» — «نفسَه» تفيد:', '[{"id":"a","text":"الشّمول"},{"id":"b","text":"توكيد الذّات (الكتاب بعينه لا غيره)"},{"id":"c","text":"توكيد المثنّى"},{"id":"d","text":"النّفي"}]'::jsonb, 'b', '«نفس» و«عين» تفيدان توكيد الذّات؛ فـ«نفسَه» تُثبت أنّ المقصود هو الكتاب بعينه لا كتابٌ آخر.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1269f361-a71f-534e-9eeb-2ee6b8b129b1', 'b9e59c81-d2f5-5965-bb12-70b65cdd93c3', '«تسلّمَتِ البطلاتُ جوائزَهنّ كلَّها في دورة المنستير» — ما إعراب «كلَّها»؟', '[{"id":"a","text":"توكيد معنويّ منصوب تابع للمفعول به «جوائزَهنّ»، و«ها» مضاف إليه"},{"id":"b","text":"توكيد مرفوع تابع للفاعل «البطلاتُ»"},{"id":"c","text":"مفعول به ثانٍ منصوب"},{"id":"d","text":"بدل مرفوع"}]'::jsonb, 'a', 'التوكيد يتبع أقرب مؤكَّدٍ له معنًى؛ و«كلَّها» توكيد شمولٍ لـ«جوائزَهنّ» المفعول به المنصوب لا للفاعل، فجاءت منصوبة، والضّمير «ها» مضاف إليه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8337bf04-4bc6-564d-88c2-dde7e5ed5844', 'b9e59c81-d2f5-5965-bb12-70b65cdd93c3', '«حكمَ القاضي نفسُه في القضيّة» — ما إعراب «نفسُه» ولِمَ الرّفع؟', '[{"id":"a","text":"فاعل ثانٍ مرفوع"},{"id":"b","text":"مبتدأ مرفوع"},{"id":"c","text":"بدل منصوب"},{"id":"d","text":"توكيد معنويّ مرفوع تابع للفاعل «القاضي»، والهاء مضاف إليه"}]'::jsonb, 'd', '«نفسُه» توكيد معنويّ يتبع المؤكَّد؛ والمؤكَّد «القاضي» فاعل مرفوع (بضمّة مقدّرة)، فجاءت «نفسُه» مرفوعة، والهاء مضاف إليه. وليست فاعلًا ثانيًا لأنّ الفعل لا يرفع فاعلَين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a1108405-664a-5ea9-946a-cd10cdfd08d7', 'b9e59c81-d2f5-5965-bb12-70b65cdd93c3', '«اشتركَتِ المدرستان كلتاهما في مسابقة البيئة بنابل» — ما إعراب «كلتاهما»؟', '[{"id":"a","text":"توكيد مرفوع بالألف تابع للفاعل «المدرستان»، و«هما» مضاف إليه"},{"id":"b","text":"توكيد منصوب بالياء"},{"id":"c","text":"فاعل مرفوع بالضّمّة"},{"id":"d","text":"حال منصوب"}]'::jsonb, 'a', '«المدرستان» فاعل مرفوع بالألف، والتوكيد يتبعه فيُعرب إعراب المثنّى بالألف في الرّفع؛ فـ«كلتاهما» توكيد مرفوع بالألف، و«هما» مضاف إليه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('406eafef-4f23-5771-a1ed-12b3c05f7e62', 'b9e59c81-d2f5-5965-bb12-70b65cdd93c3', '«ودّعتُ الصّديقَين نفسَيهما عند مطار المنستير» — هل ضبط التوكيد صحيح؟', '[{"id":"a","text":"صحيح، لأنّ المؤكَّد مثنّى"},{"id":"b","text":"خطأ؛ الصواب «أنفسَهما»، لأنّ توكيد المثنّى بـ«نفس» يأتي بصيغة الجمع (أنفُس)، منصوبًا تبعًا للمفعول به"},{"id":"c","text":"خطأ؛ الصواب «نفسهما» بالإفراد"},{"id":"d","text":"صحيح، لأنّ «نفس» لا تُجمع"}]'::jsonb, 'b', '«نفس» و«عين» في توكيد المثنّى تأتيان بصيغة الجمع لا المثنّى؛ فالصواب «أنفسَهما» لا «نفسَيهما». وهي منصوبة تبعًا للمفعول به «الصّديقَين»، و«هما» مضاف إليه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0cbfdfa8-1c58-585a-89ee-0c051d64c33e', '53ee79a4-de63-550a-b864-3140b91c2b3f', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: سقف الفصل في التوكيد', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d39f8ba1-5462-5733-b8f9-77a21133c9d3', '0cbfdfa8-1c58-585a-89ee-0c051d64c33e', '«رأيتُ عينَ الأسدِ» ثمّ «جاءَ الأميرُ عينُه» — فرّق بين «عين» في الجملتين.', '[{"id":"a","text":"كلتاهما توكيد معنويّ"},{"id":"b","text":"كلتاهما مفعول به"},{"id":"c","text":"الأولى توكيد، والثانية مفعول به"},{"id":"d","text":"الأولى «عينَ» مفعول به (بمعنى الجارحة) مضاف إلى ظاهر، والثانية «عينُه» توكيد معنويّ مضاف إلى ضمير"}]'::jsonb, 'd', 'في «رأيتُ عينَ الأسدِ» أُريد بها الجارحة، وأُضيفت إلى الاسم الظّاهر «الأسدِ»، فهي مفعول به منصوب لا توكيد. أمّا «جاءَ الأميرُ عينُه» فأُضيفت إلى ضميرٍ يعود على المؤكَّد، فهي توكيد معنويّ للذّات.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c8255036-f365-50c5-9265-da680f8deb04', '0cbfdfa8-1c58-585a-89ee-0c051d64c33e', '«ما نجحَ إلّا المجتهدونَ أنفسُهم» — ما إعراب «أنفسُهم»؟', '[{"id":"a","text":"توكيد معنويّ مرفوع تابع للفاعل «المجتهدونَ»، و«هم» مضاف إليه"},{"id":"b","text":"مستثنى منصوب بالياء"},{"id":"c","text":"بدل منصوب"},{"id":"d","text":"مفعول به مرفوع"}]'::jsonb, 'a', 'الأسلوب منفيٌّ مفرّغ («ما ... إلّا»)، فـ«المجتهدونَ» فاعلٌ مرفوع بالواو. و«أنفسُهم» توكيد معنويّ يتبعه في الرّفع، و«هم» مضاف إليه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3bc3ca3a-150b-59d8-9e1f-e5056232b5f7', '0cbfdfa8-1c58-585a-89ee-0c051d64c33e', '«سلّمَ الرّئيسُ الوسامَ للبطلَين كليهما لا لأحدهما» — ما دلالة «كليهما» وما إعرابها؟', '[{"id":"a","text":"تفيد الذّات؛ مرفوعة بالألف"},{"id":"b","text":"تفيد شمول المثنّى (كلا البطلَين معًا)؛ توكيد مجرور بالياء تابع للاسم المجرور بعد اللام"},{"id":"c","text":"توكيد لفظيّ منصوب"},{"id":"d","text":"بدل بعضٍ من كلّ"}]'::jsonb, 'b', '«كلا/كلتا» تفيدان توكيد شمول المثنّى؛ فـ«كليهما» تُثبت أنّ الحكم عمّ البطلَين معًا لا أحدهما. و«البطلَين» اسم مجرور باللام بالياء، فتبعه التوكيد مجرورًا بالياء.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a219c48-c7e1-50a3-b56e-f383a6930ea4', '0cbfdfa8-1c58-585a-89ee-0c051d64c33e', '«حفظَ التلميذُ القصيدةَ القصيدةَ حتّى أتقنَها» — أعرب «القصيدةَ» الثّانية.', '[{"id":"a","text":"توكيد معنويّ منصوب"},{"id":"b","text":"مفعول به ثانٍ منصوب"},{"id":"c","text":"توكيد لفظيّ منصوب تابع للمفعول به «القصيدةَ»، لأنّ التوكيد اللفظيّ يتبع المؤكَّد في إعرابه"},{"id":"d","text":"بدل مرفوع"}]'::jsonb, 'c', 'أُعيد الاسم «القصيدةَ» توكيدًا لفظيًّا؛ والتوكيد اللفظيّ يتبع المؤكَّد، والمؤكَّد مفعول به منصوب فجاء التوكيد منصوبًا. وليس مفعولًا ثانيًا لأنّ «حفظ» لا يتعدّى إلى مفعولَين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ebecc26-434a-56e1-9bc3-cf0989155748', '0cbfdfa8-1c58-585a-89ee-0c051d64c33e', 'في أيّ جملةٍ وردَ لفظٌ من ألفاظ التوكيد لكنّه ليس توكيدًا؟', '[{"id":"a","text":"قرأتُ جميعَ الكتبِ في المكتبة الوطنيّة"},{"id":"b","text":"صافحتُ الوزيرَ نفسَه"},{"id":"c","text":"نجحَ الطلّابُ جميعُهم"},{"id":"d","text":"حضرَ الضّيوفُ أنفسُهم"}]'::jsonb, 'a', 'في «قرأتُ جميعَ الكتبِ» أُضيفت «جميع» إلى الاسم الظّاهر «الكتبِ»، فخرجت من التوكيد وأُعربت مفعولًا به منصوبًا. أمّا البواقي فألفاظ توكيد مضافة إلى ضمير (نفسَه، جميعُهم، أنفسُهم).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5c94d383-c430-5523-a04f-9144021502d7', '0cbfdfa8-1c58-585a-89ee-0c051d64c33e', '«تفوّقتِ التلميذتانِ كلتاهما، وكافأتُ التلميذتَينِ كلتيهما» — علّل اختلاف صورة التوكيد بين الجملتين.', '[{"id":"a","text":"خطأ في الجملة الثانية؛ الصواب «كلتاهما»"},{"id":"b","text":"لأنّ الأولى في محلّ رفع (فاعل) فجاءت بالألف «كلتاهما»، والثانية مفعول به منصوب فجاءت بالياء «كلتيهما»، كإعراب المثنّى"},{"id":"c","text":"لأنّ الأولى توكيد والثانية بدل"},{"id":"d","text":"لأنّهما مبنيّتان على ما قبلهما"}]'::jsonb, 'b', 'كلا وكلتا تُعربان إعراب المثنّى: بالألف رفعًا وبالياء نصبًا وجرًّا. فتبِعتِ الأولى الفاعلَ المرفوع «التلميذتانِ» بالألف، وتبِعتِ الثانية المفعولَ المنصوب «التلميذتَينِ» بالياء.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('fa39d7ed-81a2-5e8e-85c3-6d10dce28929', '7ed244aa-0193-58dd-9c12-ffa5c70ba029', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a6f3397-2e26-566a-83e4-7d4a35d0d1c7', 'fa39d7ed-81a2-5e8e-85c3-6d10dce28929', 'البدل واحدٌ من التّوابع الأربعة، وهي:', '[{"id":"a","text":"النّعت والتوكيد والبدل والعطف"},{"id":"b","text":"الفاعل والمفعول به والحال والتمييز"},{"id":"c","text":"المبتدأ والخبر والفعل والفاعل"},{"id":"d","text":"الرّفع والنّصب والجرّ والجزم"}]'::jsonb, 'a', 'التّوابع أربعة: النّعت، والتوكيد، والبدل، والعطف؛ وكلّها تتبع ما قبلها في الإعراب. والبدل أحدها، وهو موضوع هذا الفصل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('416b2096-41e6-55e6-b3f8-35eb23dfddf3', 'fa39d7ed-81a2-5e8e-85c3-6d10dce28929', '«وصلَ صديقي أنيسٌ إلى قمّة جبل زغوان» — ما نوع البدل في «أنيسٌ»؟', '[{"id":"a","text":"بدل بعض من كلّ"},{"id":"b","text":"بدل اشتمال"},{"id":"c","text":"بدل كلّ من كلّ (مطابق)"},{"id":"d","text":"نعت"}]'::jsonb, 'c', '«أنيسٌ» هو «صديقي» نفسه، لا جزءٌ منه ولا صفةٌ فيه، ويصحّ أن نقول: وصلَ أنيسٌ. فهو بدل كلّ من كلّ (مطابق).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c79c478e-28cd-5689-8ba5-2d7957c52415', 'fa39d7ed-81a2-5e8e-85c3-6d10dce28929', 'بدل البعض من الكلّ وبدل الاشتمال لا بدّ في كلٍّ منهما من:', '[{"id":"a","text":"حرف عطف يربط البدل بالمبدل منه"},{"id":"b","text":"أداة نصب قبل البدل"},{"id":"c","text":"تنوين في آخر البدل"},{"id":"d","text":"ضميرٍ يعود على المبدل منه يتّصل بالبدل"}]'::jsonb, 'd', 'يلزم في بدل البعض وبدل الاشتمال ضميرٌ متّصلٌ بالبدل يعود على المبدل منه (نصفَه، علمُه)؛ وهو ما يميّزهما عن بدل كلّ من كلّ الّذي لا يحتاج ضميرًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6e8cc652-6085-5089-b975-3a2786c2899d', 'fa39d7ed-81a2-5e8e-85c3-6d10dce28929', '«أعجبني الرّسّامُ إتقانُه في معرض قرطاجَ» — ما نوع «إتقانُه»؟', '[{"id":"a","text":"بدل كلّ من كلّ"},{"id":"b","text":"بدل اشتمال، لأنّ الإتقان معنًى يشتمل عليه الرّسّام"},{"id":"c","text":"بدل بعض من كلّ، لأنّ الإتقان جزءٌ من الرّسّام"},{"id":"d","text":"توكيد معنويّ"}]'::jsonb, 'b', '«الإتقان» صفةٌ ومعنًى يشتمل عليه الرّسّام لا جزءٌ ماديٌّ من جسده، واتّصل به ضميرٌ عائدٌ على المبدل منه، فهو بدل اشتمال.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('826dc0ad-3091-52cc-87aa-b92aefe2dc68', 'fa39d7ed-81a2-5e8e-85c3-6d10dce28929', '«قرأتُ الكتابَ نصفَه في مكتبة صفاقسَ» — ما إعراب «نصفَه»؟', '[{"id":"a","text":"بدل بعض من كلّ منصوب تابع للمفعول به «الكتابَ»، والهاء مضاف إليه"},{"id":"b","text":"مفعول به ثانٍ منصوب"},{"id":"c","text":"نعت منصوب"},{"id":"d","text":"توكيد منصوب"}]'::jsonb, 'a', '«النّصف» جزءٌ حقيقيٌّ من «الكتابَ»، فهو بدل بعض من كلّ يتبع المبدل منه في النّصب، والهاء ضميرٌ في محلّ جرّ مضاف إليه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a367e7ff-a8d5-556e-b0f7-c1a0b6e7a2fd', '7ed244aa-0193-58dd-9c12-ffa5c70ba029', 'arabic-8eme', '⭐ تمرين: البدل', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
