  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1308f599-dbc9-517c-8ee8-1fdd63e6ac62', 'a367e7ff-a8d5-556e-b0f7-c1a0b6e7a2fd', 'ما البدل؟', '[{"id":"a","text":"تابعٌ يوضّح ما قبله (المبدل منه)، والحكم في الحقيقة له"},{"id":"b","text":"صفةٌ مشتقّة تصف ما قبلها"},{"id":"c","text":"حرفٌ يربط بين جملتين"},{"id":"d","text":"اسمٌ يدلّ على العدد"}]'::jsonb, 'a', 'البدل تابعٌ يُذكر بعد اسمٍ (المبدل منه) ليوضّحه أو يفصّله، والحكم في الحقيقة للبدل حتّى ليصحّ حذف المبدل منه ويستقيم المعنى.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c40bf58d-e990-53f5-9c58-fd6431a219d1', 'a367e7ff-a8d5-556e-b0f7-c1a0b6e7a2fd', '«حكمَ قرطاجَ القائدُ حنبعلُ» — ما نوع البدل في «حنبعلُ»؟', '[{"id":"a","text":"بدل اشتمال"},{"id":"b","text":"بدل بعض من كلّ"},{"id":"c","text":"توكيد معنويّ"},{"id":"d","text":"بدل كلّ من كلّ، لأنّ حنبعلَ هو القائدُ نفسه"}]'::jsonb, 'd', '«حنبعلُ» هو «القائدُ» نفسه لا جزءٌ منه ولا صفةٌ فيه، ويصحّ أن نقول: حكمَ قرطاجَ حنبعلُ. فهو بدل كلّ من كلّ (مطابق) ولا يحتاج ضميرًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f2572f4d-44bc-5dcb-9e21-4752a18b6447', 'a367e7ff-a8d5-556e-b0f7-c1a0b6e7a2fd', '«أكلتُ التّفّاحةَ نصفَها» — ما نوع البدل في «نصفَها»؟', '[{"id":"a","text":"بدل كلّ من كلّ"},{"id":"b","text":"بدل بعض من كلّ، لأنّ النّصف جزءٌ من التّفّاحة"},{"id":"c","text":"بدل اشتمال"},{"id":"d","text":"نعت"}]'::jsonb, 'b', '«النّصف» جزءٌ حقيقيٌّ ماديٌّ من «التّفّاحةَ»، واتّصل به ضميرٌ يعود على المبدل منه، فهو بدل بعض من كلّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('583ee828-317f-5553-97c4-1bf7f5923bdd', 'a367e7ff-a8d5-556e-b0f7-c1a0b6e7a2fd', 'أيّ نوعٍ من البدل لا يلزمه ضميرٌ يعود على المبدل منه؟', '[{"id":"a","text":"بدل الاشتمال"},{"id":"b","text":"بدل بعض من كلّ"},{"id":"c","text":"بدل كلّ من كلّ (المطابق)"},{"id":"d","text":"لا نوعَ إلّا ويلزمه ضمير"}]'::jsonb, 'c', 'بدل كلّ من كلّ لا يحتاج ضميرًا لأنّ البدل هو المبدل منه نفسه؛ أمّا بدل البعض وبدل الاشتمال فيلزم كلًّا منهما ضميرٌ رابط.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a06b09e4-abb6-5cdb-af8b-1ddb2af5f2e2', 'a367e7ff-a8d5-556e-b0f7-c1a0b6e7a2fd', '«نفعني المعلّمُ علمُه» — ما نوع البدل في «علمُه»؟', '[{"id":"a","text":"بدل اشتمال، لأنّ العلم معنًى يشتمل عليه المعلّم"},{"id":"b","text":"بدل بعض من كلّ"},{"id":"c","text":"بدل كلّ من كلّ"},{"id":"d","text":"توكيد معنويّ"}]'::jsonb, 'a', '«العلم» معنًى وصفةٌ يشتمل عليها المعلّم لا جزءٌ ماديٌّ من جسده، واتّصل به ضميرٌ عائدٌ على المبدل منه، فهو بدل اشتمال.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0811d56a-7aff-5180-b2d2-14e956024e92', 'a367e7ff-a8d5-556e-b0f7-c1a0b6e7a2fd', '«جاءَ الطّبيبُ سميرٌ» — ما إعراب «سميرٌ»؟', '[{"id":"a","text":"فاعل ثانٍ مرفوع"},{"id":"b","text":"نعت مرفوع"},{"id":"c","text":"مبتدأ مرفوع"},{"id":"d","text":"بدل كلّ من كلّ مرفوع تابعٌ للفاعل «الطّبيبُ»"}]'::jsonb, 'd', '«سميرٌ» هو «الطّبيبُ» نفسه، فهو بدل كلّ من كلّ يتبع المبدل منه في إعرابه؛ والمبدل منه فاعلٌ مرفوع، فجاء البدل مرفوعًا مثله.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('57cc4d23-4cb5-5d51-a251-1a7edcbcbbbe', '7ed244aa-0193-58dd-9c12-ffa5c70ba029', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: أنواع البدل وإعرابه', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
