INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d57c120e-d03d-5cf9-afac-504685ab2a08', '57cc4d23-4cb5-5d51-a251-1a7edcbcbbbe', '«تألّمتْ يدي أصبعُها» — ما نوع البدل في «أصبعُها»؟', '[{"id":"a","text":"بدل كلّ من كلّ"},{"id":"b","text":"بدل اشتمال"},{"id":"c","text":"بدل بعض من كلّ، لأنّ الأصبع جزءٌ ماديٌّ من اليد"},{"id":"d","text":"توكيد"}]'::jsonb, 'c', '«الأصبع» جزءٌ محسوسٌ من «اليد»، واتّصل به ضميرٌ يعود على المبدل منه، فهو بدل بعض من كلّ لا اشتمال؛ لأنّ الاشتمال يكون بمعنًى لا بجزءٍ ماديّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6079c66b-330e-596e-94e3-e497f1a07f26', '57cc4d23-4cb5-5d51-a251-1a7edcbcbbbe', '«سلّمتُ على الضّيفِ منيرٍ» — ما إعراب «منيرٍ»؟', '[{"id":"a","text":"بدل مجرور تابعٌ للاسم المجرور «الضّيفِ»، وعلامة جرّه الكسرة"},{"id":"b","text":"بدل مرفوع بالضمّة"},{"id":"c","text":"نعت منصوب"},{"id":"d","text":"مضاف إليه مجرور"}]'::jsonb, 'a', '«منيرٍ» بدل كلّ من كلّ من «الضّيفِ»، والبدل يتبع المبدل منه في إعرابه؛ و«الضّيفِ» اسمٌ مجرور بحرف الجرّ «على»، فجاء البدل مجرورًا مثله.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4efe9e34-23ec-5b73-9dae-b152727141b1', '57cc4d23-4cb5-5d51-a251-1a7edcbcbbbe', '«راقني البستانُ جمالُه» و«راقني البستانُ الجميلُ» — ما الفرق بين الكلمتين الأخيرتين؟', '[{"id":"a","text":"كلتاهما بدل اشتمال"},{"id":"b","text":"كلتاهما نعت"},{"id":"c","text":"الأولى نعت والثّانية بدل"},{"id":"d","text":"الأولى بدل اشتمال («جمالُه» معنًى مضافٌ إلى ضمير)، والثّانية نعت («الجميلُ» صفةٌ مشتقّة)"}]'::jsonb, 'd', '«جمالُه» اسمٌ يدلّ على معنًى يشتمل عليه البستان واتّصل به ضمير، فهو بدل اشتمال؛ أمّا «الجميلُ» فصفةٌ مشتقّة تصف البستان، فهو نعت.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ce16c97d-2bbe-5cdd-8eec-7d8e0dbb99fe', '57cc4d23-4cb5-5d51-a251-1a7edcbcbbbe', '«شربتُ العصيرَ نصفَه» — أعرب تلميذٌ «نصفَه» مفعولًا به ثانيًا. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، فهو مفعول به ثانٍ"},{"id":"b","text":"الصّواب أنّه توكيد لفظيّ"},{"id":"c","text":"الصّواب أنّه بدل بعض من كلّ منصوب تابعٌ للمفعول «العصيرَ»، والهاء مضاف إليه"},{"id":"d","text":"الصّواب أنّه حال منصوبة"}]'::jsonb, 'c', 'الفعل «شربَ» لا يأخذ مفعولين، و«النّصف» جزءٌ من «العصيرَ» متّصلٌ بضميرٍ يعود عليه، فهو بدل بعض من كلّ يتبع المفعول به في النّصب، والهاء في محلّ جرّ مضاف إليه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('61028592-b1e6-54c9-ac08-27a8a2472ee9', '57cc4d23-4cb5-5d51-a251-1a7edcbcbbbe', '«أدهشني المطربُ صوتُه» — لماذا كان «صوتُه» بدل اشتمال لا بدل بعض من كلّ؟', '[{"id":"a","text":"لأنّه لا ضمير في «صوتُه»"},{"id":"b","text":"لأنّ الصّوت معنًى يشتمل عليه المطرب لا جزءٌ ماديٌّ محسوسٌ منه"},{"id":"c","text":"لأنّ «المطربُ» علمٌ"},{"id":"d","text":"لأنّ الصّوت جزءٌ ماديٌّ من المطرب"}]'::jsonb, 'b', 'الفيصل بين البدلين أنّ بدل البعض جزءٌ ماديٌّ يُقتطع (كالأصبع والفرع)، وبدل الاشتمال معنًى أو صفة (كالصّوت والعلم)؛ والصّوت معنًى يشتمل عليه المطرب، فهو بدل اشتمال.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b18ebe7-016c-562a-b6bb-b008fec4127c', '57cc4d23-4cb5-5d51-a251-1a7edcbcbbbe', '«كرّمتُ الفائزَ إيادًا» — ما إعراب «إيادًا»؟', '[{"id":"a","text":"بدل كلّ من كلّ منصوب تابعٌ للمفعول به «الفائزَ»"},{"id":"b","text":"مفعول به ثانٍ منصوب"},{"id":"c","text":"نعت منصوب"},{"id":"d","text":"حال منصوبة"}]'::jsonb, 'a', '«إيادًا» هو «الفائزَ» نفسه، فهو بدل كلّ من كلّ يتبع المبدل منه في الإعراب؛ و«الفائزَ» مفعول به منصوب، فجاء البدل منصوبًا مثله.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

