  ('512a329f-264f-58b4-999f-24fb4a85ad29', '7ed244aa-0193-58dd-9c12-ffa5c70ba029', 'arabic-8eme', '⭐⭐ مراجعة: البدل', 2, 70, 15, 'practice', 'admin', 3)
