INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('43f77a24-d9ff-5991-a25a-8679314ff662', '512a329f-264f-58b4-999f-24fb4a85ad29', 'اختر المثال الّذي فيه بدل كلّ من كلّ:', '[{"id":"a","text":"جاءَ الرّجلُ الطّويلُ"},{"id":"b","text":"أكلتُ الرّغيفَ نصفَه"},{"id":"c","text":"زُرتُ الخليفةَ عمرَ"},{"id":"d","text":"أعجبني الطّالبُ خلقُه"}]'::jsonb, 'c', 'في «زُرتُ الخليفةَ عمرَ» يكون «عمرَ» هو «الخليفةَ» نفسه، فهو بدل كلّ من كلّ. أمّا «الطّويلُ» فنعت، و«نصفَه» بدل بعض من كلّ، و«خلقُه» بدل اشتمال.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a88f95f-8daf-5457-b147-b2f389ce7f6a', '512a329f-264f-58b4-999f-24fb4a85ad29', '«قطفتُ الوردةَ ...» — أكمل ببدلٍ من نوع بعض من كلّ صحيح:', '[{"id":"a","text":"نصفَها"},{"id":"b","text":"الحمراءَ"},{"id":"c","text":"جمالَها"},{"id":"d","text":"نفسَها"}]'::jsonb, 'a', 'بدل البعض جزءٌ ماديٌّ من المبدل منه متّصلٌ بضمير؛ و«نصفَها» جزءٌ من الوردة، بخلاف «الحمراءَ» (نعت) و«جمالَها» (اشتمال) و«نفسَها» (توكيد).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a983ba20-2841-5240-8df9-30e671a01e36', '512a329f-264f-58b4-999f-24fb4a85ad29', '«فازَ العدّاءُ رامزٌ بسباق بنزرتَ» — ما إعراب «رامزٌ»؟', '[{"id":"a","text":"فاعل ثانٍ مرفوع"},{"id":"b","text":"نعت مرفوع"},{"id":"c","text":"مبتدأ مرفوع"},{"id":"d","text":"بدل كلّ من كلّ مرفوع تابعٌ للفاعل «العدّاءُ»"}]'::jsonb, 'd', '«رامزٌ» هو «العدّاءُ» نفسه، فهو بدل كلّ من كلّ يتبع المبدل منه؛ والمبدل منه فاعلٌ مرفوع، فجاء البدل مرفوعًا مثله لا فاعلًا ثانيًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1fcff850-2158-590c-8248-5ad6790ae9b2', '512a329f-264f-58b4-999f-24fb4a85ad29', '«سُررتُ بالتّلميذِ أدبِه» — ما نوع البدل وإعراب «أدبِه»؟', '[{"id":"a","text":"بدل بعض من كلّ مرفوع"},{"id":"b","text":"بدل اشتمال مجرور تابعٌ لـ«التّلميذِ»، والهاء مضاف إليه"},{"id":"c","text":"نعت مجرور"},{"id":"d","text":"توكيد مجرور"}]'::jsonb, 'b', '«الأدب» معنًى يشتمل عليه التّلميذ، فهو بدل اشتمال يتبع المبدل منه في الجرّ (لأنّ «التّلميذِ» مجرورٌ بالباء)، والهاء ضميرٌ في محلّ جرّ مضاف إليه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b2a40ae8-6eeb-5819-9b8f-f3d7140fa1ad', '512a329f-264f-58b4-999f-24fb4a85ad29', '«حفظتُ السّورةَ نصفَها» و«أعجبني الشّاعرُ خيالُه» — ما الفرق بين البدلين؟', '[{"id":"a","text":"الأوّل بدل بعض من كلّ (جزء)، والثّاني بدل اشتمال (معنًى)"},{"id":"b","text":"كلاهما بدل بعض من كلّ"},{"id":"c","text":"كلاهما بدل اشتمال"},{"id":"d","text":"الأوّل اشتمال والثّاني بعض من كلّ"}]'::jsonb, 'a', '«نصفَها» جزءٌ ماديٌّ من السّورة فهو بدل بعض من كلّ، و«خيالُه» معنًى يشتمل عليه الشّاعر فهو بدل اشتمال؛ والفيصل بينهما: جزءٌ محسوس أم معنًى مُشتمَلٌ عليه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3134721f-3819-5b65-8ea5-363eb6d6d6c5', '512a329f-264f-58b4-999f-24fb4a85ad29', '«هذا الكتابُ ...» — أيّ كلمةٍ إن أُتبعت بها كانت نعتًا لا بدلًا؟', '[{"id":"a","text":"نصفُه"},{"id":"b","text":"عنوانُه"},{"id":"c","text":"المفيدُ"},{"id":"d","text":"غلافُه"}]'::jsonb, 'c', '«المفيدُ» صفةٌ مشتقّة تصف الكتاب فهي نعت؛ أمّا «نصفُه» و«غلافُه» فبدل بعض من كلّ، و«عنوانُه» بدل اشتمال، وكلّها أبدال لا نعوت.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('e53fe280-a334-5f20-9b19-5accdb7f5e52', '7ed244aa-0193-58dd-9c12-ffa5c70ba029', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: إتقان البدل', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
