  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('62c19520-14c9-554b-ada7-6c5367c0124b', 'e53fe280-a334-5f20-9b19-5accdb7f5e52', '«أقسمَ الشّاعرُ المتنبّي بعزمه» — «المتنبّي» تابعٌ جامدٌ يوضّح متبوعه، والمقصود بالإسناد هو «الشّاعرُ». فما هذا التّابع؟', '[{"id":"a","text":"بدل بعض من كلّ"},{"id":"b","text":"عطف بيان"},{"id":"c","text":"توكيد معنويّ"},{"id":"d","text":"تمييز"}]'::jsonb, 'b', 'عطف البيان تابعٌ جامدٌ يوضّح متبوعه، لكنّ المقصود بالحكم هو المتبوع لا التّابع؛ وهنا المقصود بالإقسام «الشّاعرُ»، و«المتنبّي» موضِّحٌ له، فهو عطف بيان لا بدل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fac678aa-fa83-5bb7-98f1-711315df589c', 'e53fe280-a334-5f20-9b19-5accdb7f5e52', '«رأيتُ أخاك عليًّا في نادي صفاقسَ» — ما إعراب «عليًّا»؟', '[{"id":"a","text":"نعت منصوب"},{"id":"b","text":"مفعول به ثانٍ منصوب"},{"id":"c","text":"بدل كلّ من كلّ منصوب تابعٌ للمفعول به «أخاك»"},{"id":"d","text":"حال منصوبة"}]'::jsonb, 'c', '«عليًّا» هو «أخاك» نفسه، فهو بدل كلّ من كلّ يتبع المبدل منه؛ و«أخاك» مفعول به منصوب (من الأسماء الخمسة)، فجاء البدل منصوبًا بالفتحة تبعًا له.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0fbf7f32-9bca-5ebc-8172-9c9a38d8bdba', 'e53fe280-a334-5f20-9b19-5accdb7f5e52', 'قال تلميذٌ «أكلتُ الرّغيفَ نصفًا» يريد بدل بعض من كلّ. أين خطؤه؟', '[{"id":"a","text":"لا خطأ في الجملة"},{"id":"b","text":"الصّواب حذف «الرّغيفَ»"},{"id":"c","text":"الصّواب «نصفَه» بضميرٍ يعود على المبدل منه؛ فبدل البعض لا يصحّ بلا ضمير رابط"},{"id":"d","text":"الصّواب رفع الكلمة فيقال «نصفٌ»"}]'::jsonb, 'c', 'بدل البعض من الكلّ يلزمه ضميرٌ يعود على المبدل منه يتّصل بالبدل، فالصّواب «أكلتُ الرّغيفَ نصفَه»؛ فبلا ضميرٍ لا يتحقّق هذا البدل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('79689000-2efe-5222-ba52-109c9649ff16', 'e53fe280-a334-5f20-9b19-5accdb7f5e52', '«جاءَ صديقي كريمٌ الشّجاعُ» — ما إعراب «كريمٌ» و«الشّجاعُ»؟', '[{"id":"a","text":"كلاهما بدلان من «صديقي»"},{"id":"b","text":"«كريمٌ» نعتٌ و«الشّجاعُ» بدل"},{"id":"c","text":"كلاهما نعتان لـ«صديقي»"},{"id":"d","text":"«كريمٌ» بدل كلّ من كلّ من «صديقي»، و«الشّجاعُ» نعتٌ لـ«كريمٌ»"}]'::jsonb, 'd', '«كريمٌ» اسمٌ جامدٌ (علم) هو «صديقي» نفسه فهو بدل كلّ من كلّ، و«الشّجاعُ» صفةٌ مشتقّة تصف «كريمٌ» فهي نعتٌ له؛ وكلاهما مرفوعٌ تبعًا لما قبله.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9f4421a-bf09-5cbc-b1ac-255dc1c8996a', 'e53fe280-a334-5f20-9b19-5accdb7f5e52', '«سرّني الحقلُ خضرتُه» — لماذا امتنع أن يكون «خضرتُه» بدل بعض من كلّ وكان بدل اشتمال؟', '[{"id":"a","text":"لأنّ الخضرة معنًى وصفةٌ يشتمل عليها الحقل لا جزءٌ ماديٌّ يُقتطع منه"},{"id":"b","text":"لأنّه لا ضمير في «خضرتُه»"},{"id":"c","text":"لأنّ «الحقلُ» نكرة"},{"id":"d","text":"لأنّ الخضرة جزءٌ ماديٌّ محسوسٌ من الحقل"}]'::jsonb, 'a', 'بدل البعض جزءٌ ماديٌّ يُقتطع من المبدل منه، وبدل الاشتمال معنًى أو صفةٌ يشتمل عليها؛ والخضرة صفةٌ يشتمل عليها الحقل لا قطعةٌ تُنتزع منه، فهو بدل اشتمال.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e897c4d9-3027-586f-b07c-7c2b110ef356', 'e53fe280-a334-5f20-9b19-5accdb7f5e52', '«عادَ المسافرانِ أخواك من إيطاليا» — ما إعراب «أخواك»؟', '[{"id":"a","text":"فاعل ثانٍ مرفوع"},{"id":"b","text":"بدل كلّ من كلّ مرفوع بالألف لأنّه مثنّى، تابعٌ للفاعل «المسافرانِ»"},{"id":"c","text":"توكيد مرفوع بالألف"},{"id":"d","text":"نعت مرفوع بالضمّة"}]'::jsonb, 'b', '«أخواك» هما «المسافرانِ» نفساهما، فهو بدل كلّ من كلّ يتبع المبدل منه؛ والمبدل منه فاعلٌ مثنّى مرفوعٌ بالألف، فجاء البدل مرفوعًا بالألف مثله.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

