  ('561567db-d5ed-5d4f-9213-5647e9e39634', '7ed244aa-0193-58dd-9c12-ffa5c70ba029', 'arabic-8eme', '⚔️ تدريب الزّعماء ⭐⭐⭐: البدل في الجملة', 3, 120, 30, 'boss', 'admin', 5)
