INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('268d8007-3e87-5331-8a3a-9c247554299f', '561567db-d5ed-5d4f-9213-5647e9e39634', '«شاهدتُ اللاعبَ مسعودًا في ملعب رادسَ» — ما نوع البدل في «مسعودًا»؟', '[{"id":"a","text":"بدل كلّ من كلّ، لأنّ مسعودًا هو اللاعبُ نفسه"},{"id":"b","text":"بدل بعض من كلّ"},{"id":"c","text":"بدل اشتمال"},{"id":"d","text":"نعت"}]'::jsonb, 'a', '«مسعودًا» هو «اللاعبَ» نفسه لا جزءٌ منه ولا صفةٌ فيه، ويصحّ: شاهدتُ مسعودًا. فهو بدل كلّ من كلّ (مطابق).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('06f5eb5a-6415-5a78-8e45-09bb770cd956', '561567db-d5ed-5d4f-9213-5647e9e39634', '«قرأتُ الرّوايةَ فصلَها الأخيرَ» — ما نوع البدل في «فصلَها»؟', '[{"id":"a","text":"بدل اشتمال"},{"id":"b","text":"بدل بعض من كلّ، لأنّ الفصل جزءٌ من الرّواية"},{"id":"c","text":"بدل كلّ من كلّ"},{"id":"d","text":"توكيد"}]'::jsonb, 'b', '«الفصل» جزءٌ حقيقيٌّ من «الرّوايةَ»، واتّصل به ضميرٌ يعود على المبدل منه، فهو بدل بعض من كلّ؛ و«الأخيرَ» نعتٌ لـ«فصلَها».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ba0e676-1fe5-57ba-8ad7-0aaf674cd48b', '561567db-d5ed-5d4f-9213-5647e9e39634', '«راقني المتحفُ نظامُه» — ما نوع البدل في «نظامُه»؟', '[{"id":"a","text":"بدل بعض من كلّ"},{"id":"b","text":"بدل كلّ من كلّ"},{"id":"c","text":"بدل اشتمال، لأنّ النّظام معنًى يشتمل عليه المتحف"},{"id":"d","text":"نعت"}]'::jsonb, 'c', '«النّظام» معنًى وصفةٌ يشتمل عليها المتحف لا جزءٌ ماديٌّ منه، واتّصل به ضميرٌ عائدٌ على المبدل منه، فهو بدل اشتمال.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d3cf521-20f9-5fa3-9eb8-80cd06e19670', '561567db-d5ed-5d4f-9213-5647e9e39634', '«مررتُ بالكاتبِ محمودٍ» — ما إعراب «محمودٍ»؟', '[{"id":"a","text":"بدل كلّ من كلّ مجرور تابعٌ للاسم المجرور «الكاتبِ»"},{"id":"b","text":"نعت مجرور بالكسرة"},{"id":"c","text":"مضاف إليه مجرور"},{"id":"d","text":"بدل مرفوع بالضمّة"}]'::jsonb, 'a', '«محمودٍ» هو «الكاتبِ» نفسه، فهو بدل كلّ من كلّ يتبع المبدل منه في إعرابه؛ و«الكاتبِ» مجرورٌ بالباء، فجاء البدل مجرورًا بالكسرة مثله.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('651412bc-7b2b-5c28-a4f7-fbbee69f162c', '561567db-d5ed-5d4f-9213-5647e9e39634', 'في أيّ جملةٍ لا يصحّ إعراب الكلمة الأخيرة بدلًا (بل هي نعت)؟', '[{"id":"a","text":"أعجبني الوردُ لونُه"},{"id":"b","text":"كافأتُ الفائزَ سميرًا"},{"id":"c","text":"أكلتُ الخبزةَ نصفَها"},{"id":"d","text":"جاءَ التّلميذُ المجتهدُ"}]'::jsonb, 'd', '«المجتهدُ» صفةٌ مشتقّة تصف التّلميذ فهي نعت لا بدل؛ أمّا «لونُه» فبدل اشتمال، و«سميرًا» بدل كلّ من كلّ، و«نصفَها» بدل بعض من كلّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
