  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('36701344-2377-5871-ada9-6117d4246ad9', '561567db-d5ed-5d4f-9213-5647e9e39634', '«عالجَ الطّبيبُ المريضَ جرحَه» — «جرحَه» بدل بعض من كلّ؛ علامَ يعود الضّمير وما إعراب البدل؟', '[{"id":"a","text":"يعود على «الطّبيبُ»، والبدل مرفوع"},{"id":"b","text":"يعود على «المريضَ»، والبدل منصوب تابعٌ له، والهاء مضاف إليه"},{"id":"c","text":"يعود على «الطّبيبُ»، والهاء فاعل"},{"id":"d","text":"لا ضمير في الجملة"}]'::jsonb, 'b', '«الجرح» جزءٌ من «المريضَ»، فالضّمير الهاء يعود على المبدل منه «المريضَ»؛ والبدل يتبعه في النّصب لأنّه مفعول به، والهاء في محلّ جرّ مضاف إليه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

