  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6883a492-fd89-56ac-ba6d-5167835545bc', 'ec6e58f8-03c8-5820-bd85-3b8185e7c871', 'من التّوابع الّتي تتبع ما قبلها وتوضّحه، أيّها اسمٌ (غالبًا جامد) هو المقصود بالحكم دون ما قبله؟', '[{"id":"a","text":"النّعت"},{"id":"b","text":"العطف بالحرف"},{"id":"c","text":"البدل"},{"id":"d","text":"التوكيد اللفظيّ"}]'::jsonb, 'c', 'البدل هو التّابع الّذي يكون المقصود بالحكم، حتّى ليصحّ حذف المبدل منه؛ أمّا النّعت فيصف والمقصود المنعوت، والتوكيد يثبّت، والعطف يربط.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('34334bd9-2fa3-54af-a951-a99db9b558a1', 'ec6e58f8-03c8-5820-bd85-3b8185e7c871', '«سلّمتُ على العالِمِ ابنِ خلدونَ» — ما إعراب «ابنِ»؟', '[{"id":"a","text":"بدل كلّ من كلّ مجرور تابعٌ للمجرور «العالِمِ»، و«خلدونَ» مضاف إليه"},{"id":"b","text":"نعت مجرور"},{"id":"c","text":"توكيد مجرور"},{"id":"d","text":"بدل منصوب"}]'::jsonb, 'a', '«ابنِ» هو «العالِمِ» نفسه، فهو بدل كلّ من كلّ يتبع المبدل منه في الجرّ (لأنّ «العالِمِ» مجرورٌ بحرف الجرّ)، و«خلدونَ» مضاف إليه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d41e1171-4514-5abc-8c44-a9e887c218f0', 'ec6e58f8-03c8-5820-bd85-3b8185e7c871', '«أبهرني القصرُ زخرفُه» و«أبهرني القصرُ الفخمُ» و«أبهرني القصرُ جناحُه الأيمنُ» — ما نوع كلٍّ على التّرتيب؟', '[{"id":"a","text":"نعت، ثمّ بدل، ثمّ توكيد"},{"id":"b","text":"كلّها أبدال اشتمال"},{"id":"c","text":"كلّها نعوت"},{"id":"d","text":"بدل اشتمال (زخرفُه)، ثمّ نعت (الفخمُ)، ثمّ بدل بعض من كلّ (جناحُه)"}]'::jsonb, 'd', '«زخرفُه» معنًى يشتمل عليه القصر فهو بدل اشتمال، و«الفخمُ» صفةٌ مشتقّة فهو نعت، و«جناحُه» جزءٌ ماديٌّ من القصر فهو بدل بعض من كلّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a314e86-b806-5e7b-9a11-d50a18726ece', 'ec6e58f8-03c8-5820-bd85-3b8185e7c871', 'أعرب تلميذٌ «نفسَه» في «جاءَ المديرُ نفسَه» بدلًا. ما الصّواب؟', '[{"id":"a","text":"هو بدل كلّ من كلّ فعلًا"},{"id":"b","text":"الصّواب أنّه توكيد معنويّ، فـ«نفس» من ألفاظ التوكيد لا من الأبدال"},{"id":"c","text":"الصّواب أنّه نعت"},{"id":"d","text":"الصّواب أنّه بدل اشتمال"}]'::jsonb, 'b', '«نفس» لفظٌ من ألفاظ التوكيد المعنويّ المضافة إلى ضمير، لا من الأبدال؛ فـ«نفسَه» توكيد معنويّ للمدير لا بدل، وهو خطأٌ شائع في الخلط بين التّابعَين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('71ea1937-b0df-57f5-8942-6913bb66631b', 'ec6e58f8-03c8-5820-bd85-3b8185e7c871', '«كرّمتِ المدرسةُ الفائزَينِ أخوَيكَ» — ما إعراب «أخوَيكَ»؟', '[{"id":"a","text":"بدل كلّ من كلّ منصوب بالياء لأنّه مثنّى، تابعٌ للمفعول به «الفائزَينِ»"},{"id":"b","text":"توكيد منصوب"},{"id":"c","text":"فاعل مرفوع"},{"id":"d","text":"نعت مرفوع بالياء"}]'::jsonb, 'a', '«أخوَيكَ» هما «الفائزَينِ» نفساهما، فهو بدل كلّ من كلّ يتبع المبدل منه؛ والمبدل منه مفعول به مثنّى منصوبٌ بالياء، فجاء البدل منصوبًا بالياء مثله.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f320fdc-fbcc-5e8e-b407-4d76fe583690', 'ec6e58f8-03c8-5820-bd85-3b8185e7c871', '«شربتُ الكأسَ نصفَها ثمّ أهديتُ صديقي عمرَ الباقيَ» — كم بدلًا في الجملة وما نوعاهما؟', '[{"id":"a","text":"بدلٌ واحدٌ فقط هو «نصفَها»"},{"id":"b","text":"بدلان: «نصفَها» بدل بعض من كلّ من «الكأسَ»، و«عمرَ» بدل كلّ من كلّ من «صديقي»"},{"id":"c","text":"ثلاثة أبدال"},{"id":"d","text":"لا بدل في الجملة"}]'::jsonb, 'b', '«نصفَها» جزءٌ من «الكأسَ» فهو بدل بعض من كلّ، و«عمرَ» هو «صديقي» نفسه فهو بدل كلّ من كلّ؛ أمّا «الباقيَ» فمفعولٌ به ثانٍ للفعل «أهدى» لا بدل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('fb56108d-ef77-5b9e-a3b3-04f6a2f48a9f', '5befaad0-a866-568a-88db-413a1e0a520a', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1bf92150-c4ce-50e2-be83-2df8ff02867b', 'fb56108d-ef77-5b9e-a3b3-04f6a2f48a9f', 'العطف تابعٌ يربط بين اسمَينِ أو جملتَينِ بواسطة:', '[{"id":"a","text":"حرفٍ من حروف العطف"},{"id":"b","text":"حرفٍ من حروف الجرّ"},{"id":"c","text":"ضميرٍ متّصل"},{"id":"d","text":"علامةِ إعرابٍ ظاهرة"}]'::jsonb, 'a', 'العطف تابعٌ يربط بين المعطوف عليه والمعطوف بحرفٍ من حروف العطف (كالواو والفاء وثمّ)، فيشتركان في الحكم الإعرابيّ نفسه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('61035ce0-5ff1-5c93-8c27-16a6674a05c1', 'fb56108d-ef77-5b9e-a3b3-04f6a2f48a9f', 'في جملة «حضرَ المعلّمُ والتّلاميذُ» — ما هو المعطوف؟', '[{"id":"a","text":"المعلّمُ"},{"id":"b","text":"حضرَ"},{"id":"c","text":"الواو"},{"id":"d","text":"التّلاميذُ"}]'::jsonb, 'd', 'المعطوف هو الاسم الواقع بعد حرف العطف، وهو «التّلاميذُ»؛ أمّا «المعلّمُ» فمعطوف عليه (قبل الحرف)، والواو حرف العطف.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a523109a-e5c3-5b3d-a560-ec0c15399d64', 'fb56108d-ef77-5b9e-a3b3-04f6a2f48a9f', 'أيُّ حرفٍ من حروف العطف يفيد الترتيب والتعقيب (وقوعَ الثّاني بعد الأوّل مباشرةً بلا مهلة)؟', '[{"id":"a","text":"الواو"},{"id":"b","text":"الفاء"},{"id":"c","text":"ثمّ"},{"id":"d","text":"أو"}]'::jsonb, 'b', 'الفاء تفيد الترتيب والتعقيب، أي أنّ المعطوف يقع بعد المعطوف عليه مباشرةً بلا مهلة (سمعَ الجرسَ فقامَ).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('be2f68d2-ecb0-5de7-a139-d04d9e3c602d', 'fb56108d-ef77-5b9e-a3b3-04f6a2f48a9f', '«زرعَ الفلّاحُ ثمّ حصدَ» — ماذا يفيد حرف العطف «ثمّ» هنا؟', '[{"id":"a","text":"التخيير بين الزّرع والحصاد"},{"id":"b","text":"الترتيب مع التراخي (بمهلةٍ بين الفعلَينِ)"},{"id":"c","text":"مطلق الجمع بلا ترتيب"},{"id":"d","text":"نفيَ الحصاد"}]'::jsonb, 'b', '«ثمّ» تفيد الترتيب مع التراخي: الحصاد يقع بعد الزّرع بمهلةٍ وفترة (أشهر)، بخلاف الفاء التي تفيد التعقيب الفوريّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30a2fb38-8e90-5395-a147-ea531ca14bf5', 'fb56108d-ef77-5b9e-a3b3-04f6a2f48a9f', 'ما القاعدة الّتي تحكم إعراب المعطوف؟', '[{"id":"a","text":"يكون مرفوعًا دائمًا مهما كان موقعه"},{"id":"b","text":"يكون منصوبًا دائمًا لأنّه تابع"},{"id":"c","text":"يتبع المعطوف عليه في إعرابه"},{"id":"d","text":"يأخذ إعراب حرف العطف الّذي قبله"}]'::jsonb, 'c', 'المعطوف تابعٌ للمعطوف عليه في إعرابه: يرفع برفعه، ويُنصب بنصبه، ويُجرّ بجرّه، ويُجزم بجزمه؛ أمّا حرف العطف فمبنيّ لا محلّ له من الإعراب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('10a9ffec-5c54-5aef-82fd-ff91760f42d2', '5befaad0-a866-568a-88db-413a1e0a520a', 'arabic-8eme', '⭐ تمرين: تمييز أركان العطف ومعاني حروفه', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3ba90ab0-9fbe-5cbf-a89d-e0b6efb19b84', '10a9ffec-5c54-5aef-82fd-ff91760f42d2', 'في جملة «قرأَ الطّالبُ القصّةَ والرّوايةَ» — ما هو حرف العطف؟', '[{"id":"a","text":"قرأَ"},{"id":"b","text":"الواو"},{"id":"c","text":"القصّةَ"},{"id":"d","text":"الرّوايةَ"}]'::jsonb, 'b', 'الواو في «والرّوايةَ» هي حرف العطف الّذي ربط بين المعطوف عليه «القصّةَ» والمعطوف «الرّوايةَ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('469d4087-b34b-58ff-874f-5c15bc70d9a7', '10a9ffec-5c54-5aef-82fd-ff91760f42d2', '«جاء عليٌّ وخالدٌ» — ما هو المعطوف عليه؟', '[{"id":"a","text":"خالدٌ"},{"id":"b","text":"الواو"},{"id":"c","text":"عليٌّ"},{"id":"d","text":"جاء"}]'::jsonb, 'c', 'المعطوف عليه هو الاسم الواقع قبل حرف العطف، وهو «عليٌّ»؛ والمعطوف هو «خالدٌ» الواقع بعد الواو.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fab08005-8e80-5a20-bb4d-1633960ac888', '10a9ffec-5c54-5aef-82fd-ff91760f42d2', 'أيُّ حرفٍ من حروف العطف يفيد التخيير (اختيار واحدٍ من شيئَينِ)؟', '[{"id":"a","text":"أو"},{"id":"b","text":"ثمّ"},{"id":"c","text":"الفاء"},{"id":"d","text":"حتّى"}]'::jsonb, 'a', '«أو» تفيد التخيير أو الإباحة، أي اختيار واحدٍ من المذكورَينِ: «خذْ كتابًا أو دفترًا».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4300864a-b0fc-55b4-a9c2-3df9efbb7079', '10a9ffec-5c54-5aef-82fd-ff91760f42d2', '«سمعَ التّلميذُ الجرسَ فدخلَ الصّفَّ» — ماذا يفيد حرف العطف «الفاء»؟', '[{"id":"a","text":"الترتيب مع التراخي (بمهلة)"},{"id":"b","text":"مطلق الجمع بلا ترتيب"},{"id":"c","text":"الترتيب والتعقيب (فورًا بلا مهلة)"},{"id":"d","text":"الإضراب عن الأوّل"}]'::jsonb, 'c', 'الفاء تفيد الترتيب والتعقيب: الدّخول وقع عقب سماع الجرس مباشرةً بلا مهلة، بخلاف «ثمّ» الّتي تفيد التراخي.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07f61bdd-4f98-52c1-a3da-5c07d0899d14', '10a9ffec-5c54-5aef-82fd-ff91760f42d2', '«ما نجحَ الكسولُ لا المجتهدُ» — تصحيحُ المعنى يقتضي وضعَ حرفٍ يُثبت النّجاح للمجتهد بعد نفيه عن الكسول. ما الحرف الصّحيح؟', '[{"id":"a","text":"لا"},{"id":"b","text":"بل"},{"id":"c","text":"الواو"},{"id":"d","text":"ثمّ"}]'::jsonb, 'b', '«بل» للإضراب: تُبطل الحكم عن الأوّل وتُثبته للثّاني، فنقول «ما نجحَ الكسولُ بل المجتهدُ». أمّا «لا» فتنفي عن الثّاني بعد إثباته للأوّل، وهو عكس المعنى المطلوب هنا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8cc7e459-c5c5-5a47-bec6-f7cff632ca99', '10a9ffec-5c54-5aef-82fd-ff91760f42d2', '«جاء المعلّمُ وتلميذُه» — «تلميذُه» معطوفٌ على «المعلّمُ» (وهو فاعل مرفوع). فما إعراب «تلميذُه»؟', '[{"id":"a","text":"معطوف منصوب"},{"id":"b","text":"معطوف مجرور"},{"id":"c","text":"حرف عطف"},{"id":"d","text":"معطوف مرفوع"}]'::jsonb, 'd', 'المعطوف يتبع المعطوف عليه في إعرابه؛ ولمّا كان «المعلّمُ» مرفوعًا (فاعلًا)، كان «تلميذُه» معطوفًا مرفوعًا مثله، وعلامة رفعه الضّمّة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('7f993aaf-e099-5105-8bc5-d09cde42b917', '5befaad0-a866-568a-88db-413a1e0a520a', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: معاني حروف العطف وإعراب المعطوف', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db09e97e-34e1-5541-ad74-97dcfcd06d13', '7f993aaf-e099-5105-8bc5-d09cde42b917', '«دخلَ الأبُ فالابنُ» و«دخلَ الأبُ ثمّ الابنُ» — ما الفرق الدّقيق بين الجملتَينِ؟', '[{"id":"a","text":"الأولى فيها ترتيبٌ بمهلة والثّانية ترتيبٌ فوريّ"},{"id":"b","text":"الأولى دخولٌ فوريّ متتابع والثّانية دخولٌ بمهلةٍ بينهما"},{"id":"c","text":"لا فرق بينهما في المعنى"},{"id":"d","text":"الأولى تفيد التخيير والثّانية تفيد الجمع"}]'::jsonb, 'b', 'الفاء تفيد الترتيب والتعقيب: دخلَ الابنُ عقبَ الأبِ مباشرةً؛ وثمّ تفيد الترتيب مع التراخي: دخلَ الابنُ بعد الأبِ بمهلة. كلاهما ترتيبٌ، والفرق في المهلة، والخطأ الشّائع هو عكس الحرفَينِ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('78d38bbd-ede3-5744-a642-4ffe526cbfa9', '7f993aaf-e099-5105-8bc5-d09cde42b917', '«ما اشتريتُ القميصَ بل المعطفَ» — ماذا يفيد حرف العطف «بل»؟', '[{"id":"a","text":"الاستدراك بعد نهيٍ"},{"id":"b","text":"التخيير بين القميص والمعطف"},{"id":"c","text":"الإضراب: نفيُ الشّراء عن القميص وإثباتُه للمعطف"},{"id":"d","text":"مطلق الجمع بينهما"}]'::jsonb, 'c', '«بل» للإضراب: تُبطل الحكم عن المعطوف عليه «القميصَ» وتُثبته للمعطوف «المعطفَ»، فالمعنى: لم أشترِ القميصَ وإنّما اشتريتُ المعطفَ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8ecf87f1-fffc-5117-b9d9-a9c0f89704c1', '7f993aaf-e099-5105-8bc5-d09cde42b917', '«سلّمتُ على المديرِ والأستاذِ» — ما إعراب «الأستاذِ»؟', '[{"id":"a","text":"معطوف مرفوع بالضّمّة"},{"id":"b","text":"معطوف منصوب بالفتحة"},{"id":"c","text":"معطوف مجرور بالكسرة تبعًا للمعطوف عليه"},{"id":"d","text":"فاعل مرفوع"}]'::jsonb, 'c', '«المديرِ» اسمٌ مجرور بحرف الجرّ «على»، والمعطوف يتبع المعطوف عليه في إعرابه، فـ«الأستاذِ» معطوف مجرور بالكسرة. الخطأ الشّائع النّظر إلى المعطوف وحدَه دون النّظر إلى حكم المعطوف عليه المجرور.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a331f74-8d59-52a6-9003-afc9c9788bc7', '7f993aaf-e099-5105-8bc5-d09cde42b917', '«كرّمَ المديرُ الفائزَ والمتفوّقَ» — ما إعراب «المتفوّقَ»؟', '[{"id":"a","text":"معطوف منصوب بالفتحة تبعًا للمعطوف عليه (المفعول به)"},{"id":"b","text":"معطوف مرفوع بالضّمّة"},{"id":"c","text":"معطوف مجرور بالكسرة"},{"id":"d","text":"فاعل مرفوع بالضّمّة"}]'::jsonb, 'a', '«الفائزَ» مفعول به منصوب، والمعطوف يتبع المعطوف عليه، فـ«المتفوّقَ» معطوف منصوب بالفتحة. القاعدة الذّهبيّة: أوّلًا أعرِبِ المعطوف عليه، ثمّ ألزِمِ المعطوفَ حكمَه نفسه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b3fef03a-ba59-52ef-b574-378a8fe8158c', '7f993aaf-e099-5105-8bc5-d09cde42b917', '«ما القمرُ مضيئًا بذاته لكنْ عاكسٌ لضوء الشّمس» — ماذا يفيد حرف العطف «لكنْ» هنا، وبِمَ سُبق؟', '[{"id":"a","text":"الإضراب، وسُبق بإثبات"},{"id":"b","text":"الاستدراك، وسُبق بنفيٍ (ما)"},{"id":"c","text":"التخيير، وسُبق باستفهام"},{"id":"d","text":"الترتيب والتعقيب، وسُبق بأمر"}]'::jsonb, 'b', '«لكنْ» للاستدراك، وشرطُها أن تُسبق بنفيٍ أو نهيٍ؛ هنا سُبقت بالنّفي «ما»، فأثبتت للمعطوف «عاكسٌ» ما نُفيَ عن المعطوف عليه «مضيئًا». تختلف عن «بل» الّتي تُصحّح فتنقل الحكم كلَّه إلى الثّاني.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07f6d400-e65e-55a1-b792-e8819b7d9ecb', '7f993aaf-e099-5105-8bc5-d09cde42b917', '«قرأتُ الكتابَ حتّى خاتمتِه» — ما نوع حرف العطف «حتّى» وما إعراب «خاتمتِه»؟', '[{"id":"a","text":"حرف عطف يفيد التخيير، و«خاتمتِه» معطوف منصوب"},{"id":"b","text":"حرف عطف يفيد الغاية، و«خاتمتِه» معطوف مجرور (المعطوف عليه مجرور)"},{"id":"c","text":"حرف جرّ، و«خاتمتِه» اسم مجرور فقط لا معطوف"},{"id":"d","text":"حرف عطف يفيد الغاية، و«خاتمتِه» معطوف منصوب تبعًا للمفعول به"}]'::jsonb, 'd', '«حتّى» هنا حرف عطف يفيد الغاية، والمعطوف بها جزءٌ من المعطوف عليه (الخاتمة جزء من الكتاب). والمعطوف عليه «الكتابَ» مفعول به منصوب، فالمعطوف «خاتمتِه» منصوب تبعًا له، وعلامة نصبه الفتحة، وهو مضاف والهاء مضاف إليه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b4c7177d-ec1a-552a-9912-dc9f964988a1', '5befaad0-a866-568a-88db-413a1e0a520a', 'arabic-8eme', '⭐⭐ تمرين مراجعة (نمط امتحان): حروف العطف والإعراب', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1328c777-ce89-51f8-b36f-0c2a0148f4a3', 'b4c7177d-ec1a-552a-9912-dc9f964988a1', '«أكلَ الطّفلُ التّفاحةَ والموزةَ» — ماذا يفيد حرف العطف «الواو» هنا؟', '[{"id":"a","text":"مطلق الجمع والمشاركة بلا ترتيب"},{"id":"b","text":"الترتيب والتعقيب"},{"id":"c","text":"الإضراب"},{"id":"d","text":"الغاية"}]'::jsonb, 'a', 'الواو تفيد مطلق الجمع والمشاركة في الحكم دون ترتيبٍ ولا تعقيب؛ فقد يكون أكلَ التّفاحةَ أوّلًا أو الموزةَ أوّلًا أو معًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6c84bf2-6ad3-5236-9b4b-ec208f357885', 'b4c7177d-ec1a-552a-9912-dc9f964988a1', 'أيُّ حرفٍ من حروف العطف يفيد نفيَ الحكم عن الثّاني بعد إثباته للأوّل؟', '[{"id":"a","text":"بل"},{"id":"b","text":"لا"},{"id":"c","text":"أو"},{"id":"d","text":"الفاء"}]'::jsonb, 'b', '«لا» العاطفة تُثبت الحكم للمعطوف عليه وتنفيه عن المعطوف: «نجحَ المجتهدُ لا الكسولُ» (النّجاح للأوّل لا للثّاني).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bec523f9-5719-5118-9046-2ddcdb178a82', 'b4c7177d-ec1a-552a-9912-dc9f964988a1', '«خرجَ التّلاميذُ من القسمِ ثمّ من المدرسةِ» — ما دلالة «ثمّ» في هذا السّياق؟', '[{"id":"a","text":"خروجٌ متزامنٌ من المكانَينِ"},{"id":"b","text":"الخروجُ من المدرسةِ أوّلًا"},{"id":"c","text":"ترتيبٌ مع مهلةٍ: الخروجُ من المدرسةِ بعد الخروجِ من القسمِ بفترة"},{"id":"d","text":"التخييرُ بين القسمِ والمدرسةِ"}]'::jsonb, 'c', '«ثمّ» تفيد الترتيب مع التراخي، فالخروج من المدرسة تلا الخروجَ من القسم بعد مهلةٍ، لا فورًا كما في الفاء.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('93438c6c-79d2-5fe9-8802-a533547a7c30', 'b4c7177d-ec1a-552a-9912-dc9f964988a1', '«مررتُ بحديقةٍ وملعبٍ» — ما إعراب «ملعبٍ»؟', '[{"id":"a","text":"معطوف مرفوع بالضّمّة"},{"id":"b","text":"معطوف مجرور بالكسرة تبعًا للمعطوف عليه"},{"id":"c","text":"معطوف منصوب بالفتحة"},{"id":"d","text":"مبتدأ مرفوع"}]'::jsonb, 'b', '«حديقةٍ» اسم مجرور بالباء، والمعطوف يتبع المعطوف عليه، فـ«ملعبٍ» معطوف مجرور بالكسرة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('21763845-62bb-5156-9df9-340e5404778e', 'b4c7177d-ec1a-552a-9912-dc9f964988a1', '«فتحَ التّاجرُ محلَّه فباعَ» — لماذا اختير حرف «الفاء» دون «ثمّ»؟', '[{"id":"a","text":"لأنّ البيعَ تلا الفتحَ مباشرةً بلا مهلة"},{"id":"b","text":"لأنّ البيعَ سبقَ الفتحَ"},{"id":"c","text":"لأنّ الفعلَينِ وقعا في وقتٍ واحد"},{"id":"d","text":"لأنّ الفاء تفيد التخيير بين الفتح والبيع"}]'::jsonb, 'a', 'الفاء للترتيب والتعقيب: البيع عقبَ فتحِ المحلّ مباشرةً بلا مهلة، ولو أُريدت مهلةٌ بينهما لاستُعملت «ثمّ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9573204a-23d2-55be-8b08-763b3bd12256', 'b4c7177d-ec1a-552a-9912-dc9f964988a1', 'أيُّ الجمل التّالية تحوي عطفًا صحيحًا يتبع فيه المعطوفُ المعطوفَ عليه في الإعراب؟', '[{"id":"a","text":"شاهدتُ اللّاعبَ والحكمُ"},{"id":"b","text":"شاهدتُ اللّاعبُ والحكمَ"},{"id":"c","text":"شاهدتُ اللّاعبِ والحكمَ"},{"id":"d","text":"شاهدتُ اللّاعبَ والحكمَ"}]'::jsonb, 'd', '«اللّاعبَ» مفعول به منصوب، فيجب أن يكون المعطوف «الحكمَ» منصوبًا مثله؛ فالصّواب «شاهدتُ اللّاعبَ والحكمَ» بنصب الاسمَينِ، لأنّ المعطوف يتبع المعطوف عليه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('23298a95-ad18-5174-9cfa-9a0e0b800c04', '5befaad0-a866-568a-88db-413a1e0a520a', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: إتقان معاني العطف وإعرابه والعطف على التوابع', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('df63e2d5-709f-5c53-bc2e-5353c4b7b0e3', '23298a95-ad18-5174-9cfa-9a0e0b800c04', '«أعجبني الرّجلُ الكريمُ والشّجاعُ» — على أيِّ كلمةٍ عُطف «الشّجاعُ»، وما إعرابه؟', '[{"id":"a","text":"عُطف على الفاعل «الرّجلُ»، وهو معطوف مرفوع"},{"id":"b","text":"عُطف على النّعت «الكريمُ»، وهو معطوف مرفوع تبعًا له"},{"id":"c","text":"عُطف على «أعجبني»، وهو فعل"},{"id":"d","text":"لا محلّ له من الإعراب لأنّه نعت"}]'::jsonb, 'b', '«الشّجاعُ» معطوفٌ على النّعت «الكريمُ» (عطفٌ على تابع)، فيتبعه في الرّفع؛ و«الكريمُ» نعتٌ للفاعل «الرّجلُ» مرفوع، فالمعطوف عليه مرفوع، والمعطوف «الشّجاعُ» مرفوع مثله بالضّمّة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cceb5045-c784-5201-a403-a9e841ce3d98', '23298a95-ad18-5174-9cfa-9a0e0b800c04', '«صافحتُ المعلّمينَ والتّلاميذَ» — ما إعراب «التّلاميذَ»، ولماذا اختلفت علامتُه عن المعطوف عليه؟', '[{"id":"a","text":"معطوف منصوب بالفتحة، والمعطوف عليه منصوب بالياء لأنّه جمع مذكّر سالم"},{"id":"b","text":"معطوف مرفوع بالضّمّة"},{"id":"c","text":"معطوف مجرور بالكسرة"},{"id":"d","text":"معطوف منصوب بالياء مثل المعطوف عليه"}]'::jsonb, 'a', '«المعلّمينَ» مفعول به منصوب بالياء لأنّه جمع مذكّر سالم، و«التّلاميذَ» جمع تكسير يُنصب بالفتحة. فالمعطوف يتبع المعطوف عليه في أصل الإعراب (النّصب) لا في علامته الفرعيّة؛ فكلٌّ يأخذ علامته بحسب نوعه، والحكم واحد: النّصب.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1bf1eb33-adcc-520a-8deb-83a6e38a1fe2', '23298a95-ad18-5174-9cfa-9a0e0b800c04', '«لم يزرْني صديقي بل هاتفَني» — لِمَ صحّ العطف بـ«بل» هنا، وما دلالتها؟', '[{"id":"a","text":"لأنّها للاستدراك، وتشترط أن تُسبق بنفي"},{"id":"b","text":"لأنّها للإضراب، أبطلت الزّيارة وأثبتت المهاتفة"},{"id":"c","text":"لأنّها للتخيير بين الزّيارة والمهاتفة"},{"id":"d","text":"لأنّها للغاية، والمهاتفة جزء من الزّيارة"}]'::jsonb, 'b', '«بل» للإضراب: نقلت الحكم من المعطوف عليه (الزّيارة) إلى المعطوف (المهاتفة)، أي: لم تقعِ الزّيارةُ وإنّما وقعتِ المهاتفةُ. وهي هنا تعطف جملةً على جملة. تختلف عن «لكنْ» الاستدراكيّة الّتي لا تُبطل الأوّل بل تستدرك عليه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ddb945e9-02f8-5904-938e-d7e970f04df5', '23298a95-ad18-5174-9cfa-9a0e0b800c04', '«أتفضّل الشّايَ أم القهوةَ؟» — ما نوع حرف العطف «أم» ودلالته؟', '[{"id":"a","text":"«أم» عاطفة تفيد طلب التعيين بعد همزة الاستفهام"},{"id":"b","text":"«أم» تفيد الإباحة كـ«أو» تمامًا بلا فرق"},{"id":"c","text":"«أم» تفيد الإضراب عن الشّاي"},{"id":"d","text":"«أم» حرف نفيٍ لا عطف"}]'::jsonb, 'a', '«أم» حرف عطف يفيد طلب التعيين، وتأتي بعد همزة الاستفهام لطلب تحديد أحد أمرَينِ: أتفضّل هذا أم ذاك؟ وتختلف عن «أو» الّتي تفيد التخيير أو الإباحة في الخبر لا طلبَ التعيين.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f554d858-ad57-5314-94f9-eca39400cf54', '23298a95-ad18-5174-9cfa-9a0e0b800c04', '«لا تصاحبِ الكسولَ ولا المهملَ» — ما إعراب «المهملَ»، وما دلالة تكرار «لا»؟', '[{"id":"a","text":"معطوف مرفوع، و«لا» للتخيير"},{"id":"b","text":"معطوف مجرور، و«لا» للاستدراك"},{"id":"c","text":"معطوف منصوب تبعًا للمفعول به، والواو عاطفة و«لا» زائدة لتوكيد النّهي"},{"id":"d","text":"فاعل مرفوع، و«لا» ناهية جديدة"}]'::jsonb, 'c', '«الكسولَ» مفعول به منصوب بعد فعل النّهي، والعطف هنا بالواو، فـ«المهملَ» معطوف منصوب بالفتحة تبعًا له؛ و«لا» بعد الواو زائدةٌ لتوكيد معنى النّهي وشموله للاثنَينِ. القاعدة: أعرِبِ المعطوف عليه أوّلًا (منصوب) ثمّ ألزِمِ المعطوفَ حكمَه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f1d55ff-eddb-5292-86c5-c952f93ae299', '23298a95-ad18-5174-9cfa-9a0e0b800c04', '«حفظَ الشّاعرُ القصيدةَ فأنشدَها ثمّ شرحَها» — ما دلالة «الفاء» و«ثمّ» على التّرتيب الزّمنيّ للأفعال؟', '[{"id":"a","text":"الشّرح أوّلًا ثمّ الإنشاد ثمّ الحفظ"},{"id":"b","text":"الأفعال الثّلاثة وقعت في وقتٍ واحد"},{"id":"c","text":"الإنشاد بعد الحفظ بمهلة، والشّرح عقب الإنشاد فورًا"},{"id":"d","text":"الإنشاد عقب الحفظ مباشرةً، والشّرح بعد الإنشاد بمهلة"}]'::jsonb, 'd', 'الترتيب: حفظٌ ← إنشادٌ ← شرحٌ. الفاء (فأنشدَها) تفيد التعقيب، فالإنشاد تلا الحفظَ مباشرةً؛ وثمّ (ثمّ شرحَها) تفيد التراخي، فالشّرح تلا الإنشادَ بعد مهلة. الخطأ الشّائع عكسُ دلالتَي الحرفَينِ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('be6f538d-55be-52c8-8f05-489c6f241f10', '5befaad0-a866-568a-88db-413a1e0a520a', 'arabic-8eme', '📝 تدريب ⭐⭐⭐: مراجعة شاملة على باب العطف', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c0b3a6b6-6699-56a4-b53f-08a5ac6d3aa8', 'be6f538d-55be-52c8-8f05-489c6f241f10', 'أيُّ حرفٍ يفيد الغاية، ويكون المعطوف بها جزءًا من المعطوف عليه؟', '[{"id":"a","text":"أم"},{"id":"b","text":"حتّى"},{"id":"c","text":"لكنْ"},{"id":"d","text":"الواو"}]'::jsonb, 'b', '«حتّى» العاطفة تفيد الغاية، وشرطُها أن يكون المعطوف بها جزءًا من المعطوف عليه وغايةً فيه: «أكلتُ السّمكةَ حتّى رأسِها» (الرّأس جزء من السّمكة).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dbadbf13-1d99-5820-bb9e-3681f49ed463', 'be6f538d-55be-52c8-8f05-489c6f241f10', '«زارَ الوفدُ تونسَ وسوسةَ وصفاقسَ» — على أيِّ أساسٍ عُطفت «صفاقسَ»؟', '[{"id":"a","text":"عُطفت على المعطوف «سوسةَ» (عطفٌ على معطوف في سلسلة)، وهي منصوبة مثله"},{"id":"b","text":"عُطفت على الفاعل «الوفدُ» وهي مرفوعة"},{"id":"c","text":"ليست معطوفةً بل مبتدأ"},{"id":"d","text":"عُطفت على الفعل «زارَ»"}]'::jsonb, 'a', 'في سلسلة العطف يُعطف كلُّ اسمٍ على ما قبله؛ «تونسَ» مفعول به منصوب، و«سوسةَ» معطوف منصوب عليه، و«صفاقسَ» معطوف منصوب على «سوسةَ». والثّلاثة ممنوعة من الصّرف تُنصب بالفتحة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('da98fae4-6665-5d82-b416-6091bf136d4a', 'be6f538d-55be-52c8-8f05-489c6f241f10', '«نجحَ المجتهدونَ والمجتهداتُ» — ما إعراب «المجتهداتُ» وعلامته؟', '[{"id":"a","text":"معطوف مرفوع بالواو"},{"id":"b","text":"معطوف منصوب بالكسرة"},{"id":"c","text":"معطوف مرفوع بالضّمّة تبعًا للفاعل"},{"id":"d","text":"معطوف مجرور بالكسرة"}]'::jsonb, 'c', '«المجتهدونَ» فاعل مرفوع بالواو (جمع مذكّر سالم)، والمعطوف يتبعه في الرّفع، فـ«المجتهداتُ» معطوف مرفوع؛ وعلامة رفعه الضّمّة لأنّه جمع مؤنّث سالم. اتّحدا في الحكم (الرّفع) واختلفا في العلامة بحسب النّوع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('920d0b7b-f205-5e3b-9c75-f434d9c9be7b', 'be6f538d-55be-52c8-8f05-489c6f241f10', '«لم أقرأِ الرّوايةَ لكنِ القصّةَ» و«ما قرأتُ الرّوايةَ بل القصّةَ» — أيُّ العبارتَينِ يصف الفرق بدقّة؟', '[{"id":"a","text":"لا فرق؛ الحرفانِ بمعنًى واحد"},{"id":"b","text":"«لكنْ» استدراكٌ يُثبت للقصّة ما نُفيَ عن الرّواية، و«بل» إضرابٌ ينقل القراءة إلى القصّة؛ والمعنى متقارب والوظيفة مختلفة"},{"id":"c","text":"«بل» تفيد الغاية و«لكنْ» تفيد التخيير"},{"id":"d","text":"«لكنْ» لا تصحّ بعد النّفي و«بل» لا تصحّ إلّا بعد الأمر"}]'::jsonb, 'b', '«لكنْ» للاستدراك بعد النّفي: تُثبت للمعطوف «القصّةَ» ما نُفيَ عن المعطوف عليه؛ و«بل» للإضراب: تُبطل قراءة الرّواية وتُثبت قراءة القصّة. والوجهانِ صحيحانِ بعد النّفي، والفرق في الوظيفة (استدراك مقابل تصحيح).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5dfb9eb2-0757-5003-9eb5-4d358a5145a7', 'be6f538d-55be-52c8-8f05-489c6f241f10', '«يُثابُ المحسنُ فيُكرَمُ» — «يُكرَمُ» فعلٌ مضارعٌ معطوفٌ بالفاء على «يُثابُ». ما حكمه الإعرابيّ؟', '[{"id":"a","text":"مجزوم بالسّكون تبعًا للمعطوف عليه"},{"id":"b","text":"منصوب بالفتحة"},{"id":"c","text":"مرفوع بالضّمّة تبعًا للمعطوف عليه المرفوع"},{"id":"d","text":"مبنيّ لا محلّ له من الإعراب"}]'::jsonb, 'c', '«يُثابُ» فعل مضارع مرفوع بالضّمّة (لم يسبقه ناصبٌ ولا جازم)، و«يُكرَمُ» معطوف عليه بالفاء، فيتبعه في الرّفع؛ فهو مرفوع بالضّمّة. العطف يجري في الأفعال كما يجري في الأسماء: المعطوف يتبع المعطوف عليه في إعرابه.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ffb24358-35f0-5053-85e1-9af65d862bdf', 'be6f538d-55be-52c8-8f05-489c6f241f10', '«اشتريتُ الكتبَ والأقلامَ لا الدّفاترَ» — ما إعراب «الدّفاترَ» ودلالة «لا»؟', '[{"id":"a","text":"معطوف مرفوع، و«لا» ناهية"},{"id":"b","text":"معطوف مجرور، و«لا» للاستدراك"},{"id":"c","text":"مبتدأ مرفوع، و«لا» نافية للجنس"},{"id":"d","text":"معطوف منصوب بالفتحة تبعًا للمفعول به، و«لا» عاطفة تنفي الشّراء عن الدّفاتر"}]'::jsonb, 'd', '«الكتبَ» مفعول به منصوب، فالمعطوف «الدّفاترَ» منصوب بالفتحة تبعًا له؛ و«لا» العاطفة أثبتت الشّراء للكتب والأقلام ونفته عن الدّفاتر (اشتريتُ الأوّلَينِ دون الدّفاتر). القاعدة: المعطوف يتبع المعطوف عليه، والحكم هنا النّصب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('55dc7672-98df-5f99-950a-fa7d920a783b', '5befaad0-a866-568a-88db-413a1e0a520a', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: التحليل الشّامل لتراكيب العطف', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb25da50-0f1e-5c72-96cc-1fb37e6b04c8', '55dc7672-98df-5f99-950a-fa7d920a783b', '«ما فازَ في المسابقةِ التّلميذُ المتكاسلُ بل المجدُّ» — أعرِبْ «المجدُّ» إعرابًا كاملًا.', '[{"id":"a","text":"معطوف مرفوع بالضّمّة، لأنّه عُطف بـ«بل» على الفاعل «التّلميذُ» فتبعه في الرّفع"},{"id":"b","text":"معطوف منصوب بالفتحة تبعًا للمفعول به"},{"id":"c","text":"معطوف مجرور بالكسرة تبعًا لِما بعد حرف الجرّ"},{"id":"d","text":"نعت مرفوع للتّلميذ"}]'::jsonb, 'a', '«التّلميذُ» فاعل مرفوع بالضّمّة، و«بل» أضربت عن الفوز عنه وأثبتته للمعطوف «المجدُّ»، فهو معطوف يتبع المعطوف عليه في الرّفع، وعلامة رفعه الضّمّة. المعنى: لم يفزِ المتكاسلُ وإنّما فازَ المجدُّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0ea52806-b3df-54d4-af9a-2ff0c33c003d', '55dc7672-98df-5f99-950a-fa7d920a783b', '«سلّمتُ على الطّبيبِ الماهرِ والممرّضِ» — «الممرّضِ» عُطف على أيِّ كلمةٍ، وما إعرابه؟', '[{"id":"a","text":"عُطف على النّعت «الماهرِ» فهو معطوف مجرور، والمعنى: على الطّبيبِ الماهرِ والممرّضِ الماهرِ"},{"id":"b","text":"عُطف على «الطّبيبِ» فهو معطوف مجرور، والمعنى: سلّمتُ على الطّبيبِ وعلى الممرّضِ"},{"id":"c","text":"معطوف منصوب لأنّه مفعول به"},{"id":"d","text":"معطوف مرفوع لأنّه فاعل"}]'::jsonb, 'b', 'المعنى المستقيم أنّ «الممرّضِ» معطوف على الاسم المجرور «الطّبيبِ» لا على نعته، فالتّسليمُ وقع على شخصَينِ: الطّبيبِ والممرّضِ. وهو معطوف مجرور بالكسرة تبعًا للمعطوف عليه المجرور بـ«على». لو عُطف على النّعت لاقتضى أنّ الممرّضَ صفةٌ أخرى للطّبيب نفسه، وهو غير المقصود.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8fbb2910-3208-5e87-877c-634d5b96ffcf', '55dc7672-98df-5f99-950a-fa7d920a783b', '«أقبلَ الرّبيعُ فاخضرّتِ الحقولُ وتفتّحتِ الأزهارُ» — ما نوع المعطوفات، وما الرّابط بينها؟', '[{"id":"a","text":"عطفُ مفردٍ على مفرد بالواو فقط"},{"id":"b","text":"عطفُ جملٍ: الفاء عطفت جملة «اخضرّت» على «أقبل» (تعقيب)، والواو عطفت «تفتّحت» على «اخضرّت» (جمع)"},{"id":"c","text":"لا عطف فيها، كلّها جمل مستقلّة"},{"id":"d","text":"عطفٌ بحرفِ «ثمّ» يفيد التراخي"}]'::jsonb, 'b', 'العطف يقع على الجمل كما يقع على المفردات. الفاء عطفت جملة «اخضرّتِ الحقولُ» على جملة «أقبلَ الرّبيعُ» فأفادت التعقيب، والواو عطفت جملة «تفتّحتِ الأزهارُ» على ما قبلها فأفادت الجمع؛ فالجملُ المعطوفة لا محلّ لها من الإعراب لأنّها معطوفة على جملةٍ ابتدائيّةٍ لا محلّ لها.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('964f2388-7418-5444-9bd7-236db7835cf5', '55dc7672-98df-5f99-950a-fa7d920a783b', '«حضرَ القاضي والمحامونَ والشّهودُ» — إذا كان «القاضي» فاعلًا مرفوعًا، فما الحكم الإعرابيّ الجامع للمعطوفَينِ «المحامونَ» و«الشّهودُ»، وبأيِّ علامةٍ؟', '[{"id":"a","text":"كلاهما مرفوع؛ «المحامونَ» بالواو (جمع مذكّر سالم) و«الشّهودُ» بالضّمّة (جمع تكسير)"},{"id":"b","text":"كلاهما مرفوع بالضّمّة"},{"id":"c","text":"كلاهما منصوب لأنّهما معطوفان"},{"id":"d","text":"«المحامونَ» مرفوع و«الشّهودُ» مجرور"}]'::jsonb, 'a', 'المعطوف يتبع المعطوف عليه في الحكم (الرّفع)، وتبقى لكلّ اسمٍ علامتُه بحسب نوعه: «المحامونَ» جمع مذكّر سالم يُرفع بالواو، و«الشّهودُ» جمع تكسير يُرفع بالضّمّة. فالحكم واحد (الرّفع) والعلامات مختلفة، وهذا لا يخلّ بقاعدة التّبعيّة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8e4f98f6-5646-5bdc-946c-2493f883f055', '55dc7672-98df-5f99-950a-fa7d920a783b', '«لن يتأخّرَ المسافرُ ولن يضيعَ» — «يضيعَ» فعلٌ مضارعٌ معطوفٌ بالواو على «يتأخّرَ». ما إعرابه؟', '[{"id":"a","text":"مرفوع بالضّمّة"},{"id":"b","text":"مجزوم بالسّكون"},{"id":"c","text":"منصوب بالفتحة تبعًا للمعطوف عليه المنصوب بـ«لن»"},{"id":"d","text":"مبنيّ على الفتح"}]'::jsonb, 'c', '«لن» حرف نصبٍ، فـ«يتأخّرَ» مضارع منصوب بالفتحة، و«يضيعَ» معطوف عليه بالواو فيتبعه في النّصب؛ وعلامة نصبه الفتحة. تكرارُ «لن» قبل المعطوف مؤكِّدٌ للنّفي ولا يغيّر أنّ الحكم الجامع هو النّصب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf2207bd-b028-5e1e-ab57-4936820e5adc', '55dc7672-98df-5f99-950a-fa7d920a783b', '«ما ربحَ التّاجرُ ثمّ خسرَ» — هل تركيب الجملة سليمٌ من حيث المعنى مع «ثمّ»؟', '[{"id":"a","text":"لا؛ لأنّ «ثمّ» لا تُعطف بها الجمل بحالٍ"},{"id":"b","text":"لا؛ لأنّ «ثمّ» تفيد التعقيب الفوريّ فيتناقض مع المهلة"},{"id":"c","text":"نعم؛ لكنّ «ثمّ» هنا تفيد التخيير بين الرّبح والخسارة"},{"id":"d","text":"نعم؛ «ثمّ» تفيد ترتيبًا مع مهلة: انتفى الرّبح ثمّ وقعت الخسارة بعد فترة، وهو معنًى مستقيم"}]'::jsonb, 'd', '«ثمّ» تعطف الجمل والمفردات، وتفيد الترتيب مع التراخي؛ فالمعنى: لم يربحِ التّاجرُ، ثمّ وقعت الخسارةُ بعد مدّةٍ، وهو ترتيبٌ زمنيٌّ مستقيم. الخطأ الشّائع نسبةُ التعقيب الفوريّ إلى «ثمّ»، وإنّما التعقيبُ للفاء، والتّراخي لِـ«ثمّ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('52c57e29-03dc-5d85-9874-f69839714eb7', 'cd8c6f13-7567-5ccc-a03c-f87cd9e25033', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
