  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('77758398-7dd8-5bcd-9d8a-89ccc83a560e', '52c57e29-03dc-5d85-9874-f69839714eb7', 'أيّ الكلمات التّالية أداةُ نداءٍ؟', '[{"id":"a","text":"هلْ"},{"id":"b","text":"يا"},{"id":"c","text":"لنْ"},{"id":"d","text":"في"}]'::jsonb, 'b', '«يا» أداةُ نداءٍ تُستعمل للقريب والبعيد، أمّا «هل» فأداةُ استفهام، و«لن» حرفُ نصبٍ ونفي، و«في» حرفُ جرّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9e4c4e8-d15b-53d2-9834-9eaf6c6251ae', '52c57e29-03dc-5d85-9874-f69839714eb7', '«يا محمدُ، اجتهدْ» — ما نوعُ المنادى «محمدُ»؟', '[{"id":"a","text":"مضاف"},{"id":"b","text":"شبيهٌ بالمضاف"},{"id":"c","text":"مفردٌ علَم"},{"id":"d","text":"نكرةٌ غير مقصودة"}]'::jsonb, 'c', '«محمد» اسمُ علمٍ كلمةٌ واحدة ليس مضافًا ولا شبيهًا بالمضاف، فهو منادًى مفردٌ علَم.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d6b55c7-eeb1-52e6-a3b9-3da07e83133e', '52c57e29-03dc-5d85-9874-f69839714eb7', 'المنادى المفردُ العلَم «محمدُ» في «يا محمدُ» حكمُه أنّه:', '[{"id":"a","text":"مبنيٌّ على الضّمّ في محلّ نصب"},{"id":"b","text":"منصوبٌ علامتُه الفتحة"},{"id":"c","text":"مرفوعٌ علامتُه الضّمّة"},{"id":"d","text":"مجرورٌ علامتُه الكسرة"}]'::jsonb, 'a', 'المفردُ العلَم يُبنى على الضّمّ في محلّ نصب؛ فالضّمّةُ ظاهرةٌ لكنّ موقعَه نصبٌ لأنّه منادًى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ec093ebd-d38b-59b8-aa50-875a2e7ea9b5', '52c57e29-03dc-5d85-9874-f69839714eb7', '«يا عبدَ اللهِ, أحسِنْ» — ما حكمُ المنادى «عبدَ»؟', '[{"id":"a","text":"مبنيٌّ على الضّمّ"},{"id":"b","text":"منصوبٌ لأنّه مضاف"},{"id":"c","text":"مبنيٌّ على الفتح"},{"id":"d","text":"مرفوعٌ لأنّه منادًى"}]'::jsonb, 'b', '«عبدَ» مضافٌ و«اللهِ» مضافٌ إليه مجرور؛ والمنادى المضاف منصوبٌ علامتُه الفتحة، لا مبنيٌّ على الضّمّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e496d532-5690-5ec7-9d27-f9e723200573', '52c57e29-03dc-5d85-9874-f69839714eb7', 'قال الشّرطيُّ محذّرًا سائقًا بعينه: «يا سائقُ, تمهَّلْ» — نوعُ المنادى «سائقُ» هو:', '[{"id":"a","text":"نكرةٌ غير مقصودة"},{"id":"b","text":"مضاف"},{"id":"c","text":"شبيهٌ بالمضاف"},{"id":"d","text":"نكرةٌ مقصودة"}]'::jsonb, 'd', '«سائق» نكرةٌ قُصد بها سائقٌ معيَّنٌ حاضر، فهي نكرةٌ مقصودة تُبنى على الضّمّ في محلّ نصب، لا غيرُ المقصودة (المنصوبة).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('cece4065-01c9-5d80-858c-d4acfccfcdc5', 'cd8c6f13-7567-5ccc-a03c-f87cd9e25033', 'arabic-8eme', '⭐ تمرين: أوّلُ نداء', 1, 50, 10, 'practice', 'admin', 1)
