  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2e08c84c-ef99-5e7c-9bcb-56cc787e2908', 'cece4065-01c9-5d80-858c-d4acfccfcdc5', 'أيّ الأدوات التّالية تختصّ بنداء البعيد؟', '[{"id":"a","text":"أيا"},{"id":"b","text":"أيْ"},{"id":"c","text":"الهمزة (أ)"},{"id":"d","text":"يا"}]'::jsonb, 'a', '«أيا» (وكذلك «هيا») تختصّ بنداء البعيد؛ أمّا الهمزة و«أيْ» فللقريب، و«يا» تصلح للقريب والبعيد معًا فلا تختصّ بالبعيد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63b85702-fa78-52f5-b28f-ee40aaed91d7', 'cece4065-01c9-5d80-858c-d4acfccfcdc5', '«يا تلميذُ، انتبهْ إلى الدّرسِ» قالها المعلّمُ لتلميذٍ حاضرٍ بعينه — نوعُ المنادى «تلميذُ»:', '[{"id":"a","text":"مفردٌ علَم"},{"id":"b","text":"نكرةٌ مقصودة"},{"id":"c","text":"مضاف"},{"id":"d","text":"نكرةٌ غير مقصودة"}]'::jsonb, 'b', '«تلميذ» نكرةٌ قُصد بها تلميذٌ حاضرٌ معيَّن، فهي نكرةٌ مقصودة تُبنى على الضّمّ في محلّ نصب؛ وليست علمًا ولا مضافةً ولا غيرَ مقصودة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f8a643d-8263-5da3-835a-f52ab7c5812e', 'cece4065-01c9-5d80-858c-d4acfccfcdc5', '«يا طالبَ العلمِ، ثابِرْ» — نوعُ المنادى «طالبَ»:', '[{"id":"a","text":"مفردٌ علَم"},{"id":"b","text":"نكرةٌ مقصودة"},{"id":"c","text":"مضاف"},{"id":"d","text":"شبيهٌ بالمضاف"}]'::jsonb, 'c', '«طالبَ» أُضيف إلى «العلمِ» (مضافٌ إليه مجرور) فهو منادًى مضاف منصوب، وليس شبيهًا بالمضاف لأنّه بلا تنوينٍ ويليه اسمٌ مجرور مباشرةً.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('735dc28a-69d8-5e47-b121-c10b61b57efa', 'cece4065-01c9-5d80-858c-d4acfccfcdc5', 'المنادى المضاف مثل «عبدَ» في «يا عبدَ اللهِ» حكمُه أنّه:', '[{"id":"a","text":"مبنيٌّ على الضّمّ"},{"id":"b","text":"مرفوعٌ بالضّمّة"},{"id":"c","text":"مبنيٌّ على الفتح"},{"id":"d","text":"منصوبٌ علامتُه الفتحة"}]'::jsonb, 'd', 'المنادى المضاف منصوبٌ (مُعرَب) علامتُه الفتحة، لا مبنيّ؛ فالبناءُ على الضّمّ خاصٌّ بالمفرد العلَم والنكرة المقصودة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('86c6a537-cbc7-5d4e-963e-ef55d08cd965', 'cece4065-01c9-5d80-858c-d4acfccfcdc5', 'ما الضّبطُ الصّحيحُ لآخر المنادى في نداء البنتِ فاطمة؟', '[{"id":"a","text":"يا فاطمةُ"},{"id":"b","text":"يا فاطمةَ"},{"id":"c","text":"يا فاطمةِ"},{"id":"d","text":"يا فاطمةٍ"}]'::jsonb, 'a', '«فاطمة» مفردٌ علَم يُبنى على الضّمّ في محلّ نصب، فآخرُه مضمومٌ «فاطمةُ»؛ لا منصوبًا ولا مجرورًا ولا منوَّنًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1d376d0a-2029-54c8-8b7b-780ff99441a3', 'cece4065-01c9-5d80-858c-d4acfccfcdc5', '«ناديتُ مَن لا أعرفُه في الظّلامِ: يا رجلًا، دُلَّني على الطّريقِ» — نوعُ المنادى «رجلًا»:', '[{"id":"a","text":"نكرةٌ مقصودة"},{"id":"b","text":"نكرةٌ غير مقصودة"},{"id":"c","text":"مفردٌ علَم"},{"id":"d","text":"مضاف"}]'::jsonb, 'b', 'لم يُقصد رجلٌ معيَّن، فهي نكرةٌ غير مقصودة منصوبة، ودليلُ نصبها التّنوينُ بالفتح «رجلًا»؛ ولو قُصد حاضرٌ معيَّن لبُنيت على الضّمّ «يا رجلُ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('bee6da92-b108-573d-b97a-3158f538588d', 'cd8c6f13-7567-5ccc-a03c-f87cd9e25033', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: أنواعُ المنادى وأحكامُها', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
