  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9d228b97-976d-539d-b6e5-a656b6bebd71', 'bee6da92-b108-573d-b97a-3158f538588d', '«يا مجتهدونَ، واصِلوا الكفاحَ» قالها المدرّبُ لفريقٍ حاضرٍ — ما حكمُ المنادى «مجتهدونَ»؟', '[{"id":"a","text":"منادًى مرفوعٌ بالواو"},{"id":"b","text":"منادًى منصوبٌ بالياء"},{"id":"c","text":"منادًى مبنيٌّ على الألف في محلّ نصب"},{"id":"d","text":"منادًى مبنيٌّ على الواو في محلّ نصب"}]'::jsonb, 'd', '«مجتهدونَ» نكرةٌ مقصودةٌ (جمعُ مذكّرٍ سالم)، والمنادى المبنيّ يُبنى على ما يُرفع به؛ وجمعُ المذكّر السّالم يُرفع بالواو فيُبنى عليها في محلّ نصب، لا على الألف (خاصٌّ بالمثنّى) ولا يُنصب بالياء.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('351ee47d-77ef-5f00-890f-0bbc62957cd3', 'bee6da92-b108-573d-b97a-3158f538588d', '«يا بطلانِ، تقدّما إلى الميدانِ» — ما حكمُ المنادى «بطلانِ»؟', '[{"id":"a","text":"منادًى مبنيٌّ على الألف في محلّ نصب"},{"id":"b","text":"منادًى مبنيٌّ على الضّمّ في محلّ نصب"},{"id":"c","text":"منادًى منصوبٌ علامتُه الألف"},{"id":"d","text":"منادًى مرفوعٌ علامتُه الألف"}]'::jsonb, 'a', '«بطلانِ» مثنًّى، ويُبنى المنادى المثنّى على ما يُرفع به وهو الألف، في محلّ نصب؛ لا على الضّمّ (خاصٌّ بالمفرد) ولا هو مُعرَبٌ منصوبٌ لأنّه من النّوع المبنيّ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('732fbe96-eeaf-54eb-ae67-a829f2506899', 'bee6da92-b108-573d-b97a-3158f538588d', '«يا طالعًا جبلًا، احذَرِ الزّلقَ» — ما نوعُ المنادى «طالعًا»؟', '[{"id":"a","text":"مضاف"},{"id":"b","text":"نكرةٌ غير مقصودة"},{"id":"c","text":"شبيهٌ بالمضاف"},{"id":"d","text":"نكرةٌ مقصودة"}]'::jsonb, 'c', '«طالعًا» منوَّنٌ ويتبعه معمولٌ هو «جبلًا» (مفعولٌ به)، فهو شبيهٌ بالمضاف منصوب؛ ولو كان مضافًا لَحُذف تنوينُه وجاء بعده اسمٌ مجرور، ولو كان نكرةً غير مقصودةٍ لَما اتّصل به معمولٌ يُتمّم معناه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eab5689a-1315-56be-9061-215e1b93116a', 'bee6da92-b108-573d-b97a-3158f538588d', 'أيُّ العبارات ضُبط منادَاها المضافُ ضبطًا صحيحًا؟', '[{"id":"a","text":"يا صاحبُ الفضلِ"},{"id":"b","text":"يا صاحبَ الفضلِ"},{"id":"c","text":"يا صاحبٍ الفضلَ"},{"id":"d","text":"يا صاحبِ الفضلِ"}]'::jsonb, 'b', '«صاحبَ» مضافٌ و«الفضلِ» مضافٌ إليه مجرور؛ والمنادى المضاف منصوبٌ علامتُه الفتحة «صاحبَ»، لا مبنيٌّ على الضّمّ «صاحبُ» ولا مجرورٌ ولا منوَّن.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('32d8381b-3155-5ad1-9dcd-40b81120dcb0', 'bee6da92-b108-573d-b97a-3158f538588d', 'لاحظتَ أنّ آخرَ المنادى في «يا عاملُ، أتقِنْ» جاء مضمومًا بلا تنوين؛ فهذا يدلّ على أنّه:', '[{"id":"a","text":"نكرةٌ مقصودةٌ مبنيّةٌ على الضّمّ"},{"id":"b","text":"نكرةٌ غير مقصودةٍ منصوبة"},{"id":"c","text":"مضافٌ منصوبٌ بالفتحة"},{"id":"d","text":"مفردٌ علَمٌ منصوبٌ بالتّنوين"}]'::jsonb, 'a', 'ضمُّ آخرِه بلا تنوينٍ دليلُ البناء على الضّمّ، والنكرةُ المبنيّةُ على الضّمّ هي المقصودة؛ ولو كانت غيرَ مقصودةٍ لَنُصبت ونُوّنت «يا عاملًا»، ولو كانت مضافةً لَتبعها مضافٌ إليه مجرور.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bfd6187e-db97-5516-92e2-da36505d305a', 'bee6da92-b108-573d-b97a-3158f538588d', '«يا رسولَ اللهِ، هدِّئْ رَوعَنا» — ما إعرابُ «اللهِ»؟', '[{"id":"a","text":"منادًى منصوبٌ علامتُه الكسرة"},{"id":"b","text":"مضافٌ إليه مجرورٌ علامتُه الكسرة"},{"id":"c","text":"نعتٌ مجرور"},{"id":"d","text":"بدلٌ مرفوع"}]'::jsonb, 'b', '«رسولَ» منادًى مضاف منصوب، و«اللهِ» أُضيف إليه فهو مضافٌ إليه مجرورٌ علامتُه الكسرة؛ وليس منادًى (المنادى هو «رسولَ» وحدَه) ولا نعتًا ولا بدلًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3ec9a691-8c13-5e66-b881-2500b08c9e78', 'cd8c6f13-7567-5ccc-a03c-f87cd9e25033', 'arabic-8eme', '⭐⭐ تمرينُ مراجعةٍ: أدواتُ النداء وأحكامُ المنادى', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
