  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3d3f8253-eead-5e04-aa1b-a5fc6521b284', '3ec9a691-8c13-5e66-b881-2500b08c9e78', 'أيُّ أداةٍ تُستعمل للنُّدبة (نداءِ المتوجَّعِ عليه)؟', '[{"id":"a","text":"وا"},{"id":"b","text":"يا"},{"id":"c","text":"أيا"},{"id":"d","text":"الهمزة (أ)"}]'::jsonb, 'a', '«وا» أداةُ النُّدبة (وا حسرتاهُ)؛ أمّا «يا» فللقريب والبعيد، و«أيا» للبعيد، والهمزةُ للقريب، فلا يُندَب بشيءٍ منها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80441ef3-8ed1-52b3-8827-79cb29db1a24', '3ec9a691-8c13-5e66-b881-2500b08c9e78', 'بأيّ أداةٍ يُنادى لفظُ الجلالة «اللهُ»؟', '[{"id":"a","text":"أيا"},{"id":"b","text":"أيْ"},{"id":"c","text":"يا"},{"id":"d","text":"الهمزة (أ)"}]'::jsonb, 'c', 'لا يُنادى لفظُ الجلالة إلّا بـ «يا» (يا اللهُ)؛ فهي أعمُّ الأدوات وأصلُها، ولا تُستعمل معه «أيا» ولا الهمزةُ ولا «أيْ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('558b3cae-2ff1-52f9-8acd-f7cea702f329', '3ec9a691-8c13-5e66-b881-2500b08c9e78', '«يا حارسَ المرمى، انتبِهْ للكرةِ» — ما نوعُ المنادى «حارسَ»؟', '[{"id":"a","text":"نكرةٌ مقصودة"},{"id":"b","text":"مضاف"},{"id":"c","text":"شبيهٌ بالمضاف"},{"id":"d","text":"نكرةٌ غير مقصودة"}]'::jsonb, 'b', '«حارسَ» أُضيف إلى «المرمى» (مضافٌ إليه مجرور) بلا تنوين، فهو منادًى مضاف منصوب؛ وليس شبيهًا بالمضاف لأنّه غيرُ منوَّنٍ ويتبعه اسمٌ مجرورٌ لا معمول.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2af669a4-e93e-55f6-85a0-d09aa3812151', '3ec9a691-8c13-5e66-b881-2500b08c9e78', 'المنادى النكرةُ المقصودة مثل «شرطيُّ» في «يا شرطيُّ» حكمُه أنّه:', '[{"id":"a","text":"منصوبٌ علامتُه الفتحة"},{"id":"b","text":"مرفوعٌ علامتُه الضّمّة"},{"id":"c","text":"مبنيٌّ على الفتح في محلّ نصب"},{"id":"d","text":"مبنيٌّ على الضّمّ في محلّ نصب"}]'::jsonb, 'd', 'النكرةُ المقصودة تُبنى على الضّمّ في محلّ نصب مثلَ المفرد العلَم؛ فالضّمّةُ ظاهرةٌ لكنّ الموقعَ نصبٌ، وليست منصوبةً ظاهرًا (خاصٌّ بالمضاف وأخوَيه) ولا مرفوعة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0e627861-d624-588f-b951-33634a5ee899', '3ec9a691-8c13-5e66-b881-2500b08c9e78', 'أيُّ الأدوات التّالية تختصّ بنداء القريب؟', '[{"id":"a","text":"أيْ"},{"id":"b","text":"أيا"},{"id":"c","text":"هيا"},{"id":"d","text":"وا"}]'::jsonb, 'a', '«أيْ» (والهمزة) تختصّ بنداء القريب؛ أمّا «أيا» و«هيا» فللبعيد، و«وا» للنُّدبة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc158979-5db3-51d1-a89e-9553c6546b88', '3ec9a691-8c13-5e66-b881-2500b08c9e78', 'ناديتَ رجلًا لا تقصد شخصًا بعينه لتطلبَ عونًا؛ ما الضّبطُ الصّحيحُ للمنادى؟', '[{"id":"a","text":"يا سائلُ خُذْ"},{"id":"b","text":"يا سائلًا خُذْ"},{"id":"c","text":"يا سائلَ خُذْ"},{"id":"d","text":"يا سائلٍ خُذْ"}]'::jsonb, 'b', 'النكرةُ غير المقصودة منادًى منصوب، وعلامةُ نصب النكرةِ التّنوينُ بالفتح «سائلًا»؛ لا الضّمُّ «سائلُ» (خاصٌّ بالمقصودة) ولا الفتحةُ دون تنوينٍ ولا الكسرةُ مع تنوين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('5d999715-34aa-5d09-aff8-84d31055d42d', 'cd8c6f13-7567-5ccc-a03c-f87cd9e25033', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: تمييزُ الأنواع وضبطُ الإعراب', 4, 300, 60, 'challenge', 'admin', 4)
