INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4cb45baa-6325-5756-a59f-67844a9cafaa', '5d999715-34aa-5d09-aff8-84d31055d42d', '«يا عبادَ اللهِ، اتّقوا ربَّكم» — ما حكمُ المنادى «عبادَ»؟', '[{"id":"a","text":"مبنيٌّ على الضّمّ في محلّ نصب"},{"id":"b","text":"منادًى منصوبٌ علامتُه الفتحة وهو مضاف"},{"id":"c","text":"منادًى منصوبٌ علامتُه الكسرة"},{"id":"d","text":"مرفوعٌ علامتُه الضّمّة"}]'::jsonb, 'b', '«عبادَ» أُضيف إلى «اللهِ»، فهو منادًى مضاف منصوب علامتُه الفتحة؛ لا يُبنى على الضّمّ (البناءُ خاصٌّ بالمفرد العلَم والنكرة المقصودة)، وعلامةُ نصبِه الفتحةُ لا الكسرة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc13cc03-c5e3-5ddb-a11b-85b337595aa5', '5d999715-34aa-5d09-aff8-84d31055d42d', 'أعرب تلميذٌ «يا مُحسنَ الخُلُقِ» فقال: «مُحسنَ: منادًى مبنيٌّ على الضّمّ». أين وجهُ الصّواب؟', '[{"id":"a","text":"الصّوابُ أنّه منادًى منصوبٌ لأنّه مضاف"},{"id":"b","text":"لا خطأ؛ هو مبنيٌّ على الضّمّ لأنّه مفرد"},{"id":"c","text":"الصّوابُ أنّه مرفوعٌ لأنّه منادًى"},{"id":"d","text":"الصّوابُ أنّه مبنيٌّ على الفتح"}]'::jsonb, 'a', 'هذا خطأٌ مقصودٌ في التّمرين: «مُحسنَ» أُضيف إلى «الخُلُقِ» فهو منادًى مضاف منصوبٌ علامتُه الفتحة، لا مبنيٌّ على الضّمّ؛ فالبناءُ على الضّمّ خاصٌّ بالمفرد العلَم والنكرة المقصودة فقط.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('093362e8-ec4f-5168-bacb-05b96b444a3f', '5d999715-34aa-5d09-aff8-84d31055d42d', 'أيُّ العبارات التّالية عن المنادى خاطئةٌ؟', '[{"id":"a","text":"المفردُ العلَم يُبنى على الضّمّ في محلّ نصب"},{"id":"b","text":"المضافُ منادًى منصوب"},{"id":"c","text":"النكرةُ غير المقصودة تُبنى على الضّمّ"},{"id":"d","text":"الشبيهُ بالمضاف منادًى منصوب"}]'::jsonb, 'c', 'النكرةُ غير المقصودة تُنصب (يا رجلًا)، ولا تُبنى؛ فالبناءُ على الضّمّ خاصٌّ بالمفرد العلَم والنكرة المقصودة. أمّا بقيّةُ العبارات فصحيحة: المفردُ العلَم مبنيٌّ على الضّمّ، والمضافُ والشبيهُ بالمضاف منصوبان.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('deb57425-60eb-54a4-9342-a1f983d76c3a', '5d999715-34aa-5d09-aff8-84d31055d42d', 'أيُّ العبارات الآتية منادَاها شبيهٌ بالمضاف؟', '[{"id":"a","text":"يا كريمًا خُلُقُه"},{"id":"b","text":"يا كريمَ الخُلُقِ"},{"id":"c","text":"يا كريمُ، أقبِلْ"},{"id":"d","text":"يا كريمَ الأخلاقِ"}]'::jsonb, 'a', '«كريمًا خُلُقُه» منوَّنٌ ويتبعه فاعلٌ هو «خُلُقُه»، فهو شبيهٌ بالمضاف منصوب؛ أمّا «كريمَ الخُلُقِ» و«كريمَ الأخلاقِ» فمضافان (بلا تنوينٍ يتبعهما مضافٌ إليه مجرور)، و«كريمُ» وحدَه مفردٌ علَمٌ مبنيٌّ على الضّمّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d55d37d-aefb-554e-9394-ea747ca818aa', '5d999715-34aa-5d09-aff8-84d31055d42d', 'منادًى جاء آخرُه منصوبًا منوَّنًا بالفتح «يا ظالمًا»، ولم يتّصل به مضافٌ إليه ولا معمول؛ فهو:', '[{"id":"a","text":"نكرةٌ مقصودة"},{"id":"b","text":"مضاف"},{"id":"c","text":"شبيهٌ بالمضاف"},{"id":"d","text":"نكرةٌ غير مقصودة"}]'::jsonb, 'd', 'التّنوينُ بالفتح دليلُ النّصب، وانتفاءُ المضاف إليه يمنع كونَه مضافًا، وانتفاءُ المعمول يمنع كونَه شبيهًا بالمضاف؛ فلم يبقَ إلّا النكرةُ غير المقصودة. ولو قُصد شخصٌ حاضرٌ بعينه لَبُني على الضّمّ «يا ظالمُ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a86932d-5a1a-5493-96a5-6fff2c406b75', '5d999715-34aa-5d09-aff8-84d31055d42d', 'المنادى في أصله مفعولٌ به لفعلٍ محذوفٍ؛ فما تقديرُ هذا الفعل المحذوف؟', '[{"id":"a","text":"أتعجّبُ"},{"id":"b","text":"أدعو (أنادي)"},{"id":"c","text":"أستفهمُ"},{"id":"d","text":"أؤكّدُ"}]'::jsonb, 'b', 'أصلُ «يا محمدُ» هو «أدعو محمدًا» أو «أنادي محمدًا»، فالمنادى مفعولٌ به لفعلٍ محذوفٍ تقديرُه «أدعو/أنادي»؛ ولهذا كان أصلُ المنادى النّصب. وليس التّقديرُ أتعجّبُ ولا أستفهمُ ولا أؤكّدُ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('03d2ec87-0d45-55e6-8cf6-726d12419030', 'cd8c6f13-7567-5ccc-a03c-f87cd9e25033', 'arabic-8eme', '📝 تدريب ⭐⭐⭐: مراجعةٌ شاملةٌ في المنادى', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
