  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e1cf5b57-dc9a-5b11-9546-b7c2dee2cbc6', '03d2ec87-0d45-55e6-8cf6-726d12419030', '«يا مصرُ، انهضي بأبنائِك» — ما نوعُ المنادى «مصرُ»؟', '[{"id":"a","text":"مفردٌ علَم"},{"id":"b","text":"نكرةٌ مقصودة"},{"id":"c","text":"مضاف"},{"id":"d","text":"شبيهٌ بالمضاف"}]'::jsonb, 'a', '«مصر» اسمُ علمٍ (بلد) كلمةٌ واحدة ليست مضافةً ولا شبيهةً بالمضاف، فهي منادًى مفردٌ علَمٌ مبنيٌّ على الضّمّ في محلّ نصب.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('674f64b4-ea78-5b64-9d90-ac273a4f7c5d', '03d2ec87-0d45-55e6-8cf6-726d12419030', '«يا سيّدةَ النّساءِ، سلامٌ عليكِ» — ما حكمُ المنادى «سيّدةَ»؟', '[{"id":"a","text":"مبنيٌّ على الضّمّ في محلّ نصب"},{"id":"b","text":"مرفوعٌ علامتُه الضّمّة"},{"id":"c","text":"منادًى منصوبٌ علامتُه الفتحة وهو مضاف"},{"id":"d","text":"مبنيٌّ على الفتح في محلّ نصب"}]'::jsonb, 'c', '«سيّدةَ» أُضيف إلى «النّساءِ» (مضافٌ إليه مجرور)، فهو منادًى مضاف منصوب علامتُه الفتحة؛ لا يُبنى على الضّمّ لأنّه ليس مفردًا علَمًا ولا نكرةً مقصودة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7059fce5-be34-5ec8-9ada-ac5b8edea79d', '03d2ec87-0d45-55e6-8cf6-726d12419030', '«يا رفيقًا بالضّعفاءِ، دُمْ على خيرِك» — ما نوعُ المنادى «رفيقًا»؟', '[{"id":"a","text":"نكرةٌ غير مقصودة"},{"id":"b","text":"مضاف"},{"id":"c","text":"شبيهٌ بالمضاف"},{"id":"d","text":"نكرةٌ مقصودة"}]'::jsonb, 'c', '«رفيقًا» منوَّنٌ ويتبعه جارٌّ ومجرورٌ «بالضّعفاءِ» متعلّقٌ به يُتمّم معناه، فهو شبيهٌ بالمضاف منصوب؛ ومنعَه التّنوينُ من أن يكون مضافًا، ومنعَه اتّصالُ المعمول من أن يكون نكرةً غير مقصودةٍ خالصة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a943e2d-7080-58dd-a56f-6323ac48579a', '03d2ec87-0d45-55e6-8cf6-726d12419030', 'أيُّ الجُمل ضُبط منادَاها ضبطًا صحيحًا؟', '[{"id":"a","text":"يا حاملُ الرّايةِ"},{"id":"b","text":"يا مسافرونِ"},{"id":"c","text":"يا رجالِ"},{"id":"d","text":"يا حاملَ الرّايةِ"}]'::jsonb, 'd', '«حاملَ الرّايةِ» منادًى مضاف منصوب علامتُه الفتحة «حاملَ»؛ أمّا «حاملُ» بالضّمّ فخطأٌ (لأنّه مضاف لا مفرد علَم)، و«مسافرونِ» بالكسر و«رجالِ» بالكسر خطآن في ضبط المنادى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b9dce1f-16c0-51d2-95dd-ec0208975e4a', '03d2ec87-0d45-55e6-8cf6-726d12419030', 'نادى الطّبيبُ في قاعةِ الانتظارِ مريضًا أشار إليه بعينه: «يا مريضُ، تفضّلْ» — ما نوعُ المنادى «مريضُ»؟', '[{"id":"a","text":"نكرةٌ مقصودة"},{"id":"b","text":"نكرةٌ غير مقصودة"},{"id":"c","text":"مفردٌ علَم"},{"id":"d","text":"مضاف"}]'::jsonb, 'a', '«مريض» نكرةٌ قُصد بها مريضٌ حاضرٌ معيَّنٌ أُشير إليه، فهي نكرةٌ مقصودة تُبنى على الضّمّ في محلّ نصب؛ ولو لم يُقصد أحدٌ بعينه لَنُصبت ونُوّنت «يا مريضًا».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('65acf0aa-af46-5206-acb4-584b64da7634', '03d2ec87-0d45-55e6-8cf6-726d12419030', '«يا أهلَ الكرمِ، أكرِمونا» — ما الإعرابُ الصّحيحُ التّامّ للمنادى وما بعدَه؟', '[{"id":"a","text":"«أهلَ» مبنيٌّ على الضّمّ، و«الكرمِ» مضافٌ إليه"},{"id":"b","text":"«أهلَ» منادًى منصوبٌ مضاف، و«الكرمِ» مضافٌ إليه مجرور"},{"id":"c","text":"«أهلَ» منادًى منصوب، و«الكرمِ» نعتٌ مجرور"},{"id":"d","text":"«أهلَ» مرفوع، و«الكرمِ» مضافٌ إليه"}]'::jsonb, 'b', '«أهلَ» منادًى مضاف منصوبٌ علامتُه الفتحة، و«الكرمِ» مضافٌ إليه مجرورٌ علامتُه الكسرة؛ فلا يُبنى «أهلَ» على الضّمّ (لأنّه مضاف) ولا يُرفع، و«الكرمِ» مضافٌ إليه لا نعت.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('ca32e7c6-6a25-51d0-afa2-0f8bc2eeaa15', 'cd8c6f13-7567-5ccc-a03c-f87cd9e25033', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: دقائقُ المنادى والإعرابُ المتقدّم', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('af65da54-092b-5673-87fa-9f2e634224d1', 'ca32e7c6-6a25-51d0-afa2-0f8bc2eeaa15', '«يا مُحبِّي الخيرِ، ثابِروا» — أصلُ «مُحبِّي» هو «مُحبّونَ»، فلماذا حُذفت نونُه؟', '[{"id":"a","text":"لأنّه شبيهٌ بالمضاف"},{"id":"b","text":"لأنّه مضافٌ إلى «الخيرِ»"},{"id":"c","text":"لأنّه نكرةٌ غير مقصودة"},{"id":"d","text":"لأنّه مبنيٌّ على الواو"}]'::jsonb, 'b', '«مُحبِّي» أصلُها «مُحبّونَ» جمعُ مذكّرٍ سالم، أُضيفت إلى «الخيرِ» فحُذفت نونُها للإضافة، وصارت منادًى مضاف منصوبًا بالياء؛ فالحذفُ سببُه الإضافة، لا الشّبهُ بالمضاف ولا البناء.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('443c4080-4d4a-552b-9935-236acc1f12a0', 'ca32e7c6-6a25-51d0-afa2-0f8bc2eeaa15', 'أيُّ العبارات التّالية صحيحةٌ عن أحكام المنادى؟', '[{"id":"a","text":"المضافُ يبقى منوَّنًا"},{"id":"b","text":"المفردُ العلَم يُنصب بالفتحة"},{"id":"c","text":"النكرةُ المقصودة تُنصب بالفتحة"},{"id":"d","text":"الشبيهُ بالمضاف يبقى منوَّنًا"}]'::jsonb, 'd', 'الشبيهُ بالمضاف يبقى منوَّنًا ويتبعه معمولُه (يا طالعًا جبلًا)؛ أمّا المضافُ فيُحذف تنوينُه، والمفردُ العلَم والنكرةُ المقصودة يُبنيان على الضّمّ لا يُنصبان بالفتحة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d46d17b0-8413-540a-82dc-1e6008790c16', 'ca32e7c6-6a25-51d0-afa2-0f8bc2eeaa15', 'أعرب تلميذٌ «يا ساعيًا في الخيرِ» فقال: «ساعيًا: منادًى منصوب لأنّه مضاف». ما وجهُ الخطأ؟', '[{"id":"a","text":"الحكمُ بالنّصب خطأٌ؛ الصّوابُ البناءُ على الضّمّ"},{"id":"b","text":"لا خطأ؛ هو مضافٌ فعلًا"},{"id":"c","text":"هو شبيهٌ بالمضاف لا مضاف؛ فالنّصبُ صحيحٌ لكنّ تسميتَه مضافًا خطأ"},{"id":"d","text":"هو نكرةٌ مقصودةٌ مبنيّةٌ على الضّمّ"}]'::jsonb, 'c', '«ساعيًا» منوَّنٌ ويتبعه جارٌّ ومجرورٌ «في الخيرِ» معمولٌ له، فهو شبيهٌ بالمضاف؛ فحكمُ النّصب صحيحٌ لكنّ تسميتَه «مضافًا» خطأ، إذ المضافُ لا يُنوَّن ويتبعه مضافٌ إليه مجرورٌ لا معمول.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1189de64-db71-5326-8c00-68ee0a38461b', 'ca32e7c6-6a25-51d0-afa2-0f8bc2eeaa15', '«يا طالبَ العلمِ، ويا مُتقنًا عملَه» — أيُّ وصفٍ يجمع المنادَيَين «طالبَ» و«مُتقنًا» جمعًا صحيحًا؟', '[{"id":"a","text":"كلاهما مبنيٌّ على الضّمّ"},{"id":"b","text":"كلاهما منادًى منصوبٌ علامتُه الفتحة"},{"id":"c","text":"الأوّلُ منصوبٌ والثّاني مبنيٌّ على الضّمّ"},{"id":"d","text":"الأوّلُ مبنيٌّ والثّاني منصوب"}]'::jsonb, 'b', '«طالبَ» مضاف منصوب (يتبعه «العلمِ» مضافًا إليه)، و«مُتقنًا» شبيهٌ بالمضاف منصوب (منوَّنٌ يتبعه «عملَه» مفعولًا به)؛ فكلاهما منادًى منصوبٌ علامتُه الفتحة، ولا بناءَ في أيٍّ منهما.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5720902-7ad7-55fb-913d-df8712049d30', 'ca32e7c6-6a25-51d0-afa2-0f8bc2eeaa15', 'منادًى بُني على الواو في محلّ نصب؛ فهو حتمًا:', '[{"id":"a","text":"مثنًّى"},{"id":"b","text":"مضافٌ جمعِ مذكّرٍ سالم"},{"id":"c","text":"جمعُ مذكّرٍ سالمٍ مقصودٌ أو علَم"},{"id":"d","text":"مفردٌ علَمٌ واحد"}]'::jsonb, 'c', 'البناءُ على الواو يكون لجمع المذكّر السّالم المنادى نكرةً مقصودةً أو علمًا (يا مؤمنونَ)؛ أمّا المثنّى فيُبنى على الألف، والمضافُ جمعِ المذكّر يُنصب بالياء وتُحذف نونُه، والمفردُ العلَم الواحد يُبنى على الضّمّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f5235103-e2eb-56e5-9e7f-f93a565dddc6', 'ca32e7c6-6a25-51d0-afa2-0f8bc2eeaa15', '«يا حاميَ الدّيارِ، ثبِّتْ خُطانا» — ما الإعرابُ الصّحيحُ لـ «حاميَ»؟', '[{"id":"a","text":"منادًى منصوبٌ علامتُه الفتحة الظّاهرة وهو مضاف"},{"id":"b","text":"منادًى مبنيٌّ على الضّمّ المقدّر"},{"id":"c","text":"شبيهٌ بالمضاف منصوبٌ بالتّنوين"},{"id":"d","text":"منادًى مرفوعٌ بالضّمّة المقدّرة"}]'::jsonb, 'a', '«حامي» اسمٌ منقوصٌ أُضيف إلى «الدّيارِ»، فهو منادًى مضاف منصوبٌ تظهر فتحتُه على الياء «حاميَ»، و«الدّيارِ» مضافٌ إليه مجرور؛ فليس مبنيًّا ولا شبيهًا بالمضاف (لا تنوينَ فيه) ولا مرفوعًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('5c8ff424-6f8c-5964-9c1e-3d94b2c84214', '2feeb938-4ca1-5a03-955f-ef08c97ff4bd', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
