INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5296ea28-dcf7-51cf-85e2-a97e122cb395', '5c8ff424-6f8c-5964-9c1e-3d94b2c84214', 'العددان «واحد» و«اثنان» في علاقتهما بالمعدود:', '[{"id":"a","text":"يطابقانه في التّذكير والتّأنيث"},{"id":"b","text":"يخالفانه في التّذكير والتّأنيث"},{"id":"c","text":"يبقيان ثابتين لا يتغيّران"},{"id":"d","text":"لا علاقة لصورتهما بالمعدود"}]'::jsonb, 'a', 'العددان 1 و2 يطابقان المعدود: كتابٌ واحدٌ، مجلّةٌ واحدةٌ، كتابانِ اثنانِ، مجلّتانِ اثنتانِ. أمّا المخالفة فحكم الأعداد 3-10.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('56e2869c-199f-5405-8293-0a89b96fa3b8', '5c8ff424-6f8c-5964-9c1e-3d94b2c84214', 'الأعداد من «ثلاثة» إلى «عشرة» تعامل معدودها بقاعدة:', '[{"id":"a","text":"المطابقة"},{"id":"b","text":"المخالفة"},{"id":"c","text":"الثّبات"},{"id":"d","text":"لا قاعدة ثابتة لها"}]'::jsonb, 'b', 'الأعداد 3-10 تخالف المعدود: مع المذكّر تلحقها التاء (ثلاثة كتب)، ومع المؤنّث تُحذف (ثلاث مجلّات).', 2)
