INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd009906-e055-507f-9aef-b35ec44d8813', '5c8ff424-6f8c-5964-9c1e-3d94b2c84214', 'على أيّ شيء نقيس تذكير العدد وتأنيثه؟', '[{"id":"a","text":"على صيغة جمع المعدود"},{"id":"b","text":"على مفرد المعدود"},{"id":"c","text":"على العدد نفسه دون المعدود"},{"id":"d","text":"على موقع العدد في الجملة"}]'::jsonb, 'b', 'الحكم يُقاس على مفرد المعدود؛ ففي «ثلاثة رجال» ننظر إلى «رجل» (مذكّر) لا إلى «رجال»، فنؤنّث العدد: ثلاثة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('861099a0-2a46-5f42-8709-1fcfc657aa12', '5c8ff424-6f8c-5964-9c1e-3d94b2c84214', 'تمييز العدد من «ثلاثة» إلى «عشرة» يكون:', '[{"id":"a","text":"مفردًا منصوبًا"},{"id":"b","text":"مفردًا مجرورًا"},{"id":"c","text":"جمعًا مجرورًا"},{"id":"d","text":"جمعًا منصوبًا"}]'::jsonb, 'c', 'تمييز 3-10 جمعٌ مجرور (مضاف إليه): ثلاثةُ كتبٍ، عشرُ مجلّاتٍ. أمّا المفرد المنصوب فتمييز 11-99، والمفرد المجرور فتمييز المئة والألف.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('43891eab-770d-5e35-bb2a-2c8829867c46', '5c8ff424-6f8c-5964-9c1e-3d94b2c84214', '«عشرونَ طالبًا» و«عشرونَ طالبةً» — ماذا نستنتج من ثبات لفظ «عشرون»؟', '[{"id":"a","text":"ألفاظ العقود ثابتة لا تخالف ولا تطابق"},{"id":"b","text":"ألفاظ العقود تخالف المعدود دائمًا"},{"id":"c","text":"ألفاظ العقود تطابق المعدود دائمًا"},{"id":"d","text":"لفظ «عشرون» خطأ والصّواب «عشرة»"}]'::jsonb, 'a', 'ألفاظ العقود (عشرون، ثلاثون…) تلزم صورة واحدة مع المذكّر والمؤنّث، فلا تلحقها تاءٌ ولا تُحذف؛ فهي ثابتة كالمئة والألف.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

