INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('605ed858-c2ca-562a-bd5a-f026293283e2', '0878366a-3c6b-5c95-b667-808fd0fdbfa7', 'أيّ صورة صحيحة للعدد مع المعدود المذكّر «كتب»؟', '[{"id":"a","text":"ثلاثُ كتبٍ"},{"id":"b","text":"ثلاثةُ كتبٍ"},{"id":"c","text":"ثلاثونُ كتبٍ"},{"id":"d","text":"ثلاثانِ كتبٍ"}]'::jsonb, 'b', 'مفرد المعدود «كتاب» مذكّر، والعدد 3-10 يخالف، فتلحقه التاء: ثلاثةُ كتبٍ. أمّا «ثلاث» فتكون مع المؤنّث.', 1)
