INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a02a5c14-b94f-5c89-acfb-60668325fc73', '0878366a-3c6b-5c95-b667-808fd0fdbfa7', 'أيّ صورة صحيحة للعدد مع المعدود المؤنّث «مجلّات»؟', '[{"id":"a","text":"خمسةُ مجلّاتٍ"},{"id":"b","text":"خمسونُ مجلّاتٍ"},{"id":"c","text":"خمسُ مجلّاتٍ"},{"id":"d","text":"خمستانِ مجلّاتٍ"}]'::jsonb, 'c', 'مفرد المعدود «مجلّة» مؤنّث، والعدد 3-10 يخالف، فتُحذف التاء: خمسُ مجلّاتٍ. أمّا «خمسة» فتكون مع المذكّر.', 2)
