INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1cdd88be-9eb6-5e40-9804-05895f0ca7f7', '0878366a-3c6b-5c95-b667-808fd0fdbfa7', 'أكمل: «في الخزانة كتابٌ ____» (المعدود مذكّر مفرد).', '[{"id":"a","text":"واحدةٌ"},{"id":"b","text":"واحدٌ"},{"id":"c","text":"أحدَ عشرَ"},{"id":"d","text":"عشرةٌ"}]'::jsonb, 'b', 'العدد 1 يطابق المعدود؛ و«كتاب» مذكّر فيقال «كتابٌ واحدٌ»، ويأتي العدد بعد المعدود كالنّعت.', 3)
