INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('52d159d1-f32a-5170-8d18-a5e113d6d372', '0878366a-3c6b-5c95-b667-808fd0fdbfa7', 'أكمل: «قرأتُ مجلّتينِ ____» (المعدود مؤنّث مثنّى).', '[{"id":"a","text":"اثنانِ"},{"id":"b","text":"اثنتانِ"},{"id":"c","text":"اثنتينِ"},{"id":"d","text":"ثنتانِ"}]'::jsonb, 'c', 'العدد 2 يطابق المعدود؛ و«مجلّتينِ» مؤنّث منصوب، فيقال «مجلّتينِ اثنتينِ» (توكيد منصوب بالياء تبعًا للمعدود).', 4)
