INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a420f74-43b5-59f4-b0cf-1e869423e62e', '0878366a-3c6b-5c95-b667-808fd0fdbfa7', 'ما تمييز العدد في «اشترى الفلّاحُ سبعةَ أبقارٍ»؟ وما نوعه؟', '[{"id":"a","text":"«أبقارٍ» تمييز جمع مجرور"},{"id":"b","text":"«أبقارٍ» تمييز مفرد منصوب"},{"id":"c","text":"«سبعةَ» تمييز مفرد مجرور"},{"id":"d","text":"لا تمييز في الجملة"}]'::jsonb, 'a', 'العدد «سبعة» من 3-10، فتمييزه جمعٌ مجرور: «أبقارٍ» جمعٌ مجرور مضاف إليه. والمفرد المنصوب تمييز 11-99 لا 3-10.', 5)
ON CONFLICT (id) DO UPDATE SET
