  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d76264fe-17b4-5f71-b25b-0dcf0f0d2fe4', '0878366a-3c6b-5c95-b667-808fd0fdbfa7', 'أيّ جملة طبّقت قاعدة المخالفة تطبيقًا صحيحًا؟', '[{"id":"a","text":"في الأسبوع سبعُ أيّامٍ"},{"id":"b","text":"في الأسبوع سبعةُ أيّامٍ"},{"id":"c","text":"في الأسبوع سبعونُ أيّامٍ"},{"id":"d","text":"في الأسبوع سبعُ يومٍ"}]'::jsonb, 'b', 'مفرد «أيّام» هو «يوم» مذكّر، فالعدد 3-10 يخالفه بالتاء: سبعةُ أيّامٍ. أمّا «سبع» فتُستعمل مع المؤنّث، والتمييز جمعٌ مجرور لا مفرد.', 6)
