INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fa92255-0b83-5150-b542-c201041d61e5', 'c8a96028-9ec1-50fb-85d1-beceff84ae4c', '«في الحقيبة ____ أقلامٍ» — املأ الفراغ بالعدد الصحيح لـ «تسعة/تسع» (المعدود «أقلام» مذكّر).', '[{"id":"a","text":"تسعُ"},{"id":"b","text":"تسعةُ"},{"id":"c","text":"تسعونَ"},{"id":"d","text":"تسعةَ عشرَ"}]'::jsonb, 'b', 'مفرد «أقلام» هو «قلم» مذكّر، والعدد 3-10 يخالف بالتاء: تسعةُ أقلامٍ. أمّا «تسع» فمع المؤنّث، و«تسعون» عقدٌ تمييزه مفرد منصوب.', 1)
ON CONFLICT (id) DO UPDATE SET
