  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('579a9f80-e663-5af7-9f97-8b1b011fcfd2', 'c8a96028-9ec1-50fb-85d1-beceff84ae4c', 'أيّ جملة أخطأت في نوع التمييز؟', '[{"id":"a","text":"قرأتُ ثمانيَ قصصٍ"},{"id":"b","text":"قرأتُ خمسةَ عشرَ قصّةً"},{"id":"c","text":"قرأتُ مئةَ قصّةٍ"},{"id":"d","text":"قرأتُ خمسَ عشرةَ قصصٍ"}]'::jsonb, 'd', 'تمييز 11-99 مفردٌ منصوب لا جمعٌ مجرور؛ فالصّواب «خمسَ عشرةَ قصّةً». والجمل الأخرى صحيحة: جمع مجرور مع 3-10، ومنصوب مع المركّب، ومجرور مع المئة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
