  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ec6360d2-102e-535f-8ff3-45181da64937', 'c8a96028-9ec1-50fb-85d1-beceff84ae4c', '«زرعَ الفلّاحُ ____ نخلةً» — أيّ عدد مركّب يصحّ مع المعدود المؤنّث «نخلة»؟', '[{"id":"a","text":"ثلاثةَ عشرَ"},{"id":"b","text":"ثلاثَ عشرةَ"},{"id":"c","text":"ثلاثةَ عشرةَ"},{"id":"d","text":"ثلاثونُ"}]'::jsonb, 'b', '«نخلة» مؤنّث؛ في المركّب 13-19 يخالف الجزء الأوّل ويطابق الثاني: فالأوّل بلا تاء (ثلاث) والثاني بالتاء (عشرة): ثلاثَ عشرةَ نخلةً.', 3)
ON CONFLICT (id) DO UPDATE SET
