  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b4008a8d-cd15-5cdc-805f-726378400fa9', 'c8a96028-9ec1-50fb-85d1-beceff84ae4c', '«حضرَ إلى الملعب ____ لاعبًا» — أيّ عدد مركّب يصحّ مع المعدود المذكّر «لاعب»؟', '[{"id":"a","text":"أربعَ عشرةَ"},{"id":"b","text":"أربعةَ عشرةَ"},{"id":"c","text":"أربعةَ عشرَ"},{"id":"d","text":"أربعُ عشرَ"}]'::jsonb, 'c', '«لاعب» مذكّر؛ الجزء الأوّل يخالف فيلحقه التاء (أربعة)، والجزء الثاني يطابق فيتجرّد من التاء (عشرَ): أربعةَ عشرَ لاعبًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
