  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('95287432-378d-5730-8b62-85d6a0dc562d', 'c8a96028-9ec1-50fb-85d1-beceff84ae4c', '«في السّنة اثنا عشرَ شهرًا» — ما إعراب «شهرًا» وما نوعه بوصفه تمييزًا؟', '[{"id":"a","text":"تمييز مفرد منصوب"},{"id":"b","text":"تمييز جمع مجرور"},{"id":"c","text":"تمييز مفرد مجرور"},{"id":"d","text":"مضاف إليه مجرور"}]'::jsonb, 'a', '«شهرًا» تمييزٌ للعدد المركّب 12 (من 11-99)، فهو مفردٌ منصوب. ولا يكون جمعًا مجرورًا إلّا مع 3-10، ولا مجرورًا إلّا مع المئة والألف.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b3e2f33-3b6f-5731-a275-0e99bf7bf7af', 'c8a96028-9ec1-50fb-85d1-beceff84ae4c', 'أيّ جملة سليمة تمامًا من حيث صورة العدد وتمييزه معًا؟', '[{"id":"a","text":"في المدرسة ثلاثُ معلّمينَ وعشرُ معلّماتٍ"},{"id":"b","text":"في المدرسة ثلاثةُ معلّمينَ وعشرُ معلّماتٍ"},{"id":"c","text":"في المدرسة ثلاثةُ معلّماتٍ وعشرةُ معلّمينَ"},{"id":"d","text":"في المدرسة ثلاثُ معلّمًا وعشرةُ معلّمةً"}]'::jsonb, 'b', '«معلّمون» مذكّر فالعدد بالتاء (ثلاثة)، و«معلّمات» مؤنّث فالعدد بلا تاء (عشر)، والتمييزان جمعان مجروران. الخيارات الأخرى عكست المخالفة أو أخطأت في التمييز.', 6)
