INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6dc85aae-74b6-5096-bc5e-f06479824236', '6ac0c9a9-1cee-5c91-9d42-e8892b0d5c7d', 'أيّ صورة صحيحة مع المعدود المؤنّث «ساعات»؟', '[{"id":"a","text":"ستّةُ ساعاتٍ"},{"id":"b","text":"ستُّ ساعاتٍ"},{"id":"c","text":"ستّونُ ساعاتٍ"},{"id":"d","text":"ستّتانِ ساعاتٍ"}]'::jsonb, 'b', 'مفرد «ساعات» هو «ساعة» مؤنّث، والعدد 3-10 يخالفه بحذف التاء: ستُّ ساعاتٍ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
