INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9abbe423-cbfb-5aff-a91a-c3a8f73ae329', '6ac0c9a9-1cee-5c91-9d42-e8892b0d5c7d', 'أيّ جملة صحيحة في تمييز المئة؟', '[{"id":"a","text":"في المكتبة مئةُ كتبٍ"},{"id":"b","text":"في المكتبة مئةُ كتابًا"},{"id":"c","text":"في المكتبة مئةُ كتابٍ"},{"id":"d","text":"في المكتبة مئةٌ كتابٍ"}]'::jsonb, 'c', 'تمييز المئة مفردٌ مجرور: مئةُ كتابٍ. فليس جمعًا (كتبٍ) كتمييز 3-10، ولا منصوبًا (كتابًا) كتمييز 11-99.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3be82cb8-175f-57d2-a680-d0821807f367', '6ac0c9a9-1cee-5c91-9d42-e8892b0d5c7d', '«جاء ثلاثونَ ضيفًا» ثمّ «جاءت ثلاثونَ ضيفةً» — لماذا لم يتغيّر لفظ «ثلاثون»؟', '[{"id":"a","text":"لأنّه من ألفاظ العقود الثّابتة"},{"id":"b","text":"لأنّه يخالف المعدود دائمًا"},{"id":"c","text":"لأنّه يطابق المعدود دائمًا"},{"id":"d","text":"لأنّ التمييز جمعٌ مجرور"}]'::jsonb, 'a', '«ثلاثون» من ألفاظ العقود، وهي تلزم صورةً واحدة مع المذكّر والمؤنّث، فلا تخالف ولا تطابق، وتمييزها مفردٌ منصوب.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6bc0af0-4bbc-5b25-a9ab-39ec94076c78', '6ac0c9a9-1cee-5c91-9d42-e8892b0d5c7d', 'صحّح: «في يدي خمسُ أصابعَ» (مفرد المعدود «إصبع» مؤنّثة في الفصحى).', '[{"id":"a","text":"الجملة صحيحة: خمسُ أصابعَ"},{"id":"b","text":"الصّواب: خمسةُ أصابعَ"},{"id":"c","text":"الصّواب: خمسونَ أصابعَ"},{"id":"d","text":"الصّواب: خمسُ إصبعٍ"}]'::jsonb, 'a', '«إصبع» مؤنّثة، والعدد 3-10 يخالف المؤنّث بحذف التاء: خمسُ أصابعَ. فالجملة صحيحة، و«خمسة» تكون مع المذكّر.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24df253b-f2ca-5e18-8e24-3c92f21ae12d', '6ac0c9a9-1cee-5c91-9d42-e8892b0d5c7d', 'أيّ صورة صحيحة تمامًا مع المعدود المذكّر «كوكبًا» في العدد المركّب؟', '[{"id":"a","text":"إحدى عشرةَ كوكبًا"},{"id":"b","text":"أحدَ عشرَ كوكبًا"},{"id":"c","text":"أحدَ عشرةَ كوكبًا"},{"id":"d","text":"إحدى عشرَ كوكبًا"}]'::jsonb, 'b', 'في العدد 11 يطابق الجزآن المعدود؛ و«كوكب» مذكّر فيقال «أحدَ عشرَ كوكبًا» بلا تاء في الجزأين، وتمييزه مفردٌ منصوب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('c2d91025-6415-572e-bd03-3079c24f83c1', '2feeb938-4ca1-5a03-955f-ef08c97ff4bd', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: العدد المركّب والمعطوف وإعرابه', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
