  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e190c79b-bf64-56b4-9bfd-730e6f527667', 'c2d91025-6415-572e-bd03-3079c24f83c1', '«سافرَ التّاجرُ اثني عشرَ يومًا» — ما إعراب الجزء الأوّل «اثني»؟', '[{"id":"a","text":"مبنيّ على الفتح لا محلّ له"},{"id":"b","text":"منصوب بالياء؛ يُعرب إعراب المثنّى"},{"id":"c","text":"مرفوع بالواو؛ إعراب جمع المذكّر السالم"},{"id":"d","text":"مجرور بالكسرة الظاهرة"}]'::jsonb, 'b', 'العدد 12 وحده يُعرب جزؤه الأوّل إعراب المثنّى (بالألف رفعًا؛ بالياء نصبًا وجرًّا)، فـ«اثني» هنا منصوب بالياء لأنّه ظرف زمان، والجزء الثاني «عشرَ» مبنيّ على الفتح. أمّا سائر الأعداد المركّبة (11؛ 13-19) فمبنيّة الجزأين.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dd2ec0d9-7e38-50cb-9843-f42777f125a7', 'c2d91025-6415-572e-bd03-3079c24f83c1', '«جمعَ الطّفلُ ستّةً وسبعينَ عنقودًا» — ما نوع تمييز العدد «عنقودًا»؟', '[{"id":"a","text":"جمع مجرور"},{"id":"b","text":"مفرد مجرور"},{"id":"c","text":"مفرد منصوب"},{"id":"d","text":"جمع منصوب"}]'::jsonb, 'c', 'العدد المعطوف (21-99) تمييزه مفردٌ منصوب كتمييز 11-99؛ فـ«عنقودًا» مفردٌ منصوب. ولا يكون التمييز جمعًا مجرورًا إلّا مع 3-10، ولا مفردًا مجرورًا إلّا مع المئة والألف.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f17eb5f1-8351-53da-8944-aebea849f1be', 'c2d91025-6415-572e-bd03-3079c24f83c1', 'أيّ جملةٍ سليمةٌ تمامًا في صورة العدد وتمييزه؟', '[{"id":"a","text":"في الحديقة ثلاثُ أشجارٍ وستُّ ورودٍ"},{"id":"b","text":"في الحديقة ثلاثةُ أشجارٍ وستُّ ورودٍ"},{"id":"c","text":"في الحديقة ثلاثُ أشجارٍ وستّةُ ورودٍ"},{"id":"d","text":"في الحديقة ثلاثونُ أشجارٍ وستُّ ورودٍ"}]'::jsonb, 'a', '«شجرة» و«وردة» مؤنّثان، والعدد 3-10 يخالف المؤنّث بحذف التاء: ثلاثُ أشجارٍ؛ ستُّ ورودٍ، وتمييزهما جمعٌ مجرور. أمّا (ب) و(ج) فألحقا التاء بالعدد مع المؤنّث، و(د) شوّه العقد وتمييزه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('04bf4dc7-8f53-5606-91b5-230220e4c1ac', 'c2d91025-6415-572e-bd03-3079c24f83c1', '«فازَ أحدَ عشرَ متسابقًا» ثمّ «كافأتُ أحدَ عشرَ متسابقًا» — لماذا لم تتغيّر صورة العدد بين الجملتين؟', '[{"id":"a","text":"لأنّه يُعرب إعراب جمع المذكّر السالم"},{"id":"b","text":"لأنّه من ألفاظ العقود الثّابتة"},{"id":"c","text":"لأنّه يُعرب إعراب المثنّى"},{"id":"d","text":"لأنّ العدد المركّب (عدا 12) مبنيٌّ على فتح الجزأين في محلّ رفعٍ أو نصب"}]'::jsonb, 'd', 'الأعداد المركّبة 11 و13-19 مبنيّةٌ على فتح الجزأين، فلا تتغيّر صورتها بتغيّر الموقع (فاعل في الأولى، مفعول به في الثانية)؛ يتغيّر محلّها الإعرابيّ لا صورتها. والعقود وحدها تُعرب إعراب جمع المذكّر السالم، والعدد 12 وحده جزؤه الأوّل كالمثنّى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07183540-d65b-5fc4-9a83-3a180cc8cf88', 'c2d91025-6415-572e-bd03-3079c24f83c1', '«في المستشفى ____ أطبّاءٍ» — أيّ صورةٍ صحيحة للعدد؟ (انتبه: مفرد «أطبّاء» هو «طبيب»)', '[{"id":"a","text":"تسعُ أطبّاءٍ"},{"id":"b","text":"تسعةُ أطبّاءٍ"},{"id":"c","text":"تسعةَ عشرَ طبيبًا"},{"id":"d","text":"تسعونُ أطبّاءٍ"}]'::jsonb, 'b', 'الحكم يُقاس على مفرد المعدود لا على صيغة جمعه؛ ومفرد «أطبّاء» هو «طبيب» مذكّر، فالعدد 3-10 يخالف بالتاء: تسعةُ أطبّاءٍ، وتمييزه جمعٌ مجرور. الخطأ الشائع أن يُنظر إلى صورة الجمع فيُحذف التاء.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3b173707-45cb-5262-80ee-16d8ef092fb4', 'c2d91025-6415-572e-bd03-3079c24f83c1', 'الكتاب في 300 صفحةٍ — أيّ صورةٍ صحيحةٌ للعدد مع معدوده؟', '[{"id":"a","text":"ثلاثُمئةِ صفحةٍ"},{"id":"b","text":"ثلاثةُمئةِ صفحةٍ"},{"id":"c","text":"ثلاثُمئةِ صفحاتٍ"},{"id":"d","text":"ثلاثُمئةَ صفحةً"}]'::jsonb, 'a', '«مئة» مؤنّثة، والعدد 3-10 يخالفها بحذف التاء: «ثلاث مئة»، وتمييز المئة مفردٌ مجرور: «صفحةٍ»؛ فالصّواب «ثلاثُمئةِ صفحةٍ». و«ثلاثة» خطأٌ لأنّ مئة مؤنّثة، والجمع «صفحاتٍ» والنصب «صفحةً» خطأٌ في تمييز المئة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

