  ('0385c299-55fb-5411-978c-9c37ed27e210', '2feeb938-4ca1-5a03-955f-ef08c97ff4bd', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: أحكام الأعداد وإعرابها', 3, 120, 30, 'boss', 'admin', 5)
