INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('68d36095-66d2-5cbb-8731-26a9c66b1df5', '0385c299-55fb-5411-978c-9c37ed27e210', 'أيّ جملة صحيحة في تمييز الألف؟', '[{"id":"a","text":"ألفُ دنانيرَ"},{"id":"b","text":"ألفٌ دينارٍ"},{"id":"c","text":"ألفُ دينارٍ"},{"id":"d","text":"ألفُ دينارًا"}]'::jsonb, 'c', 'تمييز الألف مفردٌ مجرور: ألفُ دينارٍ. فلا يُجمع (دنانير) كتمييز 3-10، ولا يُنصب (دينارًا) كتمييز 11-99.', 1)
