INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a32d579-6236-5c3a-87fa-c131c681659e', '0385c299-55fb-5411-978c-9c37ed27e210', '«اشتركَ في السّباق ____ متسابقةً» — أيّ صورة صحيحة للعقد المعطوف مع «متسابقة» المؤنّث؟', '[{"id":"a","text":"خمسةٌ وعشرونَ"},{"id":"b","text":"خمسٌ وعشرونَ"},{"id":"c","text":"خمسٌ وعشرونةَ"},{"id":"d","text":"خمسةٌ وعشرينَ"}]'::jsonb, 'b', 'في العدد المعطوف (21-99) يعامَل الجزء المفرد بقاعدته والعقدُ ثابت. «متسابقة» مؤنّث فالمفرد يخالف بحذف التاء: خمسٌ وعشرونَ، وتمييزه مفرد منصوب.', 2)
ON CONFLICT (id) DO UPDATE SET
