  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8152aa9e-8d52-58b0-a883-be7c5d8fc890', '0385c299-55fb-5411-978c-9c37ed27e210', '«جاء عشرونَ طالبًا» — ما علامة رفع «عشرون» وما نوع إعرابها؟', '[{"id":"a","text":"مرفوعة بالواو، إعراب جمع المذكّر السالم"},{"id":"b","text":"مرفوعة بالضمّة الظاهرة"},{"id":"c","text":"مبنيّة على الفتح في محلّ رفع"},{"id":"d","text":"مرفوعة بالألف، إعراب المثنّى"}]'::jsonb, 'a', 'ألفاظ العقود تُعرب إعراب جمع المذكّر السالم: بالواو رفعًا وبالياء نصبًا وجرًّا؛ فـ«عشرون» فاعل مرفوع بالواو.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('06930402-ba7c-553d-87ab-f73136ee2cfd', '0385c299-55fb-5411-978c-9c37ed27e210', '«رأيتُ ____ كوكبًا» — أيّ صورة صحيحة للعقد في محلّ نصب مع المعدود المذكّر؟', '[{"id":"a","text":"عشرونَ"},{"id":"b","text":"عشرينَ"},{"id":"c","text":"عشرةَ"},{"id":"d","text":"عشراتٍ"}]'::jsonb, 'b', '«عشرين» مفعول به منصوب؛ والعقود تُنصب بالياء (إعراب جمع المذكّر السالم): رأيتُ عشرينَ كوكبًا، والتمييز مفرد منصوب «كوكبًا».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
