INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('79a5d229-2457-5704-b0ab-28ff72ac8d13', '0385c299-55fb-5411-978c-9c37ed27e210', '«في المتحف ____ لوحةً و____ تمثالًا» — أيّ ملء يجمع الحكمين بصواب (لوحة مؤنّث، تمثال مذكّر)؟', '[{"id":"a","text":"ثلاثةَ عشرَ … ثلاثَ عشرةَ"},{"id":"b","text":"ثلاثَ عشرةَ … ثلاثَ عشرةَ"},{"id":"c","text":"ثلاثَ عشرةَ … ثلاثةَ عشرَ"},{"id":"d","text":"ثلاثةَ عشرةَ … ثلاثةَ عشرَ"}]'::jsonb, 'c', '«لوحة» مؤنّث: الأوّل يخالف بلا تاء والثاني يطابق بالتاء → ثلاثَ عشرةَ. «تمثال» مذكّر: الأوّل بالتاء والثاني بلا تاء → ثلاثةَ عشرَ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fde4e7d7-90e7-5a83-9a7a-44ce88c09aa6', '0385c299-55fb-5411-978c-9c37ed27e210', 'أيّ جملة أخطأت في حكم العدد المفرد ضمن العقد المعطوف؟', '[{"id":"a","text":"في الصّفّ واحدٌ وثلاثونَ تلميذًا"},{"id":"b","text":"في الصّفّ إحدى وثلاثونَ تلميذةً"},{"id":"c","text":"في الصّفّ واحدةٌ وثلاثونَ تلميذةً"},{"id":"d","text":"في الصّفّ واحدةٌ وثلاثونَ تلميذًا"}]'::jsonb, 'd', 'المفرد في العقد المعطوف يطابق معدوده كالعددين 1 و2؛ و«تلميذًا» مذكّر فالصّواب «واحدٌ وثلاثونَ». الخيار (د) أنّث المفرد مع مذكّر، والخياران (أ) و(ب) صحيحان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a7e4f8f2-430e-564c-90dd-b3e1f21c4dcf', '2feeb938-4ca1-5a03-955f-ef08c97ff4bd', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: قممُ العدد (الآلاف والمعطوف والإعراب)', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1227fcb7-de7b-5538-a100-f8473fba0a3c', 'a7e4f8f2-430e-564c-90dd-b3e1f21c4dcf', '«تبرّعَ المحسنُ بـ ____ دينارٍ» (المبلغ 3000) — أيّ صورةٍ صحيحة؟', '[{"id":"a","text":"ثلاثِ آلافِ دينارٍ"},{"id":"b","text":"ثلاثةِ آلافِ دينارٍ"},{"id":"c","text":"ثلاثةِ آلافِ دنانيرَ"},{"id":"d","text":"ثلاثةِ ألفٍ دينارًا"}]'::jsonb, 'b', '«آلاف» جمع «ألف»، و«ألف» مذكّر، فالعدد 3-10 يخالف بالتاء: «ثلاثة». و«آلاف» تمييز العدد 3 (جمع مجرور)، و«دينار» تمييز الألف (مفرد مجرور)؛ فالصّواب «ثلاثةِ آلافِ دينارٍ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1248ec0b-a32e-59a0-a11d-500edbab3afb', 'a7e4f8f2-430e-564c-90dd-b3e1f21c4dcf', '«حفظَ الطّالبُ مئتي بيتٍ من الشّعر» — ما صورة العدد ونوع تمييزه؟', '[{"id":"a","text":"«مئتي» جمعٌ، والتمييز «بيتٍ» جمع مجرور"},{"id":"b","text":"«مئتي» عقدٌ، والتمييز «بيتٍ» مفرد منصوب"},{"id":"c","text":"الصّواب «مئتانِ أبياتٍ»"},{"id":"d","text":"«مئتي» مثنّى مئة، والتمييز «بيتٍ» مفرد مجرور"}]'::jsonb, 'd', '«مئتان/مئتين» مثنّى «مئة» يُعرب إعراب المثنّى (بالألف رفعًا؛ بالياء نصبًا وجرًّا)، وهنا «مئتي» منصوبٌ بالياء لأنّه مفعول به مضاف؛ وتمييزه كتمييز المئة: مفردٌ مجرور «بيتٍ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('078be9e7-798a-59a8-851c-3736e4a218ac', 'a7e4f8f2-430e-564c-90dd-b3e1f21c4dcf', '«الحاضرونَ خمسةٌ وعشرونَ رجلًا» — ما إعراب «خمسةٌ» و«عشرونَ»؟', '[{"id":"a","text":"كلاهما مبنيٌّ على الفتح في محلّ رفع"},{"id":"b","text":"«خمسةٌ» مبتدأ، و«عشرونَ» تمييز منصوب"},{"id":"c","text":"«خمسةٌ» خبر مرفوع بالضمّة، و«عشرونَ» معطوفٌ مرفوعٌ بالواو"},{"id":"d","text":"«خمسةٌ» خبر منصوب، و«عشرونَ» مجرور بالياء"}]'::jsonb, 'c', 'العدد المعطوف جزآن: «خمسةٌ» خبرٌ مرفوع بالضمّة، و«عشرونَ» معطوفٌ عليه مرفوعٌ بالواو (إعراب جمع المذكّر السالم)؛ والتمييز «رجلًا» مفردٌ منصوب. و«رجل» مذكّر فالمفرد بالتاء: خمسة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5cce9930-36a8-5c14-89e6-f5d58c7505e3', 'a7e4f8f2-430e-564c-90dd-b3e1f21c4dcf', '«عندي تسعُ مجلّاتٍ» و«عندي تسعَ عشرةَ مجلّةً» — كيف اختلف نوع التمييز مع أنّ المعدود واحد؟', '[{"id":"a","text":"الأولى تمييزها جمع مجرور، والثانية مفرد منصوب"},{"id":"b","text":"كلتاهما تمييزها جمع مجرور"},{"id":"c","text":"الأولى مفرد منصوب، والثانية جمع مجرور"},{"id":"d","text":"كلتاهما مفرد منصوب"}]'::jsonb, 'a', 'تمييز 3-10 جمعٌ مجرور: «مجلّاتٍ»، وتمييز 11-99 (ومنه 19) مفردٌ منصوب: «مجلّةً». فانتقال العدد من 9 إلى 19 قلبَ التمييز من الجمع المجرور إلى المفرد المنصوب، مع بقاء المخالفة في الجزء المفرد (تسع بلا تاء مع المؤنّث).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ca3ac58f-416e-5d06-898e-b6024d5e25bf', 'a7e4f8f2-430e-564c-90dd-b3e1f21c4dcf', '«في القطيع ____ نعجةً» (المعدود 99) — أيّ صورةٍ صحيحة للعدد مع المؤنّث «نعجة»؟', '[{"id":"a","text":"تسعةٌ وتسعونَ نعجةً"},{"id":"b","text":"تسعٌ وتسعونَ نعجةً"},{"id":"c","text":"تسعٌ وتسعونَ نعاجٍ"},{"id":"d","text":"تسعونَ وتسعٌ نعجةً"}]'::jsonb, 'b', '«نعجة» مؤنّث، والمفرد في العقد المعطوف يخالف كالعدد المستقلّ فيُحذف منه التاء: «تسعٌ»، والعقد «تسعون» ثابت، والتمييز مفردٌ منصوب «نعجةً»؛ فالصّواب «تسعٌ وتسعونَ نعجةً». و(ج) أخطأ في تمييز العقد بجمعه، و(د) قلبَ ترتيب المعطوف.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80393247-157e-5b39-91c1-041705509c7d', 'a7e4f8f2-430e-564c-90dd-b3e1f21c4dcf', 'أيّ جملةٍ خاليةٌ من كلّ خطأ في العدد والتمييز؟', '[{"id":"a","text":"قطعَ الرّاكبُ مئةَ كيلومتراتٍ وثلاثينَ كيلومترًا"},{"id":"b","text":"قطعَ الرّاكبُ مئةً كيلومترًا وثلاثينَ كيلومترًا"},{"id":"c","text":"قطعَ الرّاكبُ مئةَ كيلومترٍ وثلاثينَ كيلومترًا"},{"id":"d","text":"قطعَ الرّاكبُ مئةَ كيلومترٍ وثلاثينَ كيلومترٍ"}]'::jsonb, 'c', 'تمييز المئة مفردٌ مجرور «كيلومترٍ»، وتمييز العقد (ثلاثين) مفردٌ منصوب «كيلومترًا»؛ فالجملة (ج) طبّقت الحكمين معًا. أمّا (أ) فجمعَ تمييز المئة، و(ب) نصبَ تمييز المئة، و(د) جرَّ تمييز العقد خطأً.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9f67f6cd-6635-5a12-b561-edb81f20116e', '5ead9433-8508-5a25-9926-bfce53cd5d8f', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
