  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('428838fa-ee5d-578b-82cf-56cbb127d5f0', '9f67f6cd-6635-5a12-b561-edb81f20116e', 'عَلامَ يدلّ أسلوبُ التعجّب؟', '[{"id":"a","text":"على انفعالِ النفسِ عند استعظامِ أمرٍ إعجابًا واستحسانًا"},{"id":"b","text":"على طلبِ الفعلِ من المخاطَبِ"},{"id":"c","text":"على الاستفهامِ عن مكانِ الشيءِ"},{"id":"d","text":"على نفيِ الحدثِ عن الفاعلِ"}]'::jsonb, 'a', 'التعجّبُ أسلوبٌ نُظهِرُ به انفعالَ النفسِ حين تستعظمُ أمرًا ندَرَ نظيرُه أو خفيَ سببُه، إعجابًا أو استحسانًا؛ لا طلبًا ولا استفهامًا ولا نفيًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf225690-a412-5a97-a095-7848b70f3285', '9f67f6cd-6635-5a12-b561-edb81f20116e', 'ما صيغتا التعجّبِ القياسيّ؟', '[{"id":"a","text":"نِعمَ وبئسَ"},{"id":"b","text":"ما أفعلَه! وأفعِلْ بـه!"},{"id":"c","text":"أفعَل التفضيلِ ومِفعال"},{"id":"d","text":"يا وأيا للنداءِ"}]'::jsonb, 'b', 'للتعجّبِ القياسيِّ صيغتانِ لا ثالثَ لهما: «ما أفعلَه» (ما أروعَ البحرَ!) و«أفعِلْ بـه» (أروِعْ بالبحرِ!). أمّا «نِعمَ وبئسَ» فأسلوبُ مدحٍ وذمٍّ، و«أفعَل» صيغةُ تفضيلٍ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('160f5f45-d590-5ef2-bb84-11f454a76aa4', '9f67f6cd-6635-5a12-b561-edb81f20116e', 'في جملةِ «ما أجملَ البحرَ!» ما إعرابُ «ما»؟', '[{"id":"a","text":"حرفُ تعجّبٍ لا محلَّ له"},{"id":"b","text":"اسمُ استفهامٍ"},{"id":"c","text":"اسمٌ نكرةٌ تامّةٌ في محلِّ رفعٍ مبتدأٌ"},{"id":"d","text":"اسمٌ موصولٌ في محلِّ نصبٍ"}]'::jsonb, 'c', '«ما» التعجبيّةُ اسمٌ نكرةٌ تامّةٌ بمعنى «شيءٌ عظيمٌ»، مبنيٌّ في محلِّ رفعٍ مبتدأٌ. الخطأُ الشائعُ عدُّها حرفًا أو اسمَ استفهامٍ؛ وهي هنا ليست استفهاميّةً ولا موصولةً.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('39b98e15-23f0-5bc6-a473-14f96a9bcdf3', '9f67f6cd-6635-5a12-b561-edb81f20116e', 'أيُّ الجملِ الآتيةِ تعجّبٌ سماعيٌّ (خارجٌ عن الصيغتين القياسيّتين)؟', '[{"id":"a","text":"ما أنبلَ الطبيبَ!"},{"id":"b","text":"أنبِلْ بالطبيبِ!"},{"id":"c","text":"سبحانَ اللهِ! ما أعظمَ خلقَه!"},{"id":"d","text":"ما أصدقَ الصديقَ!"}]'::jsonb, 'c', '«سبحانَ اللهِ!» تعجّبٌ سماعيٌّ يُفهَمُ من السياقِ ولا يجري على صيغةٍ مقيسٍ عليها. أمّا الباقي فقياسيٌّ: «ما أنبلَ» و«ما أصدقَ» على صيغةِ (ما أفعلَه)، و«أنبِلْ بـ» على صيغةِ (أفعِلْ بـه).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('45951391-5851-5e3a-ab0a-57ef5e6c5e14', '9f67f6cd-6635-5a12-b561-edb81f20116e', 'في «أكرِمْ بالعلمِ!» ما إعرابُ «العلمِ»؟', '[{"id":"a","text":"اسمٌ مجرورٌ بالباءِ لا غيرُ"},{"id":"b","text":"مفعولٌ به منصوبٌ"},{"id":"c","text":"فاعلٌ مرفوعٌ محلًّا، مجرورٌ لفظًا بالباءِ الزائدةِ"},{"id":"d","text":"مبتدأٌ مرفوعٌ"}]'::jsonb, 'c', 'الباءُ في هذه الصيغةِ حرفُ جرٍّ زائدٌ، والاسمُ بعدَها «العلمِ» فاعلٌ لـ«أكرِمْ» مرفوعٌ في المحلِّ، مجرورٌ في اللفظِ. الخطأُ الشائعُ الاكتفاءُ بأنّه «مجرورٌ»، أو عدُّه مفعولًا به.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('169d480e-24ce-5d67-af28-1d70e9102e83', '5ead9433-8508-5a25-9926-bfce53cd5d8f', 'arabic-8eme', '⭐ تمرين: أوّلُ خطوةٍ في التعجّب', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ded34317-94b6-57d1-a793-16e6ad58f0fc', '169d480e-24ce-5d67-af28-1d70e9102e83', 'أيُّ الجملِ الآتيةِ على صيغةِ التعجّبِ «ما أفعلَه»؟', '[{"id":"a","text":"ما أروعَ الشاطئَ!"},{"id":"b","text":"أروِعْ بالشاطئِ!"},{"id":"c","text":"الشاطئُ رائعٌ."},{"id":"d","text":"هل الشاطئُ رائعٌ؟"}]'::jsonb, 'a', '«ما أروعَ الشاطئَ!» تبدأُ بـ«ما» يليها فعلٌ على وزنِ «أفعَلَ» ثمّ اسمٌ منصوبٌ، فهي على صيغةِ «ما أفعلَه». أمّا «أروِعْ بالشاطئِ!» فعلى الصيغةِ الثانيةِ، والباقي خبرٌ واستفهامٌ لا تعجّبَ فيهما.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4a1f6400-5f31-57a7-9024-ef3b646316a5', '169d480e-24ce-5d67-af28-1d70e9102e83', 'أيُّ الجملِ الآتيةِ على صيغةِ التعجّبِ «أفعِلْ بـه»؟', '[{"id":"a","text":"ما أكرمَ الصديقَ!"},{"id":"b","text":"أكرِمْ بالصديقِ!"},{"id":"c","text":"الصديقُ كريمٌ."},{"id":"d","text":"أكرَمَ الصديقُ ضيفَه."}]'::jsonb, 'b', '«أكرِمْ بالصديقِ!» فعلٌ على صورةِ الأمرِ تليه الباءُ فاسمٌ مجرورٌ، فهي على صيغةِ «أفعِلْ بـه». أمّا «ما أكرمَ الصديقَ!» فعلى الصيغةِ الأولى، و«أكرَمَ الصديقُ ضيفَه» فعلٌ ماضٍ عاديٌّ لا تعجّبَ فيه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('069ec959-9dea-5eb3-ad7c-b9d92c8ee19a', '169d480e-24ce-5d67-af28-1d70e9102e83', 'كم صيغةً قياسيّةً للتعجّب؟', '[{"id":"a","text":"صيغةٌ واحدةٌ"},{"id":"b","text":"صيغتانِ اثنتانِ"},{"id":"c","text":"ثلاثُ صيغٍ"},{"id":"d","text":"لا صيغةَ ثابتةً له"}]'::jsonb, 'b', 'للتعجّبِ القياسيِّ صيغتانِ لا ثالثَ لهما: «ما أفعلَه» و«أفعِلْ بـه». وما خرجَ عنهما فهو تعجّبٌ سماعيٌّ لا قياسيٌّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4a730687-1ceb-547f-ac3c-a6fb1ef15885', '169d480e-24ce-5d67-af28-1d70e9102e83', '«ما أطيبَ رائحةَ الياسمينِ!» — ما نوعُ هذا التعجّب؟', '[{"id":"a","text":"تعجّبٌ قياسيٌّ"},{"id":"b","text":"تعجّبٌ سماعيٌّ"},{"id":"c","text":"أسلوبُ مدحٍ"},{"id":"d","text":"أسلوبُ نداءٍ"}]'::jsonb, 'a', 'الجملةُ على صيغةِ «ما أفعلَه» (ما أطيبَ ...!)، وهي إحدى الصيغتين القياسيّتين، فالتعجّبُ فيها قياسيٌّ لا سماعيٌّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e74aab17-ec75-5570-be39-3f7750399e12', '169d480e-24ce-5d67-af28-1d70e9102e83', 'أيُّ الأفعالِ الآتيةِ يصلحُ لصوغِ التعجّبِ منه مباشرةً (لأنّه ثلاثيٌّ تامٌّ)؟', '[{"id":"a","text":"استخرجَ"},{"id":"b","text":"كَرُمَ"},{"id":"c","text":"كانَ"},{"id":"d","text":"احمرَّ"}]'::jsonb, 'b', '«كَرُمَ» فعلٌ ثلاثيٌّ تامٌّ مستوفٍ للشروطِ، فنقولُ: ما أكرمَه! أمّا «استخرجَ» فزائدٌ على ثلاثةٍ، و«كانَ» ناقصٌ، و«احمرَّ» وصفُه على «أفعلَ فعلاءَ»؛ فلا يُتعجّبُ منها مباشرةً.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9b54d61-0a07-5769-b683-c2ef9702d4fc', '169d480e-24ce-5d67-af28-1d70e9102e83', '«سبحانَ اللهِ!» — ما نوعُ هذا التعجّب؟', '[{"id":"a","text":"تعجّبٌ قياسيٌّ على صيغةِ (ما أفعلَه)"},{"id":"b","text":"تعجّبٌ قياسيٌّ على صيغةِ (أفعِلْ بـه)"},{"id":"c","text":"تعجّبٌ سماعيٌّ"},{"id":"d","text":"ليس تعجّبًا"}]'::jsonb, 'c', '«سبحانَ اللهِ!» تعجّبٌ سماعيٌّ خرجَ عن الصيغتين القياسيّتين، يُفهَمُ من السياقِ ونبرةِ الكلامِ، ولا يُقاسُ عليه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('90dc9aa4-4a47-54b0-964d-bd3a61f7a542', '5ead9433-8508-5a25-9926-bfce53cd5d8f', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: أسرارُ الإعراب والشروط', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dbcc1bd3-10b7-56f5-a411-a74dec73182f', '90dc9aa4-4a47-54b0-964d-bd3a61f7a542', 'في «أكرِمْ بالمعلّمِ!» ما إعرابُ الباءِ؟', '[{"id":"a","text":"حرفُ جرٍّ أصليٌّ متعلّقٌ بالفعلِ"},{"id":"b","text":"حرفُ جرٍّ زائدٌ"},{"id":"c","text":"حرفُ عطفٍ"},{"id":"d","text":"حرفُ قسمٍ"}]'::jsonb, 'b', 'الباءُ في صيغةِ «أفعِلْ بـه» حرفُ جرٍّ زائدٌ، دخلتْ على الفاعلِ فجرّتْه لفظًا وهو مرفوعٌ محلًّا. وليست أصليّةً ولا عطفًا ولا قسمًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dd03d697-e03a-5374-b601-22ead0e0e059', '90dc9aa4-4a47-54b0-964d-bd3a61f7a542', 'في «أكرِمْ بالمعلّمِ!» ما إعرابُ «المعلّمِ»؟', '[{"id":"a","text":"مفعولٌ به منصوبٌ"},{"id":"b","text":"اسمٌ مجرورٌ بالباءِ فحسبُ"},{"id":"c","text":"فاعلٌ مرفوعٌ محلًّا، مجرورٌ لفظًا بالباءِ الزائدةِ"},{"id":"d","text":"بدلٌ مجرورٌ"}]'::jsonb, 'c', '«المعلّمِ» فاعلُ الفعلِ «أكرِمْ»، مرفوعٌ في المحلِّ، مجرورٌ في اللفظِ بالباءِ الزائدةِ. الخطأُ الشائعُ الاكتفاءُ بأنّه «مجرورٌ» أو عدُّه مفعولًا به؛ والصوابُ أنّه فاعلٌ في المحلِّ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dbb89fc3-9c91-5b2a-bda0-2069151043dc', '90dc9aa4-4a47-54b0-964d-bd3a61f7a542', 'في «ما أروعَ الصحراءَ!» ما محلُّ الجملةِ الفعليّةِ «أروعَ الصحراءَ» من الإعرابِ؟', '[{"id":"a","text":"في محلِّ نصبٍ مفعولٌ به"},{"id":"b","text":"في محلِّ رفعٍ خبرٌ للمبتدأِ «ما»"},{"id":"c","text":"في محلِّ جرٍّ مضافٌ إليه"},{"id":"d","text":"لا محلَّ لها من الإعرابِ"}]'::jsonb, 'b', '«ما» مبتدأٌ، والجملةُ الفعليّةُ بعدَها «أروعَ الصحراءَ» خبرُه، فهي في محلِّ رفعٍ. وهذا هو التحليلُ المعتمَدُ لصيغةِ «ما أفعلَه».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9bfa2e41-2f3a-52ea-9aed-ebd21717919f', '90dc9aa4-4a47-54b0-964d-bd3a61f7a542', 'أيُّ الأفعالِ الآتيةِ لا يُصاغُ منه التعجّبُ (لا مباشرةً ولا بمساعدٍ) لأنّه فعلٌ ناقصٌ؟', '[{"id":"a","text":"نفَعَ"},{"id":"b","text":"صارَ"},{"id":"c","text":"شرُفَ"},{"id":"d","text":"عدَلَ"}]'::jsonb, 'b', '«صارَ» فعلٌ ناقصٌ (من أخواتِ كان)، والفعلُ الناقصُ ممتنعٌ منه التعجّبُ لأنّه لا يتمُّ معناه بفاعلٍ. أمّا «نفَعَ، شرُفَ، عدَلَ» فأفعالٌ ثلاثيّةٌ تامّةٌ يصحُّ التعجّبُ منها: ما أنفعَه! ما أشرفَه! ما أعدلَه!', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c892f93c-48dc-5fe4-b221-112ee48c5ff1', '90dc9aa4-4a47-54b0-964d-bd3a61f7a542', 'أردتَ التعجّبَ من روعةِ استخراجِ الكنزِ، والفعلُ «استخرجَ» زائدٌ على ثلاثةِ أحرفٍ. ما الصياغةُ الصحيحةُ؟', '[{"id":"a","text":"ما أستخرجَ الكنزَ!"},{"id":"b","text":"استخرِجْ بالكنزِ!"},{"id":"c","text":"ما أروعَ استخراجَ الكنزِ!"},{"id":"d","text":"ما أخرجَ الكنزَ!"}]'::jsonb, 'c', 'لأنّ «استخرجَ» غيرُ ثلاثيٍّ، لا يُصاغُ منه فعلُ التعجّبِ مباشرةً؛ فنأتي بفعلٍ مساعدٍ ثلاثيٍّ مستوفٍ «ما أروعَ» ثمّ المصدرِ الصريحِ منصوبًا «استخراجَ»: ما أروعَ استخراجَ الكنزِ!', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1fd2fb26-ad4c-58fc-98d6-d617de044b1b', '90dc9aa4-4a47-54b0-964d-bd3a61f7a542', 'في «ما أعذبَ ماءَ العيونِ!» أين فاعلُ الفعلِ «أعذبَ»؟', '[{"id":"a","text":"«ماءَ» هو الفاعلُ"},{"id":"b","text":"«العيونِ» هي الفاعلُ"},{"id":"c","text":"ضميرٌ مستترٌ وجوبًا تقديرُه (هو) يعودُ على «ما»"},{"id":"d","text":"«ما» هي الفاعلُ"}]'::jsonb, 'c', 'فاعلُ فعلِ التعجّبِ «أعذبَ» ضميرٌ مستترٌ وجوبًا تقديرُه (هو) يعودُ على «ما» المبتدأِ. أمّا «ماءَ» فمفعولٌ به منصوبٌ (المتعجَّبُ منه)، و«العيونِ» مضافٌ إليه مجرورٌ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('2a6bc3a7-04e8-5bfa-8011-e527257c6d96', '5ead9433-8508-5a25-9926-bfce53cd5d8f', 'arabic-8eme', '⭐⭐ تمرين مراجعة (نمط امتحان): الصياغةُ والإعراب', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e4235ffe-cbaa-52a5-a51e-a465125b6d9e', '2a6bc3a7-04e8-5bfa-8011-e527257c6d96', 'حوّلِ الجملةَ «العلمُ نافعٌ» إلى تعجّبٍ على صيغةِ «ما أفعلَه».', '[{"id":"a","text":"ما أنفعَ العلمَ!"},{"id":"b","text":"ما أنفعُ العلمِ!"},{"id":"c","text":"أنفِعْ بالعلمِ!"},{"id":"d","text":"العلمُ أنفعُ!"}]'::jsonb, 'a', 'على صيغةِ «ما أفعلَه»: «ما» ثمّ الفعلُ «أنفعَ» مفتوحَ الآخرِ، ثمّ الاسمُ المنصوبُ «العلمَ». أمّا «أنفِعْ بالعلمِ!» فهي الصيغةُ الأخرى، و«ما أنفعُ العلمِ!» خطأٌ لرفعِ الفعلِ وجرِّ الاسمِ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4cecc6e7-45fa-566a-b046-1985a63eefc2', '2a6bc3a7-04e8-5bfa-8011-e527257c6d96', 'حوّلِ الجملةَ «العلمُ نافعٌ» إلى تعجّبٍ على صيغةِ «أفعِلْ بـه».', '[{"id":"a","text":"ما أنفعَ العلمَ!"},{"id":"b","text":"أنفِعْ بالعلمِ!"},{"id":"c","text":"أنفِعْ العلمَ!"},{"id":"d","text":"أنفعَ بالعلمِ!"}]'::jsonb, 'b', 'صيغةُ «أفعِلْ بـه»: فعلٌ على صورةِ الأمرِ «أنفِعْ» ثمّ الباءُ الزائدةُ فالاسمُ المجرورُ لفظًا «بالعلمِ». و«أنفِعْ العلمَ!» خطأٌ لسقوطِ الباءِ، و«أنفعَ بالعلمِ!» خطأٌ لأنّ الفعلَ يجبُ أن يكونَ على صورةِ الأمرِ (أنفِعْ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4f02eb3c-c180-5ce5-b8e1-8d80e97be265', '2a6bc3a7-04e8-5bfa-8011-e527257c6d96', 'في «ما أجملَ الوردَ!» ما إعرابُ «أجملَ»؟', '[{"id":"a","text":"فعلُ أمرٍ مبنيٌّ على السكونِ"},{"id":"b","text":"فعلٌ مضارعٌ مرفوعٌ"},{"id":"c","text":"فعلٌ ماضٍ جامدٌ مبنيٌّ على الفتحِ، فاعلُه ضميرٌ مستترٌ وجوبًا تقديرُه (هو)"},{"id":"d","text":"اسمُ تفضيلٍ منصوبٌ"}]'::jsonb, 'c', '«أجملَ» في التعجّبِ فعلٌ ماضٍ جامدٌ مبنيٌّ على الفتحِ، وفاعلُه ضميرٌ مستترٌ وجوبًا تقديرُه (هو) يعودُ على «ما». الخطأُ الشائعُ عدُّه أمرًا أو مضارعًا، أو خلطُه باسمِ التفضيلِ «أجمل».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31233899-5046-53b5-9b27-afee0049f423', '2a6bc3a7-04e8-5bfa-8011-e527257c6d96', 'في «ما أجملَ الوردَ!» ما إعرابُ «الوردَ»؟', '[{"id":"a","text":"فاعلٌ مرفوعٌ"},{"id":"b","text":"مفعولٌ به منصوبٌ"},{"id":"c","text":"مبتدأٌ مؤخّرٌ"},{"id":"d","text":"اسمٌ مجرورٌ"}]'::jsonb, 'b', '«الوردَ» هو المتعجَّبُ منه، وإعرابُه مفعولٌ به منصوبٌ للفعلِ «أجملَ» وعلامةُ نصبِه الفتحةُ. الفاعلُ ضميرٌ مستترٌ، فلا يكونُ «الوردَ» فاعلًا ولا مبتدأً.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0c2a55c4-b788-56c2-a861-27a67a3166b6', '2a6bc3a7-04e8-5bfa-8011-e527257c6d96', 'في «ما أصدقَ الوفيَّ!» ما إعرابُ «ما»؟', '[{"id":"a","text":"اسمٌ نكرةٌ تامّةٌ مبنيٌّ في محلِّ رفعٍ مبتدأٌ"},{"id":"b","text":"حرفُ نفيٍ"},{"id":"c","text":"اسمٌ موصولٌ في محلِّ رفعٍ فاعلٌ"},{"id":"d","text":"حرفُ تعجّبٍ لا محلَّ له من الإعرابِ"}]'::jsonb, 'a', '«ما» التعجبيّةُ اسمٌ نكرةٌ تامّةٌ بمعنى «شيءٌ عظيمٌ»، مبنيٌّ في محلِّ رفعٍ مبتدأٌ، وخبرُه الجملةُ الفعليّةُ بعدَه. وليست حرفَ نفيٍ ولا موصولةً ولا حرفَ تعجّبٍ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a3a6098-8e89-5fbb-9cf1-bb193aa8a6b5', '2a6bc3a7-04e8-5bfa-8011-e527257c6d96', 'أردتَ التعجّبَ من شدّةِ زُرقةِ البحرِ، والفعلُ «ازرقَّ» وصفُه على «أفعلَ فعلاءَ». ما الصياغةُ الصحيحةُ؟', '[{"id":"a","text":"ما أزرقَ البحرَ!"},{"id":"b","text":"أزرِقْ بالبحرِ!"},{"id":"c","text":"ما أشدَّ زُرقةَ البحرِ!"},{"id":"d","text":"ما أزرقُ البحرِ!"}]'::jsonb, 'c', 'لأنّ الوصفَ على وزنِ «أفعلَ فعلاءَ» (أزرق/زرقاء)، لا يُتعجّبُ منه مباشرةً؛ بل نأتي بفعلٍ مساعدٍ مستوفٍ للشروطِ «ما أشدَّ» ثمّ المصدرِ منصوبًا «زُرقةَ»: ما أشدَّ زُرقةَ البحرِ!', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('80644c82-9a38-5f2e-aa93-1760dd3caadd', '5ead9433-8508-5a25-9926-bfce53cd5d8f', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: خبايا الصياغة والإعراب', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a3351ade-e2a5-5a82-bdcd-6b2bea480639', '80644c82-9a38-5f2e-aa93-1760dd3caadd', 'في «ما أشدَّ زُرقةَ البحرِ!» ما إعرابُ «زُرقةَ»؟', '[{"id":"a","text":"فاعلٌ مرفوعٌ"},{"id":"b","text":"تمييزٌ منصوبٌ"},{"id":"c","text":"مفعولٌ به منصوبٌ للفعلِ «أشدَّ» (وهو المصدرُ المتعجَّبُ منه)، و«البحرِ» مضافٌ إليه"},{"id":"d","text":"مضافٌ إليه مجرورٌ"}]'::jsonb, 'c', 'في التعجّبِ بالفعلِ المساعدِ يبقى الإعرابُ كإعرابِ «ما أفعلَه»: «أشدَّ» فعلٌ ماضٍ جامدٌ، و«زُرقةَ» مفعولٌ به منصوبٌ (وهو المصدرُ المتعجَّبُ منه)، و«البحرِ» مضافٌ إليه مجرورٌ. فليس «زُرقةَ» تمييزًا ولا فاعلًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('92d7df21-f982-5dd4-80b4-d7b93c0ce9b1', '80644c82-9a38-5f2e-aa93-1760dd3caadd', 'في «ما أجملَ أن تُساعدَ الضعيفَ!» ما المتعجَّبُ منه (المفعولُ به)؟', '[{"id":"a","text":"«الضعيفَ» وحدَه"},{"id":"b","text":"«تُساعدَ» وحدَه"},{"id":"c","text":"لا مفعولَ به في الجملةِ"},{"id":"d","text":"المصدرُ المؤوّلُ «أن تُساعدَ الضعيفَ» في محلِّ نصبٍ مفعولٌ به"}]'::jsonb, 'd', '«أن» والفعلُ بعدَها يُؤوَّلانِ بمصدرٍ (مساعدتِكَ الضعيفَ)، وهذا المصدرُ المؤوّلُ في محلِّ نصبٍ مفعولٌ به للفعلِ «أجملَ»، وهو المتعجَّبُ منه. أمّا «الضعيفَ» فمفعولٌ به للفعلِ «تُساعدَ» داخلَ الصلةِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1ca62083-6d69-5e4f-a9c7-2a02c0c588d3', '80644c82-9a38-5f2e-aa93-1760dd3caadd', '«عَظُمَ» فعلٌ ثلاثيٌّ تامٌّ. عند التعجّبِ نقولُ «أعظِمْ باللهِ!». ما إعرابُ لفظِ الجلالةِ «اللهِ»؟', '[{"id":"a","text":"اسمُ الجلالةِ مجرورٌ بالباءِ فحسبُ"},{"id":"b","text":"مفعولٌ به منصوبٌ محلًّا"},{"id":"c","text":"فاعلٌ مرفوعٌ محلًّا، مجرورٌ لفظًا بالباءِ الزائدةِ"},{"id":"d","text":"منادى مبنيٌّ"}]'::jsonb, 'c', 'في صيغةِ «أفعِلْ بـه» الباءُ حرفُ جرٍّ زائدٌ، والاسمُ بعدَها فاعلٌ لفعلِ التعجّبِ: «اللهِ» فاعلٌ مرفوعٌ محلًّا مجرورٌ لفظًا. الخطأُ الاكتفاءُ بأنّه «مجرورٌ» أو عدُّه مفعولًا أو منادى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('28ae67ba-9fe7-51c8-8f23-9e5177babdae', '80644c82-9a38-5f2e-aa93-1760dd3caadd', 'في أيِّ الجملِ الآتيةِ «ما» تعجبيّةٌ (اسمٌ نكرةٌ تامّةٌ مبتدأٌ) لا نافيةٌ ولا استفهاميّةٌ ولا موصولةٌ؟', '[{"id":"a","text":"ما أجملَ الصدقَ!"},{"id":"b","text":"ما جاءَ المسافرُ."},{"id":"c","text":"ما عندَكَ من كتبٍ؟"},{"id":"d","text":"قرأتُ ما كُتِبَ على اللوحِ."}]'::jsonb, 'a', '«ما أجملَ الصدقَ!» على صيغةِ «ما أفعلَه»، فـ«ما» فيها تعجبيّةٌ اسمٌ نكرةٌ تامّةٌ مبتدأٌ. أمّا الثانيةُ فـ«ما» نافيةٌ، والثالثةُ استفهاميّةٌ، والرابعةُ موصولةٌ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1667a6c-269c-571b-b91e-0483dd6a965a', '80644c82-9a38-5f2e-aa93-1760dd3caadd', 'أردتَ التعجّبَ من فعلٍ مبنيٍّ للمجهولِ مثلِ «يُكرَمُ». بأيِّ صورةٍ نأتي بعدَ الفعلِ المساعدِ؟', '[{"id":"a","text":"بمصدرٍ مؤوّلٍ من «أن» والفعلِ المبنيِّ للمجهولِ: ما أجملَ أن يُكرَمَ المجدُّ!"},{"id":"b","text":"بالمصدرِ الصريحِ منصوبًا: ما أجملَ إكرامَ المجدِّ!"},{"id":"c","text":"بالفعلِ المبنيِّ للمجهولِ مباشرةً بعدَ «ما» دونَ مساعدٍ"},{"id":"d","text":"باسمِ التفضيلِ: المجدُّ أكرمُ!"}]'::jsonb, 'a', 'المبنيُّ للمجهولِ لا يُتعجَّبُ منه مباشرةً، وإذا أتينا بالمصدرِ الصريحِ «إكرام» ذهبَ معنى البناءِ للمجهولِ؛ فنأتي بالفعلِ المساعدِ ثمّ بمصدرٍ مؤوّلٍ من «أن» والفعلِ المبنيِّ للمجهولِ: ما أجملَ أن يُكرَمَ المجدُّ!', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('22961d4b-72b6-5f78-a91c-16b9f9fa2f41', '80644c82-9a38-5f2e-aa93-1760dd3caadd', 'أيُّ الإعرابِ الآتي صحيحٌ كاملٌ لجملةِ «أكرِمْ بأخلاقِ محمّدٍ!»؟', '[{"id":"a","text":"«أكرِمْ» فعلُ أمرٍ، «بأخلاقِ» جارٌّ ومجرورٌ متعلّقٌ بالفعلِ، «محمّدٍ» مضافٌ إليه"},{"id":"b","text":"«أكرِمْ» فعلٌ ماضٍ جاءَ على صورةِ الأمرِ مبنيٌّ على السكونِ، الباءُ زائدةٌ، «أخلاقِ» فاعلٌ مرفوعٌ محلًّا مجرورٌ لفظًا، «محمّدٍ» مضافٌ إليه مجرورٌ"},{"id":"c","text":"«أكرِمْ» فعلُ أمرٍ، «أخلاقِ» مفعولٌ به، «محمّدٍ» فاعلٌ مؤخّرٌ"},{"id":"d","text":"«أكرِمْ» فعلٌ ماضٍ، «أخلاقِ» مبتدأٌ، «محمّدٍ» خبرٌ"}]'::jsonb, 'b', '«أكرِمْ» فعلُ تعجّبٍ ماضٍ جاءَ لفظُه لفظَ الأمرِ ومعناه التعجّبُ، مبنيٌّ على السكونِ؛ والباءُ زائدةٌ؛ و«أخلاقِ» فاعلٌ مرفوعٌ محلًّا مجرورٌ لفظًا؛ و«محمّدٍ» مضافٌ إليه مجرورٌ. الخطأُ عدُّه فعلَ أمرٍ حقيقيًّا أو جعلُ «أخلاقِ» مفعولًا به.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('37869cac-019b-54b7-a80e-d1cebeabcaa5', '5ead9433-8508-5a25-9926-bfce53cd5d8f', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: تمرّسٌ على الشروطِ والصياغةِ', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1569c43b-871d-58d6-bf38-d29b65c9a716', '37869cac-019b-54b7-a80e-d1cebeabcaa5', 'في «ما أحسنَ الخُلُقَ!» و«خالدٌ أحسنُ الطلّابِ»، ما الفرقُ بين «أحسنَ» الأولى و«أحسنُ» الثانيةِ؟', '[{"id":"a","text":"الأولى فعلُ تعجّبٍ ماضٍ (مفتوحُ الآخرِ)، والثانيةُ اسمُ تفضيلٍ (مرفوعٌ)"},{"id":"b","text":"كلتاهما فعلُ تعجّبٍ"},{"id":"c","text":"كلتاهما اسمُ تفضيلٍ"},{"id":"d","text":"الأولى اسمُ تفضيلٍ والثانيةُ فعلُ تعجّبٍ"}]'::jsonb, 'a', '«أحسنَ الخُلُقَ» فعلُ تعجّبٍ ماضٍ جامدٌ مفتوحُ الآخرِ يليه مفعولٌ به منصوبٌ. أمّا «أحسنُ الطلّابِ» فاسمُ تفضيلٍ مرفوعٌ (خبرٌ) مضافٌ. الضبطُ يفرّقُ بينهما: فتحةٌ في التعجّبِ، وضمّةٌ في التفضيلِ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88318aac-1b66-58ae-9625-cdcd0cae8dcf', '37869cac-019b-54b7-a80e-d1cebeabcaa5', 'أردتَ التعجّبَ من عدمِ كذبِ الصادقِ (والفعلُ منفيٌّ: لا يكذبُ). ما الصياغةُ الصحيحةُ؟', '[{"id":"a","text":"ما أكذبَ الصادقَ!"},{"id":"b","text":"لا أكذِبْ بالصادقِ!"},{"id":"c","text":"ما ألّا يكذبَ الصادقَ!"},{"id":"d","text":"ما أجملَ ألّا يكذبَ الصادقُ!"}]'::jsonb, 'd', 'الفعلُ المنفيُّ لا يُتعجّبُ منه مباشرةً؛ فنأتي بفعلٍ مساعدٍ مستوفٍ للشروطِ «ما أجملَ» ثمّ بمصدرٍ مؤوّلٍ من «أن» و«لا» والفعلِ: «ما أجملَ ألّا يكذبَ الصادقُ!». أمّا «ما أكذبَ الصادقَ!» فمعناها مدحُ كذبِه، وهو عكسُ المقصودِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03b506e1-ac06-53ec-9f72-25d05ae5cd54', '37869cac-019b-54b7-a80e-d1cebeabcaa5', 'أيُّ الأفعالِ الآتيةِ لا يُتعجّبُ منه لأنّه جامدٌ غيرُ متصرّفٍ؟', '[{"id":"a","text":"عَلِمَ"},{"id":"b","text":"بئسَ"},{"id":"c","text":"حسُنَ"},{"id":"d","text":"صدَقَ"}]'::jsonb, 'b', '«بئسَ» فعلُ ذمٍّ جامدٌ لا يتصرّفُ، فيمتنعُ التعجّبُ منه. أمّا «عَلِمَ، حسُنَ، صدَقَ» فأفعالٌ ثلاثيّةٌ تامّةٌ متصرّفةٌ يصحُّ التعجّبُ منها: ما أعلمَه! ما أحسنَه! ما أصدقَه!', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3bf15b56-87a3-5703-8977-1c4e0d19a226', '37869cac-019b-54b7-a80e-d1cebeabcaa5', 'لماذا يمتنعُ التعجّبُ من الفعلِ «ماتَ» مباشرةً مع أنّه ثلاثيٌّ تامٌّ؟', '[{"id":"a","text":"لأنّه غيرُ ثلاثيٍّ"},{"id":"b","text":"لأنّه مبنيٌّ للمجهولِ"},{"id":"c","text":"لأنّه لا يقبلُ التفاوتَ زيادةً ونقصًا"},{"id":"d","text":"لأنّه فعلٌ ناقصٌ من أخواتِ كانَ"}]'::jsonb, 'c', '«ماتَ» يستوفي أكثرَ الشروطِ، لكنّه يدلُّ على حدثٍ لا يقبلُ التفاوتَ (فالموتُ لا يزيدُ ولا ينقصُ)؛ ومن شرطِ فعلِ التعجّبِ أن يكونَ الوصفُ منه قابلًا للتفاوتِ. وهو ثلاثيٌّ تامٌّ مبنيٌّ للمعلومِ، فلا تصحُّ العللُ الأخرى.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('061780b2-0e1e-5a4b-9a51-fb19420e7e35', '37869cac-019b-54b7-a80e-d1cebeabcaa5', 'ما الإعرابُ الصحيحُ الكاملُ لجملةِ «ما أنبلَ الشهيدَ!»؟', '[{"id":"a","text":"«ما» اسمٌ نكرةٌ تامّةٌ مبتدأٌ، «أنبلَ» فعلٌ ماضٍ جامدٌ فاعلُه مستترٌ (هو)، «الشهيدَ» مفعولٌ به منصوبٌ، والجملةُ الفعليّةُ خبرُ «ما»"},{"id":"b","text":"«ما» نافيةٌ، «أنبلَ» فعلٌ ماضٍ، «الشهيدَ» فاعلٌ مؤخّرٌ"},{"id":"c","text":"«ما» استفهاميّةٌ مبتدأٌ، «أنبلَ» خبرٌ، «الشهيدَ» بدلٌ"},{"id":"d","text":"«ما» مبتدأٌ، «أنبلَ» اسمُ تفضيلٍ خبرٌ، «الشهيدَ» مضافٌ إليه"}]'::jsonb, 'a', '«ما» التعجبيّةُ نكرةٌ تامّةٌ مبتدأٌ في محلِّ رفعٍ، و«أنبلَ» فعلٌ ماضٍ جامدٌ فاعلُه ضميرٌ مستترٌ وجوبًا تقديرُه (هو)، و«الشهيدَ» مفعولٌ به منصوبٌ (المتعجَّبُ منه)، وجملةُ «أنبلَ الشهيدَ» في محلِّ رفعٍ خبرٌ. فليست «ما» نافيةً ولا استفهاميّةً، ولا «أنبلَ» اسمَ تفضيلٍ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c68effe8-3637-55a9-aea2-feeee05c6022', '37869cac-019b-54b7-a80e-d1cebeabcaa5', 'أيُّ العباراتِ الآتيةِ تعجّبٌ سماعيٌّ (خارجٌ عن الصيغتين القياسيّتين)؟', '[{"id":"a","text":"ما أشجعَ الجنديَّ!"},{"id":"b","text":"أشجِعْ بالجنديِّ!"},{"id":"c","text":"للهِ درُّ الجنديِّ فارسًا!"},{"id":"d","text":"ما أشدَّ شجاعةَ الجنديِّ!"}]'::jsonb, 'c', '«للهِ درُّ الجنديِّ فارسًا!» تعجّبٌ سماعيٌّ يُفهَمُ من السياقِ ولا يجري على صيغةٍ مقيسٍ عليها. أمّا «ما أشجعَ» فعلى صيغةِ (ما أفعلَه)، و«أشجِعْ بـ» على صيغةِ (أفعِلْ بـه)، و«ما أشدَّ شجاعةَ» تعجّبٌ قياسيٌّ بفعلٍ مساعدٍ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('98a4a4cb-ed65-5358-939b-91ff49cfa1df', '5ead9433-8508-5a25-9926-bfce53cd5d8f', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: دقائقُ الصياغةِ وخبايا الإعراب', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fcecdf6-b18e-586d-a4df-dccca8f77dec', '98a4a4cb-ed65-5358-939b-91ff49cfa1df', 'في «ما أعظمَ المجاهدينَ!» ما إعرابُ «المجاهدينَ»؟', '[{"id":"a","text":"مفعولٌ به منصوبٌ وعلامةُ نصبِه الياءُ لأنّه جمعُ مذكّرٍ سالمٌ"},{"id":"b","text":"مفعولٌ به منصوبٌ وعلامةُ نصبِه الفتحةُ"},{"id":"c","text":"فاعلٌ مرفوعٌ وعلامةُ رفعِه الواوُ"},{"id":"d","text":"اسمٌ مجرورٌ وعلامةُ جرِّه الياءُ"}]'::jsonb, 'a', '«المجاهدينَ» هو المتعجَّبُ منه، فهو مفعولٌ به للفعلِ «أعظمَ»، منصوبٌ وعلامةُ نصبِه الياءُ لأنّه جمعُ مذكّرٍ سالمٌ. والفاعلُ ضميرٌ مستترٌ، فلا يكونُ «المجاهدينَ» فاعلًا ولا مجرورًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('255b97d9-e271-537e-a444-64a1c5d68f01', '98a4a4cb-ed65-5358-939b-91ff49cfa1df', 'أردتَ التعجّبَ من شدّةِ عَرَجِ الرجلِ، والفعلُ «عَرِجَ» وصفُه على «أفعلَ فعلاءَ» (أعرج/عرجاء). ما الصياغةُ الصحيحةُ؟', '[{"id":"a","text":"ما أعرجَ الرجلَ!"},{"id":"b","text":"أعرِجْ بالرجلِ!"},{"id":"c","text":"ما عرجَ الرجلُ!"},{"id":"d","text":"ما أشدَّ عَرَجَ الرجلِ!"}]'::jsonb, 'd', 'ما دام الوصفُ على وزنِ «أفعلَ فعلاءَ» (كالعيوبِ والألوانِ) امتنعَ التعجّبُ منه مباشرةً؛ فنأتي بفعلٍ مساعدٍ مستوفٍ «ما أشدَّ» ثمّ بالمصدرِ منصوبًا «عَرَجَ»: «ما أشدَّ عَرَجَ الرجلِ!»؛ و«الرجلِ» مضافٌ إليه مجرورٌ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3743e6d3-e650-5323-b0cf-8a5a0db53b1a', '98a4a4cb-ed65-5358-939b-91ff49cfa1df', 'في «ما أجملَ ما صنعَ اللهُ!» ما إعرابُ «ما» الأولى و«ما» الثانيةِ؟', '[{"id":"a","text":"كلتاهما تعجبيّةٌ مبتدأٌ"},{"id":"b","text":"الأولى تعجبيّةٌ (نكرةٌ تامّةٌ مبتدأٌ)، والثانيةُ موصولةٌ في محلِّ نصبٍ مفعولٌ به"},{"id":"c","text":"الأولى استفهاميّةٌ، والثانيةُ نافيةٌ"},{"id":"d","text":"الأولى موصولةٌ، والثانيةُ تعجبيّةٌ"}]'::jsonb, 'b', '«ما» الأولى تعجبيّةٌ نكرةٌ تامّةٌ مبتدأٌ، و«أجملَ» فعلُ التعجّبِ. أمّا «ما» الثانيةُ فاسمٌ موصولٌ (بمعنى الذي)، وجملةُ «صنعَ اللهُ» صلتُها، والموصولُ في محلِّ نصبٍ مفعولٌ به (المتعجَّبُ منه). و«اللهُ» فاعلُ «صنعَ» مرفوعٌ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('223b80a8-eb74-51ce-aa43-dbd05e1e8744', '98a4a4cb-ed65-5358-939b-91ff49cfa1df', '«يا لَه من عالِمٍ!» — ما نوعُ هذا التعجّبِ وما علّتُه؟', '[{"id":"a","text":"قياسيٌّ على صيغةِ «ما أفعلَه»"},{"id":"b","text":"قياسيٌّ على صيغةِ «أفعِلْ بـه»"},{"id":"c","text":"سماعيٌّ؛ لأنّه لم يجرِ على إحدى الصيغتين القياسيّتين ويُفهَمُ من السياقِ"},{"id":"d","text":"ليس تعجّبًا بل أسلوبُ نداءٍ محضٍ"}]'::jsonb, 'c', '«يا لَه من عالِمٍ!» أسلوبٌ سماعيٌّ للتعجّبِ، لم يجرِ على صيغةِ «ما أفعلَه» ولا «أفعِلْ بـه»، ويُفهَمُ التعجّبُ فيه من السياقِ ونبرةِ الكلامِ. وليس نداءً محضًا وإن دخلَتْه «يا»، بل استُعمِلَ للتعجّبِ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8ac9632d-f998-5341-a65f-ce76a11fd957', '98a4a4cb-ed65-5358-939b-91ff49cfa1df', 'أيُّ الجملِ الآتيةِ خاطئةٌ في صياغةِ التعجّبِ (خلطتْ بين الصيغتين)؟', '[{"id":"a","text":"ما أعدلَ القاضيَ!"},{"id":"b","text":"أعدِلْ بالقاضي!"},{"id":"c","text":"ما أرحمَ الأمَّ!"},{"id":"d","text":"ما أعدلَ بالقاضي!"}]'::jsonb, 'd', '«ما أعدلَ بالقاضي!» خطأٌ؛ لأنّها جمعتْ بين «ما» (من الصيغةِ الأولى) والباءِ (من الصيغةِ الثانيةِ). والصوابُ إمّا «ما أعدلَ القاضيَ!» بالنصبِ دونَ باءٍ، وإمّا «أعدِلْ بالقاضي!» بالباءِ على صورةِ الأمرِ. أمّا «ما أرحمَ الأمَّ!» فصحيحةٌ على الصيغةِ الأولى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('15998d62-1a6a-5589-ae83-5257a5751b9e', '98a4a4cb-ed65-5358-939b-91ff49cfa1df', '«أكرَمَ الغنيُّ الفقيرَ» و«ما أكرمَ الغنيَّ!» — ما الفرقُ بين «أكرَمَ» في الجملتين؟', '[{"id":"a","text":"كلتاهما فعلُ تعجّبٍ جامدٌ"},{"id":"b","text":"الأولى فعلٌ ماضٍ متصرّفٌ (رباعيٌّ) له فاعلٌ ومفعولٌ، والثانيةُ فعلُ تعجّبٍ ماضٍ جامدٌ فاعلُه مستترٌ"},{"id":"c","text":"الأولى فعلُ تعجّبٍ والثانيةُ فعلٌ ماضٍ عاديٌّ"},{"id":"d","text":"كلتاهما اسمُ تفضيلٍ"}]'::jsonb, 'b', '«أكرَمَ الغنيُّ الفقيرَ» فعلٌ ماضٍ رباعيٌّ متصرّفٌ (بمعنى: أعطاه الكرامةَ)، «الغنيُّ» فاعلُه و«الفقيرَ» مفعولُه. أمّا «ما أكرمَ الغنيَّ!» فهو فعلُ تعجّبٍ ماضٍ جامدٌ صيغَ من «كرُمَ»، فاعلُه ضميرٌ مستترٌ (هو)، و«الغنيَّ» مفعولٌ به. فالتشابهُ في الرسمِ لا يخفي اختلافَ الوظيفةِ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('2dd22830-94c8-50df-98b0-d7508260dcec', 'e7316dd2-63a5-5a75-b004-aab4c1ab4f9c', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
