INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0192cbb3-e913-5266-b944-5cef8f54de6a', '2dd22830-94c8-50df-98b0-d7508260dcec', 'أنواع الجملة المركّبة ثلاثة، هي:', '[{"id":"a","text":"التركيب بالوصل، والتركيب بالإسناد، والتركيب بالربط"},{"id":"b","text":"التركيب بالفاعل، والمفعول، والحال"},{"id":"c","text":"الجملة الاسميّة، والفعليّة، والشرطيّة"},{"id":"d","text":"المبتدأ، والخبر، والصلة"}]'::jsonb, 'a', 'تنقسم الجملة المركّبة إلى ثلاثة أنواع: التركيب بالوصل (بحرف عطف)، والتركيب بالإسناد (جملة صغرى تقع ركنًا)، والتركيب بالربط (بأداة ربطٍ كالموصول).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('88928a14-2e64-54c7-b3dc-82c873d8c16a', '2dd22830-94c8-50df-98b0-d7508260dcec', 'صلة الموصول من حيث الإعراب:', '[{"id":"a","text":"لها محلّ رفع دائمًا"},{"id":"b","text":"لها محلّ نصب دائمًا"},{"id":"c","text":"لا محلّ لها من الإعراب"},{"id":"d","text":"تُعرب بحسب موقع الموصول"}]'::jsonb, 'c', 'صلة الموصول لا محلّ لها من الإعراب أبدًا؛ وظيفتها توضيح معنى الموصول لا أن تسدّ مسدّ ركنٍ. أمّا الاسم الموصول نفسه فيُعرب بحسب موقعه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef34c908-5910-5025-ab3d-28cdb3ab60c3', '2dd22830-94c8-50df-98b0-d7508260dcec', '«نجحَ الّذي راجعَ دروسَه» — الاسم الموصول في هذه الجملة هو:', '[{"id":"a","text":"نجحَ"},{"id":"b","text":"الّذي"},{"id":"c","text":"راجعَ"},{"id":"d","text":"دروسَه"}]'::jsonb, 'b', '«الّذي» اسمٌ موصولٌ، وصلتُه جملة «راجعَ دروسَه» التي فيها عائدٌ (الضمير في «دروسَه») يعود عليه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('49e0fc57-6b46-5e08-8046-bce58d0b3e6b', '2dd22830-94c8-50df-98b0-d7508260dcec', '«حضرَ الضّيوفُ وجلسوا» — نوع التركيب في هذه الجملة:', '[{"id":"a","text":"التركيب بالإسناد"},{"id":"b","text":"التركيب بالربط"},{"id":"c","text":"التركيب بالوصل"},{"id":"d","text":"ليست جملة مركّبة"}]'::jsonb, 'c', 'جملتان تامّتان (حضرَ الضّيوفُ) و(جلسوا) وُصِلتا بحرف العطف الواو، فالتركيب بالوصل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5d009347-2691-579d-8a11-0db67281a748', '2dd22830-94c8-50df-98b0-d7508260dcec', '«الطّائرُ يبني عشَّه» — جملة «يبني عشَّه» في هذه الجملة الكبرى:', '[{"id":"a","text":"في محلّ رفع خبر المبتدأ"},{"id":"b","text":"لا محلّ لها لأنّها صلة موصول"},{"id":"c","text":"في محلّ نصب حال"},{"id":"d","text":"في محلّ جرّ مضاف إليه"}]'::jsonb, 'a', 'الجملة الفعليّة «يبني عشَّه» وقعت خبرًا للمبتدأ «الطّائرُ»، وعائدها الضمير المستتر في «يبني»، فهي في محلّ رفع خبر (تركيب بالإسناد).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

