  ('7d83ff28-8286-5694-8f47-96bed4127abf', 'e7316dd2-63a5-5a75-b004-aab4c1ab4f9c', 'arabic-8eme', '⭐ تمرين: الجملة المركّبة', 1, 50, 10, 'practice', 'admin', 1)
