INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab8832ed-9a8c-5cf2-91fa-af6f92691290', '7d83ff28-8286-5694-8f47-96bed4127abf', '«أشرقتِ الشّمسُ فذابَ الجليدُ» — نوع التركيب في هذه الجملة:', '[{"id":"a","text":"التركيب بالوصل"},{"id":"b","text":"التركيب بالإسناد"},{"id":"c","text":"التركيب بالربط"},{"id":"d","text":"جملة بسيطة لا مركّبة"}]'::jsonb, 'a', 'جملتان تامّتان (أشرقتِ الشّمسُ) و(ذابَ الجليدُ) وُصِلتا بحرف العطف الفاء، فالتركيب بالوصل.', 1)
