INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f0e46377-7a7d-5522-9be4-15873b3e15de', '7d83ff28-8286-5694-8f47-96bed4127abf', '«أعجبتْني الّتي فازتْ بالجائزةِ» — الاسم الموصول هو:', '[{"id":"a","text":"أعجبتْني"},{"id":"b","text":"الّتي"},{"id":"c","text":"فازتْ"},{"id":"d","text":"الجائزةِ"}]'::jsonb, 'b', '«الّتي» اسمٌ موصولٌ، وصلتُه جملة «فازتْ بالجائزةِ» التي فيها عائدٌ (ضميرٌ مستترٌ في «فازتْ») يعود عليه.', 2)
