INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c330024c-12f1-5909-868c-783730679ded', '7d83ff28-8286-5694-8f47-96bed4127abf', 'صلة الموصول من حيث محلّها من الإعراب:', '[{"id":"a","text":"في محلّ رفع"},{"id":"b","text":"في محلّ نصب"},{"id":"c","text":"في محلّ جرّ"},{"id":"d","text":"لا محلّ لها من الإعراب"}]'::jsonb, 'd', 'صلة الموصول لا محلّ لها من الإعراب دائمًا؛ فهي تكمّل معنى الموصول ولا تسدّ مسدّ ركنٍ يُعرب.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('547d35db-f739-5781-860d-f6ca3cee7d86', '7d83ff28-8286-5694-8f47-96bed4127abf', '«كافأتُ التّلميذَ الّذي تفوّقَ» — نوع التركيب في هذه الجملة:', '[{"id":"a","text":"التركيب بالوصل"},{"id":"b","text":"التركيب بالربط"},{"id":"c","text":"جملة بسيطة"},{"id":"d","text":"لا تركيب فيها"}]'::jsonb, 'b', 'رُبطتْ جملة «تفوّقَ» بما قبلها بالاسم الموصول «الّذي» (صلته)، فالتركيب بالربط، لا عطفٌ ولا خبرٌ جملة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cdedf3ed-6db5-5b76-989c-3bffcc6cced3', '7d83ff28-8286-5694-8f47-96bed4127abf', '«القمرُ يضيءُ اللّيلَ» — جملة «يضيءُ اللّيلَ»:', '[{"id":"a","text":"في محلّ رفع خبر المبتدأ «القمرُ»"},{"id":"b","text":"لا محلّ لها لأنّها صلة موصول"},{"id":"c","text":"في محلّ نصب مفعول به"},{"id":"d","text":"جملة ابتدائيّة لا محلّ لها"}]'::jsonb, 'a', 'الجملة الفعليّة «يضيءُ اللّيلَ» وقعت خبرًا للمبتدأ «القمرُ»، وعائدها الضمير المستتر في «يضيءُ»، فهي في محلّ رفع خبر (تركيب بالإسناد).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('da98525d-17a9-5b87-a61d-04398965f6a6', '7d83ff28-8286-5694-8f47-96bed4127abf', '«هبّتِ الرّيحُ وتساقطَ الورقُ» — جملة «تساقطَ الورقُ»:', '[{"id":"a","text":"في محلّ رفع خبر"},{"id":"b","text":"في محلّ نصب حال"},{"id":"c","text":"لا محلّ لها، معطوفة على جملةٍ ابتدائيّةٍ لا محلّ لها"},{"id":"d","text":"في محلّ جرّ مضاف إليه"}]'::jsonb, 'c', 'الجملة الأولى «هبّتِ الرّيحُ» ابتدائيّةٌ لا محلّ لها، وجملة «تساقطَ الورقُ» معطوفةٌ عليها بالواو، فتأخذ حكمَها: لا محلّ لها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a6c149a9-f91a-566e-91de-8b07af336537', 'e7316dd2-63a5-5a75-b004-aab4c1ab4f9c', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: محلّ الجمل من الإعراب', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
