INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4fc1b064-d732-5b09-88c7-d64a19bc4e82', 'a6c149a9-f91a-566e-91de-8b07af336537', '«كانَ العاملُ يجدُّ في مهنتِه» — جملة «يجدُّ في مهنتِه»:', '[{"id":"a","text":"في محلّ رفع خبر"},{"id":"b","text":"في محلّ نصب خبر «كانَ»"},{"id":"c","text":"لا محلّ لها، صلة موصول"},{"id":"d","text":"في محلّ جرّ مضاف إليه"}]'::jsonb, 'b', '«كانَ» ناسخٌ يرفع الاسم وينصب الخبر؛ وقعت جملة «يجدُّ في مهنتِه» خبرًا له، فهي في محلّ نصب خبر «كانَ»، وعائدها الضمير المستتر في «يجدُّ».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('228a8ae3-bcde-59e8-876f-e131a85c9cb8', 'a6c149a9-f91a-566e-91de-8b07af336537', '«رأيتُ رجلًا يقرأُ الصّحيفةَ» — جملة «يقرأُ الصّحيفةَ»:', '[{"id":"a","text":"في محلّ نصب نعت لـ«رجلًا»"},{"id":"b","text":"في محلّ نصب حال"},{"id":"c","text":"لا محلّ لها، صلة موصول"},{"id":"d","text":"في محلّ رفع خبر"}]'::jsonb, 'a', '«رجلًا» نكرةٌ، والجملة بعد النكرة نعتٌ؛ فجملة «يقرأُ الصّحيفةَ» في محلّ نصب نعت لـ«رجلًا» المنصوب، وعائدها الضمير المستتر في «يقرأُ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a15603f2-5c7a-5c75-b4fd-6cf45a8f284e', 'a6c149a9-f91a-566e-91de-8b07af336537', '«أكرمتُ الّذي ساعدَني في محنتي» — ما العائد الذي يربط الصّلة بالموصول؟', '[{"id":"a","text":"الاسم الموصول «الّذي»"},{"id":"b","text":"الفعل «ساعدَ»"},{"id":"c","text":"الضمير «الياء» في «ساعدَني»"},{"id":"d","text":"كلمة «محنتي»"}]'::jsonb, 'c', 'العائد ضميرٌ في جملة الصّلة يعود على الموصول؛ هنا هو ياء المتكلّم في «ساعدَني». (وصلة الموصول «ساعدَني في محنتي» لا محلّ لها من الإعراب.)', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('938da435-b5c7-5714-a811-d7bee446ab99', 'a6c149a9-f91a-566e-91de-8b07af336537', '«شاهدتُ اللّاعبَ يجري نحو المرمى» — جملة «يجري نحو المرمى»:', '[{"id":"a","text":"في محلّ نصب نعت لـ«اللّاعبَ»"},{"id":"b","text":"في محلّ نصب حال من «اللّاعبَ»"},{"id":"c","text":"لا محلّ لها، صلة موصول"},{"id":"d","text":"في محلّ رفع خبر"}]'::jsonb, 'b', '«اللّاعبَ» معرفةٌ (بأل)، والجملة بعد المعرفة حالٌ لا نعت؛ فجملة «يجري نحو المرمى» في محلّ نصب حال تصف هيئة اللّاعب، وعائدها الضمير المستتر في «يجري».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d815996a-7e00-59a8-9856-b5883cf4bb4f', 'a6c149a9-f91a-566e-91de-8b07af336537', '«انتظرتُك حيثُ افترقنا أوّلَ مرّةٍ» — جملة «افترقنا أوّلَ مرّةٍ» بعد الظّرف «حيثُ»:', '[{"id":"a","text":"في محلّ نصب حال"},{"id":"b","text":"لا محلّ لها، صلة موصول"},{"id":"c","text":"في محلّ جرّ مضاف إليه"},{"id":"d","text":"في محلّ رفع خبر"}]'::jsonb, 'c', '«حيثُ» ظرفٌ يُضاف إلى الجمل؛ فجملة «افترقنا أوّلَ مرّةٍ» في محلّ جرّ مضاف إليه بعده. المحلّ جرٌّ لأنّ المضاف إليه مجرور.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6ce96c0-0692-5520-9947-a0b07a5bd32a', 'a6c149a9-f91a-566e-91de-8b07af336537', 'قالَ تلميذٌ في «فازَ الّذي اجتهدَ»: صلة الموصول «اجتهدَ» في محلّ رفع لأنّها بعد فعلٍ مرفوعٍ فاعلُه. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، التّحليل صحيح"},{"id":"b","text":"الخطأ أنّ صلة الموصول لا محلّ لها من الإعراب دائمًا، لا محلّ رفعٍ ولا غيره"},{"id":"c","text":"الخطأ أنّ «اجتهدَ» في محلّ نصب لا رفع"},{"id":"d","text":"الخطأ أنّ «الّذي» هو الصّلة لا «اجتهدَ»"}]'::jsonb, 'b', 'صلة الموصول «اجتهدَ» لا محلّ لها من الإعراب مطلقًا. الذي له محلّ رفعٍ هو الاسم الموصول «الّذي» نفسه (فاعل «فازَ»)، لا صلتُه. الخطأ الشّائع: نسبةُ محلّ الموصول إلى صلته.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

