  ('929e2ef0-4ad9-5685-a7fa-b1f264210b29', 'e7316dd2-63a5-5a75-b004-aab4c1ab4f9c', 'arabic-8eme', '⭐⭐ تمرين: أنواعُ المركّبةِ وجملتُها الموصولةُ', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
