INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d6c31abe-88b7-59c1-995e-ba075c2d12c6', '929e2ef0-4ad9-5685-a7fa-b1f264210b29', '«الفلّاحُ يزرعُ حقلَه» — نوع التركيب في هذه الجملة:', '[{"id":"a","text":"التركيب بالإسناد"},{"id":"b","text":"التركيب بالوصل"},{"id":"c","text":"التركيب بالربط"},{"id":"d","text":"جملة بسيطة لا مركّبة"}]'::jsonb, 'a', '«الفلّاحُ» مبتدأٌ، وجملة «يزرعُ حقلَه» الفعليّة سدّت مسدّ الخبر، فوقعت جملةٌ صغرى ركنًا في الكبرى؛ وهذا هو التركيب بالإسناد، لا عطفٌ ولا أداة ربطٍ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d0ab4a2c-192c-57a6-a804-18d5c75de724', '929e2ef0-4ad9-5685-a7fa-b1f264210b29', '«أحبُّ مَن يصدُقُ في قولِه» — الاسم الموصول في هذه الجملة هو:', '[{"id":"a","text":"أحبُّ"},{"id":"b","text":"مَن"},{"id":"c","text":"يصدُقُ"},{"id":"d","text":"قولِه"}]'::jsonb, 'b', '«مَن» اسمٌ موصولٌ للعاقل، وصلتُه جملة «يصدُقُ في قولِه» التي فيها عائدٌ (ضميرٌ مستترٌ في «يصدُقُ» والهاء في «قولِه») يعود عليه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d0b9cca3-51aa-55f6-9e45-53cae32014e0', '929e2ef0-4ad9-5685-a7fa-b1f264210b29', '«سافرَ أخي ثمّ عادَ» — نوع التركيب في هذه الجملة:', '[{"id":"a","text":"التركيب بالإسناد"},{"id":"b","text":"التركيب بالربط"},{"id":"c","text":"التركيب بالوصل"},{"id":"d","text":"جملة بسيطة لا مركّبة"}]'::jsonb, 'c', 'جملتان تامّتان (سافرَ أخي) و(عادَ) وُصِلتا بحرف العطف «ثمّ»؛ ووصلُ جملتين مستقلّتين بحرف عطفٍ هو التركيب بالوصل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
