  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ae4b5933-cabc-53ea-ad18-04f8220d0035', '929e2ef0-4ad9-5685-a7fa-b1f264210b29', '«التّلميذُ الّذي يجتهدُ ينجحُ» — جملة «يجتهدُ» بعد الاسم الموصول:', '[{"id":"a","text":"في محلّ رفع خبر"},{"id":"b","text":"في محلّ نصب حال"},{"id":"c","text":"في محلّ نصب نعت"},{"id":"d","text":"لا محلّ لها، صلة الموصول"}]'::jsonb, 'd', '«يجتهدُ» جملةُ صلةٍ للموصول «الّذي»، وصلةُ الموصول لا محلّ لها من الإعراب أبدًا. وخبرُ المبتدأ «التّلميذُ» هو جملة «ينجحُ» لا «يجتهدُ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('16d0ed7e-0da0-532b-a4ec-47a3b3571a1a', '929e2ef0-4ad9-5685-a7fa-b1f264210b29', '«قالَ المعلّمُ: العلمُ نورٌ» — جملة «العلمُ نورٌ»:', '[{"id":"a","text":"جملة ابتدائيّة لا محلّ لها"},{"id":"b","text":"في محلّ نصب مفعول به (مقول القول)"},{"id":"c","text":"في محلّ رفع خبر"},{"id":"d","text":"في محلّ نصب حال"}]'::jsonb, 'b', 'جملة «العلمُ نورٌ» هي مقولُ القول، وقعت مفعولًا به للفعل «قالَ»، فهي في محلّ نصب مفعول به؛ فالجملُ الواقعةُ مقولًا للقول لها محلّ نصب.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e52bbcdd-e353-551b-8e53-ee38b6cbf6a8', '929e2ef0-4ad9-5685-a7fa-b1f264210b29', '«مررتُ بطفلٍ يلعبُ» — جملة «يلعبُ»:', '[{"id":"a","text":"في محلّ نصب حال"},{"id":"b","text":"في محلّ رفع خبر"},{"id":"c","text":"في محلّ جرّ نعت"},{"id":"d","text":"لا محلّ لها، صلة الموصول"}]'::jsonb, 'c', '«طفلٍ» نكرةٌ مجرورةٌ بالباء، والجملةُ بعد النكرةِ نعتٌ يتبعُها في إعرابها؛ فجملة «يلعبُ» في محلّ جرّ نعت. ولو كانت «بالطّفلِ» معرفةً لصارت حالًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
