INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ff8f9234-c192-51a6-9efe-8a7d3f50a691', '74845f6c-b6e9-59cd-a5c3-fee2d13cfadb', 'الجملة المعطوفة على جملةٍ لا محلّ لها من الإعراب تكون:', '[{"id":"a","text":"في محلّ رفع دائمًا"},{"id":"b","text":"لا محلّ لها من الإعراب أيضًا"},{"id":"c","text":"في محلّ نصب دائمًا"},{"id":"d","text":"تُعرب بحسب موقعها هي"}]'::jsonb, 'b', 'القاعدة: المعطوفُ يأخذ حكمَ المعطوف عليه؛ فالجملة المعطوفة على جملةٍ لا محلّ لها تكون هي أيضًا لا محلّ لها، والمعطوفة على جملةٍ لها محلّ تشاركها محلَّها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a3ba4a5c-35cb-5605-a4a1-09ef9c70997e', '74845f6c-b6e9-59cd-a5c3-fee2d13cfadb', '«رأيتُ القافلةَ تسيرُ في الصّحراءِ» — جملة «تسيرُ في الصّحراءِ»:', '[{"id":"a","text":"في محلّ نصب نعت لـ«القافلةَ»"},{"id":"b","text":"لا محلّ لها، صلة موصول"},{"id":"c","text":"في محلّ نصب حال من «القافلةَ»"},{"id":"d","text":"في محلّ رفع خبر"}]'::jsonb, 'c', '«القافلةَ» معرفةٌ (بأل)، والجملةُ بعد المعرفةِ حالٌ لا نعتٌ؛ فجملة «تسيرُ في الصّحراءِ» في محلّ نصب حال تصف هيئةَ القافلة، وعائدُها الضميرُ المستترُ في «تسيرُ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7064430a-8448-5ea3-85d6-a2f0eb18a253', '74845f6c-b6e9-59cd-a5c3-fee2d13cfadb', '«الّذي يزرعُ يحصدُ» — ما إعراب الاسم الموصول «الّذي»؟', '[{"id":"a","text":"مبتدأ، في محلّ رفع"},{"id":"b","text":"فاعل، في محلّ رفع"},{"id":"c","text":"لا محلّ له، صلة موصول"},{"id":"d","text":"مفعول به، في محلّ نصب"}]'::jsonb, 'a', '«الّذي» اسمٌ موصولٌ مبنيٌّ في محلّ رفع مبتدأ، وصلتُه جملة «يزرعُ» (لا محلّ لها)، وخبرُه جملة «يحصدُ» في محلّ رفع. والموصولُ يُعرب بحسب موقعه لا بحسب صلتِه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47c4e32c-7fd3-57f8-8ef1-b53d2d0ac729', '74845f6c-b6e9-59cd-a5c3-fee2d13cfadb', '«اشتريتُ ثوبًا لونُه زاهٍ» — جملة «لونُه زاهٍ»:', '[{"id":"a","text":"في محلّ نصب حال"},{"id":"b","text":"في محلّ رفع خبر"},{"id":"c","text":"لا محلّ لها، صلة موصول"},{"id":"d","text":"في محلّ نصب نعت لـ«ثوبًا»"}]'::jsonb, 'd', '«ثوبًا» نكرةٌ منصوبةٌ (مفعول به)، والجملةُ الاسميّةُ «لونُه زاهٍ» بعد النكرةِ نعتٌ يتبعُها في النصبِ؛ فهي في محلّ نصب نعت، وعائدُها الهاءُ في «لونُه».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6bfa6db2-cd61-5237-8b9f-34141d5745ef', '74845f6c-b6e9-59cd-a5c3-fee2d13cfadb', '«خرجَ الرّجلُ والشّمسُ تغربُ» — جملة «الشّمسُ تغربُ» بعد الواو:', '[{"id":"a","text":"معطوفة، لا محلّ لها"},{"id":"b","text":"في محلّ رفع خبر"},{"id":"c","text":"في محلّ نصب حال (واو الحال)"},{"id":"d","text":"لا محلّ لها، صلة موصول"}]'::jsonb, 'c', 'الواوُ هنا واوُ الحال لا العطف؛ لأنّ الجملةَ بعدها تصف هيئةَ خروج الرّجل. فجملة «الشّمسُ تغربُ» في محلّ نصب حال. ولو كانت واوَ عطفٍ لوصلت جملتين متكافئتين في المعنى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c5bc2ee-eba5-5c99-848c-0e266a85c9d4', '74845f6c-b6e9-59cd-a5c3-fee2d13cfadb', 'قالَ تلميذٌ في «جاءَ رجلٌ يبتسمُ»: جملةُ «يبتسمُ» حالٌ في محلّ نصب. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، التّحليل صحيح"},{"id":"b","text":"الخطأ أنّ «رجلٌ» نكرةٌ، فالجملةُ نعتٌ لا حالٌ"},{"id":"c","text":"الخطأ أنّ الجملةَ صلةُ موصولٍ لا محلّ لها"},{"id":"d","text":"الخطأ أنّ الجملةَ خبرٌ في محلّ رفع"}]'::jsonb, 'b', 'المنعوتُ «رجلٌ» نكرةٌ، والجملةُ بعد النكرةِ نعتٌ لا حالٌ؛ فجملة «يبتسمُ» في محلّ رفع نعت لـ«رجلٌ» المرفوع. الخطأُ الشّائع: الحكمُ بالحالِ دون النّظر إلى تنكير صاحبها أو تعريفه.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

