  ('77a4ea9d-d280-5584-946b-282e3c515b22', 'e7316dd2-63a5-5a75-b004-aab4c1ab4f9c', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: إعرابُ الموصولِ ومحلُّ الجملِ', 3, 120, 30, 'boss', 'admin', 5)
