INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a23a1de2-bf9c-50e9-a3a7-ce5ce6419949', '77a4ea9d-d280-5584-946b-282e3c515b22', '«أصبحَ الجوُّ يبردُ» — جملة «يبردُ»:', '[{"id":"a","text":"في محلّ نصب خبر «أصبحَ»"},{"id":"b","text":"في محلّ رفع خبر"},{"id":"c","text":"في محلّ نصب حال"},{"id":"d","text":"لا محلّ لها، صلة موصول"}]'::jsonb, 'a', '«أصبحَ» ناسخٌ يرفع الاسم وينصب الخبر؛ ووقعت جملة «يبردُ» خبرًا له، فهي في محلّ نصب خبر «أصبحَ»، وعائدُها الضميرُ المستترُ في «يبردُ».', 1)
ON CONFLICT (id) DO UPDATE SET
