INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3eed3101-baa3-51f0-acf0-3bd0acdce0f8', '77a4ea9d-d280-5584-946b-282e3c515b22', '«جاءَ الّذي فازَ» — ما إعراب الاسم الموصول «الّذي»؟', '[{"id":"a","text":"مبتدأ، في محلّ رفع"},{"id":"b","text":"مفعول به، في محلّ نصب"},{"id":"c","text":"فاعل «جاءَ»، في محلّ رفع"},{"id":"d","text":"لا محلّ له، صلة موصول"}]'::jsonb, 'c', '«الّذي» اسمٌ موصولٌ مبنيٌّ في محلّ رفع فاعل «جاءَ»؛ وصلتُه جملة «فازَ» لا محلّ لها. والموصولُ يُعرب بموقعه في الجملة الكبرى، لا بصلتِه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
