INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c1b94bd1-4ee4-51a6-9889-d1ff3d58504b', '77a4ea9d-d280-5584-946b-282e3c515b22', '«قرأتُ ما كُتِبَ على اللّوحِ» — ما إعراب الاسم الموصول «ما»؟', '[{"id":"a","text":"فاعل، في محلّ رفع"},{"id":"b","text":"مفعول به لـ«قرأتُ»، في محلّ نصب"},{"id":"c","text":"مبتدأ، في محلّ رفع"},{"id":"d","text":"لا محلّ له، صلة موصول"}]'::jsonb, 'b', '«ما» اسمٌ موصولٌ لغير العاقل، مبنيٌّ في محلّ نصب مفعول به للفعل «قرأتُ»؛ وصلتُه جملة «كُتِبَ على اللّوحِ» لا محلّ لها، وعائدُها نائبُ الفاعل المستترُ في «كُتِبَ».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('91c1794b-c3d3-52d2-adac-e4d70869da17', '77a4ea9d-d280-5584-946b-282e3c515b22', '«التّلميذُ يقرأُ ويكتبُ» — جملة «يكتبُ» المعطوفة:', '[{"id":"a","text":"لا محلّ لها، معطوفة"},{"id":"b","text":"في محلّ نصب حال"},{"id":"c","text":"في محلّ نصب مفعول به"},{"id":"d","text":"في محلّ رفع، معطوفة على خبرٍ لها محلّ رفع"}]'::jsonb, 'd', 'جملة «يقرأُ» خبرٌ للمبتدأ «التّلميذُ» في محلّ رفع، وجملة «يكتبُ» معطوفةٌ عليها بالواو فتأخذ حكمَها: في محلّ رفع. فالمعطوفُ على جملةٍ لها محلّ يشاركُها محلَّها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('01045355-003a-521d-86af-c35046750ce8', '77a4ea9d-d280-5584-946b-282e3c515b22', '«النّجارُ يصنعُ البابَ» — ما محلّ الجملة الكبرى كلِّها من الإعراب؟', '[{"id":"a","text":"ابتدائيّة، لا محلّ لها من الإعراب"},{"id":"b","text":"في محلّ رفع خبر"},{"id":"c","text":"في محلّ نصب حال"},{"id":"d","text":"في محلّ جرّ مضاف إليه"}]'::jsonb, 'a', 'الجملةُ الكبرى «النّجارُ يصنعُ البابَ» جملةٌ ابتدائيّةٌ استُهلّ بها الكلام، فلا محلّ لها. أمّا الجملةُ الصغرى «يصنعُ البابَ» فخبرٌ للمبتدأ في محلّ رفع؛ فلا تخلط بين محلّ الكبرى ومحلّ الصغرى.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('76e3ea60-4dcb-5fb9-b2db-bd1ade5ca77a', '77a4ea9d-d280-5584-946b-282e3c515b22', '«أزورُك يومَ تعودُ» — جملة «تعودُ» بعد الظّرف «يومَ»:', '[{"id":"a","text":"في محلّ نصب حال"},{"id":"b","text":"لا محلّ لها، صلة موصول"},{"id":"c","text":"في محلّ جرّ مضاف إليه"},{"id":"d","text":"في محلّ رفع خبر"}]'::jsonb, 'c', '«يومَ» ظرفٌ يُضاف إلى الجمل؛ فجملة «تعودُ» في محلّ جرّ مضاف إليه بعده. والمحلّ جرٌّ لأنّ المضافَ إليه مجرورٌ، وإن كان الظّرفُ نفسُه منصوبًا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

