  ('8751fedf-02ae-57e3-8b38-7567f41c6848', 'e7316dd2-63a5-5a75-b004-aab4c1ab4f9c', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: أسرارُ الجملةِ الموصولةِ والحالِ', 4, 300, 60, 'challenge', 'admin', 6)
