INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ff17861c-83d1-5fae-880a-cd622837176b', '8751fedf-02ae-57e3-8b38-7567f41c6848', 'الاسم الموصول (الّذي، الّتي، مَن، ما…) من حيث الإعراب:', '[{"id":"a","text":"لا محلّ له من الإعراب مطلقًا"},{"id":"b","text":"يكون فاعلًا دائمًا"},{"id":"c","text":"يكون في محلّ رفع دائمًا"},{"id":"d","text":"مبنيٌّ يُعرب بحسب موقعه في الجملة الكبرى"}]'::jsonb, 'd', 'الاسمُ الموصول مبنيٌّ، فيُعرب في محلٍّ بحسب موقعه (فاعلًا أو مفعولًا أو مبتدأً أو مجرورًا…). أمّا الّتي لا محلّ لها فهي صلتُه، لا هو.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('995f88a2-99ac-55ba-89cd-c839d0464737', '8751fedf-02ae-57e3-8b38-7567f41c6848', '«عادَ المسافرونَ الّذينَ غابوا» — ما إعراب الاسم الموصول «الّذينَ»؟', '[{"id":"a","text":"لا محلّ له، صلة موصول"},{"id":"b","text":"نعت لـ«المسافرونَ»، في محلّ رفع"},{"id":"c","text":"فاعل «عادَ»، في محلّ رفع"},{"id":"d","text":"بدل من «المسافرونَ»، في محلّ رفع"}]'::jsonb, 'b', '«المسافرونَ» معرفةٌ مرفوعةٌ (فاعل «عادَ»)، والاسمُ الموصول بعد المعرفةِ نعتٌ يتبعُها في الرفعِ؛ فـ«الّذينَ» نعتٌ في محلّ رفع، وصلتُه جملة «غابوا» لا محلّ لها، وعائدُها واوُ الجماعة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c81ef38-056e-5f58-aa11-27ec820f1e85', '8751fedf-02ae-57e3-8b38-7567f41c6848', '«هذا بيتٌ نوافذُه واسعةٌ» — جملة «نوافذُه واسعةٌ»:', '[{"id":"a","text":"في محلّ رفع نعت لـ«بيتٌ»"},{"id":"b","text":"في محلّ رفع خبر «هذا»"},{"id":"c","text":"في محلّ نصب حال"},{"id":"d","text":"لا محلّ لها، صلة موصول"}]'::jsonb, 'a', '«بيتٌ» نكرةٌ مرفوعةٌ (خبر «هذا»)، والجملةُ الاسميّةُ «نوافذُه واسعةٌ» بعد النكرةِ نعتٌ يتبعُها في الرفعِ؛ فهي في محلّ رفع نعت، وعائدُها الهاءُ في «نوافذُه».', 3)
ON CONFLICT (id) DO UPDATE SET
