  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4e311e2-70d9-5f6f-b3af-a269477e47c2', '8751fedf-02ae-57e3-8b38-7567f41c6848', 'قالَ تلميذٌ في «أعجبني الّذي كتبتَه»: «الّذي» في محلّ نصب لأنّه جاء بعد الفعل. أين الخطأ؟', '[{"id":"a","text":"لا خطأ، التّحليل صحيح"},{"id":"b","text":"الخطأ أنّ صلةَ الموصول لها محلّ نصب"},{"id":"c","text":"الخطأ أنّ «الّذي» فاعلُ «أعجبَ» في محلّ رفع لا نصب"},{"id":"d","text":"الخطأ أنّ «كتبتَه» ليست صلةَ الموصول"}]'::jsonb, 'c', '«الّذي» فاعلُ الفعل «أعجبَ» (أعجبني الّذي… أي: أعجبني هذا)، فهو في محلّ رفع فاعل، لا نصب. والموصولُ يُعرب بموقعه؛ وصلتُه «كتبتَه» لا محلّ لها، وعائدُها الهاءُ في «كتبتَه».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('06b7ceb5-ae29-5df4-af6e-a6bdf2b46265', '8751fedf-02ae-57e3-8b38-7567f41c6848', 'أيُّ الجملِ التّاليةِ تركيبُها بالإسناد؟', '[{"id":"a","text":"«جاءَ زيدٌ وعمرٌو»"},{"id":"b","text":"«الحقلُ أزهارُه يانعةٌ»"},{"id":"c","text":"«سافرَ أبي ثمّ رجعَ»"},{"id":"d","text":"«قرأتُ كتابًا مفيدًا»"}]'::jsonb, 'b', 'في «الحقلُ أزهارُه يانعةٌ» وقعت جملةٌ صغرى «أزهارُه يانعةٌ» خبرًا للمبتدأ «الحقلُ»، فهو تركيبٌ بالإسناد. أمّا «جاءَ زيدٌ وعمرٌو» فعطفُ مفردٍ (بسيطة)، و«سافرَ أبي ثمّ رجعَ» تركيبٌ بالوصل، و«قرأتُ كتابًا مفيدًا» جملةٌ بسيطةٌ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('30467a47-1c29-524b-b6a1-41b5b72709a2', '8751fedf-02ae-57e3-8b38-7567f41c6848', 'قالَ تلميذٌ في «شاهدتُ الفارسَ يمتطي جوادَه»: جملةُ «يمتطي جوادَه» نعتٌ لـ«الفارسَ». أين الخطأ؟', '[{"id":"a","text":"لا خطأ، التّحليل صحيح"},{"id":"b","text":"الخطأ أنّ الجملةَ صلةُ موصولٍ لا محلّ لها"},{"id":"c","text":"الخطأ أنّ «الفارسَ» معرفةٌ، فالجملةُ حالٌ لا نعتٌ"},{"id":"d","text":"الخطأ أنّ الجملةَ خبرٌ في محلّ رفع"}]'::jsonb, 'c', '«الفارسَ» معرفةٌ (بأل)، والجملةُ بعد المعرفةِ حالٌ لا نعتٌ؛ فجملة «يمتطي جوادَه» في محلّ نصب حال. القاعدةُ الحاسمة: بعد النكرةِ نعتٌ، وبعد المعرفةِ حالٌ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('5ee591f2-2eff-5304-94b5-89af4a1347cd', '9c0c6656-27fd-5a19-9686-7973e09dd6ed', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7a7c133-b198-5a69-bb90-8af11e28c1a3', '5ee591f2-2eff-5304-94b5-89af4a1347cd', 'على أيِّ وزنٍ يُصاغ اسم التفضيل صياغةً مباشرةً؟', '[{"id":"a","text":"أفعَل"},{"id":"b","text":"فَعّال"},{"id":"c","text":"مِفعال"},{"id":"d","text":"فاعِل"}]'::jsonb, 'a', 'يُصاغ اسم التفضيل على وزنِ (أفعَل): كَرُمَ ← أكرَم ؛ عَظُمَ ← أعظَم. أمّا (فَعّال) و(مِفعال) فمن صيغِ المبالغةِ واسمِ الآلةِ، و(فاعِل) اسمُ فاعلٍ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f984599c-68ef-5b26-a7f0-cd2b48a9c28b', '5ee591f2-2eff-5304-94b5-89af4a1347cd', 'في «العلمُ أنفعُ من المالِ»، ما المفضَّلُ عليه؟', '[{"id":"a","text":"العلمُ"},{"id":"b","text":"أنفعُ"},{"id":"c","text":"المالِ"},{"id":"d","text":"مِن"}]'::jsonb, 'c', 'المفضَّلُ عليه هو الطرفُ الذي دخلتْ عليه «مِن» الجارّةُ، وهو «المالِ». أمّا «العلمُ» فهو المفضَّلُ، و«أنفعُ» اسمُ التفضيلِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('312cda54-c586-52d9-8c31-6ab36f4c0f1f', '5ee591f2-2eff-5304-94b5-89af4a1347cd', 'ما الحرفُ الذي يجرُّ المفضَّلَ عليه بعدَ اسم التفضيل المجرّدِ؟', '[{"id":"a","text":"إلى"},{"id":"b","text":"عن"},{"id":"c","text":"في"},{"id":"d","text":"مِن"}]'::jsonb, 'd', 'المفضَّلُ عليه يُجرّ بحرفِ «مِن»: الحديدُ أصلبُ من النّحاسِ. ولا يُجرّ بـ«إلى» أو «عن» أو «في».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f28f306e-1cb9-54d5-9250-c8ecd3f07a8b', '5ee591f2-2eff-5304-94b5-89af4a1347cd', 'أيُّ الأفعالِ الآتيةِ يُصاغ منه اسم التفضيل صياغةً مباشرةً؟', '[{"id":"a","text":"اجتهدَ"},{"id":"b","text":"كَبُرَ"},{"id":"c","text":"اخضرَّ"},{"id":"d","text":"كانَ"}]'::jsonb, 'b', '«كَبُرَ» فعلٌ ثلاثيٌّ مجرّدٌ تامٌّ متصرّفٌ قابلٌ للتفاوتِ، فيُصاغ منه (أكبَر). أمّا «اجتهدَ» فمزيدٌ، و«اخضرَّ» وصفُ لونٍ على وزنِ أفعلَ فعلاءَ، و«كانَ» فعلٌ ناقصٌ غيرُ تامٍّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('37e7c77f-717a-5167-97db-f3d37d8e5294', '5ee591f2-2eff-5304-94b5-89af4a1347cd', 'إذا اقترنَ اسم التفضيل بـ«أل» فما حكمُه في المطابقةِ؟', '[{"id":"a","text":"يلزمُ الإفرادَ والتذكيرَ دائمًا"},{"id":"b","text":"يجبُ أن يطابقَ موصوفَه إفرادًا وتثنيةً وجمعًا وتذكيرًا وتأنيثًا"},{"id":"c","text":"تدخلُ عليه «مِن» وجوبًا"},{"id":"d","text":"يُبنى على الفتحِ فلا يتغيّرُ"}]'::jsonb, 'b', 'اسم التفضيل المقترنُ بـ«أل» يجبُ أن يطابقَ موصوفَه: الأفضل، الفُضلى، الأفضلان، الأفضلون، الفُضليات، ولا تدخلُ عليه «مِن». أمّا لزومُ الإفرادِ والتذكيرِ فحكمُ المجرّدِ والمضافِ إلى نكرةٍ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('88cf0972-016b-5bf3-ac9d-207cec67ae50', '9c0c6656-27fd-5a19-9686-7973e09dd6ed', 'arabic-8eme', '⭐ تمرين: أوّلُ خطوةٍ مع اسم التفضيل', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2670a8cc-e33d-514b-801a-fee914398e8f', '88cf0972-016b-5bf3-ac9d-207cec67ae50', 'على أيِّ معنًى يدلّ اسم التفضيل؟', '[{"id":"a","text":"وصفِ اسمٍ واحدٍ دونَ مقارنةٍ بغيرِه"},{"id":"b","text":"اشتراكِ شيئين في صفةٍ وزيادةِ أحدِهما فيها على الآخرِ"},{"id":"c","text":"زمنِ وقوعِ الفعلِ ومكانِه"},{"id":"d","text":"الآلةِ التي يقعُ بها الفعلُ"}]'::jsonb, 'b', 'اسم التفضيل يدلّ على أنّ شيئين اشتركا في صفةٍ وزاد أحدُهما على الآخرِ فيها، نحو: الذهبُ أغلى من الفضّةِ. أمّا الوصفُ دونَ مقارنةٍ فهو النعتُ، والزمانُ والمكانُ والآلةُ صيغٌ صرفيّةٌ أخرى.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('087e7d9b-6196-59dc-90ff-e07e3571923d', '88cf0972-016b-5bf3-ac9d-207cec67ae50', 'في «الذهبُ أغلى من الفضّةِ»، مَن المفضَّلُ؟', '[{"id":"a","text":"الفضّةِ"},{"id":"b","text":"أغلى"},{"id":"c","text":"الذهبُ"},{"id":"d","text":"مِن"}]'::jsonb, 'c', 'المفضَّلُ هو الطرفُ الذي حكمنا له بالزيادةِ، وهو «الذهبُ». و«الفضّةِ» هي المفضَّلُ عليه لأنّ «مِن» دخلتْ عليها، و«أغلى» اسمُ التفضيلِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('695bf656-94c7-54b2-9ab6-c178c505efd4', '88cf0972-016b-5bf3-ac9d-207cec67ae50', 'صُغِ اسم التفضيل من الفعلِ «كَرُمَ».', '[{"id":"a","text":"كريم"},{"id":"b","text":"أكرَم"},{"id":"c","text":"مكروم"},{"id":"d","text":"كِرام"}]'::jsonb, 'b', 'اسم التفضيل على وزنِ أفعَل، فمن «كَرُمَ» نقول «أكرَم». أمّا «كريم» فاسمُ فاعلٍ (صفةٌ مشبّهةٌ)، و«مكروم» اسمُ مفعولٍ، و«كِرام» جمعٌ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ee84e7b3-613e-55f1-a257-af3033c01607', '88cf0972-016b-5bf3-ac9d-207cec67ae50', 'أكملْ (اسمُ التفضيلِ مجرّدٌ): «الطالبتانِ ... من غيرِهما».', '[{"id":"a","text":"أفضلُ"},{"id":"b","text":"فُضلَيان"},{"id":"c","text":"الفُضلى"},{"id":"d","text":"فُضلَيات"}]'::jsonb, 'a', 'اسم التفضيل المجرّدُ من «أل» والإضافةِ يلزمُ الإفرادَ والتذكيرَ دائمًا، فيبقى «أفضلُ» وإن كان المفضَّلُ مثنّى مؤنّثًا، وبعدَه «مِن».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('50e2f0e7-3aff-5f8c-bbcb-afed42b07ac6', '88cf0972-016b-5bf3-ac9d-207cec67ae50', 'بأيِّ حرفٍ يُجرّ المفضَّلُ عليه بعدَ اسم التفضيل المجرّدِ؟', '[{"id":"a","text":"الباءِ"},{"id":"b","text":"اللامِ"},{"id":"c","text":"الكافِ"},{"id":"d","text":"مِن"}]'::jsonb, 'd', 'المفضَّلُ عليه يُجرّ بـ«مِن»: النهارُ أطولُ من الليلِ في الصيفِ. ولا تُستعملُ الباءُ ولا اللامُ ولا الكافُ لهذا الغرضِ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba38e4bc-3232-5eb2-b708-5a5bc636e8ca', '88cf0972-016b-5bf3-ac9d-207cec67ae50', 'في «البحرُ أوسعُ من النّهرِ»، ما إعرابُ «أوسعُ»؟', '[{"id":"a","text":"خبرٌ مرفوعٌ وعلامةُ رفعِه الضمّةُ"},{"id":"b","text":"مبتدأٌ مرفوعٌ"},{"id":"c","text":"نعتٌ مجرورٌ"},{"id":"d","text":"فاعلٌ مرفوعٌ"}]'::jsonb, 'a', '«البحرُ» مبتدأٌ، و«أوسعُ» اسمُ تفضيلٍ وقعَ خبرًا مرفوعًا وعلامةُ رفعِه الضمّةُ، و«من النّهرِ» جارٌّ ومجرورٌ (المفضَّلُ عليه).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('bf0c0ef5-5dd0-58a3-aa1b-33e51a41ac79', '9c0c6656-27fd-5a19-9686-7973e09dd6ed', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: شروطُ الصوغِ وأحكامُ اسم التفضيل', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
