  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83b80c60-a4bf-5328-9bae-28ff1bf951f8', 'bf0c0ef5-5dd0-58a3-aa1b-33e51a41ac79', 'أيُّ فعلٍ يمتنعُ صوغُ اسم التفضيل منه صياغةً مباشرةً؟', '[{"id":"a","text":"استخرجَ"},{"id":"b","text":"عَظُمَ"},{"id":"c","text":"صَغُرَ"},{"id":"d","text":"بَعُدَ"}]'::jsonb, 'a', '«استخرجَ» فعلٌ مزيدٌ (سِتّةُ أحرفٍ)، ومن شروطِ الصوغِ المباشرِ أن يكونَ الفعلُ ثلاثيًّا مجرّدًا؛ فيمتنعُ منه المباشرُ. أمّا «عَظُمَ» و«صَغُرَ» و«بَعُدَ» فثلاثيّةٌ مجرّدةٌ تصلحُ للصوغِ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc35046f-c5f2-5666-b7bc-9fbe04b35128', 'bf0c0ef5-5dd0-58a3-aa1b-33e51a41ac79', 'للتفضيلِ من الفعلِ المزيدِ «اجتهدَ» نقول:', '[{"id":"a","text":"هو أجهَدُ من أخيه"},{"id":"b","text":"هو أكثرُ اجتهادًا من أخيه"},{"id":"c","text":"هو مُجتهِدٌ من أخيه"},{"id":"d","text":"هو اجتهادٌ من أخيه"}]'::jsonb, 'b', 'لأنّ «اجتهدَ» مزيدٌ تعذّرَ صوغُ (أفعَل) منه، فنأتي بـ«أكثرُ» ثمّ مصدرِه «اجتهادًا» منصوبًا على أنّه تمييزٌ: هو أكثرُ اجتهادًا من أخيه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b700593-2206-520f-8fc7-6d188cc931ff', 'bf0c0ef5-5dd0-58a3-aa1b-33e51a41ac79', 'التفضيلُ في اللونِ من «حَمِرَ» (أحمر/حمراء) يكونُ بقولِنا:', '[{"id":"a","text":"هذا الثوبُ أشدُّ حُمرةً من ذاك"},{"id":"b","text":"هذا الثوبُ أحمرُ من ذاك"},{"id":"c","text":"هذا الثوبُ حمراءُ من ذاك"},{"id":"d","text":"هذا الثوبُ محمرٌّ من ذاك"}]'::jsonb, 'a', 'الوصفُ «أحمر» على وزنِ أفعلَ الذي مؤنّثُه فعلاءُ (لونٌ)، فلا يُصاغ منه تفضيلٌ مباشرٌ. نأتي بـ«أشدُّ» ثمّ المصدرِ «حُمرةً» تمييزًا منصوبًا: أشدُّ حُمرةً.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4e9bfb9f-da64-5734-affc-2b90933bbd82', 'bf0c0ef5-5dd0-58a3-aa1b-33e51a41ac79', 'أكملْ (اسمُ التفضيلِ مضافٌ إلى نكرةٍ): «مريمُ ... طالبةٍ في المعهدِ».', '[{"id":"a","text":"الفُضلى"},{"id":"b","text":"فُضلى"},{"id":"c","text":"أفضلُ"},{"id":"d","text":"فُضليات"}]'::jsonb, 'c', 'اسم التفضيل المضافُ إلى نكرةٍ يلزمُ الإفرادَ والتذكيرَ كالمجرّدِ، فيبقى «أفضلُ» وإن كان المفضَّلُ مؤنّثًا: مريمُ أفضلُ طالبةٍ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b58c5355-2728-54f3-ac91-21244edd38c7', 'bf0c0ef5-5dd0-58a3-aa1b-33e51a41ac79', 'أكملْ (اسمُ التفضيلِ معرّفٌ بأل): «هؤلاءِ الفتياتُ هنّ ... في النادي».', '[{"id":"a","text":"الأفضلُ"},{"id":"b","text":"أفضلُ"},{"id":"c","text":"الفُضلى"},{"id":"d","text":"الفُضليات"}]'::jsonb, 'd', 'المقترنُ بـ«أل» يطابقُ موصوفَه؛ و«الفتياتُ» جمعُ مؤنّثٍ، فيطابقُه اسمُ التفضيلِ بجمعِ المؤنّثِ «الفُضليات». و«الفُضلى» للمفردةِ، و«أفضلُ» بلا أل لا يقترنُ بها.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bd3cf697-69bd-52bd-b1fe-dd6f221fcdcd', 'bf0c0ef5-5dd0-58a3-aa1b-33e51a41ac79', 'في «عليٌّ أكثرُ علمًا من زميلِه»، ما إعرابُ «علمًا»؟', '[{"id":"a","text":"مفعولٌ به منصوبٌ"},{"id":"b","text":"تمييزٌ منصوبٌ"},{"id":"c","text":"حالٌ منصوبةٌ"},{"id":"d","text":"مفضَّلٌ عليه مجرورٌ"}]'::jsonb, 'b', 'بعدَ «أكثرُ» يأتي المصدرُ منصوبًا على التمييزِ يكشفُ جهةَ المفاضلةِ، فـ«علمًا» تمييزٌ منصوبٌ. أمّا المفضَّلُ عليه فهو «زميلِه» المجرورُ بـ«مِن».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('119db2fc-454b-54de-b10e-6f9f098aa43d', '9c0c6656-27fd-5a19-9686-7973e09dd6ed', 'arabic-8eme', '⭐⭐ تمرين: صوغُ اسم التفضيل ومطابقتُه', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('78d91aa2-5586-5033-b50e-9e1957117874', '119db2fc-454b-54de-b10e-6f9f098aa43d', 'أيُّ الكلماتِ الآتيةِ اسمُ تفضيلٍ على وزنِ أفعَل؟', '[{"id":"a","text":"أعظَم"},{"id":"b","text":"مِصباح"},{"id":"c","text":"عظيم"},{"id":"d","text":"عظمة"}]'::jsonb, 'a', '«أعظَم» على وزنِ أفعَل، فهو اسمُ تفضيلٍ. أمّا «مِصباح» فاسمُ آلةٍ، و«عظيم» صفةٌ مشبّهةٌ، و«عظمة» مصدرٌ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3828bfb2-265b-5d7b-b9c1-d30b8c86ab72', '119db2fc-454b-54de-b10e-6f9f098aa43d', 'في «الصيفُ أحرُّ من الشتاءِ»، ما موقعُ «الشتاءِ» في تركيبِ التفضيلِ؟', '[{"id":"a","text":"المفضَّلُ"},{"id":"b","text":"المفضَّلُ عليه"},{"id":"c","text":"تمييزٌ"},{"id":"d","text":"نعتٌ"}]'::jsonb, 'b', '«الشتاءِ» دخلتْ عليه «مِن» الجارّةُ، فهو المفضَّلُ عليه المجرورُ. و«الصيفُ» هو المفضَّلُ، و«أحرُّ» اسمُ التفضيلِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e4318ab4-cf66-52a8-b409-6655e721e620', '119db2fc-454b-54de-b10e-6f9f098aa43d', 'أكملْ (اسمُ التفضيلِ مجرّدٌ): «المجتهدونَ ... من الكسالى».', '[{"id":"a","text":"أفضلونَ"},{"id":"b","text":"الأفضلونَ"},{"id":"c","text":"أفضلُ"},{"id":"d","text":"فُضلى"}]'::jsonb, 'c', 'المجرّدُ من «أل» والإضافةِ يلزمُ الإفرادَ والتذكيرَ ولو كان المفضَّلُ جمعًا، وبعدَه «مِن»: المجتهدونَ أفضلُ من الكسالى.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('df6fc8d2-a92b-540a-87a7-19c6704b21f3', '119db2fc-454b-54de-b10e-6f9f098aa43d', 'ما الصيغةُ الصحيحةُ لمؤنّثِ اسم التفضيل معرّفًا بأل من «أفضل»؟', '[{"id":"a","text":"أفضلةٌ"},{"id":"b","text":"فَضْلاءُ"},{"id":"c","text":"الأفضلُ"},{"id":"d","text":"الفُضلى"}]'::jsonb, 'd', 'مؤنّثُ «أفعَل» على وزنِ «فُعلى»، فمؤنّثُ «الأفضل» معرّفًا بأل هو «الفُضلى»: فاطمةُ الفُضلى. أمّا «الأفضلُ» فللمذكّرِ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7cced81d-421c-5a6a-89d3-26ed0cb3185b', '119db2fc-454b-54de-b10e-6f9f098aa43d', 'أيُّ فعلٍ تتوفّرُ فيه شروطُ صوغِ اسم التفضيل مباشرةً؟', '[{"id":"a","text":"نِعمَ"},{"id":"b","text":"عُرِفَ"},{"id":"c","text":"شَرُفَ"},{"id":"d","text":"تعلّمَ"}]'::jsonb, 'c', '«شَرُفَ» ثلاثيٌّ مجرّدٌ تامٌّ متصرّفٌ مبنيٌّ للمعلومِ قابلٌ للتفاوتِ، فيُصاغ منه «أشرَف». أمّا «نِعمَ» فجامدٌ، و«عُرِفَ» مبنيٌّ للمجهولِ، و«تعلّمَ» مزيدٌ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('16da476e-1e0e-5cfb-975f-23248def20a1', '119db2fc-454b-54de-b10e-6f9f098aa43d', 'في «هؤلاءِ هم أفضلُ القومِ» (مضافٌ إلى معرفةٍ)، ما الوجهُ الآخرُ الجائزُ بالمطابقةِ؟', '[{"id":"a","text":"أفضلونَ القومِ"},{"id":"b","text":"أفاضلُ القومِ"},{"id":"c","text":"الفُضلى القومِ"},{"id":"d","text":"أفضلُ قومٍ"}]'::jsonb, 'b', 'المضافُ إلى معرفةٍ يجوزُ فيه الإفرادُ (أفضلُ القومِ) والمطابقةُ (أفاضلُ القومِ) بجمعِ التكسيرِ المطابقِ للجماعةِ. أمّا «أفضلُ قومٍ» فمضافٌ إلى نكرةٍ، وهو حكمٌ آخرُ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('5d47919a-606d-5927-bfa4-0c2f20f22199', '9c0c6656-27fd-5a19-9686-7973e09dd6ed', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: فخاخُ اسم التفضيل ودقائقُه', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4721737f-80ab-59f4-8ad1-e9cd2fad8a21', '5d47919a-606d-5927-bfa4-0c2f20f22199', 'الخطأُ في «الطالباتُ فُضلياتٌ من غيرِهنّ» أنّ اسم التفضيل المجرّدَ...', '[{"id":"a","text":"يجبُ أن يطابقَ في الجمعِ والتأنيثِ"},{"id":"b","text":"يلزمُ الإفرادَ والتذكيرَ، فالصوابُ: أفضلُ من غيرِهنّ"},{"id":"c","text":"لا يجوزُ أن تدخلَ عليه «مِن»"},{"id":"d","text":"يُبنى على الفتحِ فلا يُعرَب"}]'::jsonb, 'b', 'اسم التفضيل المجرّدُ (بلا أل وبلا إضافةٍ) يلزمُ الإفرادَ والتذكيرَ دائمًا، فلا يُطابَقُ؛ والصوابُ: الطالباتُ أفضلُ من غيرِهنّ. والمطابقةُ إنّما تكونُ مع «أل».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7bb92860-981a-5920-9894-45f820c80893', '5d47919a-606d-5927-bfa4-0c2f20f22199', 'أكملْ (اسمُ التفضيلِ مضافٌ إلى نكرةٍ): «زينبُ ... امرأةٍ في الحيِّ».', '[{"id":"a","text":"فُضلى"},{"id":"b","text":"الفُضلى"},{"id":"c","text":"أفضلُ"},{"id":"d","text":"فُضليات"}]'::jsonb, 'c', 'المضافُ إلى نكرةٍ يلزمُ الإفرادَ والتذكيرَ، فيبقى «أفضلُ» وإن كان المفضَّلُ مؤنّثًا: زينبُ أفضلُ امرأةٍ في الحيِّ. ولو أُضيفَ إلى معرفةٍ لجازتِ المطابقةُ (فُضلى النساءِ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4402d6a-481a-591e-b0a1-7243768ba4a4', '5d47919a-606d-5927-bfa4-0c2f20f22199', 'لِمَ لا يُصاغ اسم تفضيلٍ مباشرٌ من الفعلِ «ماتَ»؟', '[{"id":"a","text":"لأنّه فعلٌ جامدٌ لا مضارعَ له"},{"id":"b","text":"لأنّه مبنيٌّ للمجهولِ"},{"id":"c","text":"لأنّه مزيدٌ على ثلاثةِ أحرفٍ"},{"id":"d","text":"لأنّ صفتَه لا تقبلُ التفاوتَ (الزيادةَ والنقصَ)"}]'::jsonb, 'd', 'من شروطِ الصوغِ أن يكونَ الفعلُ قابلًا للتفاوتِ. و«ماتَ» صفتُه لا تتفاوتُ (فالموتُ لا يزيدُ ولا ينقصُ)، فلا مفاضلةَ فيه. وهو مع ذلك فعلٌ متصرّفٌ ثلاثيٌّ، فالمانعُ هو عدمُ قبولِ التفاوتِ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('818f8e75-d65a-592c-b675-f325e05cf07e', '5d47919a-606d-5927-bfa4-0c2f20f22199', 'للتفضيلِ من «عَرِجَ» (أعرج/عرجاء، وهي على وزنِ أفعلَ فعلاءَ) نقول:', '[{"id":"a","text":"هو أشدُّ عَرَجًا من أخيه"},{"id":"b","text":"هو أعرجُ من أخيه"},{"id":"c","text":"هو عرجاءُ من أخيه"},{"id":"d","text":"هو مُعرِجٌ من أخيه"}]'::jsonb, 'a', 'الوصفُ «أعرج» على وزنِ أفعلَ الذي مؤنّثُه فعلاءُ (عيبٌ)، فيتعذّرُ الصوغُ المباشرُ؛ فنأتي بـ«أشدُّ» ثمّ المصدرِ «عَرَجًا» تمييزًا منصوبًا: أشدُّ عَرَجًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2421dabd-1a21-5e6f-85d6-72b022f94135', '5d47919a-606d-5927-bfa4-0c2f20f22199', 'في «قرأتُ الكتابَ الأنفعَ»، ما إعرابُ «الأنفعَ»؟', '[{"id":"a","text":"نعتٌ منصوبٌ وعلامةُ نصبِه الفتحةُ"},{"id":"b","text":"مفعولٌ به منصوبٌ"},{"id":"c","text":"حالٌ منصوبةٌ"},{"id":"d","text":"خبرٌ مرفوعٌ"}]'::jsonb, 'a', '«الكتابَ» مفعولٌ به منصوبٌ، و«الأنفعَ» اسمُ تفضيلٍ تبعَه نعتًا فنُصِبَ مثلَه؛ فهو نعتٌ منصوبٌ وعلامةُ نصبِه الفتحةُ. واقترانُه بـ«أل» أجازَ وقوعَه نعتًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89faf74f-6618-5500-adf7-2eb8c205ad51', '5d47919a-606d-5927-bfa4-0c2f20f22199', 'في «هو أكثرُ الناسِ إحسانًا»، ما إعرابُ «الناسِ» و«إحسانًا» على الترتيبِ؟', '[{"id":"a","text":"«الناسِ» مفضَّلٌ عليه، و«إحسانًا» تمييزٌ"},{"id":"b","text":"كلاهما تمييزٌ منصوبٌ"},{"id":"c","text":"«الناسِ» مضافٌ إليه مجرورٌ، و«إحسانًا» تمييزٌ منصوبٌ"},{"id":"d","text":"«الناسِ» فاعلٌ مرفوعٌ، و«إحسانًا» مفعولٌ به"}]'::jsonb, 'c', '«أكثرُ» اسمُ تفضيلٍ أُضيفَ إلى «الناسِ» فهي مضافٌ إليه مجرورٌ، و«إحسانًا» مصدرٌ جاءَ بعدَ «أكثرُ» تمييزًا منصوبًا يكشفُ جهةَ الزيادةِ. ولا مفضَّلَ عليه هنا (لا «مِن»).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('544701af-a94e-52eb-bf20-b080c202621b', '9c0c6656-27fd-5a19-9686-7973e09dd6ed', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: تمرّسٌ على اسم التفضيل وإعرابِه', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ea19a11a-46e2-51a4-b72f-65a3b628eaa3', '544701af-a94e-52eb-bf20-b080c202621b', 'صُغِ اسم التفضيل من الفعلِ «شَرُفَ».', '[{"id":"a","text":"أشرَف"},{"id":"b","text":"شريف"},{"id":"c","text":"مشروف"},{"id":"d","text":"شُرفاء"}]'::jsonb, 'a', 'على وزنِ أفعَل من «شَرُفَ» نقول «أشرَف»: العملُ الصادقُ أشرَفُ من الكسلِ. أمّا «شريف» فصفةٌ مشبّهةٌ، و«شُرفاء» جمعٌ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fbada23a-04be-58af-8c36-7b30d5a5ef73', '544701af-a94e-52eb-bf20-b080c202621b', 'في «التمرُ أنفعُ من الحلوى للجسمِ»، المفضَّلُ عليه هو:', '[{"id":"a","text":"التمرُ"},{"id":"b","text":"الجسمِ"},{"id":"c","text":"الحلوى"},{"id":"d","text":"أنفعُ"}]'::jsonb, 'c', '«الحلوى» دخلتْ عليها «مِن»، فهي المفضَّلُ عليه. و«التمرُ» المفضَّلُ، و«أنفعُ» اسمُ التفضيلِ، و«للجسمِ» جارٌّ ومجرورٌ متعلّقٌ بالتفضيلِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b237d02d-8046-52f8-b320-b1ba793c5daf', '544701af-a94e-52eb-bf20-b080c202621b', 'أكملْ (اسمُ التفضيلِ معرّفٌ بأل، بالمطابقةِ): «الفتياتُ المجتهداتُ هنّ ... القسمِ».', '[{"id":"a","text":"أفضلُ"},{"id":"b","text":"الفُضلى"},{"id":"c","text":"أفاضلُ"},{"id":"d","text":"الفُضليات"}]'::jsonb, 'd', 'المقترنُ بـ«أل» يطابقُ موصوفَه؛ و«الفتياتُ» جمعُ مؤنّثٍ، فالمطابقُ هو «الفُضليات». و«الفُضلى» للمفردةِ، و«أفضلُ» و«أفاضلُ» بلا «أل» فلا يقترنانِ بها هنا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e37ddb4-14f6-521e-b6ba-24dbe7889056', '544701af-a94e-52eb-bf20-b080c202621b', 'للتفضيلِ من الفعلِ المزيدِ «انطلقَ» نقولُ: «هو ... من رفيقِه».', '[{"id":"a","text":"أطلقُ"},{"id":"b","text":"أكثرُ انطلاقًا"},{"id":"c","text":"مُنطلِقٌ"},{"id":"d","text":"أشدُّ مُنطلَقًا"}]'::jsonb, 'b', '«انطلقَ» مزيدٌ، فيتعذّرُ صوغُ (أفعَل) منه؛ نأتي بـ«أكثرُ» ثمّ المصدرِ الصريحِ «انطلاقًا» تمييزًا منصوبًا: هو أكثرُ انطلاقًا من رفيقِه.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0d8917f1-5bce-5e68-832f-1a52faa323ec', '544701af-a94e-52eb-bf20-b080c202621b', 'في «الصدقُ أنجى للإنسانِ»، ما موقعُ «أنجى» من الإعرابِ؟', '[{"id":"a","text":"مبتدأٌ مرفوعٌ"},{"id":"b","text":"نعتٌ مرفوعٌ"},{"id":"c","text":"خبرٌ مرفوعٌ"},{"id":"d","text":"تمييزٌ منصوبٌ"}]'::jsonb, 'c', '«الصدقُ» مبتدأٌ، و«أنجى» اسمُ تفضيلٍ وقعَ خبرًا مرفوعًا (وعلامةُ رفعِه ضمّةٌ مقدّرةٌ على الألفِ للتعذّرِ). و«للإنسانِ» جارٌّ ومجرورٌ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7e5c73ba-bde9-5ca8-91c0-2b47893e5bb4', '544701af-a94e-52eb-bf20-b080c202621b', 'لِمَ لا يُصاغ اسم تفضيلٍ مباشرٌ من الفعلِ «كُتِبَ»؟', '[{"id":"a","text":"لأنّه مبنيٌّ للمجهولِ لا للمعلومِ"},{"id":"b","text":"لأنّه فعلٌ ثلاثيٌّ مجرّدٌ"},{"id":"c","text":"لأنّه مبنيٌّ للمعلومِ"},{"id":"d","text":"لأنّ صفتَه قابلةٌ للتفاوتِ"}]'::jsonb, 'a', 'من شروطِ الصوغِ أن يكونَ الفعلُ مبنيًّا للمعلومِ. و«كُتِبَ» مبنيٌّ للمجهولِ، فيمتنعُ منه الصوغُ المباشرُ، ويُتوصّلُ إليه بـ«أكثر/أشدّ» + مصدرٍ عندَ الحاجةِ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('2d2e61c3-138e-5eb6-9e96-8e0ed2fb2afc', '9c0c6656-27fd-5a19-9686-7973e09dd6ed', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: أسرارُ اسم التفضيل وتمحيصُ المطابقةِ', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ddb9cb85-e9dd-5a07-8294-aa504ee224ca', '2d2e61c3-138e-5eb6-9e96-8e0ed2fb2afc', 'لِمَ لا يُصاغ اسم تفضيلٍ من الفعلِ «كانَ»؟', '[{"id":"a","text":"لأنّه فعلٌ ناقصٌ غيرُ تامٍّ"},{"id":"b","text":"لأنّه فعلٌ ثلاثيٌّ مجرّدٌ"},{"id":"c","text":"لأنّه مبنيٌّ للمعلومِ"},{"id":"d","text":"لأنّ صفتَه قابلةٌ للتفاوتِ"}]'::jsonb, 'a', 'من شروطِ الصوغِ أن يكونَ الفعلُ تامًّا. و«كانَ» فعلٌ ناقصٌ يحتاجُ إلى اسمٍ وخبرٍ ولا يدلّ على حدثٍ يتفاوتُ، فلا يُصاغ منه اسمُ تفضيلٍ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8f77791e-ffcd-58a7-85dc-b321d4fc137d', '2d2e61c3-138e-5eb6-9e96-8e0ed2fb2afc', '«اسودَّ» وصفٌ على وزنِ أفعلَ فعلاءَ (أسود/سوداء) وهو أيضًا فعلٌ مزيدٌ؛ فالتفضيلُ منه:', '[{"id":"a","text":"هذا الحجرُ أسودُ من ذاك"},{"id":"b","text":"هذا الحجرُ سوداءُ من ذاك"},{"id":"c","text":"هذا الحجرُ أشدُّ سوادًا من ذاك"},{"id":"d","text":"هذا الحجرُ مُسودٌّ من ذاك"}]'::jsonb, 'c', 'اجتمعَ مانعانِ: الوصفُ لونٌ على وزنِ أفعلَ فعلاءَ، والفعلُ مزيدٌ؛ فيتعذّرُ الصوغُ المباشرُ، ونأتي بـ«أشدُّ» ثمّ المصدرِ «سوادًا» تمييزًا منصوبًا: أشدُّ سوادًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('89b15c3d-c221-52e3-bd9a-290d90df4b61', '2d2e61c3-138e-5eb6-9e96-8e0ed2fb2afc', 'في «هؤلاءِ هم أكرمُ القومِ» (مضافٌ إلى معرفةٍ)، ما الوجهُ الآخرُ الصحيحُ بالمطابقةِ؟', '[{"id":"a","text":"أكرمُ قومٍ"},{"id":"b","text":"كريمو القومِ"},{"id":"c","text":"الكُرمى القومِ"},{"id":"d","text":"أكارمُ القومِ"}]'::jsonb, 'd', 'المضافُ إلى معرفةٍ يجوزُ فيه الإفرادُ (أكرمُ القومِ) والمطابقةُ؛ ومطابقُ جماعةِ الذكورِ من «أكرم» هو جمعُ التكسيرِ «أكارم»: أكارمُ القومِ. و«أكرمُ قومٍ» مضافٌ إلى نكرةٍ، و«كريمو» ليس اسمَ تفضيلٍ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db2e717e-f298-5775-9eec-bee0095c311f', '2d2e61c3-138e-5eb6-9e96-8e0ed2fb2afc', 'أكملْ (اسمُ التفضيلِ معرّفٌ بأل، مثنّى): «الأخوانِ هما ... سنًّا في العائلةِ».', '[{"id":"a","text":"أكبرُ"},{"id":"b","text":"الأكبرانِ"},{"id":"c","text":"الكُبرى"},{"id":"d","text":"الأكبرونَ"}]'::jsonb, 'b', 'المقترنُ بـ«أل» يطابقُ موصوفَه؛ و«الأخوانِ» مثنّى مذكّرٌ، فالمطابقُ «الأكبرانِ». و«أكبرُ» بلا أل، و«الكُبرى» للمفردةِ المؤنّثةِ، و«الأكبرونَ» لجمعِ الذكورِ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b9d5bc6-1822-5fa9-a26d-0c1f7f25d219', '2d2e61c3-138e-5eb6-9e96-8e0ed2fb2afc', 'في «هو أعلمُ من أخيه وأكثرُ منه اجتهادًا»، ما إعرابُ «اجتهادًا»؟', '[{"id":"a","text":"تمييزٌ منصوبٌ"},{"id":"b","text":"مفعولٌ به منصوبٌ"},{"id":"c","text":"حالٌ منصوبةٌ"},{"id":"d","text":"مفضَّلٌ عليه مجرورٌ"}]'::jsonb, 'a', '«اجتهادًا» مصدرٌ جاءَ بعدَ «أكثرُ» تمييزًا منصوبًا يكشفُ جهةَ المفاضلةِ. أمّا المفضَّلُ عليه فهو الضميرُ في «منه» المجرورُ بـ«مِن».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5dcce838-4040-56ed-a663-9eff353e5c4e', '2d2e61c3-138e-5eb6-9e96-8e0ed2fb2afc', 'أيُّ التراكيبِ الآتيةِ صحيحٌ تمامًا صياغةً ومطابقةً وإعرابًا؟', '[{"id":"a","text":"الفتياتُ فُضلياتٌ من زميلاتِهنّ"},{"id":"b","text":"هندُ أشدُّ الطالباتِ حياءً"},{"id":"c","text":"عليٌّ أكثرُ اجتهادًا الطلابِ"},{"id":"d","text":"هذا الثوبُ أحمرُ من ذاك"}]'::jsonb, 'b', '«هندُ أشدُّ الطالباتِ حياءً» صحيحٌ: «أشدُّ» اسمُ تفضيلٍ مضافٌ إلى المعرفةِ «الطالباتِ»، و«حياءً» تمييزٌ منصوبٌ. أمّا (a) فأخطأَ في مطابقةِ المجرّدِ (الصوابُ: أفضلُ)، و(c) اختلّ فيه الترتيبُ (الصوابُ: أكثرُ الطلابِ اجتهادًا)، و(d) لونٌ لا يُقالُ فيه «أحمرُ من» بل «أشدُّ حُمرةً».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('0cf0be6e-fe6c-50b0-894b-fab37aa8bfb7', 'aa138285-95a6-5ef9-bcde-7bddb743c3f1', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c0393194-643e-58da-a5a7-bc8b23756a55', '0cf0be6e-fe6c-50b0-894b-fab37aa8bfb7', 'اسم الآلة اسمٌ مشتقّ يدلّ على:', '[{"id":"a","text":"زمان وقوع الحدث"},{"id":"b","text":"مكان وقوع الحدث"},{"id":"c","text":"الأداة التي يقع بها الحدث"},{"id":"d","text":"من قام بالحدث"}]'::jsonb, 'c', 'اسم الآلة يدلّ على الأداة أو الوسيلة التي يقع بها الفعل، مثل مِفتاح ومِنشار؛ أمّا زمان الحدث فاسم زمان، ومكانه اسم مكان، ومن قام به اسم فاعل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('63226a9c-b562-55ef-885f-ee47681599c1', '0cf0be6e-fe6c-50b0-894b-fab37aa8bfb7', 'بأيّ حركةٍ تبدأ أوزان اسم الآلة القياسيّة (مِفعَل، مِفعال، مِفعَلة)؟', '[{"id":"a","text":"بميمٍ مكسورة (مِـ)"},{"id":"b","text":"بميمٍ مفتوحة (مَـ)"},{"id":"c","text":"بميمٍ مضمومة (مُـ)"},{"id":"d","text":"بهمزةٍ مفتوحة (أَـ)"}]'::jsonb, 'a', 'أوزان اسم الآلة القياسيّة الثلاثة تبدأ كلُّها بميمٍ مكسورة (مِـ)؛ وهذه علامةٌ تميّزها عن اسم المكان الذي يبدأ بميمٍ مفتوحة (مَـ).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46da337e-009a-51e2-a6d1-4d295c332850', '0cf0be6e-fe6c-50b0-894b-fab37aa8bfb7', 'اسم المكان من الفعل «لَعِبَ ← يَلعَب» هو:', '[{"id":"a","text":"مَلعِب"},{"id":"b","text":"مِلعَب"},{"id":"c","text":"مُلعَب"},{"id":"d","text":"مَلعَب"}]'::jsonb, 'd', 'مضارع «لَعِبَ» مفتوح العين (يَلعَب)، فيُصاغ اسم المكان على وزن مَفعَل بفتح العين: مَلعَب، بميمٍ مفتوحة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fd045ab-4448-5caf-b475-03c6645b8f82', '0cf0be6e-fe6c-50b0-894b-fab37aa8bfb7', 'اسم المكان من الفعل «جَلَسَ ← يَجلِس» هو «مَجلِس» بكسر العين. ما سبب الكسر؟', '[{"id":"a","text":"لأنّ مضارعه مكسور العين (يَجلِس)"},{"id":"b","text":"لأنّ مضارعه مضموم العين"},{"id":"c","text":"لأنّه فعلٌ ناقصٌ معتلّ الآخر"},{"id":"d","text":"لأنّه فعلٌ غير ثلاثيّ"}]'::jsonb, 'a', 'يُصاغ اسم المكان على وزن مَفعِل بكسر العين إذا كان مضارع الفعل مكسور العين؛ ومضارع «جَلَسَ» هو «يَجلِس»، فجاء «مَجلِس» بالكسر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4d1544e3-61e9-52c6-9eba-fe9067b2afa5', '0cf0be6e-fe6c-50b0-894b-fab37aa8bfb7', 'الكلمة «مِكنَسة» بميمٍ مكسورة، والكلمة «مَطبَخ» بميمٍ مفتوحة. ما تصنيفهما الصحيح؟', '[{"id":"a","text":"مِكنَسة اسم مكان، ومَطبَخ اسم آلة"},{"id":"b","text":"مِكنَسة اسم آلة، ومَطبَخ اسم مكان"},{"id":"c","text":"كلاهما اسم آلة"},{"id":"d","text":"كلاهما اسم مكان"}]'::jsonb, 'b', 'الميم المكسورة علامة اسم الآلة، فـ«مِكنَسة» أداة الكنس؛ والميم المفتوحة علامة اسم المكان، فـ«مَطبَخ» مكان الطبخ. حركة الميم هي الفارق الحاسم.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

