  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('675b3b14-3285-599d-94bc-1877cfe39fb6', 'a62c3ed8-5467-593d-bebb-40a593a6540d', 'اسم الزمان اسمٌ مشتقّ يدلّ على:', '[{"id":"a","text":"مكان وقوع الحدث"},{"id":"b","text":"الأداة التي يقع بها الحدث"},{"id":"c","text":"زمان وقوع الحدث"},{"id":"d","text":"من قام بالحدث"}]'::jsonb, 'c', 'اسم الزمان يدلّ على وقت وقوع الحدث (مَوعِد، مَغرِب)؛ أمّا الدالّ على المكان فاسم مكان، والدالّ على الأداة اسم آلة، والدالّ على من قام بالحدث اسم فاعل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a458108-492b-5051-b2e7-239f57244c76', 'a62c3ed8-5467-593d-bebb-40a593a6540d', 'اسم المكان من الفعل «دَخَلَ ← يَدخُل» هو:', '[{"id":"a","text":"مَدخَل"},{"id":"b","text":"مَدخِل"},{"id":"c","text":"مِدخَل"},{"id":"d","text":"مُدخَل"}]'::jsonb, 'a', 'مضارع «دَخَلَ» مضموم العين (يَدخُل)، فيُصاغ اسم المكان على وزن مَفعَل بفتح العين وبميمٍ مفتوحة: مَدخَل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5cdda583-2874-5a7c-98c2-68e4b6415962', 'a62c3ed8-5467-593d-bebb-40a593a6540d', 'على وزن مِفعال، اسم الآلة من الجذر الدالّ على النَّشْر (نشر) هو:', '[{"id":"a","text":"مَنشَر"},{"id":"b","text":"ناشِر"},{"id":"c","text":"مِنشَرة"},{"id":"d","text":"مِنشار"}]'::jsonb, 'd', 'اسم الآلة على وزن مِفعال بميمٍ مكسورة هو «مِنشار»، وهو الأداة التي يُنشَر بها الخشب؛ أمّا «ناشِر» فاسم فاعل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b5d313e-ebaa-5e61-8194-25d1d63857e0', 'a62c3ed8-5467-593d-bebb-40a593a6540d', 'أيّ الكلمات التالية اسمُ آلة؟', '[{"id":"a","text":"مَلعَب"},{"id":"b","text":"مِطرَقة"},{"id":"c","text":"مَنزِل"},{"id":"d","text":"مَدرَسة"}]'::jsonb, 'b', '«مِطرَقة» بميمٍ مكسورة على وزن مِفعَلة اسمُ آلة (أداة الطرق)؛ أمّا «مَلعَب» و«مَنزِل» و«مَدرَسة» فبميمٍ مفتوحة، وهي أسماء مكان.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('50d183b2-7f25-52da-a9a0-804fc732a06d', 'a62c3ed8-5467-593d-bebb-40a593a6540d', 'اسم المكان من الفعل «نَزَلَ ← يَنزِل» هو:', '[{"id":"a","text":"مَنزَل"},{"id":"b","text":"مِنزَل"},{"id":"c","text":"مَنزِل"},{"id":"d","text":"مُنزَل"}]'::jsonb, 'c', 'مضارع «نَزَلَ» مكسور العين (يَنزِل)، فيُصاغ اسم المكان على وزن مَفعِل بكسر العين: مَنزِل، بميمٍ مفتوحة.', 5)
