INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('237433be-4633-5d7b-9670-e9b7dc4948c8', 'a62c3ed8-5467-593d-bebb-40a593a6540d', 'اسما الزمان والمكان يُصاغان على الوزن نفسه؛ فبِمَ يُفرَّق بينهما؟', '[{"id":"a","text":"بحركة الميم"},{"id":"b","text":"بوزن الكلمة"},{"id":"c","text":"بعدد الحروف"},{"id":"d","text":"بالسياق والمعنى"}]'::jsonb, 'd', 'لا فرق بينهما في الوزن ولا في حركة الميم؛ يُميَّز اسم الزمان من اسم المكان بالسياق والمعنى: إن دلّت الكلمة على وقتٍ فهي اسم زمان، وإن دلّت على مكانٍ فهي اسم مكان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

