INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f67e90f4-83c6-5f92-81a7-e2e6116cea4f', '87e1ad14-b03d-5bae-9df7-21814582cc82', 'اسم المكان من الفعل «نَظَرَ ← يَنظُر» هو:', '[{"id":"a","text":"مَنظِر"},{"id":"b","text":"مَنظَر"},{"id":"c","text":"مِنظَر"},{"id":"d","text":"مُنظَر"}]'::jsonb, 'b', 'مضارع «نَظَرَ» مضموم العين (يَنظُر)، وما كان مضارعه مضمومًا صيغ اسم مكانه على وزن مَفعَل بفتح العين: مَنظَر، بميمٍ مفتوحة.', 1)
