INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cc71dea1-8605-524b-844f-6309ab4c269d', '87e1ad14-b03d-5bae-9df7-21814582cc82', 'اسم الزمان من الفعل «وَقَفَ ← يَقِف» هو:', '[{"id":"a","text":"مَوقَف"},{"id":"b","text":"مِوقاف"},{"id":"c","text":"مَوقِف"},{"id":"d","text":"مُوقَف"}]'::jsonb, 'c', '«وَقَفَ» فعلٌ مثالٌ (أوّله واو) صحيحُ الآخر، والمثالُ الواويُّ يُصاغ اسما الزمان والمكان منه على وزن مَفعِل بكسر العين: مَوقِف.', 2)
