INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('80663b5b-c70b-5680-9afc-8cc7b17ea4a2', '87e1ad14-b03d-5bae-9df7-21814582cc82', 'اسم المكان من الفعل «جَرَى ← يَجري» هو:', '[{"id":"a","text":"مَجرَى"},{"id":"b","text":"مَجرِى"},{"id":"c","text":"مِجرى"},{"id":"d","text":"مُجرى"}]'::jsonb, 'a', '«جَرَى» فعلٌ ناقصٌ (معتلّ الآخر)، والناقصُ يُصاغ اسم مكانه على وزن مَفعَل بفتح العين مطلقًا: مَجرَى.', 3)
