INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('82720dee-b8b9-54a7-a952-af91624978f1', '87e1ad14-b03d-5bae-9df7-21814582cc82', 'اسم الزمان «مَولِد» من الفعل «وَلَدَ ← يَلِد» جاء بكسر اللام. ما سبب الكسر؟', '[{"id":"a","text":"لأنّ مضارعه مضموم العين"},{"id":"b","text":"لأنّه فعلٌ ناقصٌ معتلّ الآخر"},{"id":"c","text":"لأنّه فعلٌ مثالٌ (أوّله واو)"},{"id":"d","text":"لأنّه فعلٌ غير ثلاثيّ"}]'::jsonb, 'c', '«وَلَدَ» فعلٌ مثالٌ واويٌّ صحيحُ الآخر، والمثالُ الواويُّ من حالتَي وزن مَفعِل بكسر العين؛ فجاء «مَولِد» بالكسر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('123381e8-3fc6-5430-889e-0293ab50914a', '87e1ad14-b03d-5bae-9df7-21814582cc82', 'اسم المكان من الفعل «رَمَى ← يَرمي» هو:', '[{"id":"a","text":"مَرمِى"},{"id":"b","text":"مِرمى"},{"id":"c","text":"مُرمى"},{"id":"d","text":"مَرمَى"}]'::jsonb, 'd', '«رَمَى» فعلٌ ناقصٌ، والناقصُ يُصاغ اسم مكانه على وزن مَفعَل بفتح العين مطلقًا؛ فالصواب «مَرمَى» لا «مَرمِى».', 5)
