INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c49b8a71-2e46-5efe-8780-f69082458dfc', 'a8baba7a-ebf0-59bb-b175-363bbdb2d577', '«مُجتَمَع» من الفعل «اِجتَمَعَ» جاء بميمٍ مضمومة. ما سبب ذلك؟', '[{"id":"a","text":"لأنّه فعلٌ ثلاثيّ مكسور العين"},{"id":"b","text":"لأنّه فعلٌ غير ثلاثيّ (مزيد) فيُصاغ على وزن اسم المفعول"},{"id":"c","text":"لأنّه اسم آلة"},{"id":"d","text":"لأنّه فعلٌ ناقصٌ"}]'::jsonb, 'b', '«اِجتَمَعَ» فعلٌ غير ثلاثيّ (مزيد)، ويُصاغ اسما الزمان والمكان منه على وزن اسم المفعول: ميمٌ مضمومة وفتحٌ لما قبل الآخر، فجاء «مُجتَمَع».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9c0ed0c-c296-54a1-bb22-0b07e3e6899e', 'a8baba7a-ebf0-59bb-b175-363bbdb2d577', '«مِنشار» و«مَنزِل» — ما تصنيفهما الصحيح؟', '[{"id":"a","text":"كلاهما اسم آلة"},{"id":"b","text":"مِنشار اسم مكان، ومَنزِل اسم آلة"},{"id":"c","text":"كلاهما اسم مكان"},{"id":"d","text":"مِنشار اسم آلة، ومَنزِل اسم مكان"}]'::jsonb, 'd', '«مِنشار» بميمٍ مكسورة اسمُ آلة (أداة النشر)؛ و«مَنزِل» بميمٍ مفتوحة اسمُ مكان (مكان النزول). حركة الميم هي الفارق الحاسم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3220add0-b8f9-5121-be0c-fa2f38038acc', 'aa138285-95a6-5ef9-bcde-7bddb743c3f1', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: الدقائقُ والفخاخُ في الصوغ', 4, 300, 60, 'challenge', 'admin', 4)
