  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e6453aa1-4b63-538b-a992-a4413c332252', '3220add0-b8f9-5121-be0c-fa2f38038acc', 'اسم المكان من الفعل «اِستَشفَى ← يَستَشفي» هو:', '[{"id":"a","text":"مُستَشفَى"},{"id":"b","text":"مَستَشفى"},{"id":"c","text":"مِستَشفى"},{"id":"d","text":"مُستَشفِى"}]'::jsonb, 'a', '«اِستَشفَى» فعلٌ غير ثلاثيّ، فيُصاغ اسم المكان منه على وزن اسم المفعول: نأتي بالمضارع (يَستَشفي)، ونُبدل حرف المضارعة ميمًا مضمومة، ونفتح ما قبل الآخر: مُستَشفَى.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('85d15fc8-740a-52aa-b0bd-10cd554979b4', '3220add0-b8f9-5121-be0c-fa2f38038acc', 'بأيّ حركةٍ تكون الميمُ في اسمَي الزمان والمكان المصوغَين من الفعل المزيد (غير الثلاثيّ)؟', '[{"id":"a","text":"مفتوحة"},{"id":"b","text":"مكسورة"},{"id":"c","text":"ساكنة"},{"id":"d","text":"مضمومة"}]'::jsonb, 'd', 'من الثلاثيّ تكون الميم مفتوحة (مَلعَب)، أمّا من المزيد فتكون مضمومة على وزن اسم المفعول (مُجتَمَع، مُستَشفَى)؛ فمن رأى ميمًا مضمومة علم أنّ الفعل مزيدٌ لا ثلاثيّ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('99138a53-2d08-584b-a56d-c929f71c1ee2', '3220add0-b8f9-5121-be0c-fa2f38038acc', 'قياسُ «سَجَدَ ← يَسجُد» (مضموم العين) أن يكون اسمُ مكانه «مَسجَد» بالفتح، لكنّ المستعمل «مَسجِد» بالكسر. فما توجيهُ ذلك؟', '[{"id":"a","text":"لأنّه فعلٌ مثالٌ واويٌّ"},{"id":"b","text":"لفظٌ سماعيٌّ خالف القياسَ فحُفظ كما نُطق"},{"id":"c","text":"خطأٌ شائعٌ والصوابُ مَسجَد"},{"id":"d","text":"لأنّه اسمُ آلة"}]'::jsonb, 'b', 'قياسُ المضموم العين وزنُ مَفعَل بالفتح، لكنّ «مَسجِد» وردت بالكسر خلافًا للقياس، فهي من الألفاظ السماعيّة التي تُحفظ كما نُطقت (مثل مَشرِق ومَغرِب ومَطلِع) ولا يُقاس عليها.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('605ec9f4-eefe-5ad5-9c2b-7138fb983231', '3220add0-b8f9-5121-be0c-fa2f38038acc', 'اسم المكان (موضع اللقاء) من الفعل «اِلتَقَى ← يَلتَقي» هو:', '[{"id":"a","text":"مَلتَقى"},{"id":"b","text":"مُلتَقِى"},{"id":"c","text":"مُلتَقَى"},{"id":"d","text":"مِلتَقى"}]'::jsonb, 'c', '«اِلتَقَى» فعلٌ مزيدٌ، فاسم المكان منه على وزن اسم المفعول: ميمٌ مضمومة وفتحٌ لما قبل الآخر: مُلتَقَى؛ لا مَلتَقى بالفتح ولا مِلتَقى بالكسر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('11d2032f-36b4-58fa-b040-255edc628ba9', '3220add0-b8f9-5121-be0c-fa2f38038acc', 'كلمة «سَيّارة» من أوزان اسم الآلة، فعلى أيّ وزنٍ هي؟', '[{"id":"a","text":"فَعّالة"},{"id":"b","text":"مِفعَلة"},{"id":"c","text":"مِفعال"},{"id":"d","text":"مَفعَلة"}]'::jsonb, 'a', '«سَيّارة» على وزن فَعّالة، وهو الوزن الحديث الذي أضافه مجمع اللغة لاسم الآلة (غَسّالة، ثَلّاجة، طَيّارة)؛ ويتميّز بتضعيف العين وتاء التأنيث، ولا يبدأ بميم.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a319bb97-155b-5876-8f15-5d74ef2152d7', '3220add0-b8f9-5121-be0c-fa2f38038acc', 'كلمة «مَغرِب» قد تكون اسمَ زمانٍ وقد تكون اسمَ مكانٍ. فبِمَ نحدّد المقصود منها؟', '[{"id":"a","text":"بحركة الميم"},{"id":"b","text":"بالسياق والمعنى"},{"id":"c","text":"بوزن الكلمة"},{"id":"d","text":"بعدد حروفها"}]'::jsonb, 'b', 'اسما الزمان والمكان يشتركان في الوزن وفي حركة الميم، فلا يُفرَّق بينهما إلّا بالسياق: «مَغرِب الشمس» زمانٌ إن قُصد وقت الغروب، ومكانٌ إن قُصدت جهة الغرب.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

