  ('cae29dcc-36c0-5f46-b738-9edbf6877610', 'aa138285-95a6-5ef9-bcde-7bddb743c3f1', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: اسمُ الآلةِ وأوزانُه', 3, 120, 30, 'boss', 'admin', 5)
