INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84aa1039-3546-5406-b645-a1c915e2724a', 'cae29dcc-36c0-5f46-b738-9edbf6877610', 'اسم الآلة على وزن مِفعال من الجذر الدالّ على الفَتْح (فتح) هو:', '[{"id":"a","text":"فاتِح"},{"id":"b","text":"مَفتَح"},{"id":"c","text":"مِفتاح"},{"id":"d","text":"مِفتَحة"}]'::jsonb, 'c', 'اسم الآلة على وزن مِفعال بميمٍ مكسورة هو «مِفتاح»، وهو الأداة التي يُفتَح بها؛ أمّا «فاتِح» فاسم فاعل.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
