  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fd3c24a-0850-5e74-8115-b3a4353e4702', 'cae29dcc-36c0-5f46-b738-9edbf6877610', 'أيّ الكلمات التالية على وزن فَعّالة (الوزن الحديث لاسم الآلة)؟', '[{"id":"a","text":"غَسّالة"},{"id":"b","text":"مِغسَل"},{"id":"c","text":"غاسِل"},{"id":"d","text":"مِكواة"}]'::jsonb, 'a', '«غَسّالة» على وزن فَعّالة الحديث (تضعيفُ العين وتاء التأنيث)؛ أمّا «مِكواة» فعلى وزن مِفعَلة القياسيّ، و«غاسِل» اسم فاعل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
