  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('16223aa8-d21a-5825-afdd-dde7648377ec', 'cae29dcc-36c0-5f46-b738-9edbf6877610', 'كلمة «مِبرَد» (أداة البَرْد) على أيّ وزنٍ من أوزان اسم الآلة؟', '[{"id":"a","text":"مِفعال"},{"id":"b","text":"مِفعَلة"},{"id":"c","text":"فَعّالة"},{"id":"d","text":"مِفعَل"}]'::jsonb, 'd', '«مِبرَد» على وزن مِفعَل بميمٍ مكسورة وفتح العين، وهو أحد الأوزان القياسيّة الثلاثة لاسم الآلة (مثل مِنجَل ومِثقَب).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8537415b-2ac7-5927-9495-9e4c19c34e2a', 'cae29dcc-36c0-5f46-b738-9edbf6877610', 'الأداةُ الرافعةُ التي تنقل الناسَ بين طوابق البناء (المِصعَد) تُكتب بالميم:', '[{"id":"a","text":"مَصعَد (بميمٍ مفتوحة)"},{"id":"b","text":"مِصعَد (بميمٍ مكسورة)"},{"id":"c","text":"مُصعَد (بميمٍ مضمومة)"},{"id":"d","text":"مَصعِد (بفتح الميم وكسر العين)"}]'::jsonb, 'b', '«مِصعَد» أداةٌ يُصعَد بها، فهو اسمُ آلةٍ على وزن مِفعَل بميمٍ مكسورة؛ ولو فُتحت الميم «مَصعَد» لصار اسمَ مكان. والدلالة هنا على الأداة، فوجب الكسر.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f46a22ea-daf4-5d7f-8f2b-aec9557317a9', 'cae29dcc-36c0-5f46-b738-9edbf6877610', '«مِروَحة» و«مَسبَح» — ما تصنيفهما الصحيح؟', '[{"id":"a","text":"مِروَحة اسم مكان، ومَسبَح اسم آلة"},{"id":"b","text":"كلاهما اسم آلة"},{"id":"c","text":"مِروَحة اسم آلة، ومَسبَح اسم مكان"},{"id":"d","text":"كلاهما اسم مكان"}]'::jsonb, 'c', '«مِروَحة» بميمٍ مكسورة اسمُ آلة (أداة التهوية) على وزن مِفعَلة؛ و«مَسبَح» بميمٍ مفتوحة اسمُ مكان (مكان السباحة). حركة الميم تفصل بينهما.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
