  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0ee03c64-8733-5f55-aa71-c49cbaf46b07', 'cae29dcc-36c0-5f46-b738-9edbf6877610', 'اسم الآلة على وزن مِفعَلة من الجذر الدالّ على التَّسطير (سطر) هو:', '[{"id":"a","text":"مِسطَرة"},{"id":"b","text":"مِسطار"},{"id":"c","text":"مَسطَر"},{"id":"d","text":"ساطِر"}]'::jsonb, 'a', 'اسم الآلة على وزن مِفعَلة بميمٍ مكسورة وتاء تأنيثٍ هو «مِسطَرة»، وهي الأداة التي تُسطَّر بها الخطوط؛ أمّا «مَسطَر» بميمٍ مفتوحة فليس من أوزان اسم الآلة القياسيّة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
