  ('fc0a4226-d753-5ebc-bc5e-1eea009626c0', 'aa138285-95a6-5ef9-bcde-7bddb743c3f1', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: مزجُ المشتقّاتِ وأسرارُ الميم', 4, 300, 60, 'challenge', 'admin', 6)
