INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1349440a-2f7b-5117-a5bd-ee902b7130b0', 'fc0a4226-d753-5ebc-bc5e-1eea009626c0', 'اسم المكان من الفعل «اِنحَدَرَ ← يَنحَدِر» هو:', '[{"id":"a","text":"مُنحَدَر"},{"id":"b","text":"مَنحَدَر"},{"id":"c","text":"مُنحَدِر"},{"id":"d","text":"مِنحَدَر"}]'::jsonb, 'a', '«اِنحَدَرَ» فعلٌ مزيدٌ، فاسم المكان منه على وزن اسم المفعول: ميمٌ مضمومة وفتحٌ لما قبل الآخر: مُنحَدَر. و«مُنحَدِر» بكسر ما قبل الآخر اسمُ فاعل.', 1)
