INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5014af94-0790-53b9-9e47-370c8019e9d2', 'fc0a4226-d753-5ebc-bc5e-1eea009626c0', 'كلمة «مِنجَل» بميمٍ مكسورة؛ ما تصنيفها وما دليله؟', '[{"id":"a","text":"اسم مكان لأنّه يبدأ بميم"},{"id":"b","text":"اسم آلة لأنّ ميمه مكسورة"},{"id":"c","text":"اسم زمان لأنّه على وزن مَفعِل"},{"id":"d","text":"اسم مفعول من فعلٍ مزيد"}]'::jsonb, 'b', '«مِنجَل» أداةُ الحصاد، بميمٍ مكسورة على وزن مِفعَل، فهو اسمُ آلة. والميم المكسورة علامةُ اسم الآلة، لا مجرّدُ البدء بالميم؛ فأسماء المكان تبدأ بميمٍ مفتوحة.', 2)
ON CONFLICT (id) DO UPDATE SET
