  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73955719-c8b0-586d-ade0-aa65b757f3bd', 'fc0a4226-d753-5ebc-bc5e-1eea009626c0', 'اسم المكان (موضع الوُرود) من الفعل «وَرَدَ ← يَرِد» هو:', '[{"id":"a","text":"مَورَد"},{"id":"b","text":"مِوراد"},{"id":"c","text":"مَورِد"},{"id":"d","text":"مُورَد"}]'::jsonb, 'c', '«وَرَدَ» فعلٌ مثالٌ واويٌّ صحيحُ الآخر، والمثالُ الواويُّ يُصاغ اسم مكانه على وزن مَفعِل بكسر العين: مَورِد.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2bfb5994-542a-54ef-a780-a58828c866e2', 'fc0a4226-d753-5ebc-bc5e-1eea009626c0', 'قياسُ «طَلَعَ ← يَطلُع» (مضموم العين) للزمان والمكان، مع أنّ المستعمل «مَطلِع» بالكسر. فأيُّ الوزنَين هو القياسيّ؟', '[{"id":"a","text":"القياسيّ مَطلِع بالكسر، والفتح خطأ"},{"id":"b","text":"القياسيّ مَطلَع بالفتح (لأنّ المضارع مضموم)، و«مَطلِع» سماعيّ"},{"id":"c","text":"كلاهما سماعيٌّ لا قياسَ فيه"},{"id":"d","text":"القياسيّ مِطلَع بميمٍ مكسورة"}]'::jsonb, 'b', 'ما كان مضارعه مضمومًا (يَطلُع) فقياسُه وزنُ مَفعَل بالفتح: مَطلَع. أمّا «مَطلِع» بالكسر فوردت سماعًا خلافًا للقياس فحُفظت، ولا يُقاس عليها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f9eae1a0-4615-5e17-b1bf-bf7dc2d0a1ab', 'fc0a4226-d753-5ebc-bc5e-1eea009626c0', 'من الكلمتين «مُلتَقَى» و«مَلعَب»، أيُّهما مصوغٌ من فعلٍ مزيدٍ (غير ثلاثيّ)؟', '[{"id":"a","text":"مَلعَب مصوغٌ من مزيد"},{"id":"b","text":"كلاهما من مزيد"},{"id":"c","text":"مُلتَقَى مصوغٌ من مزيد"},{"id":"d","text":"كلاهما من ثلاثيّ"}]'::jsonb, 'c', '«مُلتَقَى» بميمٍ مضمومة من الفعل المزيد «اِلتَقَى» على وزن اسم المفعول؛ أمّا «مَلعَب» بميمٍ مفتوحة فمن الثلاثيّ «لَعِبَ» على وزن مَفعَل. حركةُ الميم تكشف أصلَ الفعل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('369f66f7-cdd2-5ec0-8ccf-59b9ae5b2a20', 'fc0a4226-d753-5ebc-bc5e-1eea009626c0', 'كلمة «مِيزان» (أداة الوزن) اسمُ آلةٍ، فعلى أيّ وزنٍ هي؟', '[{"id":"a","text":"مِفعَل"},{"id":"b","text":"مِفعَلة"},{"id":"c","text":"فَعّالة"},{"id":"d","text":"مِفعال"}]'::jsonb, 'd', '«مِيزان» من الجذر (وزن) على وزن مِفعال بميمٍ مكسورة (أصلها مِوزان، فأُبدلت الواو ياءً)، فهي اسمُ آلةٍ مثل مِفتاح ومِنشار.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('dad936ee-123e-5bee-9dae-14f9a7d24a0e', 'da092296-ea53-555a-87ff-d45f234755de', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('898189c9-0a34-575b-bfd8-3e36b985834b', 'dad936ee-123e-5bee-9dae-14f9a7d24a0e', 'على أيِّ معنًى تدلُّ صيغةُ المبالغةِ؟', '[{"id":"a","text":"على زمانِ وقوعِ الفعلِ ومكانِه"},{"id":"b","text":"على الكثرةِ والمبالغةِ في معنى اسمِ الفاعلِ"},{"id":"c","text":"على الآلةِ التي يقعُ بها الفعلُ"},{"id":"d","text":"على تصغيرِ الاسمِ وتقليلِه"}]'::jsonb, 'b', 'صيغةُ المبالغةِ اسمٌ مشتقٌّ من الثلاثيِّ يدلُّ على معنى اسمِ الفاعلِ مع الكثرةِ والمبالغةِ؛ فـ«صبّار» = كثيرُ الصبرِ، أبلغُ من «صابر». وليست للزمانِ ولا المكانِ ولا الآلةِ ولا التصغيرِ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('17818632-6a3c-5b1a-b57f-e5e239b30d9e', 'dad936ee-123e-5bee-9dae-14f9a7d24a0e', 'أيُّ الكلماتِ التاليةِ صيغةُ مبالغةٍ على وزنِ «فَعّال»؟', '[{"id":"a","text":"صابِر"},{"id":"b","text":"مصبور"},{"id":"c","text":"صبّار"},{"id":"d","text":"صَبر"}]'::jsonb, 'c', '«صبّار» على وزنِ «فَعّال» بتشديدِ العينِ، وهي صيغةُ مبالغةٍ. أمّا «صابِر» فاسمُ فاعلٍ (فاعِل)، و«صَبر» مصدرٌ، وليس «مصبور» ممّا يُستعملُ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c720c644-8255-56c3-b2ab-e58e3be9b30d', 'dad936ee-123e-5bee-9dae-14f9a7d24a0e', 'أيُّ هذه الأوزانِ ليس من أوزانِ صيغةِ المبالغةِ الخمسةِ؟', '[{"id":"a","text":"فاعِل"},{"id":"b","text":"فَعّال"},{"id":"c","text":"مِفعال"},{"id":"d","text":"فَعول"}]'::jsonb, 'a', 'أوزانُ صيغةِ المبالغةِ الخمسةُ هي: فَعّال، مِفعال، فَعول، فَعيل، فَعِل. أمّا «فاعِل» فهو وزنُ اسمِ الفاعلِ من الثلاثيِّ لا وزنُ مبالغةٍ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bfcdfe92-77aa-5ac5-b28f-1a11cbca6ba1', 'dad936ee-123e-5bee-9dae-14f9a7d24a0e', 'ما الفرقُ في المعنى بين «عالِم» و«علّام»؟', '[{"id":"a","text":"لا فرقَ بينهما في المعنى إطلاقًا"},{"id":"b","text":"«عالِم» اسمُ مفعولٍ و«علّام» اسمُ فاعلٍ"},{"id":"c","text":"«علّام» صيغةُ مبالغةٍ تدلُّ على كثرةِ العلمِ، و«عالِم» اسمُ فاعلٍ"},{"id":"d","text":"«علّام» تدلُّ على مكانِ العلمِ"}]'::jsonb, 'c', '«عالِم» اسمُ فاعلٍ على وزنِ فاعِل يدلُّ على من علِمَ، و«علّام» صيغةُ مبالغةٍ على وزنِ فَعّال تدلُّ على كثرةِ العلمِ وشدّتِه؛ فالمعنى يزيدُ في صيغةِ المبالغةِ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2937ce97-724e-5226-be48-888217c79d41', 'dad936ee-123e-5bee-9dae-14f9a7d24a0e', 'كلمةُ «مِعطاء» (كثيرُ العطاءِ) على أيِّ وزنٍ؟', '[{"id":"a","text":"فَعّال"},{"id":"b","text":"مِفعال"},{"id":"c","text":"فَعول"},{"id":"d","text":"فاعِل"}]'::jsonb, 'b', '«مِعطاء» على وزنِ «مِفعال» بكسرِ الميمِ ومن غيرِ تشديدٍ، وهي صيغةُ مبالغةٍ من «عطا يعطي». ولا تشديدَ فيها حتّى تكونَ «فَعّال»، ولا هي على «فَعول» أو «فاعِل».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('239f607e-f1b2-5e70-97da-d5035590068f', 'da092296-ea53-555a-87ff-d45f234755de', 'arabic-8eme', '⭐ تمرين: أوّلُ خطوةٍ مع صيغِ المبالغةِ', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
