  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9a670e00-cc3f-5aec-a768-0f919d5c94e0', '239f607e-f1b2-5e70-97da-d5035590068f', 'في «هو كذّابٌ لا يُصدَّقُ»، ما صيغةُ المبالغةِ؟', '[{"id":"a","text":"هو"},{"id":"b","text":"كذّاب"},{"id":"c","text":"يُصدَّق"},{"id":"d","text":"لا"}]'::jsonb, 'b', '«كذّاب» على وزنِ «فَعّال»، وهي صيغةُ مبالغةٍ تدلُّ على كثرةِ الكذبِ. أمّا «هو» فضميرٌ، و«يُصدَّق» فعلٌ، و«لا» حرفُ نفيٍ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('46044ea0-0564-59ca-9e91-d202634c993f', '239f607e-f1b2-5e70-97da-d5035590068f', 'ما معنى صيغةِ المبالغةِ «أكّال»؟', '[{"id":"a","text":"مكانُ الأكلِ"},{"id":"b","text":"آلةُ الأكلِ"},{"id":"c","text":"زمنُ الأكلِ"},{"id":"d","text":"كثيرُ الأكلِ"}]'::jsonb, 'd', '«أكّال» صيغةُ مبالغةٍ على وزنِ «فَعّال»، تدلُّ على من كثُرَ أكلُه واشتدَّ؛ فمعناها «كثيرُ الأكلِ»، لا مكانَه ولا آلتَه ولا زمنَه.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('23907d3c-056b-52da-85f1-d0658ff030e3', '239f607e-f1b2-5e70-97da-d5035590068f', 'أيُّ الكلماتِ صيغةُ مبالغةٍ (لا اسمُ فاعلٍ ولا اسمُ مفعولٍ)؟', '[{"id":"a","text":"غافِر"},{"id":"b","text":"غفور"},{"id":"c","text":"مغفور"},{"id":"d","text":"غَفر"}]'::jsonb, 'b', '«غفور» على وزنِ «فَعول» صيغةُ مبالغةٍ (كثيرُ المغفرةِ). أمّا «غافِر» فاسمُ فاعلٍ (فاعِل)، و«مغفور» اسمُ مفعولٍ (مَفعول)، و«غَفر» مصدرٌ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fe97d732-b5d3-5661-8c66-33d9cfedff8b', '239f607e-f1b2-5e70-97da-d5035590068f', 'صيغةُ المبالغةِ تُشتقُّ من...', '[{"id":"a","text":"الفعلِ الثلاثيِّ"},{"id":"b","text":"الحرفِ"},{"id":"c","text":"الاسمِ الجامدِ"},{"id":"d","text":"الظرفِ"}]'::jsonb, 'a', 'صيغُ المبالغةِ القياسيّةُ الخمسةُ تُشتقُّ من الفعلِ الثلاثيِّ (صبَرَ ← صبّار، عطا ← مِعطاء). فهي مشتقّةٌ من الفعلِ لا من الحرفِ ولا من الاسمِ الجامدِ ولا من الظرفِ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('defbd8af-9853-5fb7-87f8-d2b663abf62c', '239f607e-f1b2-5e70-97da-d5035590068f', 'كلمةُ «شكور» (كثيرُ الشكرِ) على أيِّ وزنٍ؟', '[{"id":"a","text":"فَعّال"},{"id":"b","text":"مِفعال"},{"id":"c","text":"فَعول"},{"id":"d","text":"فاعِل"}]'::jsonb, 'c', '«شكور» على وزنِ «فَعول»، وهي صيغةُ مبالغةٍ من «شكَرَ». وليست على «فَعّال» (لا تشديدَ فيها)، ولا «مِفعال» (لا ميمَ)، ولا «فاعِل» (ذاك اسمُ الفاعلِ «شاكِر»).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c2f2bdd9-05b3-5479-8c7b-d84e1d35b179', '239f607e-f1b2-5e70-97da-d5035590068f', 'كلمةُ «مِقدام» (كثيرُ الإقدامِ) على أيِّ وزنٍ؟', '[{"id":"a","text":"مِفعال"},{"id":"b","text":"فَعّال"},{"id":"c","text":"فَعيل"},{"id":"d","text":"فَعول"}]'::jsonb, 'a', '«مِقدام» على وزنِ «مِفعال» بكسرِ الميمِ من غيرِ تشديدٍ. ولو كانتْ «فَعّال» لقيلَ «قدّام» بتشديدٍ؛ فالميمُ المكسورةُ في أوّلِها علامةُ وزنِ «مِفعال».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('faa38309-dde4-5f74-b0bf-f76945a86124', 'da092296-ea53-555a-87ff-d45f234755de', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: الأوزانُ والتمييزُ والعملُ', 3, 120, 30, 'boss', 'admin', 2)
