INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('87e33c6c-fcac-5aeb-9212-f6cdf74563a0', 'faa38309-dde4-5f74-b0bf-f76945a86124', 'كلمةُ «مِعوان» (كثيرُ العونِ) على أيِّ وزنٍ؟', '[{"id":"a","text":"فَعّال"},{"id":"b","text":"مِفعال"},{"id":"c","text":"فَعِل"},{"id":"d","text":"فَعول"}]'::jsonb, 'b', '«مِعوان» على وزنِ «مِفعال» بكسرِ الميمِ من غيرِ تشديدٍ، صيغةُ مبالغةٍ من «عانَ يعينُ». والميمُ المكسورةُ أوّلًا هي علامةُ هذا الوزنِ.', 1)
