  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ba127981-63ba-548e-b268-a898a21adbaa', 'faa38309-dde4-5f74-b0bf-f76945a86124', 'من بين الكلماتِ الآتيةِ (كلُّها من الجذرِ ع ل م)، أيُّها اسمُ الفاعلِ؟', '[{"id":"a","text":"علّام"},{"id":"b","text":"عليم"},{"id":"c","text":"عالِم"},{"id":"d","text":"معلوم"}]'::jsonb, 'c', '«عالِم» على وزنِ «فاعِل» فهو اسمُ الفاعلِ. أمّا «علّام» (فَعّال) و«عليم» (فَعيل) فصيغتا مبالغةٍ، و«معلوم» (مَفعول) اسمُ مفعولٍ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f900df1-944c-5bf1-8aca-ee1b16d31234', 'faa38309-dde4-5f74-b0bf-f76945a86124', 'في «التلميذُ حفّاظٌ دروسَه»، ما إعرابُ «دروسَه»؟', '[{"id":"a","text":"مضافٌ إليه مجرورٌ"},{"id":"b","text":"مفعولٌ به منصوبٌ لصيغةِ المبالغةِ «حفّاظ»"},{"id":"c","text":"فاعلٌ مرفوعٌ لـ«حفّاظ»"},{"id":"d","text":"نعتٌ منصوبٌ"}]'::jsonb, 'b', '«حفّاظ» صيغةُ مبالغةٍ تعملُ عملَ اسمِ الفاعلِ: فاعلُها ضميرٌ مستترٌ تقديرُه «هو»، و«دروسَه» مفعولٌ به منصوبٌ لها. وليس مضافًا إليه لأنّه منصوبٌ لا مجرورٌ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bcefcae3-89fe-5bd1-a56e-a885e8c6f33c', 'faa38309-dde4-5f74-b0bf-f76945a86124', 'كلمتا «مِنحار» و«نحّار» صيغتا مبالغةٍ من الجذرِ (ن ح ر)، فعلى أيِّ وزنينِ جاءتا؟', '[{"id":"a","text":"فَعول وفَعيل"},{"id":"b","text":"فاعِل ومِفعال"},{"id":"c","text":"مِفعال وفَعّال"},{"id":"d","text":"فَعّال وفَعِل"}]'::jsonb, 'c', '«مِنحار» على «مِفعال» (بكسرِ الميمِ)، و«نحّار» على «فَعّال» (بالتشديدِ). فهما وزنانِ مختلفانِ لصيغةِ المبالغةِ من جذرٍ واحدٍ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ae5eeed5-a008-5fa6-98d6-7da2486e67a6', 'faa38309-dde4-5f74-b0bf-f76945a86124', 'في «اللهُ غفّارٌ ذنوبَ عبادِه»، ما عملُ «غفّار»؟', '[{"id":"a","text":"لا تعملُ شيئًا لأنّها اسمٌ جامدٌ"},{"id":"b","text":"عملتْ عملَ الفعلِ فرفعتْ فاعلًا ظاهرًا هو «ذنوبَ»"},{"id":"c","text":"جرّتْ «ذنوبَ» بالإضافةِ"},{"id":"d","text":"عملتْ عملَ اسمِ الفاعلِ: رفعتْ فاعلًا مستترًا ونصبتْ «ذنوبَ» مفعولًا به"}]'::jsonb, 'd', '«غفّار» صيغةُ مبالغةٍ تعملُ عملَ اسمِ الفاعلِ؛ فاعلُها ضميرٌ مستترٌ يعودُ على «الله»، و«ذنوبَ» مفعولٌ به منصوبٌ لها. وليست جامدةً، و«ذنوبَ» منصوبةٌ لا مرفوعةٌ ولا مجرورةٌ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f4c65dfe-39d5-54ef-9636-71ce31e107ba', 'faa38309-dde4-5f74-b0bf-f76945a86124', 'ما الميزانُ الصرفيُّ لكلمةِ «صبّار» (جذرُها: ص ب ر)؟', '[{"id":"a","text":"فَعّال"},{"id":"b","text":"فاعِل"},{"id":"c","text":"فَعول"},{"id":"d","text":"مِفعال"}]'::jsonb, 'a', 'نقابلُ حروفَ الجذرِ بالفاءِ والعينِ واللامِ: ص=ف، ب=ع، ر=ل، مع تضعيفِ العينِ (الباءِ) بالتشديدِ؛ فيكونُ الوزنُ «فَعّال». وهو أشهرُ أوزانِ المبالغةِ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('9a853bd6-3041-5dee-937e-df733bd760e7', 'da092296-ea53-555a-87ff-d45f234755de', 'arabic-8eme', '⭐⭐ تمرين: الأوزانُ والدلالةُ والتحويلُ', 2, 70, 15, 'practice', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
