  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f0f25380-1fe0-551e-a64b-f1fa9899450b', '9a853bd6-3041-5dee-937e-df733bd760e7', 'كلمةُ «رحيم» (كثيرُ الرحمةِ) على أيِّ وزنٍ؟', '[{"id":"a","text":"فَعِل"},{"id":"b","text":"مِفعال"},{"id":"c","text":"فَعّال"},{"id":"d","text":"فَعيل"}]'::jsonb, 'd', '«رحيم» على وزنِ «فَعيل»، صيغةُ مبالغةٍ من «رحِمَ» تدلُّ على كثرةِ الرحمةِ. وليست على «فَعِل» (قصيرةٌ) ولا «مِفعال» ولا «فَعّال».', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a561309-00e5-54fc-bc7b-6432aee0fa91', '9a853bd6-3041-5dee-937e-df733bd760e7', 'في أيِّ جملةٍ وردتْ صيغةُ مبالغةٍ لا اسمُ فاعلٍ؟', '[{"id":"a","text":"الرجلُ صابرٌ على مرضِه"},{"id":"b","text":"الرجلُ صبّارٌ على البلاءِ"},{"id":"c","text":"الرجلُ مصبورٌ عليه"},{"id":"d","text":"الرجلُ ذو صبرٍ"}]'::jsonb, 'b', '«صبّار» على وزنِ «فَعّال» صيغةُ مبالغةٍ. أمّا «صابر» فاسمُ فاعلٍ (فاعِل)، و«مصبور» شبيهٌ باسمِ المفعولِ، و«ذو صبرٍ» تركيبٌ إضافيٌّ لا مشتقٌّ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('411a50fa-546a-54ee-b9be-c776b943c62f', '9a853bd6-3041-5dee-937e-df733bd760e7', 'كلمةُ «حَذِر» (كثيرُ الحذرِ) على أيِّ وزنٍ من أوزانِ المبالغةِ؟', '[{"id":"a","text":"فَعيل"},{"id":"b","text":"فَعول"},{"id":"c","text":"فَعِل"},{"id":"d","text":"فاعِل"}]'::jsonb, 'c', '«حَذِر» على وزنِ «فَعِل» (بفتحِ الفاءِ وكسرِ العينِ)، وهو أحدُ الأوزانِ الخمسةِ القليلةِ الاستعمالِ. وليست على «فَعيل» الطويلةِ ولا «فَعول» ولا «فاعِل».', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9093b1af-d178-5001-9816-987af81c61d1', '9a853bd6-3041-5dee-937e-df733bd760e7', 'حوّلِ اسمَ الفاعلِ «شاكِر» إلى صيغةِ مبالغةٍ على وزنِ «فَعول».', '[{"id":"a","text":"شاكِر"},{"id":"b","text":"شكور"},{"id":"c","text":"مشكور"},{"id":"d","text":"شُكر"}]'::jsonb, 'b', '«فَعول» من الجذرِ (ش ك ر) هو «شكور». أمّا «شاكِر» فاسمُ الفاعلِ نفسُه، و«مشكور» اسمُ مفعولٍ، و«شُكر» مصدرٌ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4cfc05d9-bb1a-54d1-bfce-8a7d173e7715', '9a853bd6-3041-5dee-937e-df733bd760e7', 'لماذا كانتْ «صبّار» أبلغَ من «صابر»؟', '[{"id":"a","text":"لأنّها تدلُّ على كثرةِ الصبرِ وشدّتِه لا على مجرّدِ وقوعِه"},{"id":"b","text":"لأنّها تدلُّ على زمنِ الصبرِ"},{"id":"c","text":"لأنّها اسمُ مفعولٍ"},{"id":"d","text":"لأنّها تدلُّ على مكانِ الصبرِ"}]'::jsonb, 'a', 'صيغةُ المبالغةِ «صبّار» تحملُ معنى اسمِ الفاعلِ «صابر» وتزيدُه الكثرةَ والشدّةَ؛ فهي تدلُّ على من صارَ الصبرُ طبعًا فيه، لا على مجرّدِ وقوعِ الصبرِ مرّةً.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('28175c57-3fca-5527-8693-f4d5676e8081', '9a853bd6-3041-5dee-937e-df733bd760e7', 'ما نوعُ كلمةِ «سميع» (كثيرُ السمعِ)؟', '[{"id":"a","text":"اسمُ مفعولٍ على وزنِ مَفعول"},{"id":"b","text":"اسمُ فاعلٍ على وزنِ فاعِل"},{"id":"c","text":"صيغةُ مبالغةٍ على وزنِ فَعيل"},{"id":"d","text":"اسمُ آلةٍ على وزنِ مِفعال"}]'::jsonb, 'c', '«سميع» على وزنِ «فَعيل» صيغةُ مبالغةٍ من «سمِعَ» تدلُّ على كثرةِ السمعِ. وليست اسمَ مفعولٍ (مَفعول) ولا اسمَ فاعلٍ (فاعِل) ولا اسمَ آلةٍ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('3cfa9b06-fb0f-51a5-b1dc-d3fdb1e01da6', 'da092296-ea53-555a-87ff-d45f234755de', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: دقائقُ الأوزانِ وعملُ الصيغةِ', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
