  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('005b37aa-5f27-5be4-ad81-c5814251a5ba', '3cfa9b06-fb0f-51a5-b1dc-d3fdb1e01da6', 'أيُّ أوزانِ صيغةِ المبالغةِ أشهرُها وأكثرُها استعمالًا وقياسًا؟', '[{"id":"a","text":"فَعِل"},{"id":"b","text":"مِفعال"},{"id":"c","text":"فَعيل"},{"id":"d","text":"فَعّال"}]'::jsonb, 'd', '«فَعّال» (صبّار، غفّار، كذّاب) هو أشهرُ أوزانِ المبالغةِ وأكثرُها دورانًا وقياسًا. أمّا «فَعِل» فأقلُّها استعمالًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3628a6b1-19c1-5a51-9ef7-77f343864426', '3cfa9b06-fb0f-51a5-b1dc-d3fdb1e01da6', 'في «هذا طريقٌ طويلٌ»، هل «طويل» صيغةُ مبالغةٍ؟', '[{"id":"a","text":"نعم؛ لأنّها على وزنِ فَعيل"},{"id":"b","text":"لا؛ هي صفةٌ مشبّهةٌ تدلُّ على ثبوتِ الصفةِ لا على كثرةِ حدثٍ متجدّدٍ"},{"id":"c","text":"نعم؛ لأنّها تدلُّ على الكثرةِ"},{"id":"d","text":"لا؛ لأنّها اسمُ مفعولٍ"}]'::jsonb, 'b', 'وزنُ «فَعيل» ليس كلُّه مبالغةً. «طويل» صفةٌ مشبّهةٌ تدلُّ على صفةٍ ثابتةٍ لازمةٍ لا على كثرةِ حدثٍ متجدّدٍ؛ بخلافِ «رحيم، عليم» التي تدلُّ على كثرةِ الرحمةِ والعلمِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('05d1182f-63cc-523a-8e01-baaf9677d0ff', '3cfa9b06-fb0f-51a5-b1dc-d3fdb1e01da6', 'كلمةُ «مِهذار» (كثيرُ الكلامِ بلا فائدةٍ) على أيِّ وزنٍ؟', '[{"id":"a","text":"مِفعال"},{"id":"b","text":"فَعّال"},{"id":"c","text":"فَعول"},{"id":"d","text":"فَعيل"}]'::jsonb, 'a', '«مِهذار» على وزنِ «مِفعال» بكسرِ الميمِ من غيرِ تشديدٍ، صيغةُ مبالغةٍ من «هذَرَ». لو شُدِّدتْ لصارتْ «هذّار» على «فَعّال»، لكنّ الميمَ المكسورةَ تحسمُ الوزنَ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bf828ff5-6c38-510e-b1c2-ebb8bf93d940', '3cfa9b06-fb0f-51a5-b1dc-d3fdb1e01da6', 'في «أنتَ نصّارٌ المظلومَ»، ما إعرابُ «المظلومَ»؟', '[{"id":"a","text":"بدلٌ منصوبٌ"},{"id":"b","text":"مفعولٌ به منصوبٌ لصيغةِ المبالغةِ «نصّار»"},{"id":"c","text":"حالٌ منصوبةٌ"},{"id":"d","text":"مضافٌ إليه"}]'::jsonb, 'b', '«نصّار» صيغةُ مبالغةٍ اعتمدتْ على المبتدأِ «أنتَ»، فعملتْ عملَ اسمِ الفاعلِ: فاعلُها ضميرٌ مستترٌ، و«المظلومَ» مفعولٌ به منصوبٌ لها.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aa5968dc-f419-56ee-bfc2-532239e1e23d', '3cfa9b06-fb0f-51a5-b1dc-d3fdb1e01da6', 'الكلماتُ «حسود، حقود، كذوب» تشتركُ في وزنٍ واحدٍ، فما هو وعلى أيِّ معنًى تدلُّ؟', '[{"id":"a","text":"فَعيل، وتدلُّ على اسمِ المفعولِ"},{"id":"b","text":"فاعِل، وتدلُّ على اسمِ الفاعلِ"},{"id":"c","text":"فَعول، وتدلُّ على الكثرةِ والمبالغةِ"},{"id":"d","text":"مِفعال، وتدلُّ على الآلةِ"}]'::jsonb, 'c', '«حسود، حقود، كذوب» كلُّها على وزنِ «فَعول» صيغةَ مبالغةٍ تدلُّ على كثرةِ الحسدِ والحقدِ والكذبِ. وليست على «فَعيل» ولا «فاعِل» ولا «مِفعال».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef17ca35-d51e-5a56-964d-df3f8d159c5e', '3cfa9b06-fb0f-51a5-b1dc-d3fdb1e01da6', '«غفّار» و«غفور» صيغتا مبالغةٍ من الجذرِ (غ ف ر) على وزنينِ، فما هما؟', '[{"id":"a","text":"فَعّال وفَعول"},{"id":"b","text":"فَعيل ومِفعال"},{"id":"c","text":"فاعِل وفَعول"},{"id":"d","text":"فَعّال ومِفعال"}]'::jsonb, 'a', '«غفّار» على «فَعّال» (بالتشديدِ)، و«غفور» على «فَعول». وكلتاهما صيغةُ مبالغةٍ تدلُّ على كثرةِ المغفرةِ من جذرٍ واحدٍ بوزنينِ مختلفينِ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('77d4f0ba-0bfb-5a65-9cd7-7beeef455276', 'da092296-ea53-555a-87ff-d45f234755de', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: تمرّسٌ على الصيغِ وعملِها', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3fdeabd4-9352-5a4f-89d8-7edc50a7b3a3', '77d4f0ba-0bfb-5a65-9cd7-7beeef455276', 'أيُّ الكلماتِ التاليةِ ليست صيغةَ مبالغةٍ؟', '[{"id":"a","text":"صبّار"},{"id":"b","text":"مِعطاء"},{"id":"c","text":"شكور"},{"id":"d","text":"كاتِب"}]'::jsonb, 'd', '«كاتِب» على وزنِ «فاعِل» فهو اسمُ الفاعلِ لا صيغةُ مبالغةٍ. أمّا «صبّار» (فَعّال) و«مِعطاء» (مِفعال) و«شكور» (فَعول) فصيغُ مبالغةٍ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f275b037-c896-5c83-8f5f-21942d11d0df', '77d4f0ba-0bfb-5a65-9cd7-7beeef455276', 'ما معنى صيغةِ المبالغةِ «مِعطاء»، وعلى أيِّ وزنٍ هي؟', '[{"id":"a","text":"كثيرُ العطاءِ، على وزنِ مِفعال"},{"id":"b","text":"آلةُ العطاءِ، على وزنِ مِفعال"},{"id":"c","text":"كثيرُ العطاءِ، على وزنِ فَعّال"},{"id":"d","text":"مكانُ العطاءِ، على وزنِ مَفعَل"}]'::jsonb, 'a', '«مِعطاء» صيغةُ مبالغةٍ على وزنِ «مِفعال» تدلُّ على كثرةِ العطاءِ (كثيرُ العطاءِ)، لا على الآلةِ ولا المكانِ. والوزنُ «مِفعال» لا «فَعّال» لأنّه لا تشديدَ فيها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('31bb4d72-d8c7-501b-b03f-c11b36256e44', '77d4f0ba-0bfb-5a65-9cd7-7beeef455276', 'حوّلِ اسمَ الفاعلِ «قادِر» إلى صيغةِ مبالغةٍ على وزنِ «فَعيل».', '[{"id":"a","text":"مقدور"},{"id":"b","text":"مِقدار"},{"id":"c","text":"قدير"},{"id":"d","text":"قادِر"}]'::jsonb, 'c', '«فَعيل» من الجذرِ (ق د ر) هو «قدير» (كثيرُ القدرةِ). أمّا «مقدور» فاسمُ مفعولٍ، و«مِقدار» على مِفعال (وتعني الآلةَ/المقياسَ هنا)، و«قادِر» اسمُ الفاعلِ نفسُه.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4c62a473-f8c1-51f6-8dd5-f4c372b5953e', '77d4f0ba-0bfb-5a65-9cd7-7beeef455276', 'في «الجنديُّ مِقدامٌ في الحربِ»، ما نوعُ «مِقدام» ودلالتُها؟', '[{"id":"a","text":"اسمُ آلةٍ يدلُّ على أداةِ الإقدامِ"},{"id":"b","text":"اسمُ مكانٍ يدلُّ على موضعِ الإقدامِ"},{"id":"c","text":"اسمُ مفعولٍ"},{"id":"d","text":"صيغةُ مبالغةٍ على وزنِ مِفعال تدلُّ على كثرةِ الإقدامِ"}]'::jsonb, 'd', '«مِقدام» صيغةُ مبالغةٍ على وزنِ «مِفعال» تدلُّ على كثرةِ الإقدامِ والشجاعةِ. وتشترِكُ في الصورةِ مع بعضِ أسماءِ الآلةِ (مِفعال) لكنّ المعنى هنا الكثرةُ لا الأداةُ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cf0b550b-7ac8-501f-898b-65710fbaa7e7', '77d4f0ba-0bfb-5a65-9cd7-7beeef455276', 'في «العاملُ نحّاتٌ الصخرَ»، ما فاعلُ صيغةِ المبالغةِ «نحّات»؟', '[{"id":"a","text":"«الصخرَ» فاعلٌ مرفوعٌ"},{"id":"b","text":"ضميرٌ مستترٌ تقديرُه «هو»"},{"id":"c","text":"«العاملُ» فاعلٌ لـ«نحّات»"},{"id":"d","text":"لا فاعلَ لها لأنّها لا تعملُ"}]'::jsonb, 'b', '«نحّات» خبرٌ يعملُ عملَ اسمِ الفاعلِ؛ فاعلُه ضميرٌ مستترٌ تقديرُه «هو» يعودُ على «العامل»، و«الصخرَ» مفعولٌ به. أمّا «العاملُ» فمبتدأٌ لا فاعلٌ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fd0dcf55-de37-50a9-9d64-981389f287a3', '77d4f0ba-0bfb-5a65-9cd7-7beeef455276', 'ما الميزانُ الصرفيُّ لكلمةِ «كذّاب» (جذرُها: ك ذ ب)؟', '[{"id":"a","text":"فاعِل"},{"id":"b","text":"فَعّال"},{"id":"c","text":"فِعلال"},{"id":"d","text":"مِفعال"}]'::jsonb, 'b', 'نقابلُ ك=ف، ذ=ع، ب=ل، مع تشديدِ العينِ (الذالِ)؛ فالوزنُ «فَعّال». وليست «فاعِل» (ذاك اسمُ الفاعلِ «كاذِب») ولا «فِعلال» ولا «مِفعال».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a30ac6f4-be1b-5ad2-a1ee-063fbb97bbdd', 'da092296-ea53-555a-87ff-d45f234755de', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: أسرارُ الصيغةِ وشرطُ عملِها', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('846c3631-8c04-50d9-afc1-f56527c8b70c', 'a30ac6f4-be1b-5ad2-a1ee-063fbb97bbdd', 'كم عددُ الأوزانِ القياسيّةِ لصيغةِ المبالغةِ من الثلاثيِّ؟', '[{"id":"a","text":"3"},{"id":"b","text":"4"},{"id":"c","text":"5"},{"id":"d","text":"6"}]'::jsonb, 'c', 'الأوزانُ القياسيّةُ خمسةٌ: فَعّال، مِفعال، فَعول، فَعيل، فَعِل. وما عداها من الأوزانِ (كـ فُعَلة) فسماعيٌّ لا قياسيٌّ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6b78b0f2-c50a-5c9d-9ee3-38e97afe3b24', 'a30ac6f4-be1b-5ad2-a1ee-063fbb97bbdd', 'نقولُ «امرأةٌ صبورٌ» ولا نقولُ «صبورةٌ»؛ فما السببُ؟', '[{"id":"a","text":"خطأٌ شائعٌ والصوابُ «صبورةٌ»"},{"id":"b","text":"لأنّ وزنَ «فَعول» بمعنى فاعلٍ يستوي فيه المذكّرُ والمؤنّثُ فلا تلحقُه التاءُ"},{"id":"c","text":"لأنّ «صبور» جمعٌ لا مفردٌ"},{"id":"d","text":"لأنّ «صبور» اسمُ مفعولٍ لا يؤنَّثُ"}]'::jsonb, 'b', '«فَعول» بمعنى فاعلٍ (كثيرِ الصبرِ) يستوي فيه المذكّرُ والمؤنّثُ، فلا تلحقُه تاءُ التأنيثِ؛ فنقولُ «رجلٌ صبورٌ» و«امرأةٌ صبورٌ».', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fa87d8b1-9879-5de4-b96f-3e4e929f0be4', 'a30ac6f4-be1b-5ad2-a1ee-063fbb97bbdd', 'كلمةُ «قتيل» على وزنِ «فَعيل»، فهل هي صيغةُ مبالغةٍ؟', '[{"id":"a","text":"نعم؛ لأنّها على وزنِ فَعيل"},{"id":"b","text":"نعم؛ لأنّها تدلُّ على كثرةِ القتلِ"},{"id":"c","text":"لا؛ هي «فَعيل» بمعنى اسمِ المفعولِ (مقتول)، لا مبالغةَ فيها"},{"id":"d","text":"لا؛ لأنّها اسمُ فاعلٍ على وزنِ فاعِل"}]'::jsonb, 'c', 'ليس كلُّ «فَعيل» صيغةَ مبالغةٍ. «قتيل» على «فَعيل» لكنّها بمعنى اسمِ المفعولِ «مقتول» (وكذا جريح = مجروح)، فلا تدلُّ على كثرةِ حدثٍ من فاعلٍ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4cf3747a-fcd0-55c9-982f-b91a9555d340', 'a30ac6f4-be1b-5ad2-a1ee-063fbb97bbdd', 'متى تعملُ صيغةُ المبالغةِ عملَ اسمِ الفاعلِ (فترفعُ وتنصبُ)؟', '[{"id":"a","text":"دائمًا وفي كلِّ موضعٍ بلا شرطٍ"},{"id":"b","text":"إذا دلّتْ على الماضي فقط"},{"id":"c","text":"لا تعملُ أبدًا لأنّها اسمٌ جامدٌ"},{"id":"d","text":"إذا دلّتْ على الحالِ أو الاستقبالِ واعتمدتْ على نفيٍ أو استفهامٍ أو مبتدأٍ أو موصوفٍ"}]'::jsonb, 'd', 'شرطُ عملِها كشرطِ اسمِ الفاعلِ: أن تدلَّ على الحالِ أو الاستقبالِ وأن تعتمدَ على نفيٍ أو استفهامٍ أو مبتدأٍ أو موصوفٍ؛ حينَها ترفعُ فاعلًا وتنصبُ مفعولًا به.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a409068d-3e9b-5a32-b449-31a6b4c2d2b8', 'a30ac6f4-be1b-5ad2-a1ee-063fbb97bbdd', 'ما الميزانُ الصرفيُّ لكلمةِ «مِكثار» (جذرُها: ك ث ر)؟', '[{"id":"a","text":"فَعّال"},{"id":"b","text":"مِفعال"},{"id":"c","text":"فِعلال"},{"id":"d","text":"مَفعَل"}]'::jsonb, 'b', 'الميمُ في «مِكثار» زائدةٌ، فنقابلُ ك=ف، ث=ع، ر=ل، وتبقى الميمُ والألفُ زائدتينِ؛ فالوزنُ «مِفعال». وليست «فِعلال» لأنّ ميمَها زائدةٌ ليست أصليّةً.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('633e30d6-ac57-50bb-a923-f02f024cdc4e', 'a30ac6f4-be1b-5ad2-a1ee-063fbb97bbdd', 'الكلماتُ «يَقِظ» و«فَطِن» صيغتا مبالغةٍ على وزنٍ واحدٍ قليلِ الاستعمالِ، فما هو؟ وبمَ يختلفُ عن «فَعيل»؟', '[{"id":"a","text":"فَعِل، وهو أقصرُ من فَعيل (لا مدَّ فيه بعد العينِ)"},{"id":"b","text":"فَعيل، وهو نفسُه"},{"id":"c","text":"فَعول، وهو ممدودُ العينِ"},{"id":"d","text":"فاعِل، وهو وزنُ اسمِ الفاعلِ"}]'::jsonb, 'a', '«يَقِظ» و«فَطِن» على وزنِ «فَعِل» (بفتحِ الفاءِ وكسرِ العينِ من غيرِ مدٍّ). ويختلفُ عن «فَعيل» بأنّه لا ياءَ مدٍّ فيه بعد العينِ؛ فـ«فَطِن» على فَعِل، و«رحيم» على فَعيل.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('f1bf8e65-63e4-56c8-b9a2-f54c3e2e2c0e', 'd7920853-fb71-572d-a255-57713543e010', 'arabic-8eme', 'اختبار فهم الدرس ⭐', 1, 20, 5, 'quiz', 'admin', 0)
