  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab267080-da59-5ec9-9dc2-ab4892a00ad2', 'f1bf8e65-63e4-56c8-b9a2-f54c3e2e2c0e', 'ما جمعُ التكسيرِ؟', '[{"id":"a","text":"جمعٌ يُبقي بناءَ المفردِ ويزيدُ في آخرِه واوًا ونونًا"},{"id":"b","text":"ما دلَّ على أكثرَ من اثنين مع تغيُّرٍ في بناءِ مفردِه"},{"id":"c","text":"اسمٌ يدلّ على مكانِ وقوعِ الحدثِ"},{"id":"d","text":"جمعٌ يزيدُ في آخرِ المفردِ ألفًا وتاءً"}]'::jsonb, 'b', 'جمعُ التكسيرِ يدلّ على أكثرَ من اثنين مع تغيُّرِ بناءِ المفردِ (قلم ← أقلام). أمّا الزيادةُ (ون/ين) أو (ات) دونَ تغيُّرِ البناءِ فهي علامةُ الجمعِ السالمِ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ee75df22-70f5-5f52-b1b1-12712dcfb813', 'f1bf8e65-63e4-56c8-b9a2-f54c3e2e2c0e', 'جموعُ القلّةِ تدلّ على عددٍ محصورٍ بين...', '[{"id":"a","text":"3 و10"},{"id":"b","text":"2 و5"},{"id":"c","text":"10 وما لا نهايةَ"},{"id":"d","text":"1 و3"}]'::jsonb, 'a', 'جموعُ القلّةِ تدلّ على القليلِ من 3 إلى 10؛ وما فوقَ العشرةِ فهو من جموعِ الكثرةِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ab018aa4-f7a0-568d-bafe-1a001c332d0b', 'f1bf8e65-63e4-56c8-b9a2-f54c3e2e2c0e', 'مصدرُ الفعلِ الثّلاثيِّ (نحو: نَصَرَ، جَلَسَ) هو...', '[{"id":"a","text":"قياسيٌّ يُصاغُ بقاعدةٍ ثابتةٍ من وزنِ الفعلِ"},{"id":"b","text":"سماعيٌّ يُحفَظُ ويُرجَعُ فيه إلى المعجمِ"},{"id":"c","text":"ميميٌّ مبدوءٌ بميمٍ زائدةٍ دائمًا"},{"id":"d","text":"صناعيٌّ مختومٌ بياءٍ مشدّدةٍ وتاءٍ"}]'::jsonb, 'b', 'مصدرُ الثّلاثيِّ سماعيٌّ لا يُقاسُ عليه (نَصَرَ ← نَصْر ؛ جَلَسَ ← جُلوس)؛ أمّا القياسيُّ فهو مصدرُ غيرِ الثّلاثيِّ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e922b2b7-d103-5c3c-af51-560adbe9b283', 'f1bf8e65-63e4-56c8-b9a2-f54c3e2e2c0e', '«مساجد» و«مفاتيح» و«رسائل» جموعٌ تنتمي إلى...', '[{"id":"a","text":"جموعِ القلّةِ"},{"id":"b","text":"الجمعِ المذكّرِ السالمِ"},{"id":"c","text":"صيغةِ منتهى الجموعِ (نوعٌ من الكثرةِ)"},{"id":"d","text":"الجمعِ المؤنّثِ السالمِ"}]'::jsonb, 'c', 'بعدَ ألفِ التكسيرِ في هذه الجموعِ حرفانِ (مَفاعِل: مساجد؛ فَعائل: رسائل) أو ثلاثةٌ أوسطُها ساكنٌ (مَفاعيل: مفاتيح)، وهذا ضابطُ صيغةِ منتهى الجموعِ، وهي من جموعِ الكثرةِ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8d304615-d1dc-5818-87a7-bc3f76bd347f', 'f1bf8e65-63e4-56c8-b9a2-f54c3e2e2c0e', 'بِمَ نُميّزُ المصدرَ الصناعيَّ في آخرِ الكلمةِ؟', '[{"id":"a","text":"بميمٍ زائدةٍ في أوّلِه"},{"id":"b","text":"بألفٍ ونونٍ في آخرِه"},{"id":"c","text":"بياءٍ مشدّدةٍ وتاءٍ مربوطةٍ تدلّانِ على معنًى مجرّدٍ"},{"id":"d","text":"بتضعيفِ عينِه"}]'::jsonb, 'c', 'المصدرُ الصناعيُّ يُصاغُ بزيادةِ ياءٍ مشدّدةٍ وتاءٍ للدلالةِ على معنًى مجرّدٍ (حُرّ ← حُرّية ؛ وطن ← وطنية). أمّا الميمُ الزائدةُ في الأوّلِ فعلامةُ المصدرِ الميميِّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('29907e7b-608b-52cc-a08a-e90cf02fd4fa', 'd7920853-fb71-572d-a255-57713543e010', 'arabic-8eme', '⭐ تمرين: أوّلُ خطوةٍ مع التكسيرِ والمصادرِ', 1, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
