  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e0cf1721-b37f-5ed2-8fc6-e37e2a204278', '29907e7b-608b-52cc-a08a-e90cf02fd4fa', 'أيُّ الكلماتِ الآتيةِ جمعُ تكسيرٍ؟', '[{"id":"a","text":"مسلمون"},{"id":"b","text":"كاتبات"},{"id":"c","text":"قلوب"},{"id":"d","text":"مهندسون"}]'::jsonb, 'c', '«قلوب» غيّرتْ بناءَ مفردِها «قلب»، فهي جمعُ تكسيرٍ. أمّا «مسلمون» و«مهندسون» فجمعا مذكّرٍ سالمانِ، و«كاتبات» جمعُ مؤنّثٍ سالمٌ؛ كلُّها أبقتِ المفردَ وزادتْ عليه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a9aff869-c41b-59fa-84f5-f49f451cf84c', '29907e7b-608b-52cc-a08a-e90cf02fd4fa', 'الجمعُ الذي يدلّ على القليلِ (من 3 إلى 10) يُسمّى...', '[{"id":"a","text":"جمعَ الكثرةِ"},{"id":"b","text":"جمعَ القلّةِ"},{"id":"c","text":"الجمعَ المذكّرَ السالمَ"},{"id":"d","text":"صيغةَ منتهى الجموعِ"}]'::jsonb, 'b', 'جموعُ القلّةِ تدلّ على القليلِ من 3 إلى 10؛ وما فوقَ العشرةِ فهو من جموعِ الكثرةِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('953ab16f-31a1-5cbf-b552-78d7fecf3696', '29907e7b-608b-52cc-a08a-e90cf02fd4fa', 'على أيِّ شيءٍ يدلُّ المصدرُ؟', '[{"id":"a","text":"على مكانِ وقوعِ الحدثِ"},{"id":"b","text":"على ذاتِ الفاعلِ الذي قامَ بالحدثِ"},{"id":"c","text":"على الحدثِ مقترنًا بالزمنِ الماضي"},{"id":"d","text":"على الحدثِ مجرّدًا من الزمنِ"}]'::jsonb, 'd', 'المصدرُ اسمٌ يدلّ على الحدثِ مجرّدًا من الزمنِ (كتابة ؛ جلوس)؛ فلا يدلّ على مكانٍ ولا فاعلٍ ولا زمنٍ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b5585c38-5c6f-50ab-a47a-980e7df351b2', '29907e7b-608b-52cc-a08a-e90cf02fd4fa', 'مصدرُ الفعلِ غيرِ الثّلاثيِّ (الزائدِ على ثلاثةِ أحرفٍ) يكونُ...', '[{"id":"a","text":"قياسيًّا يُصاغُ بقاعدةٍ من وزنِ الفعلِ"},{"id":"b","text":"سماعيًّا يُحفَظُ من المعجمِ"},{"id":"c","text":"ممنوعًا من الصرفِ دائمًا"},{"id":"d","text":"جمعَ تكسيرٍ"}]'::jsonb, 'a', 'مصدرُ غيرِ الثّلاثيِّ قياسيٌّ يُصاغُ بقاعدةٍ مطّردةٍ من وزنِ الفعلِ (أكرمَ ← إكرام)؛ أمّا السماعيُّ الذي يُحفَظُ فهو مصدرُ الثّلاثيِّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8187996b-7ffd-52fc-b33a-0322b51d4390', '29907e7b-608b-52cc-a08a-e90cf02fd4fa', 'بمَ يبدأُ المصدرُ الميميُّ في أوّلِه؟', '[{"id":"a","text":"بهمزةٍ مكسورةٍ"},{"id":"b","text":"بسينٍ وتاءٍ"},{"id":"c","text":"بميمٍ زائدةٍ"},{"id":"d","text":"بتضعيفِ عينِه"}]'::jsonb, 'c', 'المصدرُ الميميُّ مصدرٌ مبدوءٌ بميمٍ زائدةٍ (مَذهَب ؛ مَقتَل ؛ مُنطَلَق)، سُمّيَ ميميًّا لهذه الميمِ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('944f4753-67d5-5b34-8845-1a9e1fa2b47b', '29907e7b-608b-52cc-a08a-e90cf02fd4fa', 'ما مصدرُ الفعلِ «أكرمَ»؟', '[{"id":"a","text":"كَرَم"},{"id":"b","text":"إكرام"},{"id":"c","text":"مُكارَمة"},{"id":"d","text":"تكريم"}]'::jsonb, 'b', '«أكرمَ» على وزنِ أفعَل، ومصدرُه القياسيُّ على وزنِ إفعال = «إكرام». و«كَرَم» مصدرُ الثّلاثيِّ «كَرُمَ»، و«تكريم» مصدرُ «كرّمَ».', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('52f0ff23-781e-5885-9df8-0865e03b4074', 'd7920853-fb71-572d-a255-57713543e010', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: القلّةُ والكثرةُ ومنتهى الجموعِ', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
