  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('413a02b2-c350-5e26-9cd1-e5dd5075841a', '52f0ff23-781e-5885-9df8-0865e03b4074', 'أيُّ الجموعِ الآتيةِ من صيغةِ منتهى الجموعِ؟', '[{"id":"a","text":"مصابيح"},{"id":"b","text":"كتب"},{"id":"c","text":"أقلام"},{"id":"d","text":"رجال"}]'::jsonb, 'a', '«مصابيح» على وزنِ مَفاعيل: بعدَ ألفِ تكسيرِها ثلاثةُ أحرفٍ أوسطُها ساكنٌ، فهي صيغةُ منتهى الجموعِ. أمّا «كتب» و«رجال» و«أقلام» فجموعُ كثرةٍ أو قلّةٍ عاديّةٌ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fb74726-aabe-5546-9ba1-4a23596dd2c6', '52f0ff23-781e-5885-9df8-0865e03b4074', 'الجمعُ «أنفُس» على وزنِ أَفْعُل، وهو من جموعِ...', '[{"id":"a","text":"الكثرةِ"},{"id":"b","text":"القلّةِ"},{"id":"c","text":"منتهى الجموعِ"},{"id":"d","text":"المذكّرِ السالمِ"}]'::jsonb, 'b', '«أَفْعُل» أحدُ أوزانِ جموعِ القلّةِ الأربعةِ، فـ«أنفُس» جمعُ قلّةٍ يدلّ على ما بين 3 و10.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2adaa7b3-829a-5735-9b5e-bc0e2cf617ee', '52f0ff23-781e-5885-9df8-0865e03b4074', 'ما مصدرُ الفعلِ «جاهدَ»؟', '[{"id":"a","text":"جُهد"},{"id":"b","text":"تجهيد"},{"id":"c","text":"اجتهاد"},{"id":"d","text":"جِهاد (أو مُجاهَدة)"}]'::jsonb, 'd', '«جاهدَ» على وزنِ فاعَل، ومصدرُه القياسيُّ على وزنِ مُفاعَلة أو فِعال = «مُجاهَدة» أو «جِهاد». و«اجتهاد» مصدرُ «اجتهدَ» (افتعل)، فانتبهْ للفرقِ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('86957fa5-3d94-5c0d-ace1-35b47f517731', '52f0ff23-781e-5885-9df8-0865e03b4074', 'الفعلُ «انطلقَ» على وزنِ انفعل، فمصدرُه القياسيُّ الأصليُّ...', '[{"id":"a","text":"طُلوق"},{"id":"b","text":"انطلاق"},{"id":"c","text":"تطليق"},{"id":"d","text":"مُنطَلَق"}]'::jsonb, 'b', '«انفعل» مصدرُه القياسيُّ على وزنِ انفعال = «انطلاق». أمّا «مُنطَلَق» فمصدرٌ ميميٌّ على وزنِ اسمِ المفعولِ، لا المصدرُ الأصليُّ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('359e1960-2ea1-51db-b99d-41dba97fa3bf', '52f0ff23-781e-5885-9df8-0865e03b4074', 'في «حزِنّا لِمَقتَلِ البطلِ»، كلمةُ «مَقتَل» على وزنِ مَفْعَل، وهي...', '[{"id":"a","text":"اسمُ مكانٍ (مكانُ القتلِ)"},{"id":"b","text":"اسمُ زمانٍ (زمنُ القتلِ)"},{"id":"c","text":"مصدرٌ ميميٌّ (يدلّ على الحدثِ نفسِه)"},{"id":"d","text":"صيغةُ مبالغةٍ"}]'::jsonb, 'c', '«مَقتَل» هنا تدلّ على الحدثِ نفسِه (القتلِ) لا على مكانِه ولا زمانِه؛ فالمعنى: حزِنّا لقتلِ البطلِ. فهي مصدرٌ ميميٌّ، والسياقُ هو الفيصلُ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a8d0a740-be74-55d8-bfe2-48686fa72c3a', '52f0ff23-781e-5885-9df8-0865e03b4074', 'في «الحُرّيةُ حقٌّ للإنسانِ»، كلمةُ «الحُرّية»...', '[{"id":"a","text":"مصدرٌ صناعيٌّ يدلّ على معنًى مجرّدٍ"},{"id":"b","text":"اسمٌ منسوبٌ مؤنّثٌ يصفُ موصوفًا"},{"id":"c","text":"مصدرٌ ميميٌّ"},{"id":"d","text":"جمعُ تكسيرٍ"}]'::jsonb, 'a', '«الحُرّية» ياءٌ مشدّدةٌ وتاءٌ تدلّانِ على معنًى مجرّدٍ قائمٍ بنفسِه (لا موصوفَ لها هنا)، فهي مصدرٌ صناعيٌّ لا منسوبٌ؛ إذ لا يصحّ جعلُها نعتًا لموصوفٍ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

