INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7a26175e-bbcc-579d-b73f-1a6985881211', '473ac3d2-07f1-5322-bd6b-4a1f98872c2a', 'أيُّ الجموعِ الآتيةِ ليس جمعَ تكسيرٍ؟', '[{"id":"a","text":"مؤمنون"},{"id":"b","text":"كتب"},{"id":"c","text":"أبواب"},{"id":"d","text":"مساجد"}]'::jsonb, 'a', '«مؤمنون» جمعُ مذكّرٍ سالمٌ (أبقى المفردَ «مؤمن» وزادَ واوًا ونونًا). أمّا «كتب» و«أبواب» و«مساجد» فغيّرتْ بناءَ مفردِها، فهي جموعُ تكسيرٍ.', 1)
