INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c809ba8f-329a-5694-b875-1437d643bd40', '473ac3d2-07f1-5322-bd6b-4a1f98872c2a', '«أطعمة» و«أرغفة» على وزنِ أَفْعِلة، فهما من جموعِ...', '[{"id":"a","text":"الكثرةِ"},{"id":"b","text":"القلّةِ"},{"id":"c","text":"منتهى الجموعِ"},{"id":"d","text":"المذكّرِ السالمِ"}]'::jsonb, 'b', '«أَفْعِلة» أحدُ أوزانِ جموعِ القلّةِ الأربعةِ (أفعُل، أفعال، أفعِلة، فِعْلة)؛ فـ«أطعمة» و«أرغفة» جمعا قلّةٍ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5a33c697-6182-5d67-b2aa-ba094d2602a6', '473ac3d2-07f1-5322-bd6b-4a1f98872c2a', '«علماء» و«شعراء» على وزنِ فُعَلاء، فهما من جموعِ...', '[{"id":"a","text":"القلّةِ"},{"id":"b","text":"المذكّرِ السالمِ"},{"id":"c","text":"الكثرةِ"},{"id":"d","text":"منتهى الجموعِ"}]'::jsonb, 'c', '«فُعَلاء» ليس من أوزانِ القلّةِ الأربعةِ، فهو من جموعِ الكثرةِ؛ ولا هو صيغةُ منتهى الجموعِ لأنّه ليس بعدَ ألفِه حرفانِ على وزنِ مَفاعِل.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a4fd7e69-c81d-503f-9e06-449e35879c8a', '473ac3d2-07f1-5322-bd6b-4a1f98872c2a', 'ما مصدرُ الفعلِ «علّمَ»؟', '[{"id":"a","text":"تعليم"},{"id":"b","text":"عِلْم"},{"id":"c","text":"مُعالَمة"},{"id":"d","text":"إعلام"}]'::jsonb, 'a', '«علّمَ» على وزنِ فعّل، ومصدرُه القياسيُّ على وزنِ تفعيل = «تعليم». و«عِلْم» مصدرُ الثّلاثيِّ «علِمَ»، و«إعلام» مصدرُ «أعلمَ».', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d101ae95-d213-53d6-aa31-2d7a0d7ac2ca', '473ac3d2-07f1-5322-bd6b-4a1f98872c2a', 'ما مصدرُ الفعلِ «استعملَ»؟', '[{"id":"a","text":"عَمَل"},{"id":"b","text":"تعميل"},{"id":"c","text":"استعمال"},{"id":"d","text":"مُعامَلة"}]'::jsonb, 'c', '«استعملَ» على وزنِ استفعل، ومصدرُه القياسيُّ على وزنِ استفعال = «استعمال». و«عَمَل» مصدرُ الثّلاثيِّ «عمِلَ».', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b4187c7-093e-519d-be3e-7a8f680c4c93', '473ac3d2-07f1-5322-bd6b-4a1f98872c2a', 'المصدرُ الصناعيُّ المصوغُ من كلمةِ «وطن» هو...', '[{"id":"a","text":"مَوطِن"},{"id":"b","text":"أوطان"},{"id":"c","text":"مواطن"},{"id":"d","text":"وطنية"}]'::jsonb, 'd', '«وطنية» بياءٍ مشدّدةٍ وتاءٍ تدلّ على معنًى مجرّدٍ، فهي مصدرٌ صناعيٌّ. و«مَوطِن» مصدرٌ ميميٌّ / اسمُ مكانٍ، و«أوطان» جمعُ تكسيرٍ، و«مواطن» صيغةُ منتهى الجموعِ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('242eb144-0ffc-5f1a-a93a-7cabb3891675', 'd7920853-fb71-572d-a255-57713543e010', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: دقائقُ التكسيرِ وفخاخُ المصادرِ', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c5e8158b-a9b7-56af-a001-0c44a276c243', '242eb144-0ffc-5f1a-a93a-7cabb3891675', 'أيُّ الجموعِ الآتيةِ جمعُ تكسيرٍ رغمَ انتهائِه بالتاءِ؟', '[{"id":"a","text":"معلّمات"},{"id":"b","text":"مؤمنات"},{"id":"c","text":"قُضاة"},{"id":"d","text":"طالبات"}]'::jsonb, 'c', '«قُضاة» جمعُ «قاضٍ» تغيّرَ بناؤه (وزنُ فُعَلة) والتاءُ من صيغةِ التكسيرِ، فهو جمعُ تكسيرٍ. أمّا «معلّمات» و«مؤمنات» و«طالبات» فجموعُ مؤنّثٍ سالمةٌ تزيدُ ألفًا وتاءً على المفردِ دونَ تغييرٍ.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4cf24fa1-c423-53a8-bcec-0371050b15b3', '242eb144-0ffc-5f1a-a93a-7cabb3891675', '«أصدقاء» على وزنِ أَفْعِلاء، و«أبواب» على وزنِ أَفْعال. أيُّهما جمعُ قلّةٍ؟', '[{"id":"a","text":"«أصدقاء» فقط"},{"id":"b","text":"«أبواب» فقط"},{"id":"c","text":"كلاهما جمعُ قلّةٍ"},{"id":"d","text":"لا شيءَ منهما"}]'::jsonb, 'b', '«أَفْعال» من أوزانِ القلّةِ الأربعةِ، فـ«أبواب» جمعُ قلّةٍ. أمّا «أَفْعِلاء» (أصدقاء) فليس من الأربعةِ، فهو من جموعِ الكثرةِ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1a34998d-ead9-5b4c-9826-17bbedffa7a8', '242eb144-0ffc-5f1a-a93a-7cabb3891675', 'أيُّ الجموعِ الآتيةِ ممنوعٌ من الصرفِ لأنّه على صيغةِ منتهى الجموعِ؟', '[{"id":"a","text":"مصابيح"},{"id":"b","text":"كتب"},{"id":"c","text":"أولاد"},{"id":"d","text":"بيوت"}]'::jsonb, 'a', '«مصابيح» على وزنِ مَفاعيل من صيغةِ منتهى الجموعِ، فهو ممنوعٌ من الصرفِ يُجَرُّ بالفتحةِ (مررتُ بمصابيحَ). أمّا «كتب» و«أولاد» و«بيوت» فجموعٌ منصرفةٌ تُنوَّنُ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f59150c-1058-561b-824b-0c8439973366', '242eb144-0ffc-5f1a-a93a-7cabb3891675', 'الفعلُ «قاتلَ» على وزنِ فاعَل، فمصدرُه القياسيُّ يكونُ على وزنِ...', '[{"id":"a","text":"مُفاعَلة أو فِعال (مُقاتَلة / قِتال)"},{"id":"b","text":"تفعيل (تقتيل)"},{"id":"c","text":"إفعال (إقتال)"},{"id":"d","text":"افتعال (اقتتال)"}]'::jsonb, 'a', '«فاعَل» مصدرُه القياسيُّ على وزنِ مُفاعَلة، وقد يأتي على فِعال؛ فمصدرُ «قاتلَ» هو «مُقاتَلة» أو «قِتال». و«اقتتال» مصدرُ «اقتتلَ» (افتعل)، فلا تخلطْ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eaf05896-9f9f-5355-8e30-8c3cfbb9af78', '242eb144-0ffc-5f1a-a93a-7cabb3891675', 'في «هذا مَسعى الخيرِ» بمعنى السعيِ إلى الخيرِ، كلمةُ «مَسعى»...', '[{"id":"a","text":"اسمُ مكانٍ (مكانُ السعيِ)"},{"id":"b","text":"اسمُ آلةٍ"},{"id":"c","text":"مصدرٌ صناعيٌّ"},{"id":"d","text":"مصدرٌ ميميٌّ (يدلّ على الحدثِ نفسِه)"}]'::jsonb, 'd', '«مَسعى» على وزنِ مَفْعَل، وهي هنا تدلّ على الحدثِ نفسِه (السعيِ) لا على مكانِه، فالمعنى: هذا سعيٌ إلى الخيرِ؛ فهي مصدرٌ ميميٌّ. ولو أُريدَ مكانُ السعيِ لكانتِ اسمَ مكانٍ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eafd9097-76f6-589d-8028-f95c673645e4', '242eb144-0ffc-5f1a-a93a-7cabb3891675', 'في «الشركةُ الوطنيّةُ للنقلِ»، لماذا تكونُ «الوطنيّة» نعتًا منسوبًا لا مصدرًا صناعيًّا؟', '[{"id":"a","text":"لأنّها تنتهي بياءٍ مشدّدةٍ وتاءٍ فهي مصدرٌ صناعيٌّ"},{"id":"b","text":"لأنّها وصفتْ موصوفًا («الشركة») فهي نسبةٌ إليه لا معنًى مجرّدٌ"},{"id":"c","text":"لأنّها جمعُ تكسيرٍ ممنوعٌ من الصرفِ"},{"id":"d","text":"لأنّها مصدرٌ ميميٌّ يدلّ على الحدثِ"}]'::jsonb, 'b', 'الميزانُ الحاسمُ: إن وُصف بها موصوفٌ فهي منسوبٌ (نعتٌ). «الوطنيّة» هنا تصفُ «الشركة» فهي نعتٌ منسوبٌ. ولو قلنا «الوطنيّةُ واجبٌ» لكانتْ مصدرًا صناعيًّا يدلّ على معنًى مجرّدٍ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

