  ('7466ac36-8e37-5579-a5a7-d1d1a6d7ed6e', 'd7920853-fb71-572d-a255-57713543e010', 'arabic-8eme', '⚔️ زعيم الفصل ⭐⭐⭐: تمرّسٌ على الأوزانِ وصياغةِ المصادرِ', 3, 120, 30, 'boss', 'admin', 5)
