INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('febd9771-f1c1-56e7-8350-f741e155af88', '7466ac36-8e37-5579-a5a7-d1d1a6d7ed6e', 'الوزنُ «فِعْلة» في «فِتية» و«صِبية» من جموعِ...', '[{"id":"a","text":"الكثرةِ"},{"id":"b","text":"القلّةِ"},{"id":"c","text":"منتهى الجموعِ"},{"id":"d","text":"المؤنّثِ السالمِ"}]'::jsonb, 'b', '«فِعْلة» أحدُ أوزانِ جموعِ القلّةِ الأربعةِ (أفعُل، أفعال، أفعِلة، فِعْلة)؛ فـ«فِتية» و«صِبية» جمعا قلّةٍ.', 1)
