INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3c62feae-afb3-59ec-ae5a-b29a3d83d12f', '7466ac36-8e37-5579-a5a7-d1d1a6d7ed6e', 'أيُّ الأوزانِ الآتيةِ ليس من أوزانِ جموعِ القلّةِ الأربعةِ؟', '[{"id":"a","text":"أَفْعُل"},{"id":"b","text":"أَفْعِلة"},{"id":"c","text":"فِعْلة"},{"id":"d","text":"فُعول"}]'::jsonb, 'd', 'أوزانُ القلّةِ أربعةٌ: أفعُل، أفعال، أفعِلة، فِعْلة. أمّا «فُعول» (بيوت ؛ قلوب) فمن جموعِ الكثرةِ.', 2)
