INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9456b78b-cd6e-5436-be24-c7ae743b0d95', '7466ac36-8e37-5579-a5a7-d1d1a6d7ed6e', 'ما مصدرُ الفعلِ «تقدّمَ»؟', '[{"id":"a","text":"تقدُّم"},{"id":"b","text":"قُدوم"},{"id":"c","text":"إقدام"},{"id":"d","text":"تقديم"}]'::jsonb, 'a', '«تقدّمَ» على وزنِ تفعّل، ومصدرُه القياسيُّ على وزنِ تفعُّل = «تقدُّم». و«إقدام» مصدرُ «أقدمَ»، و«تقديم» مصدرُ «قدّمَ».', 3)
