INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a0e638e-c4fb-577e-a60a-cff588ca05f8', '7466ac36-8e37-5579-a5a7-d1d1a6d7ed6e', 'ما مصدرُ الفعلِ «اجتمعَ»؟', '[{"id":"a","text":"جَمْع"},{"id":"b","text":"تجميع"},{"id":"c","text":"اجتماع"},{"id":"d","text":"مُجامَعة"}]'::jsonb, 'c', '«اجتمعَ» على وزنِ افتعل، ومصدرُه القياسيُّ على وزنِ افتعال = «اجتماع». و«جَمْع» مصدرُ الثّلاثيِّ «جمَعَ».', 4)
