INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fb8520c4-05ed-59a5-92a8-d000c73d58ed', '7466ac36-8e37-5579-a5a7-d1d1a6d7ed6e', 'الفعلُ «استخرجَ» على وزنِ استفعل، فمصدرُه...', '[{"id":"a","text":"خُروج"},{"id":"b","text":"تخريج"},{"id":"c","text":"إخراج"},{"id":"d","text":"استخراج"}]'::jsonb, 'd', '«استفعل» مصدرُه القياسيُّ على وزنِ استفعال = «استخراج». و«خُروج» مصدرُ الثّلاثيِّ «خرجَ»، و«إخراج» مصدرُ «أخرجَ»، و«تخريج» مصدرُ «خرّجَ».', 5)
