INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2b84ca7-429a-5edd-bf32-75d79a0b7e4a', '7466ac36-8e37-5579-a5a7-d1d1a6d7ed6e', 'في «للطالبِ المجتهدِ أفضليّةٌ»، كلمةُ «أفضليّة»...', '[{"id":"a","text":"اسمُ تفضيلٍ"},{"id":"b","text":"منسوبٌ مؤنّثٌ يصفُ موصوفًا"},{"id":"c","text":"مصدرٌ صناعيٌّ يدلّ على معنًى مجرّدٍ"},{"id":"d","text":"مصدرٌ ميميٌّ"}]'::jsonb, 'c', '«أفضليّة» بياءٍ مشدّدةٍ وتاءٍ تدلّ على معنًى مجرّدٍ (خاصّيّةِ التفوّقِ)، فهي مصدرٌ صناعيٌّ. وأصلُها اسمُ التفضيلِ «أفضل»، لكنّها بعدَ الزيادةِ صارتْ مصدرًا صناعيًّا.', 6)
