INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('b5002e11-6007-5af3-b7ad-a0f440107852', 'd7920853-fb71-572d-a255-57713543e010', 'arabic-8eme', '👑 تحدّي النخبة ⭐⭐⭐⭐: أسرارُ التكسيرِ والمصادرِ الأربعةِ', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
