INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6e761349-6b32-502e-ad40-812271a4fe68', 'b5002e11-6007-5af3-b7ad-a0f440107852', '«أعمِدة» و«أزمِنة» على وزنِ أَفْعِلة. ما نوعُ هذين الجمعين؟', '[{"id":"a","text":"جمعا كثرةٍ"},{"id":"b","text":"جمعا قلّةٍ"},{"id":"c","text":"صيغتا منتهى الجموعِ"},{"id":"d","text":"جمعا مذكّرٍ سالمانِ"}]'::jsonb, 'b', '«أَفْعِلة» من أوزانِ جموعِ القلّةِ الأربعةِ، فـ«أعمِدة» و«أزمِنة» جمعا قلّةٍ يدلّانِ على ما بين 3 و10.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('91bc61d4-97e2-51e0-b349-7e31698b76c3', 'b5002e11-6007-5af3-b7ad-a0f440107852', 'في «سُرِرتُ بنجاحِك ثمّ بتكريمِك»، أيُّ المصدرين قياسيٌّ؟', '[{"id":"a","text":"«نجاح» قياسيٌّ و«تكريم» سماعيٌّ"},{"id":"b","text":"كلاهما سماعيٌّ"},{"id":"c","text":"«تكريم» قياسيٌّ (من «كرّمَ» غيرِ الثّلاثيِّ) و«نجاح» سماعيٌّ (من «نجحَ» الثّلاثيِّ)"},{"id":"d","text":"كلاهما قياسيٌّ"}]'::jsonb, 'c', '«نجاح» مصدرُ «نجحَ» الثّلاثيِّ، فهو سماعيٌّ يُحفَظُ. و«تكريم» مصدرُ «كرّمَ» (فعّل) غيرِ الثّلاثيِّ على وزنِ تفعيل، فهو قياسيٌّ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('17862d08-9fd7-5fbe-a43c-fee0af900de1', 'b5002e11-6007-5af3-b7ad-a0f440107852', 'المصدرُ الصناعيُّ المصوغُ من كلمةِ «اشتراك» هو...', '[{"id":"a","text":"اشتراكية"},{"id":"b","text":"مُشترَك"},{"id":"c","text":"مشاركة"},{"id":"d","text":"شركات"}]'::jsonb, 'a', 'نزيدُ على «اشتراك» ياءً مشدّدةً وتاءً للدلالةِ على معنًى مجرّدٍ (المذهبِ الاقتصاديِّ) = «اشتراكية». و«مشاركة» مصدرُ «شاركَ»، و«مُشترَك» اسمُ مفعولٍ، و«شركات» جمعٌ.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('db287779-555f-5662-8b3e-2e9e342b85ee', 'b5002e11-6007-5af3-b7ad-a0f440107852', 'المصدرُ الميميُّ من الفعلِ «التقى» يُصاغُ على وزنِ اسمِ المفعولِ، وهو...', '[{"id":"a","text":"مِلقاة"},{"id":"b","text":"لِقاء"},{"id":"c","text":"تلاقٍ"},{"id":"d","text":"مُلتقًى"}]'::jsonb, 'd', 'مصدرُ الميميِّ من غيرِ الثّلاثيِّ يكونُ على وزنِ اسمِ المفعولِ؛ فمن «التقى» (افتعل) نقولُ «مُلتقًى». و«لِقاء» مصدرٌ أصليٌّ، و«مِلقاة» اسمُ آلةٍ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e1ef9cae-3faa-5673-a6f7-2208530fa6cf', 'b5002e11-6007-5af3-b7ad-a0f440107852', '«مَسعًى» و«إنسانية»: ما الفرقُ الصرفيُّ بينهما؟', '[{"id":"a","text":"كلاهما مصدرٌ صناعيٌّ"},{"id":"b","text":"«مَسعًى» مصدرٌ ميميٌّ (بميمٍ زائدةٍ في أوّلِه)، و«إنسانية» مصدرٌ صناعيٌّ (بياءٍ مشدّدةٍ وتاءٍ في آخرِه)"},{"id":"c","text":"«مَسعًى» صناعيٌّ و«إنسانية» ميميٌّ"},{"id":"d","text":"كلاهما جمعُ تكسيرٍ"}]'::jsonb, 'b', '«مَسعًى» يبدأُ بميمٍ زائدةٍ على وزنِ مَفْعَل فهو مصدرٌ ميميٌّ، و«إنسانية» يُختَمُ بياءٍ مشدّدةٍ وتاءٍ فهو مصدرٌ صناعيٌّ يدلّ على معنًى مجرّدٍ؛ فالميمُ في الأوّلِ علامةُ الميميِّ، والياءُ والتاءُ في الآخرِ علامةُ الصناعيِّ.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('64b571a5-f306-5251-9c24-a8ca8b6ce5f3', 'b5002e11-6007-5af3-b7ad-a0f440107852', 'في أيِّ جملةٍ تكونُ «العالَميّة» مصدرًا صناعيًّا (معنًى مجرّدًا) لا نعتًا منسوبًا؟', '[{"id":"a","text":"حصلتِ الجامعةُ العالَميّةُ على جائزةٍ"},{"id":"b","text":"زُرتُ المدرسةَ العالَميّةَ"},{"id":"c","text":"تسعى الشركةُ إلى العالَميّةِ (أي إلى الانتشارِ عالميًّا)"},{"id":"d","text":"هذه قناةٌ عالَميّةٌ"}]'::jsonb, 'c', 'في (c) دلّتْ «العالَميّة» على معنًى مجرّدٍ قائمٍ بنفسِه (خاصّيّةِ الانتشارِ) ولا موصوفَ لها، فهي مصدرٌ صناعيٌّ. أمّا في البواقي فوصفتْ موصوفًا (جامعة / مدرسة / قناة)، فهي نعتٌ منسوبٌ.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

